/*
 * contextdata.js  (SC.contextData) – Reise-Kontext-Inhalte für die Lernkarten.
 * REINE DATEN. Wird in data.js auf das volle context-Format gemappt und an die
 * passenden Karten gehängt (Karten-id als Schlüssel).
 *
 * Kompakte Schreibweise pro Eintrag:
 *   e = sentenceEs  – echter, sprechbarer Reisesatz auf Spanisch (LatAm)
 *   d = sentenceDe  – deutsche Übersetzung
 *   s = situation   – konkrete Situation: wann nutzt man das?
 *   n = note        – kurzer Reisetipp / Besonderheit / regionale Variante
 *
 * Inhaltsregeln (siehe data.js): immer ein echter Satz, den man unterwegs sagt –
 * nicht schulisch, nicht künstlich, LatAm-Fokus, lieber ein guter als drei mittlere.
 * Reine Zahlen-Karten (z + Ziffern) bekommen ihren Kontext NICHT hier, sondern
 * praktisch generiert in data.js (Preis/Menge im Reisealltag).
 */
(function () {
  "use strict";

  const C = {
    // ===================== KERN-KARTEN (Showcase, früher inline) =====================
    b10: { e: "Perdón, no entiendo. ¿Puede repetir?", d: "Entschuldigung, ich verstehe nicht. Können Sie das wiederholen?", dEn: "Sorry, I don't understand. Can you repeat that?", s: "Wenn jemand zu schnell oder undeutlich spricht.", sEn: "When someone speaks too fast or unclearly.", n: "Bleib ruhig und ergänze direkt ¿Puede repetir? – das hilft fast immer weiter.", nEn: "Stay calm and just add ¿Puede repetir? – that almost always helps." },
    b16: { e: "Disculpe, ¿dónde está el baño?", d: "Entschuldigung, wo ist die Toilette?", dEn: "Excuse me, where's the toilet?", s: "In Restaurants, Hostels, Busbahnhöfen oder Cafés.", sEn: "In restaurants, hostels, bus stations or cafés.", n: "In Lateinamerika sagt man meistens el baño, nicht wörtlich el inodoro.", nEn: "In Latin America people usually say el baño, not literally el inodoro." },
    b17: { e: "Por favor, necesito ayuda.", d: "Bitte, ich brauche Hilfe.", dEn: "Please, I need help.", s: "Wenn du dich unsicher fühlst oder Unterstützung brauchst.", sEn: "When you feel unsure or need support.", n: "Kurz und klar. In ernsten Situationen kannst du ergänzen: Es urgente.", nEn: "Short and clear. In serious situations you can add: Es urgente." },
    e04: { e: "La cuenta, por favor.", d: "Die Rechnung, bitte.", dEn: "The bill, please.", s: "Im Restaurant, Café oder bei Streetfood mit Sitzbereich.", sEn: "At a restaurant, café or street food with seating.", n: "Kurz, höflich und völlig ausreichend. Noch höflicher: ¿Me trae la cuenta, por favor?", nEn: "Short, polite and perfectly enough. Even more polite: ¿Me trae la cuenta, por favor?" },
    e46: { e: "Para mí sin cebolla, por favor.", d: "Für mich ohne Zwiebeln, bitte.", dEn: "Without onions for me, please.", s: "Beim Bestellen, wenn du eine Zutat vermeiden willst.", sEn: "When ordering, if you want to avoid an ingredient.", n: "Die Struktur sin ... ist extrem praktisch: sin carne, sin queso, sin picante.", nEn: "The sin ... structure is super handy: sin carne, sin queso, sin picante." },
    hostel01: { e: "Hola, tengo una reserva para esta noche.", d: "Hallo, ich habe eine Reservierung für heute Nacht.", dEn: "Hi, I have a reservation for tonight.", s: "Beim Check-in im Hostel, Hotel oder Guesthouse.", sEn: "At check-in at a hostel, hotel or guesthouse.", n: "Wenn nach dem Namen gefragt wird, sag: A nombre de Marcel.", nEn: "If asked for the name, say: A nombre de Marcel." },
    hostel02: { e: "Hola, ¿tiene una cama libre para esta noche?", d: "Hallo, haben Sie für heute Nacht noch ein Bett frei?", dEn: "Hi, do you have a bed free for tonight?", s: "Wenn du spontan ein Hostel suchst oder verlängern möchtest.", sEn: "When you're looking for a hostel on the spot or want to extend.", n: "Alternativ kannst du fragen: ¿Hay una cama disponible?", nEn: "Alternatively you can ask: ¿Hay una cama disponible?" },
    hostel03: { e: "¿El desayuno está incluido en el precio?", d: "Ist das Frühstück im Preis enthalten?", dEn: "Is breakfast included in the price?", s: "Beim Check-in oder bei der Buchung vor Ort.", sEn: "At check-in or when booking on the spot.", n: "Wenn es nicht inklusive ist, frag einfach: ¿Cuánto cuesta?", nEn: "If it's not included, just ask: ¿Cuánto cuesta?" },
    hostel04: { e: "Perdón, ¿dónde está mi cama?", d: "Entschuldigung, wo ist mein Bett?", dEn: "Excuse me, where's my bed?", s: "Im Dorm, wenn dir nur eine Bett- oder Zimmernummer genannt wurde.", sEn: "In the dorm, when you've only been given a bed or room number.", n: "Oben oder unten? Man unterscheidet cama de arriba und cama de abajo.", nEn: "Top or bottom? There's cama de arriba and cama de abajo." },
    hostel05: { e: "Perdón, mi llave no funciona. ¿Me puede ayudar?", d: "Entschuldigung, mein Schlüssel funktioniert nicht. Können Sie mir helfen?", dEn: "Excuse me, my key isn't working. Can you help me?", s: "An der Rezeption, wenn Karte, Schlüssel oder Türcode streiken.", sEn: "At reception, when the card, key or door code won't work.", n: "Für eine Schlüsselkarte sag tarjeta: Mi tarjeta no funciona.", nEn: "For a key card say tarjeta: Mi tarjeta no funciona." },
    hostel06: { e: "¿Puedo dejar mi equipaje aquí hasta la tarde?", d: "Kann ich mein Gepäck hier bis zum Nachmittag lassen?", dEn: "Can I leave my luggage here until the afternoon?", s: "Vor dem Check-in oder nach dem Check-out.", sEn: "Before check-in or after check-out.", n: "Sehr praktisch am Reisetag. Für Rucksack sag mochila.", nEn: "Very handy on a travel day. For backpack say mochila." },
    hostel07: { e: "¿Hay un locker para guardar mis cosas?", d: "Gibt es ein Schließfach, um meine Sachen aufzubewahren?", dEn: "Is there a locker to store my things?", s: "Im Dorm, wenn du Wertsachen sicher verstauen willst.", sEn: "In the dorm, when you want to store valuables safely.", n: "locker wird fast überall verstanden. Spanischer wäre casillero.", nEn: "locker is understood almost everywhere. More Spanish would be casillero." },
    hostel08: { e: "Perdón, mi cama está ocupada. Creo que hay un error.", d: "Entschuldigung, mein Bett ist belegt. Ich glaube, es gibt einen Fehler.", dEn: "Excuse me, my bed is taken. I think there's been a mistake.", s: "Wenn jemand auf deinem zugewiesenen Bett liegt.", sEn: "When someone is in your assigned bed.", n: "Der Zusatz Creo que hay un error klingt ruhig, nicht aggressiv.", nEn: "Adding Creo que hay un error sounds calm, not aggressive." },
    hostel09: { e: "¿Hay cocina para los huéspedes?", d: "Gibt es eine Küche für die Gäste?", dEn: "Is there a kitchen for guests?", s: "Wenn du selbst kochen oder Essen lagern willst.", sEn: "When you want to cook for yourself or store food.", n: "Gäste heißt huéspedes – im Hostel reicht aber auch nur cocina.", nEn: "Guests is huéspedes – but at the hostel just cocina does the job." },
    hostel10: { e: "Disculpe, ¿podría cambiar de habitación? Hay mucho ruido.", d: "Entschuldigung, könnte ich das Zimmer wechseln? Es ist sehr laut.", dEn: "Excuse me, could I change rooms? It's very noisy.", s: "Wenn dein Zimmer zu laut, zu heiß oder problematisch ist.", sEn: "When your room is too noisy, too hot or otherwise a problem.", n: "Podría ist höflicher als puedo und passt gut an der Rezeption.", nEn: "Podría is more polite than puedo and fits well at reception." },
    v05: { e: "Disculpe, ¿de dónde sale el bus a Cartagena?", d: "Entschuldigung, von wo fährt der Bus nach Cartagena ab?", dEn: "Excuse me, where does the bus to Cartagena leave from?", s: "Am Busbahnhof, bei einer Agentur oder an einer Haltestelle.", sEn: "At the bus station, an agency or a stop.", n: "Je nach Land heißt der Bus auch colectivo, micro, buseta oder camión.", nEn: "Depending on the country the bus is also colectivo, micro, buseta or camión." },
    v12: { e: "¿Cuánto cuesta el viaje al centro?", d: "Wie viel kostet die Fahrt ins Zentrum?", dEn: "How much is the trip to the centre?", s: "Im Taxi oder colectivo, am besten vor dem Einsteigen.", sEn: "In a taxi or colectivo, ideally before getting in.", n: "Vorher fragen schützt vor Überraschungen. Für ein Ticket sag boleto oder pasaje.", nEn: "Asking beforehand saves surprises. For a ticket say boleto or pasaje." },
    n11: { e: "Perdí mi celular. ¿Alguien lo encontró?", d: "Ich habe mein Handy verloren. Hat es jemand gefunden?", dEn: "I've lost my phone. Has anyone found it?", s: "Im Hostel, Bus, Restaurant oder nach einer Tour.", sEn: "At the hostel, on the bus, in a restaurant or after a tour.", n: "In Lateinamerika ist celular das übliche Wort für Handy.", nEn: "In Latin America celular is the usual word for mobile phone." },
    n15: { e: "Disculpe, ¿dónde está la farmacia más cercana?", d: "Entschuldigung, wo ist die nächste Apotheke?", dEn: "Excuse me, where's the nearest pharmacy?", s: "Wenn du Medikamente oder etwas gegen Bauchweh brauchst.", sEn: "When you need medicine or something for a stomach ache.", n: "Apotheken sind in LatAm oft auch ohne Rezept hilfreich. Nachts: farmacia de turno.", nEn: "In LatAm pharmacies are often helpful even without a prescription. At night: farmacia de turno." },
    social01: { e: "Hola, ¿de dónde eres?", d: "Hey, woher kommst du?", dEn: "Hey, where are you from?", s: "Beim Frühstück, im Dorm, in einer Tourgruppe oder im Bus.", sEn: "At breakfast, in the dorm, on a tour group or on the bus.", n: "Perfekter Einstieg. Danach passt: ¿Cuánto tiempo viajas?", nEn: "Perfect opener. After that: ¿Cuánto tiempo viajas?" },
    social02: { e: "¿Viajas solo o con amigos?", d: "Reist du alleine oder mit Freunden?", dEn: "Are you travelling alone or with friends?", s: "Beim Kennenlernen anderer Backpacker.", sEn: "When getting to know other backpackers.", n: "Bei Männern solo, bei Frauen sola. Im Hostel eine ganz normale Frage.", nEn: "Men say solo, women sola. A perfectly normal question at the hostel." },
    social03: { e: "¿Cuánto tiempo estás aquí en Cartagena?", d: "Wie lange bist du hier in Cartagena?", dEn: "How long are you here in Cartagena?", s: "Wenn du wissen willst, ob jemand länger bleibt oder bald weiterreist.", sEn: "When you want to know if someone is staying longer or moving on soon.", n: "Den Ort einfach austauschen: aquí en Bogotá, aquí en Lima, aquí en Medellín.", nEn: "Just swap the place: aquí en Bogotá, aquí en Lima, aquí en Medellín." },
    social04: { e: "¿A dónde vas después de Cartagena?", d: "Wohin reist du nach Cartagena weiter?", dEn: "Where are you off to after Cartagena?", s: "Typischer Backpacker-Smalltalk über Reiserouten.", sEn: "Typical backpacker small talk about travel routes.", n: "Super, um Tipps zu bekommen oder gemeinsame Pläne zu entdecken.", nEn: "Great for getting tips or discovering joint plans." },
    social05: { e: "¿Qué haces mañana? Quiero ir a la playa.", d: "Was machst du morgen? Ich möchte an den Strand gehen.", dEn: "What are you doing tomorrow? I want to go to the beach.", s: "Wenn du gemeinsame Pläne anstoßen willst.", sEn: "When you want to get some joint plans going.", n: "Mach es direkt konkret. Nur ¿Qué haces mañana? kann leicht privat klingen.", nEn: "Make it concrete straight away. Just ¿Qué haces mañana? can sound a bit personal." },
    social06: { e: "¿Quieres ir a comer algo más tarde?", d: "Hast du Lust, später etwas essen zu gehen?", dEn: "Fancy going for something to eat later?", s: "Im Hostel, nach einer Tour oder vor dem Abend.", sEn: "At the hostel, after a tour or before the evening.", n: "más tarde bedeutet später und macht die Einladung locker.", nEn: "más tarde means later and keeps the invitation casual." },
    social07: { e: "¿Vamos juntos al centro?", d: "Gehen wir zusammen ins Zentrum?", dEn: "Shall we go to the centre together?", s: "Wenn ihr dasselbe Ziel habt oder gemeinsam losziehen wollt.", sEn: "When you have the same destination or want to set off together.", n: "juntos für gemischte Gruppen oder Männer, juntas für nur Frauen.", nEn: "juntos for mixed groups or men, juntas for women only." },
    social08: { e: "Vamos a tomar algo. ¿Te unes?", d: "Wir gehen etwas trinken. Kommst du mit?", dEn: "We're going for a drink. Are you coming?", s: "Um jemanden locker einzuladen.", sEn: "To casually invite someone.", n: "Klingt natürlicher als eine sehr formelle Einladung. Perfekt im Hostel.", nEn: "Sounds more natural than a very formal invitation. Perfect at the hostel." },
    social09: { e: "Escríbeme por WhatsApp y nos vemos más tarde.", d: "Schreib mir auf WhatsApp, dann sehen wir uns später.", dEn: "Message me on WhatsApp and we'll meet up later.", s: "Wenn ihr euch später treffen oder Pläne abstimmen wollt.", sEn: "When you want to meet up later or coordinate plans.", n: "WhatsApp ist in Lateinamerika extrem verbreitet – fast jeder nutzt es.", nEn: "WhatsApp is hugely popular in Latin America – almost everyone uses it." },
    social10: { e: "Fue un gusto conocerte. Nos vemos mañana.", d: "War schön, dich kennenzulernen. Wir sehen uns morgen.", dEn: "Nice to meet you. See you tomorrow.", s: "Nach einem ersten Gespräch im Hostel oder unterwegs.", sEn: "After a first chat at the hostel or on the road.", n: "Beim Abschied: Fue un gusto (conocerte). Beim Kennenlernen selbst sagst du Mucho gusto – Antwort oft El gusto es mío.", nEn: "When saying goodbye: Fue un gusto (conocerte). When you first meet you say Mucho gusto – reply often El gusto es mío." },
    social11: { e: "¿Quieres jugar Uno con nosotros?", d: "Möchtest du mit uns Uno spielen?", dEn: "Want to play Uno with us?", s: "Abends im Gemeinschaftsraum des Hostels, wenn eine Runde am Tisch sitzt.", sEn: "In the evening in the hostel common room, when a group is sitting at the table.", n: "Uno kennt fast jeder weltweit – ein einfacher Weg, im Dorm Anschluss zu finden. Auch jugar al Uno ist gebräuchlich.", nEn: "Almost everyone knows Uno worldwide – an easy way to connect in the dorm. jugar al Uno is also common." },
    social12: { e: "¿Quieres jugar conmigo?", d: "Möchtest du mit mir spielen?", dEn: "Want to play with me?", s: "Wenn du jemanden direkt zu einem Spiel einlädst – Karten, Tischtennis oder ein Brettspiel.", sEn: "When you invite someone directly to a game – cards, table tennis or a board game.", n: "conmigo heißt mit mir (ein Wort). Genauso: contigo = mit dir, con nosotros = mit uns.", nEn: "conmigo means with me (one word). Likewise: contigo = with you, con nosotros = with us." },
    social13: { e: "¿Jugamos a las cartas mientras esperamos el bus?", d: "Sollen wir Karten spielen, während wir auf den Bus warten?", dEn: "Shall we play cards while we wait for the bus?", s: "Beim Warten am Terminal oder an einem langen Reisetag, um die Zeit zu vertreiben.", sEn: "While waiting at the terminal or on a long travel day, to pass the time.", n: "jugar a las cartas = Karten spielen. Eine Spielkarte ist una carta, das Kartenspiel/-deck la baraja.", nEn: "jugar a las cartas = to play cards. A playing card is una carta, the deck la baraja." },
    social14: { e: "¿Trajiste una baraja? Me encanta jugar a las cartas.", d: "Hast du ein Kartenspiel dabei? Ich spiele sehr gern Karten.", dEn: "Have you got a pack of cards? I love playing cards.", s: "Wenn ihr nach einer Beschäftigung für den Abend oder die Busfahrt sucht.", sEn: "When you're after something to do for the evening or the bus ride.", n: "la baraja = das Kartenspiel (Deck). In Lateinamerika sehr beliebt, etwa bei einer Partie wie der baraja española.", nEn: "la baraja = the deck of cards. Very popular in Latin America, e.g. a game with the baraja española." },

    // ===================== GRUNDLAGEN =====================
    b01: { e: "¡Hola! Buenos días.", d: "Hallo! Guten Morgen.", dEn: "Hi! Good morning.", s: "Beim Betreten von Laden, Hostel oder Restaurant.", sEn: "When entering a shop, hostel or restaurant.", n: "Ein freundliches Hola öffnet überall Türen – auch unter Fremden völlig normal.", nEn: "A friendly Hola opens doors everywhere – completely normal even among strangers." },
    b02: { e: "Buenos días, ¿cómo está?", d: "Guten Morgen, wie geht es Ihnen?", dEn: "Good morning, how are you?", s: "Morgens an der Rezeption, im Café oder beim Bäcker.", sEn: "In the morning at reception, the café or the baker's.", n: "Bis etwa mittags Buenos días, danach Buenas tardes.", nEn: "Until about midday Buenos días, after that Buenas tardes." },
    b03: { e: "Buenas tardes, una mesa para dos, por favor.", d: "Guten Tag, einen Tisch für zwei, bitte.", dEn: "Hello, a table for two, please.", s: "Nachmittags beim Betreten von Restaurant oder Laden.", sEn: "In the afternoon when entering a restaurant or shop.", n: "Ab Einbruch der Dunkelheit wird daraus Buenas noches.", nEn: "After dark it becomes Buenas noches." },
    b04: { e: "¡Chau, nos vemos!", d: "Tschüss, bis bald!", dEn: "Bye, see you soon!", s: "Beim Verabschieden von Leuten im Hostel oder unterwegs.", sEn: "When saying goodbye to people at the hostel or on the road.", n: "Chau ist locker und in ganz Südamerika beliebt; Adiós klingt endgültiger.", nEn: "Chau is casual and popular all over South America; Adiós sounds more final." },
    b05: { e: "Una mesa para dos, por favor.", d: "Einen Tisch für zwei, bitte.", dEn: "A table for two, please.", s: "Bei jeder Bitte – Bestellung, Frage, Wunsch.", sEn: "With any request – an order, a question, a wish.", n: "Por favor am Satzende macht fast jede Bitte sofort höflich.", nEn: "Por favor at the end of a sentence makes almost any request instantly polite." },
    b06: { e: "Muchas gracias, muy amable.", d: "Vielen Dank, sehr freundlich.", dEn: "Thank you, very kind.", s: "Nach Hilfe, Service oder einem Tipp.", sEn: "After help, service or a tip.", n: "Verstärken mit Muchas gracias oder Mil gracias.", nEn: "Strengthen it with Muchas gracias or Mil gracias." },
    b07: { e: "– Gracias. – De nada.", d: "– Danke. – Gern geschehen.", dEn: "– Thanks. – You're welcome.", s: "Wenn dir jemand dankt.", sEn: "When someone thanks you.", n: "Lockerer geht auch Con gusto oder No hay de qué.", nEn: "More casually you can also say Con gusto or No hay de qué." },
    b08: { e: "Disculpe, ¿me puede ayudar?", d: "Entschuldigung, können Sie mir helfen?", dEn: "Excuse me, can you help me?", s: "Um jemanden anzusprechen oder um Hilfe zu bitten.", sEn: "To approach someone or ask for help.", n: "Disculpe, um Aufmerksamkeit zu bekommen; Perdón eher beim Anrempeln.", nEn: "Disculpe to get attention; Perdón more for bumping into someone." },
    b09: { e: "– ¿Todo bien? – Sí, gracias.", d: "– Alles gut? – Ja, danke.", dEn: "– All good? – Yes, thanks.", s: "In jeder kurzen Rückfrage.", sEn: "In any quick check-in.", n: "Ein klares Sí oder No mit einem Lächeln reicht oft völlig.", nEn: "A clear Sí or No with a smile is often plenty." },
    b11: { e: "Disculpe, ¿habla inglés?", d: "Entschuldigung, sprechen Sie Englisch?", dEn: "Excuse me, do you speak English?", s: "Wenn du sprachlich nicht weiterkommst.", sEn: "When you're stuck with the language.", n: "Oft hilft die Frage – außerhalb von Touristenorten ist die Antwort aber meist no.", nEn: "The question often helps – but outside tourist spots the answer is usually no." },
    b12: { e: "Hola, ¿cómo te llamas?", d: "Hallo, wie heißt du?", dEn: "Hi, what's your name?", s: "Beim Kennenlernen im Hostel oder unterwegs.", sEn: "When getting to know someone at the hostel or on the road.", n: "Förmlich (Sie): ¿Cómo se llama?", nEn: "Formal (you): ¿Cómo se llama?" },
    b13: { e: "Me llamo Marcel, ¿y tú?", d: "Ich heiße Marcel, und du?", dEn: "My name's Marcel, and you?", s: "Wenn du dich vorstellst.", sEn: "When you introduce yourself.", n: "Das ¿y tú? am Ende hält das Gespräch in Gang.", nEn: "The ¿y tú? at the end keeps the conversation going." },
    b14: { e: "Perdón, ¿me puedes ayudar? Estoy perdido.", d: "Entschuldigung, kannst du mir helfen? Ich habe mich verlaufen.", dEn: "Excuse me, can you help me? I'm lost.", s: "Wenn du Orientierung oder Unterstützung brauchst.", sEn: "When you need directions or support.", n: "Höflicher und förmlich: ¿Me puede ayudar?", nEn: "More polite and formal: ¿Me puede ayudar?" },
    b15: { e: "Más despacio, por favor. No entiendo.", d: "Langsamer, bitte. Ich verstehe nicht.", dEn: "Slower, please. I don't understand.", s: "Wenn jemand zu schnell spricht – oder das Taxi zu schnell fährt.", sEn: "When someone speaks too fast – or the taxi drives too fast.", n: "Kombiniert mit ¿Puede repetir? klappt es fast immer. Gilt fürs Sprechen und fürs Fahren gleichermaßen.", nEn: "Combined with ¿Puede repetir? it almost always works. Applies to speaking and driving alike." },
    b18: { e: "Necesito un médico, por favor.", d: "Ich brauche einen Arzt, bitte.", dEn: "I need a doctor, please.", s: "Bei Krankheit oder Verletzung – im Hostel, in der Apotheke.", sEn: "When ill or injured – at the hostel, at the pharmacy.", n: "Im Notfall ergänzen: Es una emergencia.", nEn: "In an emergency add: Es una emergencia." },
    b19: { e: "¡Llame a la policía, por favor!", d: "Rufen Sie die Polizei, bitte!", dEn: "Call the police, please!", s: "In einer echten Notlage.", sEn: "In a real emergency.", n: "Der Notruf ist in vielen Ländern die 911.", nEn: "The emergency number is 911 in many countries." },
    b20: { e: "Disculpe, estoy perdido. ¿Dónde queda el centro?", d: "Entschuldigung, ich habe mich verlaufen. Wo ist das Zentrum?", dEn: "Excuse me, I'm lost. Where's the centre?", s: "Wenn du die Orientierung verloren hast.", sEn: "When you've lost your bearings.", n: "Männer sagen perdido, Frauen perdida.", nEn: "Men say perdido, women perdida." },
    b21: { e: "¿Hay una farmacia cerca?", d: "Gibt es eine Apotheke in der Nähe?", dEn: "Is there a pharmacy nearby?", s: "Bei kleinen Wehwehchen oder für Medikamente.", sEn: "For minor aches or for medicine.", n: "In LatAm bekommt man in der farmacia vieles auch ohne Rezept.", nEn: "In LatAm you can get a lot at the farmacia without a prescription." },

    // ===================== ZAHLEN (Sonderfälle / Wörter) =====================
    z2025: { e: "Estamos en dos mil veinticinco.", d: "Wir haben 2025.", dEn: "It's 2025.", s: "Wenn nach dem Jahr gefragt wird – Formular, Einreise.", sEn: "When asked for the year – a form, entry into the country.", n: "Jahreszahlen sagt man als ganze Zahl: dos mil veinticinco.", nEn: "Years are said as a whole number: dos mil veinticinco." },
    zp01: { e: "Un café, por favor. – Son tres mil quinientos.", d: "Einen Kaffee, bitte. – Das macht 3.500.", dEn: "A coffee, please. – That's 3,500.", s: "Im Café beim Bezahlen.", sEn: "At the café when paying.", n: "Beträge werden oft ohne pesos genannt – nur die Zahl.", nEn: "Amounts are often given without pesos – just the number." },
    zp02: { e: "Una cerveza. – Son doce mil.", d: "Ein Bier. – Das macht 12.000.", dEn: "A beer. – That's 12,000.", s: "In der Bar oder im Restaurant.", sEn: "At the bar or restaurant.", n: "Trinkgeld (propina) steht oft schon auf der Rechnung.", nEn: "The tip (propina) is often already on the bill." },
    zp03: { e: "El menú del día cuesta veinticinco mil.", d: "Das Tagesmenü kostet 25.000.", dEn: "The set menu costs 25,000.", s: "Beim Mittagessen (almuerzo).", sEn: "At lunch (almuerzo).", n: "Das menú del día hat fast überall das beste Preis-Leistungs-Verhältnis.", nEn: "The menú del día is almost always the best value." },
    zp04: { e: "La cama cuesta cuarenta y cinco mil por noche.", d: "Das Bett kostet 45.000 pro Nacht.", dEn: "The bed costs 45,000 per night.", s: "Beim Check-in im Hostel.", sEn: "At check-in at the hostel.", n: "Frag, ob Frühstück inklusive ist: ¿El desayuno está incluido?", nEn: "Ask whether breakfast is included: ¿El desayuno está incluido?" },
    zp05: { e: "El boleto a Medellín cuesta ciento veinte mil.", d: "Das Ticket nach Medellín kostet 120.000.", dEn: "The ticket to Medellín costs 120,000.", s: "Beim Ticketkauf am Busbahnhof.", sEn: "When buying a ticket at the bus station.", n: "Nachtbusse sind oft teurer, sparen aber eine Hostel-Nacht.", nEn: "Night buses are often pricier, but save a hostel night." },
    zp06: { e: "La excursión cuesta trescientos cincuenta mil por persona.", d: "Der Ausflug kostet 350.000 pro Person.", dEn: "The trip costs 350,000 per person.", s: "Beim Buchen einer Tour.", sEn: "When booking a tour.", n: "Bei Gruppen oft Rabatt – frag: ¿Hay descuento por grupo?", nEn: "Groups often get a discount – ask: ¿Hay descuento por grupo?" },
    zp07: { e: "El alquiler es un millón quinientos mil al mes.", d: "Die Miete beträgt 1.500.000 pro Monat.", dEn: "The rent is 1,500,000 a month.", s: "Wenn du länger bleibst und etwas mietest.", sEn: "When you're staying longer and renting something.", n: "Für längere Aufenthalte lohnt es sich, über den Monatspreis zu verhandeln.", nEn: "For longer stays it's worth negotiating the monthly price." },
    znum: { e: "¿Cuál es el número de tu habitación?", d: "Welche Nummer hat dein Zimmer?", dEn: "What number is your room?", s: "Im Hostel/Hotel, bei Bett- oder Zimmernummer.", sEn: "At the hostel/hotel, with a bed or room number.", n: "número steht auch für die Telefonnummer: tu número.", nEn: "número also means phone number: tu número." },
    zmilord: { e: "Cuesta más de un millón de pesos.", d: "Es kostet über eine Million Pesos.", dEn: "It costs over a million pesos.", s: "Bei großen Beträgen wie Miete oder Flug.", sEn: "With large amounts like rent or a flight.", n: "Achtung Grammatik: un millón de pesos, mit de.", nEn: "Grammar note: un millón de pesos, with de." },
    zmitad: { e: "Solo quiero la mitad, por favor.", d: "Ich möchte nur die Hälfte, bitte.", dEn: "I'd like just half, please.", s: "Auf dem Markt oder beim Bestellen von Portionen.", sEn: "At the market or when ordering portions.", n: "medio kilo = ein halbes Kilo; la mitad = die Hälfte von etwas.", nEn: "medio kilo = half a kilo; la mitad = half of something." },
    zo01: { e: "Es la primera vez que vengo aquí.", d: "Es ist das erste Mal, dass ich hier bin.", dEn: "It's my first time here.", s: "Im Smalltalk über deine Reise.", sEn: "In small talk about your trip.", n: "Vor männlichem Nomen wird primero zu primer: el primer día.", nEn: "Before a masculine noun primero becomes primer: el primer día." },
    zo02: { e: "Mi cuarto está en el segundo piso.", d: "Mein Zimmer ist im zweiten Stock.", dEn: "My room is on the second floor.", s: "Beim Finden des Zimmers.", sEn: "When finding your room.", n: "In LatAm ist el primer piso meist die erste Etage über dem Erdgeschoss.", nEn: "In LatAm el primer piso is usually the first floor above the ground floor." },
    zo03: { e: "Bájate en la tercera parada.", d: "Steig an der dritten Haltestelle aus.", dEn: "Get off at the third stop.", s: "Beim Busfahren mit Wegbeschreibung.", sEn: "On the bus with directions.", n: "Vor männlichem Nomen wird tercero zu tercer: el tercer piso.", nEn: "Before a masculine noun tercero becomes tercer: el tercer piso." },
    zo04: { e: "Es la cuarta calle a la derecha.", d: "Es ist die vierte Straße rechts.", dEn: "It's the fourth street on the right.", s: "Bei einer Wegbeschreibung.", sEn: "When giving directions.", n: "cuarto heißt auch Zimmer – aus dem Kontext meist klar.", nEn: "cuarto also means room – usually clear from context." },
    zo05: { e: "Vivo en el quinto piso.", d: "Ich wohne im fünften Stock.", dEn: "I live on the fifth floor.", s: "Bei Adressen und Stockwerken.", sEn: "With addresses and floors.", n: "Gibt es einen Aufzug? Frag: ¿Hay ascensor?", nEn: "Is there a lift? Ask: ¿Hay ascensor?" },
    zo06: { e: "El mirador está en el sexto piso.", d: "Die Aussichtsplattform ist im sechsten Stock.", dEn: "The viewing platform is on the sixth floor.", s: "In Hotels oder Aussichtstürmen.", sEn: "In hotels or viewing towers.", n: "sexto wird in LatAm oft vereinfacht 'ses-to' gesprochen.", nEn: "sexto is often simplified to 'ses-to' in LatAm." },
    zo07: { e: "Mi habitación es la séptima puerta.", d: "Mein Zimmer ist die siebte Tür.", dEn: "My room is the seventh door.", s: "Bei der Zimmersuche im Flur.", sEn: "When finding your room in the corridor.", n: "Das p in séptimo wird oft kaum gesprochen: SE-ti-mo.", nEn: "The p in séptimo is often barely pronounced: SE-ti-mo." },
    zo08: { e: "La fiesta es en el octavo piso.", d: "Die Party ist im achten Stock.", dEn: "The party is on the eighth floor.", s: "Bei Rooftop-Bars oder Events.", sEn: "At rooftop bars or events.", n: "Ordnungszahlen über 10 nutzt man im Alltag kaum noch.", nEn: "Ordinals above 10 are barely used in everyday speech." },
    zo09: { e: "Estamos en el noveno día de viaje.", d: "Wir sind am neunten Reisetag.", dEn: "We're on the ninth day of the trip.", s: "Im Gespräch über die Reisedauer.", sEn: "When talking about how long the trip is.", n: "Ab 11 sagt man im Alltag meist die normale Zahl statt der Ordnungszahl.", nEn: "From 11 on, people usually say the normal number instead of the ordinal." },
    zo10: { e: "Es mi décimo país en este viaje.", d: "Es ist mein zehntes Land auf dieser Reise.", dEn: "It's my tenth country on this trip.", s: "Beim Erzählen über deine Route.", sEn: "When telling people about your route.", n: "Danach wird es selten: für höhere Zahlen nimmt man die normale Zahl.", nEn: "After that it's rare: for higher numbers you use the normal number." },
    zo1f: { e: "Es mi primera vez en Sudamérica.", d: "Es ist mein erstes Mal in Südamerika.", dEn: "It's my first time in South America.", s: "Im Smalltalk über die Reise.", sEn: "In small talk about the trip.", n: "primera ist die weibliche Form von primero (la primera vez).", nEn: "primera is the feminine form of primero (la primera vez)." },
    zopiso: { e: "Mi habitación está en el primer piso.", d: "Mein Zimmer ist im ersten Stock.", dEn: "My room is on the first floor.", s: "Beim Finden des Zimmers im Hostel/Hotel.", sEn: "When finding your room at the hostel/hotel.", n: "In vielen Ländern ist el primer piso die Etage über dem Erdgeschoss (planta baja).", nEn: "In many countries el primer piso is the floor above the ground floor (planta baja)." },

    // ===================== ESSEN =====================
    e01: { e: "¿A qué hora es la comida?", d: "Wann gibt es Essen?", dEn: "When is food served?", s: "Im Hostel mit Verpflegung oder bei einer Tour.", sEn: "At a hostel with meals or on a tour.", n: "comida heißt Essen allgemein, in Mexiko oft speziell das Mittagessen.", nEn: "comida means food in general, in Mexico often specifically lunch." },
    e02: { e: "Tengo hambre, ¿vamos a comer algo?", d: "Ich habe Hunger, gehen wir etwas essen?", dEn: "I'm hungry, shall we go for something to eat?", s: "Wenn du mit anderen Pläne machst.", sEn: "When making plans with others.", n: "Großer Hunger: Tengo mucha hambre.", nEn: "Really hungry: Tengo mucha hambre." },
    e03: { e: "¿Me trae la carta, por favor?", d: "Bringen Sie mir die Karte, bitte?", dEn: "Could you bring me the menu, please?", s: "Beim Hinsetzen im Restaurant.", sEn: "When sitting down at the restaurant.", n: "la carta ist die Speisekarte; el menú oft das feste Tagesmenü.", nEn: "la carta is the menu; el menú is often the fixed set menu." },
    e05: { e: "Soy vegetariano, ¿qué me recomienda?", d: "Ich bin Vegetarier, was empfehlen Sie?", dEn: "I'm vegetarian, what do you recommend?", s: "Beim Bestellen.", sEn: "When ordering.", n: "Frauen sagen vegetariana. Sicherheitshalber: ¿Tiene algo sin carne?", nEn: "Women say vegetariana. To be safe: ¿Tiene algo sin carne?" },
    e06: { e: "Algo sin carne, por favor.", d: "Etwas ohne Fleisch, bitte.", dEn: "Something without meat, please.", s: "Beim Bestellen, wenn du fleischlos isst.", sEn: "When ordering, if you eat meat-free.", n: "Achtung: pollo (Hähnchen) zählt für viele nicht als carne – extra nachfragen.", nEn: "Note: many don't count pollo (chicken) as carne – ask separately." },
    e07: { e: "¿Me trae un poco de pan?", d: "Bringen Sie mir etwas Brot?", dEn: "Could you bring me some bread?", s: "Im Restaurant oder beim Frühstück.", sEn: "At the restaurant or at breakfast.", n: "In der panadería (Bäckerei) einfach zeigen und die Menge sagen.", nEn: "At the panadería (bakery) just point and say the amount." },
    e08: { e: "Para mí el pollo, por favor.", d: "Für mich das Hähnchen, bitte.", dEn: "The chicken for me, please.", s: "Beim Bestellen.", sEn: "When ordering.", n: "pollo a la plancha = gegrillt, pollo frito = frittiert.", nEn: "pollo a la plancha = grilled, pollo frito = fried." },
    e09: { e: "¿El pescado es fresco?", d: "Ist der Fisch frisch?", dEn: "Is the fish fresh?", s: "An der Küste oder im Fischrestaurant.", sEn: "On the coast or at a fish restaurant.", n: "Tagesfang heißt oft pescado del día.", nEn: "Catch of the day is often pescado del día." },
    e10: { e: "¿Tiene fruta fresca?", d: "Haben Sie frisches Obst?", dEn: "Do you have fresh fruit?", s: "Am Marktstand oder beim Frühstück.", sEn: "At the market stall or at breakfast.", n: "Frischer Saft: jugo natural de fruta.", nEn: "Fresh juice: jugo natural de fruta." },
    e11: { e: "¿Es muy picante?", d: "Ist das sehr scharf?", dEn: "Is it very spicy?", s: "Beim Bestellen, wenn du die Schärfe checken willst.", sEn: "When ordering, if you want to check the spice level.", n: "Nicht scharf: sin picante. Schärfe extra: con ají / con chile.", nEn: "Not spicy: sin picante. Extra heat: con ají / con chile." },
    e12: { e: "¡Qué rico está esto!", d: "Wie lecker das ist!", dEn: "How delicious this is!", s: "Während des Essens, als Kompliment.", sEn: "During the meal, as a compliment.", n: "rico heißt lecker – ein Lob, das überall gut ankommt.", nEn: "rico means tasty – a compliment that goes down well everywhere." },
    e13: { e: "¿A qué hora es el desayuno?", d: "Wann gibt es Frühstück?", dEn: "When is breakfast?", s: "Im Hostel oder Hotel.", sEn: "At the hostel or hotel.", n: "Inklusive? ¿El desayuno está incluido?", nEn: "Included? ¿El desayuno está incluido?" },
    e14: { e: "Quiero el almuerzo del día.", d: "Ich möchte das Mittagsmenü.", dEn: "I'd like the lunch menu.", s: "Mittags im Lokal.", sEn: "At midday in the eatery.", n: "el almuerzo (Mittagessen) ist in LatAm oft die Hauptmahlzeit.", nEn: "el almuerzo (lunch) is often the main meal in LatAm." },
    e15: { e: "¿A qué hora sirven la cena?", d: "Wann gibt es Abendessen?", dEn: "When is dinner?", s: "Abends im Restaurant oder Hostel.", sEn: "In the evening at the restaurant or hostel.", n: "In vielen Ländern isst man spät zu Abend – oft ab 20 Uhr.", nEn: "In many countries dinner is late – often from 8pm." },
    e16: { e: "¿Qué me recomienda de la carta?", d: "Was empfehlen Sie von der Karte?", dEn: "What do you recommend from the menu?", s: "Wenn du Lokales probieren willst.", sEn: "When you want to try local food.", n: "Nach dem typischen Gericht fragen: ¿Cuál es el plato típico?", nEn: "Ask for the typical dish: ¿Cuál es el plato típico?" },
    e17: { e: "Para llevar, por favor.", d: "Zum Mitnehmen, bitte.", dEn: "To take away, please.", s: "Beim Bestellen zum Mitnehmen.", sEn: "When ordering takeaway.", n: "Gegenteil: para comer aquí (zum Hieressen).", nEn: "Opposite: para comer aquí (to eat in)." },
    e18: { e: "Tengo una alergia. ¿Esto lleva maní?", d: "Ich habe eine Allergie. Ist da Erdnuss drin?", dEn: "I have an allergy. Is there peanut in it?", s: "Beim Bestellen mit Unverträglichkeit.", sEn: "When ordering with an intolerance.", n: "Wichtig klar sagen – ergänze die konkrete Zutat (maní, gluten, lactosa).", nEn: "Important to say clearly – add the specific ingredient (maní, gluten, lactosa)." },
    e19: { e: "Con muchas verduras, por favor.", d: "Mit viel Gemüse, bitte.", dEn: "With lots of vegetables, please.", s: "Beim Bestellen.", sEn: "When ordering.", n: "In manchen Ländern auch vegetales.", nEn: "In some countries also vegetales." },
    e20: { e: "¿Viene con arroz?", d: "Kommt das mit Reis?", dEn: "Does it come with rice?", s: "Beim Bestellen.", sEn: "When ordering.", n: "Reis und Bohnen (arroz con frijoles) ist die Standard-Beilage.", nEn: "Rice and beans (arroz con frijoles) is the standard side." },
    e21: { e: "¿Tienen huevos para el desayuno?", d: "Gibt es Eier zum Frühstück?", dEn: "Are there eggs for breakfast?", s: "Beim Frühstück.", sEn: "At breakfast.", n: "Rührei = huevos revueltos.", nEn: "Scrambled eggs = huevos revueltos." },
    e22: { e: "Con queso, por favor.", d: "Mit Käse, bitte.", dEn: "With cheese, please.", s: "Beim Bestellen.", sEn: "When ordering.", n: "Arepa con queso ist ein beliebter Snack.", nEn: "Arepa con queso is a popular snack." },
    e23: { e: "¿Me pasa la sal, por favor?", d: "Reichen Sie mir das Salz, bitte?", dEn: "Could you pass me the salt, please?", s: "Am Tisch.", sEn: "At the table.", n: "Salz sal, Pfeffer pimienta – nicht verwechseln mit pimiento (Paprika).", nEn: "Salt sal, pepper pimienta – don't mix it up with pimiento (bell pepper)." },
    e24: { e: "Quiero el menú del día.", d: "Ich möchte das Tagesmenü.", dEn: "I'd like the set menu.", s: "Mittags im Lokal.", sEn: "At midday in the eatery.", n: "Meist Suppe, Hauptgang und Getränk zum Festpreis – das beste Angebot.", nEn: "Usually soup, main and a drink at a fixed price – the best deal." },
    e25: { e: "¿Qué hay de postre?", d: "Was gibt es zum Nachtisch?", dEn: "What's for dessert?", s: "Nach dem Hauptgang.", sEn: "After the main course.", n: "Oft schon im menú del día inklusive.", nEn: "Often already included in the menú del día." },
    e26: { e: "Otra, por favor.", d: "Noch eins, bitte.", dEn: "Another one, please.", s: "Um Nachschub zu bestellen.", sEn: "To order more.", n: "Form passt sich an: otro café, otra cerveza.", nEn: "The form agrees: otro café, otra cerveza." },
    e27: { e: "Disculpe, ¿podemos ordenar?", d: "Entschuldigung, können wir bestellen?", dEn: "Excuse me, can we order?", s: "Wenn du den Kellner rufen willst.", sEn: "When you want to call the waiter.", n: "In Spanien eher pedir, in LatAm meist ordenar.", nEn: "In Spain more pedir, in LatAm usually ordenar." },
    e28: { e: "Para mí lo mismo, por favor.", d: "Für mich das Gleiche, bitte.", dEn: "The same for me, please.", s: "Beim Bestellen in der Gruppe.", sEn: "When ordering as a group.", n: "Praktisch, wenn dir die Auswahl schwerfällt.", nEn: "Handy when you can't decide." },
    e29: { e: "¿Lo puede hacer menos picante?", d: "Können Sie es weniger scharf machen?", dEn: "Can you make it less spicy?", s: "Beim Bestellen scharfer Gerichte.", sEn: "When ordering spicy dishes.", n: "Ganz ohne: sin picante, por favor.", nEn: "Completely without: sin picante, por favor." },
    e30: { e: "Sin cebolla y con extra queso, por favor.", d: "Ohne Zwiebel und mit extra Käse, bitte.", dEn: "Without onion and with extra cheese, please.", s: "Beim Anpassen der Bestellung.", sEn: "When adjusting your order.", n: "sin = ohne, con extra = mit zusätzlich.", nEn: "sin = without, con extra = with extra." },
    e31: { e: "¿Está libre esta mesa?", d: "Ist dieser Tisch frei?", dEn: "Is this table free?", s: "Im vollen Lokal oder Café.", sEn: "In a busy eatery or café.", n: "Besetzt? ¿Está ocupado?", nEn: "Taken? ¿Está ocupado?" },
    e32: { e: "¿Me lo puede empacar para llevar?", d: "Können Sie es mir einpacken? (Reste)", dEn: "Can you box it up for me? (leftovers)", s: "Wenn du Reste mitnehmen willst.", sEn: "When you want to take leftovers.", n: "In manchen Ländern auch envolver oder para llevar.", nEn: "In some countries also envolver or para llevar." },
    e33: { e: "Otra cerveza, por favor.", d: "Noch ein Bier, bitte.", dEn: "Another beer, please.", s: "In Bar oder Restaurant.", sEn: "At a bar or restaurant.", n: "Eine Runde für alle: una ronda para todos.", nEn: "A round for everyone: una ronda para todos." },
    e35: { e: "La comida estuvo excelente, gracias.", d: "Das Essen war ausgezeichnet, danke.", dEn: "The food was excellent, thanks.", s: "Nach dem Essen als Lob.", sEn: "After the meal, as praise.", n: "estuvo (war) für ein abgeschlossenes Erlebnis.", nEn: "estuvo (was) for a completed experience." },
    e36: { e: "Todo estuvo delicioso.", d: "Alles war köstlich.", dEn: "Everything was delicious.", s: "Beim Bezahlen oder Verabschieden.", sEn: "When paying or saying goodbye.", n: "Kommt beim Personal immer gut an.", nEn: "Always goes down well with the staff." },
    e37: { e: "Me gustó mucho, estuvo muy rico.", d: "Es hat mir sehr gefallen, war richtig lecker.", dEn: "I really enjoyed it, it was really tasty.", s: "Nach dem Essen.", sEn: "After the meal.", n: "rico = lecker, in ganz LatAm gebräuchlich.", nEn: "rico = tasty, used all over LatAm." },
    e38: { e: "Estoy satisfecho, gracias.", d: "Ich bin satt, danke.", dEn: "I'm full, thanks.", s: "Wenn man dir mehr anbietet.", sEn: "When you're offered more.", n: "Höflicher als Estoy lleno. Frauen: satisfecha.", nEn: "More polite than Estoy lleno. Women: satisfecha." },
    e39: { e: "Mis felicitaciones al chef.", d: "Mein Kompliment an den Koch.", dEn: "My compliments to the chef.", s: "Bei besonders gutem Essen.", sEn: "With especially good food.", n: "Ein nettes Extra-Lob, das selten jemand sagt.", nEn: "A nice extra compliment that few people give." },
    e40: { e: "Fue el mejor plato del viaje.", d: "Das war das beste Gericht der Reise.", dEn: "That was the best dish of the trip.", s: "Als großes Kompliment.", sEn: "As a big compliment.", n: "plato = Teller und Gericht zugleich.", nEn: "plato = both plate and dish." },
    e41: { e: "¿Puedo cambiar algo del plato?", d: "Kann ich etwas am Gericht austauschen?", dEn: "Can I swap something in the dish?", s: "Wenn du eine Zutat tauschen willst.", sEn: "When you want to swap an ingredient.", n: "Konkretisieren mit en vez de ... (statt ...).", nEn: "Be specific with en vez de ... (instead of ...)." },
    e42: { e: "¿En vez de las papas fritas, una ensalada?", d: "Statt der Pommes lieber einen Salat?", dEn: "A salad instead of the chips?", s: "Beim Anpassen der Beilage.", sEn: "When adjusting the side.", n: "papas = Kartoffeln; in Spanien patatas.", nEn: "papas = potatoes; in Spain patatas." },
    e43: { e: "¿Puedo cambiar las papas por ensalada?", d: "Kann ich die Pommes gegen Salat tauschen?", dEn: "Can I swap the chips for salad?", s: "Beim Bestellen.", sEn: "When ordering.", n: "Die Struktur cambiar X por Y ist überall nützlich.", nEn: "The cambiar X por Y structure is useful everywhere." },
    e44: { e: "En vez de arroz, frijoles, por favor.", d: "Statt Reis lieber Bohnen, bitte.", dEn: "Beans instead of rice, please.", s: "Beim Wählen der Beilage.", sEn: "When choosing the side.", n: "Bohnen: frijoles, in manchen Ländern porotos oder caraotas.", nEn: "Beans: frijoles, in some countries porotos or caraotas." },
    e45: { e: "¿Puede ser con un acompañamiento a elección?", d: "Geht das mit einer Beilage nach Wahl?", dEn: "Can I have a side of my choice?", s: "Beim Bestellen von Menüs.", sEn: "When ordering set menus.", n: "acompañamiento = Beilage.", nEn: "acompañamiento = side dish." },
    e47: { e: "Sin cilantro, por favor.", d: "Ohne Koriander, bitte.", dEn: "Without coriander, please.", s: "Beim Bestellen, wenn du Koriander nicht magst.", sEn: "When ordering, if you don't like coriander.", n: "cilantro ist in LatAm sehr verbreitet – kommt fast überall drauf.", nEn: "cilantro is very common in LatAm – it goes on almost everything." },
    e48: { e: "El aderezo aparte, por favor.", d: "Dressing bitte separat.", dEn: "Dressing on the side, please.", s: "Beim Salat bestellen.", sEn: "When ordering a salad.", n: "aparte = separat/daneben.", nEn: "aparte = separate/on the side." },
    e49: { e: "¿Puedo reemplazar el pollo por verduras?", d: "Kann ich das Hähnchen durch Gemüse ersetzen?", dEn: "Can I swap the chicken for vegetables?", s: "Für eine vegetarische Anpassung.", sEn: "For a vegetarian tweak.", n: "reemplazar X por Y = X durch Y ersetzen.", nEn: "reemplazar X por Y = to replace X with Y." },
    e50: { e: "¿Tienen Coca en versión Zero?", d: "Gibt es die Cola auch als Zero?", dEn: "Do you have the Coke in Zero?", s: "Beim Getränk bestellen.", sEn: "When ordering a drink.", n: "Light/Zero heißt oft einfach light oder sin azúcar.", nEn: "Light/Zero is often just light or sin azúcar." },
    e51: { e: "¿En vez de jugo, mejor un agua?", d: "Statt Saft lieber ein Wasser?", dEn: "A water instead of juice?", s: "Beim Getränk wählen.", sEn: "When choosing a drink.", n: "agua sin gas = still, con gas = mit Kohlensäure.", nEn: "agua sin gas = still, con gas = sparkling." },
    e52: { e: "¿Puedo cambiar la gaseosa por agua sin gas?", d: "Kann ich statt Limo ein stilles Wasser haben?", dEn: "Can I have still water instead of fizzy drink?", s: "Beim Menügetränk.", sEn: "With the set-menu drink.", n: "gaseosa = Limo/Softdrink in vielen Ländern.", nEn: "gaseosa = fizzy/soft drink in many countries." },
    e53: { e: "Un café sin azúcar, por favor.", d: "Einen Kaffee ohne Zucker, bitte.", dEn: "A coffee without sugar, please.", s: "Beim Heißgetränk.", sEn: "With a hot drink.", n: "Zucker steht oft schon mit drauf – sin azúcar vorher sagen.", nEn: "Sugar is often added by default – say sin azúcar beforehand." },
    e54: { e: "¿El jugo lleva azúcar?", d: "Ist im Saft Zucker?", dEn: "Is there sugar in the juice?", s: "Beim Saft bestellen.", sEn: "When ordering juice.", n: "Ohne Zucker bestellen: sin azúcar, por favor.", nEn: "Order without sugar: sin azúcar, por favor." },
    e55: { e: "Soy alérgico a las nueces.", d: "Ich bin allergisch gegen Nüsse.", dEn: "I'm allergic to nuts.", s: "Beim Bestellen mit Allergie.", sEn: "When ordering with an allergy.", n: "Frauen: alérgica. Wichtig, das klar und früh zu sagen.", nEn: "Women: alérgica. Important to say it clearly and early." },
    e56: { e: "¿Esto contiene gluten?", d: "Enthält das Gluten?", dEn: "Does this contain gluten?", s: "Bei Glutenunverträglichkeit.", sEn: "With a gluten intolerance.", n: "Glutenfrei: sin gluten / libre de gluten.", nEn: "Gluten-free: sin gluten / libre de gluten." },
    e57: { e: "No tolero la lactosa.", d: "Ich vertrage keine Laktose.", dEn: "I can't have lactose.", s: "Beim Bestellen mit Milchprodukten.", sEn: "When ordering with dairy.", n: "Laktosefrei: sin lactosa. Pflanzenmilch: leche vegetal.", nEn: "Lactose-free: sin lactosa. Plant milk: leche vegetal." },
    e58: { e: "¿Lleva maní? Es importante.", d: "Ist da Erdnuss drin? Das ist wichtig.", dEn: "Is there peanut in it? It's important.", s: "Bei Erdnussallergie – ernst.", sEn: "With a peanut allergy – serious.", n: "maní = Erdnuss (Spanien: cacahuete). Bei Allergie immer Es importante betonen.", nEn: "maní = peanut (Spain: cacahuete). With an allergy always stress Es importante." },
    e59: { e: "¿Me lo puede dar para llevar?", d: "Kann ich das zum Mitnehmen bekommen?", dEn: "Can I get this to take away?", s: "Wenn du das Essen mitnehmen willst.", sEn: "When you want to take the food away.", n: "para llevar = zum Mitnehmen, überall verständlich.", nEn: "para llevar = to take away, understood everywhere." },
    e60: { e: "El resto para llevar, por favor.", d: "Den Rest bitte einpacken.", dEn: "Box up the rest, please.", s: "Wenn etwas übrig bleibt.", sEn: "When there are leftovers.", n: "Reste mitnehmen ist normal – kein Grund zur Scheu.", nEn: "Taking leftovers is normal – no need to feel shy." },

    // ===================== TRINKEN =====================
    t01: { e: "Tengo sed, ¿me trae un agua?", d: "Ich habe Durst, bringen Sie mir ein Wasser?", dEn: "I'm thirsty, could you bring me a water?", s: "Im Lokal oder unterwegs.", sEn: "At the eatery or on the go.", n: "Großer Durst: Tengo mucha sed.", nEn: "Really thirsty: Tengo mucha sed." },
    t02: { e: "Un agua sin gas, por favor.", d: "Ein stilles Wasser, bitte.", dEn: "A still water, please.", s: "Beim Bestellen.", sEn: "When ordering.", n: "con gas = mit Kohlensäure, sin gas = still.", nEn: "con gas = sparkling, sin gas = still." },
    t03: { e: "¿Es potable el agua de la llave?", d: "Ist das Leitungswasser trinkbar?", dEn: "Is the tap water drinkable?", s: "Im Hostel oder Restaurant.", sEn: "At the hostel or restaurant.", n: "In vielen Ländern besser Flaschenwasser (agua embotellada) trinken.", nEn: "In many countries it's better to drink bottled water (agua embotellada)." },
    t04: { e: "Una botella de agua grande, por favor.", d: "Eine große Flasche Wasser, bitte.", dEn: "A large bottle of water, please.", s: "Im Laden oder Restaurant.", sEn: "At the shop or restaurant.", n: "grande/pequeña für die Größe.", nEn: "grande/pequeña for the size." },
    t05: { e: "Una cerveza bien fría, por favor.", d: "Ein gut gekühltes Bier, bitte.", dEn: "A nice cold beer, please.", s: "In Bar oder Restaurant.", sEn: "At a bar or restaurant.", n: "bien fría = schön kalt – wichtig in den Tropen.", nEn: "bien fría = nice and cold – important in the tropics." },
    t06: { e: "Una copa de vino tinto, por favor.", d: "Ein Glas Rotwein, bitte.", dEn: "A glass of red wine, please.", s: "Im Restaurant.", sEn: "At the restaurant.", n: "tinto = rot, blanco = weiß. Achtung: in Kolumbien ist un tinto ein schwarzer Kaffee!", nEn: "tinto = red, blanco = white. Watch out: in Colombia un tinto is a black coffee!" },
    t07: { e: "Un café, por favor.", d: "Einen Kaffee, bitte.", dEn: "A coffee, please.", s: "Im Café oder zum Frühstück.", sEn: "At the café or for breakfast.", n: "In Kolumbien heißt schwarzer Kaffee tinto; con leche = mit Milch.", nEn: "In Colombia black coffee is tinto; con leche = with milk." },
    t08: { e: "Un jugo natural de mango, por favor.", d: "Einen frischen Mangosaft, bitte.", dEn: "A fresh mango juice, please.", s: "Am Saftstand oder im Café.", sEn: "At the juice stand or café.", n: "jugo natural = frisch gepresst, oft en agua (Wasser) oder en leche (Milch).", nEn: "jugo natural = freshly pressed, often en agua (water) or en leche (milk)." },
    t09: { e: "¿El café viene con leche?", d: "Kommt der Kaffee mit Milch?", dEn: "Does the coffee come with milk?", s: "Beim Heißgetränk.", sEn: "With a hot drink.", n: "Pflanzenmilch oft als leche de almendras / de avena.", nEn: "Plant milk often as leche de almendras / de avena." },
    t10: { e: "¡Salud! Por el viaje.", d: "Prost! Auf die Reise.", dEn: "Cheers! To the trip.", s: "Beim Anstoßen.", sEn: "When toasting.", n: "Salud heißt zugleich Gesundheit – das klassische Prost.", nEn: "Salud also means health – the classic toast." },
    t11: { e: "Gracias por el trago.", d: "Danke fürs Getränk.", dEn: "Thanks for the drink.", s: "Wenn dich jemand einlädt.", sEn: "When someone treats you.", n: "trago = Drink/Schluck; un trago auszugeben ist eine nette Geste.", nEn: "trago = drink/sip; buying someone un trago is a nice gesture." },
    t12: { e: "¡Por nosotros y el viaje!", d: "Auf uns und die Reise!", dEn: "To us and the trip!", s: "Beim Anstoßen mit neuen Leuten.", sEn: "When toasting with new people.", n: "Por ... = auf ... – flexibel: por la amistad, por Colombia.", nEn: "Por ... = to ... – flexible: por la amistad, por Colombia." },
    t13: { e: "La próxima invito yo.", d: "Das nächste Mal lade ich ein.", dEn: "Next time it's on me.", s: "In geselliger Runde.", sEn: "In good company.", n: "La próxima (vez) = das nächste Mal; invitar heißt hier spendieren.", nEn: "La próxima (vez) = next time; invitar here means to treat someone." },
    t14: { e: "Este jugo está buenísimo.", d: "Dieser Saft schmeckt richtig gut.", dEn: "This juice tastes really good.", s: "Während des Trinkens.", sEn: "While drinking.", n: "-ísimo verstärkt: bueno wird zu buenísimo (sehr gut).", nEn: "-ísimo intensifies: bueno becomes buenísimo (really good)." },

    // ===================== HOTEL =====================
    h01: { e: "Hola, ¿tiene una habitación para esta noche?", d: "Hallo, haben Sie ein Zimmer für heute Nacht?", dEn: "Hi, do you have a room for tonight?", s: "Beim spontanen Check-in.", sEn: "At a spontaneous check-in.", n: "habitación = Zimmer; im Hostel eher cama (Bett).", nEn: "habitación = room; at the hostel rather cama (bed)." },
    h02: { e: "Quiero una habitación doble, por favor.", d: "Ich möchte ein Doppelzimmer, bitte.", dEn: "I'd like a double room, please.", s: "Beim Buchen vor Ort.", sEn: "When booking on the spot.", n: "doble = Doppel, sencilla/individual = Einzel.", nEn: "doble = double, sencilla/individual = single." },
    h03: { e: "Para una noche, por favor.", d: "Für eine Nacht, bitte.", dEn: "For one night, please.", s: "Beim Check-in.", sEn: "At check-in.", n: "Für mehrere: para tres noches.", nEn: "For several: para tres noches." },
    h04: { e: "¿Hay wifi en la habitación?", d: "Gibt es WLAN im Zimmer?", dEn: "Is there wifi in the room?", s: "Beim Check-in.", sEn: "At check-in.", n: "Passwort: ¿Cuál es la contraseña del wifi?", nEn: "Password: ¿Cuál es la contraseña del wifi?" },
    h05: { e: "¿Me da la llave, por favor?", d: "Geben Sie mir den Schlüssel, bitte?", dEn: "Could you give me the key, please?", s: "Beim Check-in oder Zurückkommen.", sEn: "At check-in or when coming back.", n: "Schlüsselkarte: la tarjeta.", nEn: "Key card: la tarjeta." },
    h06: { e: "La ducha no tiene agua caliente.", d: "Die Dusche hat kein warmes Wasser.", dEn: "The shower has no hot water.", s: "Wenn etwas im Bad nicht stimmt.", sEn: "When something's wrong in the bathroom.", n: "agua caliente = warmes Wasser.", nEn: "agua caliente = hot water." },
    h07: { e: "¿Me puede dar una toalla?", d: "Können Sie mir ein Handtuch geben?", dEn: "Can you give me a towel?", s: "Wenn keins im Zimmer ist.", sEn: "When there isn't one in the room.", n: "In Hostels kostet die toalla manchmal extra.", nEn: "At hostels the toalla sometimes costs extra." },
    h08: { e: "¿La habitación tiene aire acondicionado?", d: "Hat das Zimmer eine Klimaanlage?", dEn: "Does the room have air conditioning?", s: "In heißen Regionen wichtig.", sEn: "Important in hot regions.", n: "Kurz: el aire. Ventilator: el ventilador.", nEn: "Short: el aire. Fan: el ventilador." },
    h09: { e: "¿Puedo ver la habitación antes?", d: "Kann ich das Zimmer vorher sehen?", dEn: "Can I see the room first?", s: "Vor dem Buchen vor Ort.", sEn: "Before booking on the spot.", n: "Völlig normal – besonders bei günstigen Unterkünften.", nEn: "Completely normal – especially at budget places." },
    h10: { e: "¿A qué hora es el check-out?", d: "Um wie viel Uhr ist der Check-out?", dEn: "What time is check-out?", s: "Beim Planen des Abreisetags.", sEn: "When planning your departure day.", n: "Meist gegen 10–11 Uhr. Später fragen: ¿Puedo salir más tarde?", nEn: "Usually around 10–11am. Ask for later: ¿Puedo salir más tarde?" },
    h11: { e: "¿Puedo cambiar de habitación? Hay mucho ruido.", d: "Kann ich das Zimmer wechseln? Es ist sehr laut.", dEn: "Can I change rooms? It's very noisy.", s: "Bei Problemen mit dem Zimmer.", sEn: "When there are problems with the room.", n: "Höflicher: ¿Podría cambiar de habitación?", nEn: "More polite: ¿Podría cambiar de habitación?" },
    h12: { e: "No hay agua caliente en la ducha.", d: "Es gibt kein warmes Wasser in der Dusche.", dEn: "There's no hot water in the shower.", s: "An der Rezeption melden.", sEn: "Reporting it at reception.", n: "Häufiges Problem – ruhig und freundlich ansprechen.", nEn: "A common problem – raise it calmly and politely." },
    h13: { e: "Algo está roto en el baño.", d: "Etwas ist im Bad kaputt.", dEn: "Something is broken in the bathroom.", s: "Beim Melden eines Defekts.", sEn: "When reporting a fault.", n: "roto = kaputt, dañado = beschädigt/defekt.", nEn: "roto = broken, dañado = damaged/faulty." },
    h14: { e: "El aire no funciona.", d: "Die Klimaanlage geht nicht.", dEn: "The air conditioning isn't working.", s: "An der Rezeption.", sEn: "At reception.", n: "no funciona = funktioniert nicht – universell einsetzbar.", nEn: "no funciona = isn't working – useful for anything." },
    h15: { e: "El wifi no funciona en mi cuarto.", d: "Das WLAN geht nicht in meinem Zimmer.", dEn: "The wifi isn't working in my room.", s: "Bei Internetproblemen.", sEn: "With internet problems.", n: "Vielleicht neu einloggen – nach der contraseña fragen.", nEn: "Maybe log in again – ask for the contraseña." },
    h16: { e: "La luz no funciona.", d: "Das Licht geht nicht.", dEn: "The light isn't working.", s: "Beim Melden.", sEn: "When reporting it.", n: "Glühbirne: el foco / la bombilla.", nEn: "Light bulb: el foco / la bombilla." },
    h17: { e: "La habitación es muy ruidosa.", d: "Das Zimmer ist zu laut.", dEn: "The room is too noisy.", s: "Wenn du nicht schlafen kannst.", sEn: "When you can't sleep.", n: "Bitte um ein ruhigeres: ¿Tiene una más tranquila?", nEn: "Ask for a quieter one: ¿Tiene una más tranquila?" },
    h18: { e: "¿Lo pueden arreglar hoy?", d: "Können Sie es heute reparieren?", dEn: "Can you fix it today?", s: "Nach dem Melden eines Defekts.", sEn: "After reporting a fault.", n: "arreglar = reparieren/in Ordnung bringen.", nEn: "arreglar = to fix/sort out." },
    h19: { e: "Necesito otra toalla, por favor.", d: "Ich brauche noch ein Handtuch, bitte.", dEn: "I need another towel, please.", s: "An der Rezeption.", sEn: "At reception.", n: "otra = noch eine/eine weitere.", nEn: "otra = another/one more." },
    h20: { e: "¿Pueden limpiar la habitación, por favor?", d: "Können Sie das Zimmer sauber machen?", dEn: "Can you clean the room?", s: "Bei längerem Aufenthalt.", sEn: "On a longer stay.", n: "Reinigung: la limpieza.", nEn: "Cleaning: la limpieza." },
    h21: { e: "¿Puedo hacer el check-out más tarde?", d: "Kann ich später auschecken?", dEn: "Can I check out later?", s: "Am Abreisetag.", sEn: "On your departure day.", n: "Manchmal gegen Aufpreis möglich – einfach fragen.", nEn: "Sometimes possible for a surcharge – just ask." },
    h23: { e: "El baño está tapado.", d: "Die Toilette ist verstopft.", dEn: "The toilet is blocked.", s: "Beim Melden an der Rezeption.", sEn: "When reporting it at reception.", n: "tapado = verstopft. Unangenehm, aber wichtig zu sagen.", nEn: "tapado = blocked. Awkward, but important to say." },
    h24: { e: "Tengo mucho calor, ¿puedo prender el aire?", d: "Mir ist sehr warm, kann ich die Klimaanlage anmachen?", dEn: "I'm very hot, can I turn on the air conditioning?", s: "Im Zimmer.", sEn: "In the room.", n: "Wichtig: Tengo calor (mir ist warm), NICHT Estoy caliente!", nEn: "Important: Tengo calor (I'm hot), NOT Estoy caliente!" },

    // ===================== EINKAUFEN =====================
    c01: { e: "¿Cuánto cuesta esto?", d: "Wie viel kostet das?", dEn: "How much is this?", s: "Im Laden oder auf dem Markt.", sEn: "At the shop or market.", n: "Auch ¿Cuánto vale? oder auf dem Markt ¿A cómo?", nEn: "Also ¿Cuánto vale? or at the market ¿A cómo?" },
    c02: { e: "Uff, es muy caro.", d: "Puh, das ist zu teuer.", dEn: "Phew, that's too expensive.", s: "Beim Handeln auf dem Markt.", sEn: "When haggling at the market.", n: "Leitet mit einem Lächeln oft das Verhandeln ein.", nEn: "With a smile, it often kicks off the haggling." },
    c03: { e: "¿Tiene agua fría?", d: "Haben Sie kaltes Wasser?", dEn: "Do you have cold water?", s: "Im Laden/Kiosk.", sEn: "At the shop/kiosk.", n: "Universelle Frage – das Wort einfach austauschen.", nEn: "A universal question – just swap the word." },
    c04: { e: "Gracias, solo estoy mirando.", d: "Danke, ich schaue nur.", dEn: "Thanks, I'm just looking.", s: "Wenn dich Verkäufer ansprechen.", sEn: "When sellers approach you.", n: "Höflich und entspannt – ohne Kaufdruck.", nEn: "Polite and relaxed – no pressure to buy." },
    c05: { e: "Me llevo esto, gracias.", d: "Ich nehme das, danke.", dEn: "I'll take this, thanks.", s: "An der Kasse / beim Stand.", sEn: "At the till / at the stall.", n: "llevarse = mitnehmen/kaufen.", nEn: "llevarse = to take/buy." },
    c06: { e: "¿Dónde está el mercado?", d: "Wo ist der Markt?", dEn: "Where's the market?", s: "Auf der Suche nach frischen Lebensmitteln.", sEn: "When looking for fresh food.", n: "Märkte sind oft günstiger und authentischer als Supermärkte.", nEn: "Markets are often cheaper and more authentic than supermarkets." },
    c07: { e: "Busco un supermercado cerca.", d: "Ich suche einen Supermarkt in der Nähe.", dEn: "I'm looking for a supermarket nearby.", s: "Beim Selbstversorgen.", sEn: "When self-catering.", n: "Kleiner Laden um die Ecke: la tienda.", nEn: "Small shop round the corner: la tienda." },
    c08: { e: "Una bolsa, por favor.", d: "Eine Tüte, bitte.", dEn: "A bag, please.", s: "An der Kasse.", sEn: "At the till.", n: "Tüten kosten oft extra – ein Stoffbeutel lohnt sich.", nEn: "Bags often cost extra – a cloth bag pays off." },
    c09: { e: "¿Hay descuento si llevo dos?", d: "Gibt es Rabatt, wenn ich zwei nehme?", dEn: "Is there a discount if I take two?", s: "Auf dem Markt oder bei Mengen.", sEn: "At the market or when buying in bulk.", n: "descuento = Rabatt; Mengenrabatt ist oft drin.", nEn: "descuento = discount; a bulk discount is often possible." },
    c10: { e: "¿No tiene algo más barato?", d: "Haben Sie nichts Günstigeres?", dEn: "Don't you have anything cheaper?", s: "Beim Vergleichen.", sEn: "When comparing.", n: "barato = billig, caro = teuer.", nEn: "barato = cheap, caro = expensive." },
    c11: { e: "¿Me lo puedo probar?", d: "Kann ich es anprobieren?", dEn: "Can I try it on?", s: "Beim Kleiderkauf.", sEn: "When buying clothes.", n: "Umkleide: el probador.", nEn: "Changing room: el probador." },
    c13: { e: "¿Dónde está la caja?", d: "Wo ist die Kasse?", dEn: "Where's the till?", s: "Im Laden zum Bezahlen.", sEn: "At the shop when paying.", n: "caja = Kasse; cajero = Geldautomat (nicht verwechseln).", nEn: "caja = till; cajero = cash machine (don't mix them up)." },
    c14: { e: "¿Está abierto los domingos?", d: "Ist sonntags geöffnet?", dEn: "Are you open on Sundays?", s: "Beim Planen von Einkäufen.", sEn: "When planning your shopping.", n: "abierto = offen, cerrado = geschlossen.", nEn: "abierto = open, cerrado = closed." },
    c15: { e: "Un kilo de mangos, por favor.", d: "Ein Kilo Mangos, bitte.", dEn: "A kilo of mangoes, please.", s: "Am Obst-/Gemüsestand.", sEn: "At the fruit/veg stall.", n: "Mengen mit de: un kilo de ...", nEn: "Amounts with de: un kilo de ..." },
    c16: { e: "Medio kilo de tomates, por favor.", d: "Ein halbes Kilo Tomaten, bitte.", dEn: "Half a kilo of tomatoes, please.", s: "Auf dem Markt.", sEn: "At the market.", n: "medio kilo = 500 g.", nEn: "medio kilo = 500 g." },
    c17: { e: "Un poco más, por favor.", d: "Etwas mehr, bitte.", dEn: "A bit more, please.", s: "Beim Abwiegen auf dem Markt.", sEn: "When weighing out at the market.", n: "más = mehr, menos = weniger.", nEn: "más = more, menos = less." },
    c18: { e: "Eso es todo, gracias.", d: "Das ist alles, danke.", dEn: "That's all, thanks.", s: "Beim Abschließen des Einkaufs.", sEn: "When finishing up your shopping.", n: "Auch Nada más (sonst nichts).", nEn: "Also Nada más (nothing else)." },
    c19: { e: "¿Tiene algo más barato?", d: "Haben Sie etwas Günstigeres?", dEn: "Do you have anything cheaper?", s: "Wenn dir der Preis zu hoch ist.", sEn: "When the price is too high for you.", n: "Freundlicher Einstieg ins Handeln.", nEn: "A friendly way into haggling." },
    c20: { e: "Me da dos panes, por favor.", d: "Geben Sie mir zwei Brote, bitte.", dEn: "Give me two loaves, please.", s: "Am Tresen / Stand.", sEn: "At the counter / stall.", n: "Me da ... ist die typische LatAm-Bestellformel.", nEn: "Me da ... is the typical LatAm way to order." },
    c21: { e: "Quiero este vestido, por favor.", d: "Ich möchte dieses Kleid.", dEn: "I'd like this dress.", s: "Beim Kleiderkauf.", sEn: "When buying clothes.", n: "este = dieses (hier), ese = das (dort).", nEn: "este = this (here), ese = that (there)." },
    c23: { e: "¿Lo tiene en otro color?", d: "Haben Sie es in einer anderen Farbe?", dEn: "Do you have it in another colour?", s: "Beim Kleiderkauf.", sEn: "When buying clothes.", n: "color = Farbe.", nEn: "color = colour." },
    c24: { e: "¿Tiene una talla más grande?", d: "Haben Sie eine Nummer größer?", dEn: "Do you have one size bigger?", s: "Beim Anprobieren.", sEn: "When trying things on.", n: "chica ist in vielen Ländern üblich für klein (sonst pequeña).", nEn: "chica is common for small in many countries (otherwise pequeña)." },
    c25: { e: "¿Me lo deja más barato?", d: "Geht beim Preis noch was?", dEn: "Can you do a better price?", s: "Beim Handeln.", sEn: "When haggling.", n: "dejar algo más barato = günstiger machen – typische Handelsfloskel.", nEn: "dejar algo más barato = to lower the price – a typical haggling phrase." },
    c26: { e: "¿Me hace un descuento?", d: "Machen Sie mir einen Rabatt?", dEn: "Can you give me a discount?", s: "Auf dem Markt.", sEn: "At the market.", n: "Mit Charme und Lächeln klappt es eher.", nEn: "It works better with charm and a smile." },
    c27: { e: "Muy caro, gracias.", d: "Zu teuer, danke.", dEn: "Too expensive, thanks.", s: "Wenn du höflich ablehnst.", sEn: "When you politely decline.", n: "Oft kommt jetzt ein besseres Angebot – einfach abwarten.", nEn: "A better offer often comes now – just wait." },
    c28: { e: "Me llevo dos de esos.", d: "Ich nehme zwei davon.", dEn: "I'll take two of those.", s: "Am Stand.", sEn: "At the stall.", n: "de esos = von denen (dort).", nEn: "de esos = of those (over there)." },
    c29: { e: "¿Me lo puede mostrar?", d: "Können Sie mir das zeigen?", dEn: "Can you show me that?", s: "Wenn etwas hinter der Theke liegt.", sEn: "When something's behind the counter.", n: "mostrar = zeigen.", nEn: "mostrar = to show." },
    c30: { e: "¿Dónde encuentro el agua?", d: "Wo finde ich Wasser?", dEn: "Where do I find water?", s: "Im Supermarkt.", sEn: "At the supermarket.", n: "Wort austauschen: ¿Dónde encuentro el pan?", nEn: "Swap the word: ¿Dónde encuentro el pan?" },
    c31: { e: "¿Puedo probar?", d: "Darf ich probieren?", dEn: "May I try some?", s: "Am Obst-/Käsestand.", sEn: "At the fruit/cheese stall.", n: "probar = kosten UND anprobieren – Kontext klärt es.", nEn: "probar = both to taste AND to try on – context makes it clear." },
    c32: { e: "¿Me lo puede envolver?", d: "Können Sie es einpacken?", dEn: "Can you wrap it up?", s: "Bei Geschenken.", sEn: "With gifts.", n: "envolver = (ein)wickeln.", nEn: "envolver = to wrap." },
    c33: { e: "Es para regalo, ¿lo puede envolver?", d: "Es ist ein Geschenk, können Sie es einpacken?", dEn: "It's a gift, can you wrap it up?", s: "Beim Souvenirkauf.", sEn: "When buying souvenirs.", n: "regalo = Geschenk.", nEn: "regalo = gift." },
    c34: { e: "¿Este aguacate está maduro?", d: "Ist diese Avocado reif?", dEn: "Is this avocado ripe?", s: "Beim Obstkauf.", sEn: "When buying fruit.", n: "maduro = reif, verde = unreif/grün, fresco = frisch.", nEn: "maduro = ripe, verde = unripe/green, fresco = fresh." },

    // ===================== GELD =====================
    d01: { e: "¿Cómo puedo pagar?", d: "Wie kann ich bezahlen?", dEn: "How can I pay?", s: "An der Kasse.", sEn: "At the till.", n: "Folgefrage: ¿Aceptan tarjeta? (Karten ok?)", nEn: "Follow-up: ¿Aceptan tarjeta? (cards okay?)" },
    d02: { e: "¿Puedo pagar con tarjeta?", d: "Kann ich mit Karte zahlen?", dEn: "Can I pay by card?", s: "Beim Bezahlen.", sEn: "When paying.", n: "Kleine Läden nehmen oft nur efectivo (bar).", nEn: "Small shops often take only efectivo (cash)." },
    d03: { e: "Pago en efectivo.", d: "Ich zahle bar.", dEn: "I'll pay cash.", s: "Beim Bezahlen.", sEn: "When paying.", n: "Bargeld ist in LatAm oft König – immer etwas dabei haben.", nEn: "Cash is often king in LatAm – always carry some." },
    d04: { e: "¿Aceptan tarjeta?", d: "Akzeptieren Sie Karten?", dEn: "Do you accept cards?", s: "Vor dem Bestellen/Kaufen.", sEn: "Before ordering/buying.", n: "Gut, vorher zu fragen – nicht überall möglich.", nEn: "Good to ask first – not possible everywhere." },
    d05: { e: "¿Hay un cajero cerca?", d: "Gibt es einen Geldautomaten in der Nähe?", dEn: "Is there a cash machine nearby?", s: "Wenn du Bargeld brauchst.", sEn: "When you need cash.", n: "cajero automático – am sichersten in Banken oder Malls.", nEn: "cajero automático – safest in banks or malls." },
    d06: { e: "¿Me da el vuelto, por favor?", d: "Geben Sie mir das Wechselgeld, bitte?", dEn: "Could you give me the change, please?", s: "Nach dem Bezahlen.", sEn: "After paying.", n: "vuelto in LatAm, cambio anderswo – beides verständlich.", nEn: "vuelto in LatAm, cambio elsewhere – both understood." },
    d07: { e: "¿Tiene sencillo? No tengo cambio.", d: "Haben Sie es klein? Ich habe kein Kleingeld.", dEn: "Do you have small change? I don't have any.", s: "Beim Bezahlen mit großem Schein.", sEn: "When paying with a large note.", n: "sencillo = Kleingeld; große Scheine sind oft ein Problem.", nEn: "sencillo = small change; large notes are often a problem." },
    d08: { e: "¿Me da el recibo, por favor?", d: "Geben Sie mir die Quittung, bitte?", dEn: "Could you give me the receipt, please?", s: "Nach dem Bezahlen.", sEn: "After paying.", n: "recibo/boleta = Quittung; factura = formelle Rechnung.", nEn: "recibo/boleta = receipt; factura = formal invoice." },
    d09: { e: "No me queda mucha plata.", d: "Mir bleibt nicht mehr viel Geld.", dEn: "I don't have much money left.", s: "Im Gespräch über das Budget.", sEn: "When talking about the budget.", n: "plata ist das alltägliche Wort für Geld in Südamerika.", nEn: "plata is the everyday word for money in South America." },
    d10: { e: "¿La entrada es gratis?", d: "Ist der Eintritt kostenlos?", dEn: "Is entry free?", s: "Bei Museen, Touren, Events.", sEn: "At museums, tours, events.", n: "gratis = umsonst; manchmal gibt es Gratis-Tage.", nEn: "gratis = free; sometimes there are free days." },
    d11: { e: "¿Dónde puedo cambiar dinero?", d: "Wo kann ich Geld wechseln?", dEn: "Where can I change money?", s: "Nach der Ankunft im Land.", sEn: "After arriving in the country.", n: "Wechselkurs vergleichen – der erste Stand ist selten der beste.", nEn: "Compare the exchange rate – the first stand is rarely the best." },
    d12: { e: "Busco una casa de cambio.", d: "Ich suche eine Wechselstube.", dEn: "I'm looking for a bureau de change.", s: "Beim Geldwechseln.", sEn: "When changing money.", n: "Eine offizielle casa de cambio ist sicherer als Straßenwechsler.", nEn: "An official casa de cambio is safer than street changers." },
    d13: { e: "Disculpe, ¿está bien el vuelto?", d: "Stimmt das Wechselgeld so?", dEn: "Is this change right?", s: "Nach dem Bezahlen.", sEn: "After paying.", n: "Ruhig nachzählen – freundlich nachfragen ist völlig ok.", nEn: "Count it calmly – asking politely is perfectly fine." },

    // ===================== VERKEHR =====================
    v01: { e: "Disculpe, ¿dónde está la estación?", d: "Entschuldigung, wo ist der Bahnhof?", dEn: "Excuse me, where's the station?", s: "Bei der Orientierung.", sEn: "When getting your bearings.", n: "Wort austauschen: ¿dónde está el baño / el centro?", nEn: "Swap the word: ¿dónde está el baño / el centro?" },
    v02: { e: "Gire a la derecha en la esquina.", d: "Biegen Sie an der Ecke rechts ab.", dEn: "Turn right at the corner.", s: "Bei Wegbeschreibungen.", sEn: "When giving directions.", n: "izquierda = links, derecha = rechts.", nEn: "izquierda = left, derecha = right." },
    v03: { e: "Siga todo recto dos cuadras.", d: "Gehen Sie zwei Blocks geradeaus.", dEn: "Go straight on for two blocks.", s: "Bei Wegbeschreibungen.", sEn: "When giving directions.", n: "cuadra = Häuserblock, die typische Entfernungseinheit.", nEn: "cuadra = block, the typical unit of distance." },
    v04: { e: "¿Cómo llego al centro?", d: "Wie komme ich ins Zentrum?", dEn: "How do I get to the centre?", s: "Bei der Wegsuche.", sEn: "When finding your way.", n: "al = a + el. Zu femininem Ziel: a la plaza.", nEn: "al = a + el. To a feminine destination: a la plaza." },
    v06: { e: "¿Me puede pedir un taxi?", d: "Können Sie mir ein Taxi rufen?", dEn: "Can you call me a taxi?", s: "Im Hostel/Restaurant.", sEn: "At the hostel/restaurant.", n: "Sicherer als auf der Straße: per App oder vom Personal rufen lassen.", nEn: "Safer than on the street: book by app or have staff call one." },
    v07: { e: "Un boleto a Lima, por favor.", d: "Ein Ticket nach Lima, bitte.", dEn: "A ticket to Lima, please.", s: "Am Schalter.", sEn: "At the counter.", n: "boleto/pasaje/billete – je nach Land.", nEn: "boleto/pasaje/billete – depending on the country." },
    v08: { e: "¿Está lejos la estación?", d: "Ist der Bahnhof weit?", dEn: "Is the station far?", s: "Bei der Orientierung.", sEn: "When getting your bearings.", n: "Busbahnhof: el terminal / la terminal.", nEn: "Bus station: el terminal / la terminal." },
    v09: { e: "¿Cuánto cuesta al aeropuerto?", d: "Wie viel kostet es zum Flughafen?", dEn: "How much is it to the airport?", s: "Beim Taxi vor dem Abflug.", sEn: "In the taxi before your flight.", n: "Preis vorher aushandeln – Flughafenfahrten sind oft teurer.", nEn: "Agree the price beforehand – airport rides are often pricier." },
    v10: { e: "Pare aquí, por favor.", d: "Halten Sie hier, bitte.", dEn: "Stop here, please.", s: "Im Taxi/Bus am Ziel.", sEn: "In the taxi/bus at your destination.", n: "pare = halten Sie an; déjeme aquí = lassen Sie mich hier.", nEn: "pare = stop; déjeme aquí = let me off here." },
    v11: { e: "¿A qué hora sale el próximo?", d: "Wann fährt der nächste?", dEn: "When does the next one leave?", s: "Am Bahnhof/Busbahnhof.", sEn: "At the train/bus station.", n: "salir = abfahren, llegar = ankommen.", nEn: "salir = to depart, llegar = to arrive." },
    v13: { e: "¿Está lejos de aquí?", d: "Ist es weit von hier?", dEn: "Is it far from here?", s: "Bevor du losgehst.", sEn: "Before you set off.", n: "lejos = weit, cerca = nah.", nEn: "lejos = far, cerca = near." },
    v15: { e: "¿Qué tan lejos está la playa?", d: "Wie weit ist der Strand?", dEn: "How far is the beach?", s: "Beim Planen.", sEn: "When planning.", n: "¿Qué tan ...? = Wie ... – sehr LatAm (Spanien: ¿Cómo de ...?).", nEn: "¿Qué tan ...? = How ... – very LatAm (Spain: ¿Cómo de ...?)." },
    v17: { e: "¿Dónde hay una gasolinera?", d: "Wo gibt es eine Tankstelle?", dEn: "Where is there a petrol station?", s: "Beim Mietwagen/Roadtrip.", sEn: "With a hire car/road trip.", n: "In manchen Ländern bomba oder grifo (Peru).", nEn: "In some countries bomba or grifo (Peru)." },
    v18: { e: "Lleno de gasolina, por favor.", d: "Volltanken, bitte.", dEn: "Fill it up, please.", s: "An der Tankstelle.", sEn: "At the petrol station.", n: "In Chile bencina. Lleno = voll.", nEn: "In Chile bencina. Lleno = full." },
    v19: { e: "Quiero alquilar un auto.", d: "Ich möchte ein Auto mieten.", dEn: "I'd like to hire a car.", s: "Bei der Autovermietung.", sEn: "At the car hire.", n: "auto/carro/coche – je nach Land.", nEn: "auto/carro/coche – depending on the country." },
    v20: { e: "¿Dónde me bajo para el centro?", d: "Wo steige ich fürs Zentrum aus?", dEn: "Where do I get off for the centre?", s: "Im Bus/colectivo.", sEn: "On the bus/colectivo.", n: "bajarse = aussteigen, subirse = einsteigen.", nEn: "bajarse = to get off, subirse = to get on." },
    v21: { e: "Me bajo en la próxima parada.", d: "Ich steige an der nächsten Haltestelle aus.", dEn: "I'm getting off at the next stop.", s: "Im Bus.", sEn: "On the bus.", n: "parada = Haltestelle.", nEn: "parada = bus stop." },
    v22: { e: "Lléveme a esta dirección, por favor.", d: "Bringen Sie mich zu dieser Adresse.", dEn: "Take me to this address.", s: "Im Taxi – Adresse zeigen.", sEn: "In the taxi – showing the address.", n: "dirección = Adresse. Am einfachsten auf dem Handy zeigen.", nEn: "dirección = address. Easiest to show on your phone." },
    v23: { e: "¿Cuánto demora en llegar?", d: "Wie lange dauert es bis dahin?", dEn: "How long does it take to get there?", s: "Im Taxi/Bus.", sEn: "In the taxi/bus.", n: "demorar/tardar = dauern – beide gebräuchlich.", nEn: "demorar/tardar = to take (time) – both common." },
    v24: { e: "¿Puede poner el taxímetro?", d: "Können Sie das Taxameter einschalten?", dEn: "Can you turn on the meter?", s: "Beim Taxieinstieg.", sEn: "When getting into the taxi.", n: "Ohne Taxameter vorher einen Festpreis vereinbaren.", nEn: "Without a meter, agree a fixed price beforehand." },
    v25: { e: "¿Puede esperar aquí un momento?", d: "Können Sie hier kurz warten?", dEn: "Can you wait here a moment?", s: "Bei kurzem Stopp mit dem Taxi.", sEn: "On a quick stop with the taxi.", n: "esperar = warten. Wartezeit kostet meist extra.", nEn: "esperar = to wait. Waiting time usually costs extra." },
    v26: { e: "Me bajo aquí, gracias.", d: "Ich steige hier aus.", dEn: "I'm getting off here.", s: "Im colectivo/Bus.", sEn: "In the colectivo/bus.", n: "Kurz und klar – oft reicht ein lautes aquí.", nEn: "Short and clear – often a loud aquí is enough." },

    // ===================== ZEIT =====================
    ti01: { e: "Disculpe, ¿qué hora es?", d: "Entschuldigung, wie spät ist es?", dEn: "Excuse me, what time is it?", s: "Wenn du die Uhrzeit brauchst.", sEn: "When you need to know the time.", n: "Antwort meist Son las ... (z. B. Son las tres).", nEn: "Reply usually Son las ... (e.g. Son las tres)." },
    ti02: { e: "¿A qué hora abre el museo?", d: "Um wie viel Uhr öffnet das Museum?", dEn: "What time does the museum open?", s: "Beim Planen.", sEn: "When planning.", n: "abrir = öffnen, cerrar = schließen.", nEn: "abrir = to open, cerrar = to close." },
    ti03: { e: "¿Vamos ahora o más tarde?", d: "Gehen wir jetzt oder später?", dEn: "Shall we go now or later?", s: "Beim Pläne machen.", sEn: "When making plans.", n: "Achtung: ahorita heißt je nach Land sofort ODER gleich/später.", nEn: "Note: ahorita means right now OR in a bit/later, depending on the country." },
    ti04: { e: "¿Qué hacemos hoy?", d: "Was machen wir heute?", dEn: "What shall we do today?", s: "Bei der Tagesplanung.", sEn: "When planning your day.", n: "hoy = heute.", nEn: "hoy = today." },
    ti05: { e: "Salgo mañana temprano.", d: "Ich reise morgen früh ab.", dEn: "I'm leaving early tomorrow.", s: "Bei Reiseplänen.", sEn: "With travel plans.", n: "mañana = morgen UND Vormittag – Kontext entscheidet.", nEn: "mañana = tomorrow AND morning – context decides." },
    ti06: { e: "Llegué ayer por la noche.", d: "Ich bin gestern Abend angekommen.", dEn: "I arrived last night.", s: "Im Smalltalk über die Reise.", sEn: "In small talk about the trip.", n: "ayer = gestern, anteayer = vorgestern.", nEn: "ayer = yesterday, anteayer = the day before yesterday." },
    ti07: { e: "El tour es en la mañana.", d: "Die Tour ist am Vormittag.", dEn: "The tour is in the morning.", s: "Bei der Planung.", sEn: "When planning.", n: "en la mañana/tarde/noche – die Tageszeiten.", nEn: "en la mañana/tarde/noche – the times of day." },
    ti08: { e: "Me quedo una semana.", d: "Ich bleibe eine Woche.", dEn: "I'm staying a week.", s: "Bei der Aufenthaltsdauer.", sEn: "With the length of your stay.", n: "día = Tag, semana = Woche, mes = Monat.", nEn: "día = day, semana = week, mes = month." },
    ti09: { e: "Mejor salimos temprano.", d: "Wir gehen besser früh los.", dEn: "We'd better set off early.", s: "Bei der Planung.", sEn: "When planning.", n: "temprano = früh, tarde = spät (und Nachmittag).", nEn: "temprano = early, tarde = late (and afternoon)." },
    ti10: { e: "El bus sale el lunes.", d: "Der Bus fährt am Montag.", dEn: "The bus leaves on Monday.", s: "Bei Reiseplänen.", sEn: "With travel plans.", n: "Wochentage klein und ohne am: el lunes.", nEn: "Weekdays in lower case and without 'on': el lunes." },
    ti11: { e: "El martes hay tour a la montaña.", d: "Am Dienstag gibt es eine Tour zum Berg.", dEn: "On Tuesday there's a tour to the mountain.", s: "Bei Reiseplänen.", sEn: "With travel plans.", n: "martes 13 ist im Spanischen der Unglückstag – nicht Freitag der 13.", nEn: "martes 13 is the unlucky day in Spanish – not Friday the 13th." },
    ti12: { e: "Llego el miércoles.", d: "Ich komme am Mittwoch an.", dEn: "I arrive on Wednesday.", s: "Bei Verabredungen.", sEn: "When arranging to meet.", n: "miércoles hat einen Akzent: mi-ÉR-co-les.", nEn: "miércoles has an accent: mi-ÉR-co-les." },
    ti13: { e: "El jueves salgo de viaje.", d: "Am Donnerstag breche ich zur Reise auf.", dEn: "On Thursday I set off on the trip.", s: "Bei Verabredungen.", sEn: "When arranging to meet.", n: "jueves: das j klingt wie ein hartes deutsches ch (ach).", nEn: "jueves: the j sounds like the ch in loch." },
    ti14: { e: "El viernes hay fiesta.", d: "Am Freitag ist Party.", dEn: "There's a party on Friday.", s: "Beim Wochenende planen.", sEn: "When planning the weekend.", n: "el fin de semana = das Wochenende.", nEn: "el fin de semana = the weekend." },
    ti15: { e: "El sábado hay fiesta en el hostel.", d: "Am Samstag ist Party im Hostel.", dEn: "There's a party at the hostel on Saturday.", s: "Beim Wochenende planen.", sEn: "When planning the weekend.", n: "sábado hat einen Akzent: SÁ-ba-do.", nEn: "sábado has an accent: SÁ-ba-do." },
    ti16: { e: "El domingo descanso.", d: "Am Sonntag ruhe ich mich aus.", dEn: "On Sunday I'm resting.", s: "Beim Wochenende planen.", sEn: "When planning the weekend.", n: "domingo = Sonntag; viele Geschäfte haben geschlossen.", nEn: "domingo = Sunday; many shops are closed." },

    // ===================== SMALLTALK =====================
    s01: { e: "¡Hola! ¿Cómo estás?", d: "Hallo! Wie geht's?", dEn: "Hi! How are you?", s: "Bei jeder Begrüßung.", sEn: "With any greeting.", n: "Lockerer: ¿Qué tal? oder ¿Qué más? (Kolumbien).", nEn: "More casual: ¿Qué tal? or ¿Qué más? (Colombia)." },
    s02: { e: "Bien, gracias, ¿y tú?", d: "Gut, danke, und dir?", dEn: "Good, thanks, and you?", s: "Als Antwort auf ¿Cómo estás?", sEn: "As a reply to ¿Cómo estás?", n: "Das ¿y tú? zurückzugeben gehört dazu.", nEn: "Returning the ¿y tú? is part of it." },
    s05: { e: "Soy de Alemania, de Múnich.", d: "Ich komme aus Deutschland, aus München.", dEn: "I'm from Germany, from Munich.", s: "Wenn du nach deiner Herkunft gefragt wirst.", sEn: "When you're asked where you're from.", n: "Soy de + Land/Stadt.", nEn: "Soy de + country/city." },
    s06: { e: "Estoy de vacaciones por tres meses.", d: "Ich bin für drei Monate im Urlaub.", dEn: "I'm on holiday for three months.", s: "Im Smalltalk über die Reise.", sEn: "In small talk about the trip.", n: "de vacaciones = im Urlaub.", nEn: "de vacaciones = on holiday." },
    s07: { e: "Solo estoy de paso un par de días.", d: "Ich bin nur für ein paar Tage auf der Durchreise.", dEn: "I'm just passing through for a few days.", s: "Wenn du kurz bleibst.", sEn: "When you're staying briefly.", n: "de paso = auf der Durchreise.", nEn: "de paso = just passing through." },
    s08: { e: "¡Qué chévere tu viaje!", d: "Wie cool deine Reise!", dEn: "What a cool trip you're on!", s: "Als Begeisterung im Gespräch.", sEn: "To show enthusiasm in conversation.", n: "chévere (Kolumbien), bacán (Chile/Peru), padre (Mexiko).", nEn: "chévere (Colombia), bacán (Chile/Peru), padre (Mexico)." },
    s09: { e: "No hay problema, tranquilo.", d: "Kein Problem, alles entspannt.", dEn: "No problem, all relaxed.", s: "Wenn sich jemand entschuldigt.", sEn: "When someone apologises.", n: "tranquilo/a = keine Sorge – sehr gebräuchlich.", nEn: "tranquilo/a = no worries – very common." },
    s10: { e: "Claro, con gusto.", d: "Klar, gerne.", dEn: "Sure, gladly.", s: "Zur Zustimmung im Gespräch.", sEn: "To agree in conversation.", n: "Claro que sí verstärkt: aber klar!", nEn: "Claro que sí intensifies it: of course!" },
    s11: { e: "Quizás mañana, depende.", d: "Vielleicht morgen, kommt drauf an.", dEn: "Maybe tomorrow, it depends.", s: "Bei unsicheren Plänen.", sEn: "With uncertain plans.", n: "quizás/tal vez = vielleicht; depende = kommt drauf an.", nEn: "quizás/tal vez = maybe; depende = it depends." },
    s12: { e: "Hasta luego, ¡que te vaya bien!", d: "Bis später, mach's gut!", dEn: "See you later, take care!", s: "Beim Verabschieden.", sEn: "When saying goodbye.", n: "que te vaya bien = alles Gute.", nEn: "que te vaya bien = all the best." },
    s13: { e: "Hasta mañana, descansa.", d: "Bis morgen, ruh dich aus.", dEn: "See you tomorrow, get some rest.", s: "Beim Abschied am Abend.", sEn: "When saying goodnight.", n: "descansa = ruh dich aus.", nEn: "descansa = get some rest." },
    s14: { e: "¡Que tengas un buen día!", d: "Schönen Tag noch!", dEn: "Have a nice day!", s: "Beim Verabschieden.", sEn: "When saying goodbye.", n: "Antwort: Igualmente (gleichfalls).", nEn: "Reply: Igualmente (likewise)." },
    s15: { e: "Con permiso.", d: "Entschuldigung (darf ich durch).", dEn: "Excuse me (may I get past).", s: "Beim Durchgehen in der Menge.", sEn: "When getting through a crowd.", n: "Permiso zum Durchkommen, Disculpe zum Ansprechen.", nEn: "Permiso to get past, Disculpe to approach someone." },
    s16: { e: "Muchas gracias por todo.", d: "Vielen Dank für alles.", dEn: "Thank you for everything.", s: "Beim Verabschieden, z. B. nach dem Hostelaufenthalt.", sEn: "When saying goodbye, e.g. after a hostel stay.", n: "Herzlich und passend zum Abschied.", nEn: "Warm and fitting for a goodbye." },
    s17: { e: "¡Mil gracias, muy amable!", d: "Tausend Dank, sehr nett!", dEn: "Thanks a million, very kind!", s: "Bei besonderer Hilfe.", sEn: "After particular help.", n: "Verstärktes Danke – kommt von Herzen rüber.", nEn: "An intensified thank you – it comes across as heartfelt." },
    s18: { e: "Muy amable de tu parte.", d: "Das ist sehr nett von dir.", dEn: "That's very kind of you.", s: "Nach einer Gefälligkeit.", sEn: "After a favour.", n: "Förmlich: de su parte.", nEn: "Formal: de su parte." },
    s19: { e: "Gracias por la invitación.", d: "Danke für die Einladung.", dEn: "Thanks for the invitation.", s: "Nach Essen/Drink, zu dem du eingeladen warst.", sEn: "After food/a drink you were treated to.", n: "invitación = Einladung (auch wenn jemand spendiert).", nEn: "invitación = invitation (also when someone treats you)." },
    s20: { e: "Te lo agradezco mucho.", d: "Ich weiß das sehr zu schätzen.", dEn: "I really appreciate it.", s: "Bei echter Dankbarkeit.", sEn: "With genuine gratitude.", n: "Etwas wärmer und persönlicher als nur gracias.", nEn: "A bit warmer and more personal than just gracias." },
    s21: { e: "Fue un placer conocerte.", d: "Es war mir ein Vergnügen, dich kennenzulernen.", dEn: "It was a pleasure to meet you.", s: "Beim Abschied von neuen Bekannten.", sEn: "When parting from new acquaintances.", n: "Ein schöner, herzlicher Abschiedssatz.", nEn: "A lovely, warm parting phrase." },
    s22: { e: "Estoy muy contento con todo.", d: "Ich bin sehr zufrieden mit allem.", dEn: "I'm very happy with everything.", s: "Als positives Feedback.", sEn: "As positive feedback.", n: "Frauen: contenta.", nEn: "Women: contenta." },
    s23: { e: "Todo estuvo perfecto, gracias.", d: "Alles war perfekt, danke.", dEn: "Everything was perfect, thanks.", s: "Beim Auschecken/Verabschieden.", sEn: "When checking out/saying goodbye.", n: "Gutes Lob fürs Personal.", nEn: "Good praise for the staff." },
    s24: { e: "La próxima te invito yo.", d: "Das nächste Mal lade ich dich ein.", dEn: "Next time it's on me.", s: "In geselliger Runde.", sEn: "In good company.", n: "Eine nette Geste, die Sympathie schafft.", nEn: "A nice gesture that builds rapport." },

    // ===================== ALLTAG =====================
    a01: { e: "¿Cómo se dice esto en español?", d: "Wie sagt man das auf Spanisch?", dEn: "How do you say that in Spanish?", s: "Beim Lernen unterwegs.", sEn: "When learning on the go.", n: "Super, um neue Wörter direkt von Locals zu lernen.", nEn: "Great for learning new words straight from locals." },
    a02: { e: "¿Qué significa esta palabra?", d: "Was bedeutet dieses Wort?", dEn: "What does this word mean?", s: "Wenn du ein Wort nicht kennst.", sEn: "When you don't know a word.", n: "palabra = Wort. Zeig einfach drauf.", nEn: "palabra = word. Just point at it." },
    a03: { e: "¿Me lo puede escribir, por favor?", d: "Können Sie es mir aufschreiben?", dEn: "Can you write it down for me?", s: "Bei Adressen, Preisen, Namen.", sEn: "With addresses, prices, names.", n: "Hilft enorm bei Zahlen und Eigennamen.", nEn: "Hugely helpful with numbers and proper names." },
    a04: { e: "Disculpe mi español, estoy aprendiendo.", d: "Entschuldige mein Spanisch, ich lerne noch.", dEn: "Sorry about my Spanish, I'm still learning.", s: "Wenn du ins Stocken gerätst.", sEn: "When you get stuck.", n: "Bricht das Eis – die meisten helfen dann geduldig.", nEn: "Breaks the ice – most people then help patiently." },
    a05: { e: "¿Cuál es la contraseña del wifi?", d: "Wie ist das WLAN-Passwort?", dEn: "What's the wifi password?", s: "Im Café, Hostel, Restaurant.", sEn: "At the café, hostel, restaurant.", n: "contraseña/clave = Passwort.", nEn: "contraseña/clave = password." },
    a06: { e: "¿Dónde puedo comprar un chip?", d: "Wo kann ich eine SIM-Karte kaufen?", dEn: "Where can I buy a SIM card?", s: "Nach der Ankunft für mobiles Internet.", sEn: "After arriving, for mobile internet.", n: "chip = SIM-Karte in LatAm (Spanien: tarjeta SIM).", nEn: "chip = SIM card in LatAm (Spain: tarjeta SIM)." },
    a07: { e: "Quiero recargar saldo, por favor.", d: "Ich möchte Guthaben aufladen.", dEn: "I'd like to top up my credit.", s: "Im Handy-Laden oder Kiosk.", sEn: "At the phone shop or kiosk.", n: "saldo = Guthaben; recarga = die Aufladung.", nEn: "saldo = credit; recarga = the top-up." },
    a08: { e: "¿El plan incluye datos móviles?", d: "Enthält der Tarif mobile Daten?", dEn: "Does the plan include mobile data?", s: "Beim SIM-Kauf.", sEn: "When buying a SIM.", n: "datos = Datenvolumen; oft als Gigas verkauft.", nEn: "datos = data; often sold as gigas." },
    a09: { e: "¿Hay una lavandería cerca?", d: "Gibt es eine Wäscherei in der Nähe?", dEn: "Is there a laundry nearby?", s: "Wenn die Wäsche dreckig ist.", sEn: "When your laundry is dirty.", n: "Oft nach Gewicht (por kilo) – günstig und schnell.", nEn: "Often by weight (por kilo) – cheap and quick." },
    a10: { e: "Busco un departamento por un mes.", d: "Ich suche eine Wohnung für einen Monat.", dEn: "I'm looking for a flat for a month.", s: "Bei längeren Aufenthalten.", sEn: "On longer stays.", n: "departamento (LatAm) / piso (Spanien) / apartamento.", nEn: "departamento (LatAm) / piso (Spain) / apartamento." },
    a11: { e: "¿Cuánto es el alquiler al mes?", d: "Wie hoch ist die Miete pro Monat?", dEn: "How much is the rent per month?", s: "Bei der Wohnungssuche.", sEn: "When flat-hunting.", n: "alquiler/arriendo/renta – je nach Land.", nEn: "alquiler/arriendo/renta – depending on the country." },
    a12: { e: "¿Dónde está el banco más cercano?", d: "Wo ist die nächste Bank?", dEn: "Where's the nearest bank?", s: "Für Geldgeschäfte.", sEn: "For money matters.", n: "Geldautomaten in der Bank sind am sichersten.", nEn: "Cash machines inside a bank are safest." },
    a13: { e: "Quiero enviar una postal desde el correo.", d: "Ich möchte eine Postkarte von der Post schicken.", dEn: "I'd like to send a postcard from the post office.", s: "Beim Postamt.", sEn: "At the post office.", n: "correo = Post; Postkarte = postal.", nEn: "correo = post; postcard = postal." },
    a14: { e: "Necesito ir a la embajada alemana.", d: "Ich muss zur deutschen Botschaft.", dEn: "I need to go to the German embassy.", s: "Bei verlorenem Pass oder Notfällen.", sEn: "With a lost passport or emergencies.", n: "embajada = Botschaft; consulado = Konsulat.", nEn: "embajada = embassy; consulado = consulate." },
    a15: { e: "¿Dónde puedo comprar agua por aquí?", d: "Wo kann ich hier Wasser kaufen?", dEn: "Where can I buy water around here?", s: "Unterwegs bei Durst.", sEn: "When thirsty on the go.", n: "Kleiner Laden: la tienda / el kiosco.", nEn: "Small shop: la tienda / el kiosco." },

    // ===================== SÄTZE =====================
    f01: { e: "Quisiera un café, por favor.", d: "Ich hätte gern einen Kaffee, bitte.", dEn: "I'd like a coffee, please.", s: "Beim Bestellen/Wünschen.", sEn: "When ordering/requesting.", n: "Quisiera ist höflicher als Quiero.", nEn: "Quisiera is more polite than Quiero." },
    f02: { e: "Me gustaría ver el menú.", d: "Ich hätte gern die Karte.", dEn: "I'd like the menu.", s: "Bei höflichen Wünschen.", sEn: "With polite requests.", n: "Me gustaría + Infinitiv = ich würde gern ...", nEn: "Me gustaría + infinitive = I'd like to ..." },
    f03: { e: "Quiero ese, el de allá.", d: "Ich möchte das da, das dort.", dEn: "I'd like that one, the one over there.", s: "Beim Zeigen auf etwas.", sEn: "When pointing at something.", n: "ese = das (dort), aquel = das (weiter weg).", nEn: "ese = that (there), aquel = that (further away)." },
    f04: { e: "Ese de atrás, por favor.", d: "Das da hinten, bitte.", dEn: "That one at the back, please.", s: "An der Theke/Vitrine.", sEn: "At the counter/display case.", n: "atrás = hinten.", nEn: "atrás = at the back." },
    f05: { e: "Ese de abajo, por favor.", d: "Das da unten, bitte.", dEn: "That one down there, please.", s: "Beim Zeigen im Regal.", sEn: "When pointing at the shelf.", n: "abajo = unten.", nEn: "abajo = below." },
    f06: { e: "Ese de arriba, el segundo.", d: "Das da oben, das zweite.", dEn: "That one up there, the second one.", s: "Beim Zeigen im Regal.", sEn: "When pointing at the shelf.", n: "arriba = oben.", nEn: "arriba = above." },
    f07: { e: "No este, ese.", d: "Nicht dieses, das da.", dEn: "Not this one, that one.", s: "Beim Auswählen.", sEn: "When choosing.", n: "este (hier bei mir) vs. ese (dort bei dir).", nEn: "este (here by me) vs. ese (there by you)." },
    f08: { e: "Uno más, por favor.", d: "Noch eins, bitte.", dEn: "Another one, please.", s: "Für Nachschub.", sEn: "For a refill.", n: "Anpassen: una más bei femininem Wort.", nEn: "Make it agree: una más with a feminine word." },
    f09: { e: "Mejor uno menos.", d: "Lieber eins weniger.", dEn: "One less, rather.", s: "Beim Korrigieren der Menge.", sEn: "When correcting the amount.", n: "menos = weniger.", nEn: "menos = less." },
    f10: { e: "Un poco más, por favor.", d: "Ein bisschen mehr, bitte.", dEn: "A little more, please.", s: "Beim Abwiegen/Einschenken.", sEn: "When weighing out/pouring.", n: "un poco = ein bisschen.", nEn: "un poco = a little." },
    f11: { e: "Solo un poquito, gracias.", d: "Nur ein bisschen, danke.", dEn: "Just a little, thanks.", s: "Bei kleinen Mengen.", sEn: "With small amounts.", n: "-ito macht es kleiner und freundlicher: poquito.", nEn: "-ito makes it smaller and friendlier: poquito." },
    f12: { e: "Así está bien, gracias.", d: "Das reicht so, danke.", dEn: "That's enough, thanks.", s: "Beim Einschenken/Abwiegen.", sEn: "When pouring/weighing out.", n: "Signalisiert: genau richtig, stopp.", nEn: "Signals: just right, stop." },
    f13: { e: "Sí, así.", d: "Ja, genau so.", dEn: "Yes, just like that.", s: "Zur Bestätigung.", sEn: "To confirm.", n: "Kurz und klar – oft mit einer Geste.", nEn: "Short and clear – often with a gesture." },
    f14: { e: "¿Puedo pasar?", d: "Darf ich durch?", dEn: "May I get past?", s: "Um Erlaubnis bitten.", sEn: "To ask permission.", n: "¿Puedo + Infinitiv? = Darf/Kann ich ...?", nEn: "¿Puedo + infinitive? = May/Can I ...?" },
    f15: { e: "¿Puede ayudarme?", d: "Können Sie mir helfen?", dEn: "Can you help me?", s: "Um etwas bitten (förmlich).", sEn: "To ask for something (formal).", n: "¿Puede + Infinitiv? = Können Sie ...?", nEn: "¿Puede + infinitive? = Can you ...?" },
    f16: { e: "Necesito ayuda, por favor.", d: "Ich brauche Hilfe, bitte.", dEn: "I need help, please.", s: "Bei einem Bedürfnis.", sEn: "With a need.", n: "Necesito + Nomen/Infinitiv.", nEn: "Necesito + noun/infinitive." },
    f17: { e: "¿Hay baño aquí?", d: "Gibt es hier eine Toilette?", dEn: "Is there a toilet here?", s: "Auf der Suche nach etwas.", sEn: "When looking for something.", n: "hay = es gibt – eines der nützlichsten Wörter.", nEn: "hay = there is/are – one of the most useful words." },
    f18: { e: "¿Dónde hay un cajero?", d: "Wo gibt es einen Geldautomaten?", dEn: "Where is there a cash machine?", s: "Bei der Suche.", sEn: "When searching.", n: "¿Dónde hay ...? = Wo gibt es ...?", nEn: "¿Dónde hay ...? = Where is there ...?" },
    f19: { e: "Estoy buscando la estación de bus.", d: "Ich suche den Busbahnhof.", dEn: "I'm looking for the bus station.", s: "Bei der Orientierung.", sEn: "When getting your bearings.", n: "buscar = suchen.", nEn: "buscar = to look for." },
    f20: { e: "¿Qué es esto? Se ve rico.", d: "Was ist das? Sieht lecker aus.", dEn: "What's that? It looks tasty.", s: "Am Marktstand oder bei unbekanntem Gericht.", sEn: "At the market stall or with an unfamiliar dish.", n: "Neugier kommt gut an – oft bekommst du etwas zum Probieren.", nEn: "Curiosity goes down well – you often get something to taste." },
    f21: { e: "¿Cómo se llama esto en español?", d: "Wie nennt man das auf Spanisch?", dEn: "What's this called in Spanish?", s: "Beim Vokabeln lernen.", sEn: "When learning vocabulary.", n: "Tolle Frage, um Wörter von Locals zu lernen.", nEn: "A great question for learning words from locals." },
    f22: { e: "Un momento, por favor.", d: "Einen Moment, bitte.", dEn: "One moment, please.", s: "Wenn du kurz Zeit brauchst.", sEn: "When you need a moment.", n: "Auch Ya voy = ich komme gleich.", nEn: "Also Ya voy = I'm coming." },
    f23: { e: "¿Me permite? Con permiso.", d: "Darf ich mal vorbei?", dEn: "May I get past?", s: "Beim Durchkommen.", sEn: "When getting through.", n: "Con permiso ist die Standardformel zum Durchgehen.", nEn: "Con permiso is the standard phrase for getting past." },
    f24: { e: "Disculpe, una pregunta.", d: "Entschuldigung, eine Frage.", dEn: "Excuse me, a question.", s: "Bevor du jemanden etwas fragst.", sEn: "Before you ask someone something.", n: "Höflicher Einstieg, der fast immer gut ankommt.", nEn: "A polite opener that almost always lands well." },
    f25: { e: "¿Cómo? No le entendí.", d: "Wie bitte? Ich habe Sie nicht verstanden.", dEn: "Sorry? I didn't catch that.", s: "Wenn du nachfragen musst.", sEn: "When you need to ask again.", n: "¿Cómo? ist höflich; ¿Mande? ist sehr mexikanisch.", nEn: "¿Cómo? is polite; ¿Mande? is very Mexican." },
    f26: { e: "¿Puede repetir, por favor?", d: "Können Sie das wiederholen?", dEn: "Can you repeat that?", s: "Wenn du etwas verpasst hast.", sEn: "When you've missed something.", n: "Kombi mit Más despacio wirkt Wunder.", nEn: "Combined with Más despacio it works wonders." },
    f27: { e: "Solo estoy mirando, gracias.", d: "Ich möchte nur schauen, danke.", dEn: "I'm just looking, thanks.", s: "Wenn Verkäufer aufdringlich werden.", sEn: "When sellers get pushy.", n: "Höflich und ohne Druck.", nEn: "Polite and pressure-free." },
    f28: { e: "Un poco más, por favor.", d: "Etwas mehr, bitte.", dEn: "A bit more, please.", s: "Beim Dosieren.", sEn: "When portioning.", n: "más = mehr, menos = weniger.", nEn: "más = more, menos = less." },
    f29: { e: "Quiero uno como este.", d: "Ich möchte eins wie dieses.", dEn: "I'd like one like this.", s: "Beim Auswählen mit Vergleich.", sEn: "When choosing by comparison.", n: "como = wie. Zeig auf das Vorbild.", nEn: "como = like. Point at the example." },
    f30: { e: "No, gracias, estoy bien.", d: "Nein danke, alles gut.", dEn: "No thanks, I'm fine.", s: "Beim höflichen Annehmen/Ablehnen.", sEn: "When politely accepting/declining.", n: "Sí, claro (ja gern) / No, gracias (nein danke).", nEn: "Sí, claro (yes please) / No, gracias (no thanks)." },

    // ===================== BEHÖRDEN =====================
    g01: { e: "Aquí está mi pasaporte.", d: "Hier ist mein Reisepass.", dEn: "Here's my passport.", s: "Bei Einreise/Kontrolle.", sEn: "At entry/border control.", n: "Den pasaporte immer griffbereit halten.", nEn: "Keep your pasaporte handy at all times." },
    g02: { e: "¿Necesito visa para entrar?", d: "Brauche ich ein Visum zur Einreise?", dEn: "Do I need a visa to enter?", s: "Vor/bei der Einreise.", sEn: "Before/at entry.", n: "visa (LatAm) / visado (Spanien).", nEn: "visa (LatAm) / visado (Spain)." },
    g03: { e: "¿Me puede dar el sello, por favor?", d: "Können Sie mir den Stempel geben?", dEn: "Can you give me the stamp?", s: "An der Grenze.", sEn: "At the border.", n: "Prüfe, dass der Einreisestempel (sello) wirklich drin ist.", nEn: "Check that the entry stamp (sello) is really there." },
    g04: { e: "¿Cuánto falta para la frontera?", d: "Wie weit ist es noch bis zur Grenze?", dEn: "How far is it to the border?", s: "Bei der Anreise zur Grenze.", sEn: "On the way to the border.", n: "Grenzübergänge können dauern – Geduld mitbringen.", nEn: "Border crossings can take a while – bring patience." },
    g05: { e: "¿Dónde está la aduana?", d: "Wo ist der Zoll?", dEn: "Where's customs?", s: "Bei der Einreise.", sEn: "On entry.", n: "aduana = Zoll; migración = Passkontrolle.", nEn: "aduana = customs; migración = passport control." },
    g06: { e: "Soy turista, vengo de vacaciones.", d: "Ich bin Tourist, ich komme als Urlauber.", dEn: "I'm a tourist, I'm here on holiday.", s: "Bei der Einreisebefragung.", sEn: "During the entry questioning.", n: "Eine einfache, klare Antwort auf den Reisezweck.", nEn: "A simple, clear answer about the purpose of your trip." },
    g07: { e: "Aquí está mi pasaporte y el formulario.", d: "Hier ist mein Reisepass und das Formular.", dEn: "Here's my passport and the form.", s: "Am Schalter der Passkontrolle.", sEn: "At the passport control desk.", n: "Ruhig und freundlich – für die Beamten ist es Routine.", nEn: "Calm and friendly – it's routine for the officials." },
    g08: { e: "Me quedo quince días.", d: "Ich bleibe 15 Tage.", dEn: "I'm staying 15 days.", s: "Auf die Frage nach der Aufenthaltsdauer.", sEn: "When asked how long you're staying.", n: "Zahl einsetzen: Me quedo + Zahl + días.", nEn: "Insert the number: Me quedo + number + días." },
    g09: { e: "El motivo del viaje es turismo.", d: "Der Grund der Reise ist Tourismus.", dEn: "The purpose of the trip is tourism.", s: "Bei der Einreisebefragung.", sEn: "During the entry questioning.", n: "motivo = Grund/Zweck. Die Standardantwort.", nEn: "motivo = reason/purpose. The standard answer." },
    g10: { e: "¿Cuánto tiempo puedo quedarme?", d: "Wie lange darf ich bleiben?", dEn: "How long may I stay?", s: "An der Grenze.", sEn: "At the border.", n: "Oft 90 Tage für Touristen – aber das Land prüfen.", nEn: "Often 90 days for tourists – but check the country." },
    g11: { e: "No tengo nada que declarar.", d: "Ich habe nichts zu verzollen.", dEn: "I have nothing to declare.", s: "Am Zoll.", sEn: "At customs.", n: "Der Standardsatz beim grünen Ausgang.", nEn: "The standard phrase at the green channel." },
    g12: { e: "¿Dónde firmo?", d: "Wo muss ich unterschreiben?", dEn: "Where do I sign?", s: "Beim Ausfüllen von Formularen.", sEn: "When filling in forms.", n: "firmar = unterschreiben; firma = Unterschrift.", nEn: "firmar = to sign; firma = signature." },
    g13: { e: "¿Me da otro formulario, por favor?", d: "Geben Sie mir ein weiteres Formular, bitte?", dEn: "Could you give me another form, please?", s: "Bei der Einreise.", sEn: "On entry.", n: "Oft schon im Flugzeug/Bus ausfüllbar.", nEn: "Often fillable already on the plane/bus." },
    g14: { e: "¿Hay un cajero en la frontera?", d: "Gibt es an der Grenze einen Geldautomaten?", dEn: "Is there a cash machine at the border?", s: "Wenn du Bargeld für die Einreise brauchst.", sEn: "When you need cash for entry.", n: "An Grenzen oft schlechter Kurs – nur wenig wechseln.", nEn: "Often a poor rate at borders – only change a little." },
    g15: { e: "El cajero se tragó mi tarjeta.", d: "Der Automat hat meine Karte einbehalten.", dEn: "The machine swallowed my card.", s: "Am Geldautomaten – Notfall.", sEn: "At the cash machine – emergency.", n: "Sofort die Bank kontaktieren; tagsüber an Bankautomaten weniger riskant.", nEn: "Contact the bank straight away; bank ATMs by day are less risky." },
    g16: { e: "Mi tarjeta no funciona en este cajero.", d: "Meine Karte funktioniert an diesem Automaten nicht.", dEn: "My card isn't working at this machine.", s: "Beim Abheben.", sEn: "When withdrawing cash.", n: "Einen anderen Automaten oder eine Bank probieren.", nEn: "Try another machine or a bank." },
    g17: { e: "El cajero no entrega efectivo.", d: "Der Automat gibt kein Geld aus.", dEn: "The machine isn't dispensing cash.", s: "Beim Abheben.", sEn: "When withdrawing cash.", n: "efectivo = Bargeld; den Beleg aufheben.", nEn: "efectivo = cash; keep the receipt." },
    g18: { e: "Creo que bloquearon mi tarjeta.", d: "Ich glaube, meine Karte wurde gesperrt.", dEn: "I think my card has been blocked.", s: "Wenn nichts mehr geht.", sEn: "When nothing works any more.", n: "Die Reise vorher der Bank melden, damit das nicht passiert.", nEn: "Tell the bank about your trip beforehand so this doesn't happen." },
    g19: { e: "Tengo que llamar a mi banco.", d: "Ich muss meine Bank anrufen.", dEn: "I need to call my bank.", s: "Bei Kartenproblemen.", sEn: "With card problems.", n: "Die Notfallnummer der Bank separat notieren.", nEn: "Note down the bank's emergency number separately." },
    g20: { e: "¿Cuál es la comisión por retiro?", d: "Wie hoch ist die Abhebegebühr?", dEn: "How much is the withdrawal fee?", s: "Am Geldautomaten.", sEn: "At the cash machine.", n: "comisión = Gebühr; manche Automaten sind deutlich teurer.", nEn: "comisión = fee; some machines are much pricier." },

    // ===================== NOTFALL =====================
    n01: { e: "Es una emergencia, por favor ayúdeme.", d: "Es ist ein Notfall, bitte helfen Sie mir.", dEn: "It's an emergency, please help me.", s: "In einer ernsten Situation.", sEn: "In a serious situation.", n: "emergencia macht sofort klar, dass es dringend ist.", nEn: "emergencia makes it instantly clear that it's urgent." },
    n02: { e: "Me siento mal, creo que es la comida.", d: "Mir geht es schlecht, ich glaube, es war das Essen.", dEn: "I feel unwell, I think it was the food.", s: "Bei Übelkeit – im Hostel oder unterwegs.", sEn: "With nausea – at the hostel or on the go.", n: "Sehr häufig auf Reisen. Ergänzen: Necesito descansar (ich muss mich ausruhen).", nEn: "Very common when travelling. Add: Necesito descansar (I need to rest)." },
    n03: { e: "Me duele la cabeza. ¿Tiene algo?", d: "Mir tut der Kopf weh. Haben Sie etwas?", dEn: "My head hurts. Do you have anything?", s: "In der Apotheke oder im Hostel.", sEn: "At the pharmacy or hostel.", n: "Struktur Me duele + Körperteil: Me duele la espalda, me duele la garganta.", nEn: "Structure Me duele + body part: Me duele la espalda, me duele la garganta." },
    n04: { e: "Me duele el estómago desde ayer.", d: "Mir tut der Bauch seit gestern weh.", dEn: "My stomach has hurt since yesterday.", s: "Beim Arzt oder in der Apotheke.", sEn: "At the doctor's or pharmacy.", n: "Magen-Darm ist der Klassiker – sag, seit wann (desde ayer).", nEn: "Stomach trouble is the classic – say since when (desde ayer)." },
    n05: { e: "Tengo fiebre y escalofríos.", d: "Ich habe Fieber und Schüttelfrost.", dEn: "I have a fever and chills.", s: "Bei Krankheit – Apotheke oder Arzt.", sEn: "When ill – pharmacy or doctor.", n: "fiebre = Fieber; bei hohem Fieber besser zum médico.", nEn: "fiebre = fever; with a high fever better see a médico." },
    n06: { e: "Soy alérgico a la penicilina.", d: "Ich bin allergisch gegen Penizillin.", dEn: "I'm allergic to penicillin.", s: "Beim Arzt – sehr wichtig.", sEn: "At the doctor's – very important.", n: "Frauen: alérgica. Die konkrete Sache nennen (penicilina, maní, polen).", nEn: "Women: alérgica. Name the specific thing (penicilina, maní, polen)." },
    n07: { e: "Lléveme al hospital, por favor.", d: "Bringen Sie mich ins Krankenhaus, bitte.", dEn: "Take me to the hospital, please.", s: "Im Taxi bei einem Notfall.", sEn: "In the taxi in an emergency.", n: "hospital = Krankenhaus; clínica oft privat und schneller.", nEn: "hospital = hospital; clínica often private and faster." },
    n08: { e: "¡Llame a una ambulancia, rápido!", d: "Rufen Sie einen Krankenwagen, schnell!", dEn: "Call an ambulance, quick!", s: "Bei einem medizinischen Notfall.", sEn: "In a medical emergency.", n: "ambulancia = Krankenwagen; in vielen Ländern über die 911.", nEn: "ambulancia = ambulance; in many countries via 911." },
    n09: { e: "Necesito medicamentos para el dolor.", d: "Ich brauche Medikamente gegen die Schmerzen.", dEn: "I need medicine for the pain.", s: "In der Apotheke.", sEn: "At the pharmacy.", n: "para el dolor = gegen die Schmerzen; Rezept heißt receta.", nEn: "para el dolor = for the pain; a prescription is receta." },
    n10: { e: "Me robaron el celular en la calle.", d: "Man hat mir auf der Straße das Handy gestohlen.", dEn: "My phone was stolen from me in the street.", s: "Nach einem Diebstahl – Polizei/Hostel.", sEn: "After a theft – police/hostel.", n: "Für die Versicherung brauchst du eine Anzeige: una denuncia en la policía.", nEn: "For insurance you need a report: una denuncia en la policía." },
    n12: { e: "Perdí mi pasaporte. ¿Qué hago?", d: "Ich habe meinen Reisepass verloren. Was tun?", dEn: "I've lost my passport. What do I do?", s: "Bei verlorenem Pass.", sEn: "With a lost passport.", n: "Sofort zur embajada (Botschaft) – sie hilft beim Ersatz.", nEn: "Go straight to the embajada (embassy) – they help with a replacement." },
    n13: { e: "Perdí mi celular, ¿lo puedo llamar?", d: "Ich habe mein Handy verloren, kann ich es anrufen?", dEn: "I've lost my phone, can I call it?", s: "Im Hostel, Bus oder Restaurant.", sEn: "At the hostel, on the bus or in a restaurant.", n: "celular = Handy in LatAm; vielleicht hat es jemand gefunden.", nEn: "celular = mobile in LatAm; maybe someone found it." },
    n14: { e: "Por favor, ¿puede ayudarme? Es urgente.", d: "Bitte, können Sie mir helfen? Es ist dringend.", dEn: "Please, can you help me? It's urgent.", s: "In jeder Notlage, in der du Hilfe brauchst.", sEn: "In any emergency where you need help.", n: "Es urgente unterstreicht die Dringlichkeit.", nEn: "Es urgente underlines how urgent it is." },

    // ===================== BUSREISE =====================
    r01: { e: "Un boleto a Cartagena, por favor.", d: "Ein Ticket nach Cartagena, bitte.", dEn: "A ticket to Cartagena, please.", s: "Am Schalter im Busterminal.", sEn: "At the desk in the bus terminal.", n: "boleto/pasaje – das Ziel einsetzen.", nEn: "boleto/pasaje – insert the destination." },
    r02: { e: "Solo ida, por favor.", d: "Nur Hinfahrt, bitte.", dEn: "One way only, please.", s: "Beim Ticketkauf.", sEn: "When buying a ticket.", n: "ida = hin, ida y vuelta = hin und zurück.", nEn: "ida = one way, ida y vuelta = return." },
    r03: { e: "¿A qué hora sale el próximo bus?", d: "Wann fährt der nächste Bus?", dEn: "When does the next bus leave?", s: "Am Terminal.", sEn: "At the terminal.", n: "próximo = nächster; salir = abfahren.", nEn: "próximo = next; salir = to depart." },
    r04: { e: "¿Es directo o tiene paradas?", d: "Ist das ein Direktbus oder hält er?", dEn: "Is it a direct bus or does it stop?", s: "Beim Ticketkauf.", sEn: "When buying a ticket.", n: "directo = ohne Umsteigen.", nEn: "directo = without changing." },
    r05: { e: "Prefiero el bus nocturno.", d: "Ich nehme lieber den Nachtbus.", dEn: "I'd rather take the night bus.", s: "Beim Planen langer Strecken.", sEn: "When planning long journeys.", n: "Spart eine Hostel-Nacht; warm anziehen – oft eiskalte Klimaanlage.", nEn: "Saves a hostel night; dress warm – the air con is often freezing." },
    r06: { e: "¿Para el bus en Salento?", d: "Hält der Bus in Salento?", dEn: "Does the bus stop in Salento?", s: "Beim Ticketkauf/Einsteigen.", sEn: "When buying a ticket/boarding.", n: "parar = (an)halten.", nEn: "parar = to stop." },
    r07: { e: "¿Dónde está mi asiento?", d: "Wo ist mein Sitzplatz?", dEn: "Where's my seat?", s: "Beim Einsteigen.", sEn: "When boarding.", n: "asiento = Sitzplatz; die Nummer steht auf dem Ticket.", nEn: "asiento = seat; the number is on the ticket." },
    r08: { e: "¿Está libre este asiento?", d: "Ist dieser Platz frei?", dEn: "Is this seat free?", s: "Im Bus.", sEn: "On the bus.", n: "libre = frei, ocupado = besetzt.", nEn: "libre = free, ocupado = taken." },
    r09: { e: "¿Cuánto dura el viaje?", d: "Wie lange dauert die Fahrt?", dEn: "How long is the journey?", s: "Vor der Abfahrt.", sEn: "Before departure.", n: "durar = dauern; Strecken sind oft länger als gedacht.", nEn: "durar = to last; journeys are often longer than expected." },
    r10: { e: "¿Dónde dejo mi equipaje?", d: "Wo gebe ich mein Gepäck auf?", dEn: "Where do I check in my luggage?", s: "Beim Einsteigen in den Fernbus.", sEn: "When boarding the long-distance bus.", n: "Die Marke (ticket) fürs aufgegebene Gepäck aufheben.", nEn: "Keep the tag (ticket) for your checked luggage." },
    r11: { e: "¿Me avisa cuando lleguemos?", d: "Sagen Sie mir Bescheid, wenn wir da sind?", dEn: "Will you let me know when we're there?", s: "Im Bus, wenn du das Ziel nicht kennst.", sEn: "On the bus, when you don't know the destination.", n: "avisar = Bescheid geben; sehr hilfreich auf unbekannten Strecken.", nEn: "avisar = to let someone know; very helpful on unfamiliar routes." },
    r12: { e: "¿Está lejos el terminal?", d: "Ist der Busbahnhof weit?", dEn: "Is the bus station far?", s: "Bei der Anreise.", sEn: "On arrival.", n: "el terminal / la terminal – beide Formen kommen vor.", nEn: "el terminal / la terminal – both forms occur." },
    r13: { e: "¿Hay baño en el bus?", d: "Gibt es eine Toilette im Bus?", dEn: "Is there a toilet on the bus?", s: "Vor langen Fahrten.", sEn: "Before long journeys.", n: "Bei Nachtbussen meist ja – Papier selbst dabei haben.", nEn: "On night buses usually yes – bring your own paper." },
    r14: { e: "¿Cuántas paradas hay?", d: "Wie viele Stopps gibt es?", dEn: "How many stops are there?", s: "Vor der Fahrt.", sEn: "Before the journey.", n: "parada = Halt/Stopp.", nEn: "parada = stop." },
    r15: { e: "¿Para a comer en el camino?", d: "Hält er unterwegs zum Essen an?", dEn: "Does it stop for food on the way?", s: "Bei langen Fahrten.", sEn: "On long journeys.", n: "parar a + Infinitiv = anhalten, um etwas zu tun: para a comer.", nEn: "parar a + infinitive = to stop to do something: para a comer." },
    r16: { e: "¿Me puede llevar hasta el pueblo?", d: "Können Sie mich bis zum Dorf mitnehmen?", dEn: "Can you give me a lift to the village?", s: "Beim Trampen (mit Vorsicht).", sEn: "When hitchhiking (with care).", n: "llevar = mitnehmen/bringen; nur in sicheren Situationen.", nEn: "llevar = to take/give a lift; only in safe situations." },
    r17: { e: "¿Hasta dónde va?", d: "Bis wohin fahren Sie?", dEn: "How far are you going?", s: "Beim colectivo/Sammeltaxi.", sEn: "With the colectivo/shared taxi.", n: "Klärt, ob die Fahrt zu deinem Ziel passt.", nEn: "Checks whether the ride suits your destination." },
    r18: { e: "¿La combi pasa por la playa?", d: "Fährt der Minibus am Strand vorbei?", dEn: "Does the minibus go past the beach?", s: "Beim Nahverkehr.", sEn: "On local transport.", n: "combi/colectivo/micro/buseta – das lokale Sammeltaxi, günstig.", nEn: "combi/colectivo/micro/buseta – the local shared taxi, cheap." },
    r19: { e: "Pare en la esquina, por favor.", d: "Halten Sie an der Ecke.", dEn: "Stop at the corner.", s: "Im colectivo/Taxi.", sEn: "In the colectivo/taxi.", n: "esquina = Straßenecke – ein beliebter Haltepunkt.", nEn: "esquina = street corner – a popular stopping point." },
    r20: { e: "Perdí mi bus, ¿hay otro hoy?", d: "Ich habe meinen Bus verpasst, gibt es heute noch einen?", dEn: "I missed my bus, is there another one today?", s: "Wenn du zu spät am Terminal bist.", sEn: "When you're late at the terminal.", n: "perder el bus = den Bus verpassen; oft fährt bald der nächste.", nEn: "perder el bus = to miss the bus; the next one often comes soon." },

    // ===================== KLEIDUNG & SCHMUCK =====================
    kj01: { e: "¿Dónde puedo comprar ropa barata?", d: "Wo kann ich günstige Kleidung kaufen?", dEn: "Where can I buy cheap clothes?", s: "Auf dem Markt oder im Einkaufsviertel.", sEn: "At the market or in the shopping district.", n: "ropa = Kleidung, immer Singular (kein las ropas).", nEn: "ropa = clothing, always singular (no las ropas)." },
    kj02: { e: "Busco una camiseta de algodón.", d: "Ich suche ein T-Shirt aus Baumwolle.", dEn: "I'm looking for a cotton T-shirt.", s: "Beim Klamottenkauf.", sEn: "When buying clothes.", n: "In Mexiko playera, sonst camiseta; algodón = Baumwolle.", nEn: "In Mexico playera, otherwise camiseta; algodón = cotton." },
    kj03: { e: "¿Tiene esta camisa en azul?", d: "Haben Sie dieses Hemd in Blau?", dEn: "Do you have this shirt in blue?", s: "Im Bekleidungsgeschäft.", sEn: "At the clothes shop.", n: "camisa = Hemd, camiseta = T-Shirt – nicht verwechseln.", nEn: "camisa = shirt, camiseta = T-shirt – don't mix them up." },
    kj04: { e: "¿Me puedo probar este pantalón?", d: "Kann ich diese Hose anprobieren?", dEn: "Can I try on these trousers?", s: "Beim Hosenkauf.", sEn: "When buying trousers.", n: "pantalón meist Singular für eine Hose; Umkleide: el probador.", nEn: "pantalón usually singular for trousers; changing room: el probador." },
    kj05: { e: "¿Cuánto cuestan estos jeans?", d: "Wie viel kosten diese Jeans?", dEn: "How much are these jeans?", s: "Beim Einkaufen.", sEn: "When shopping.", n: "jeans wird überall verstanden; formell pantalón de mezclilla (Mexiko).", nEn: "jeans is understood everywhere; formally pantalón de mezclilla (Mexico)." },
    kj06: { e: "Hace calor, busco un short.", d: "Es ist heiß, ich suche eine kurze Hose.", dEn: "It's hot, I'm looking for some shorts.", s: "In warmen Regionen oder am Strand.", sEn: "In warm regions or at the beach.", n: "short ist gängig; auch pantalones cortos.", nEn: "short is common; also pantalones cortos." },
    kj07: { e: "¿Tiene esta falda más corta?", d: "Haben Sie diesen Rock kürzer?", dEn: "Do you have this skirt shorter?", s: "Beim Kleiderkauf.", sEn: "When buying clothes.", n: "falda = Rock; más corta = kürzer.", nEn: "falda = skirt; más corta = shorter." },
    kj08: { e: "Me gusta este vestido, ¿qué tallas hay?", d: "Mir gefällt dieses Kleid, welche Größen gibt es?", dEn: "I like this dress, what sizes are there?", s: "Beim Kleiderkauf.", sEn: "When buying clothes.", n: "vestido = Kleid; talla = Größe.", nEn: "vestido = dress; talla = size." },
    kj09: { e: "Necesito una chaqueta para la noche.", d: "Ich brauche eine Jacke für die Nacht.", dEn: "I need a jacket for the night.", s: "Abends oder in kühleren Höhen.", sEn: "In the evening or at cooler altitudes.", n: "In Mexiko chamarra; im Andenhochland werden Nächte kalt.", nEn: "In Mexico chamarra; in the Andean highlands nights get cold." },
    kj10: { e: "En la montaña hace frío, llevo un suéter.", d: "In den Bergen ist es kalt, ich nehme einen Pullover.", dEn: "It's cold in the mountains, I'll take a jumper.", s: "Vor einem Ausflug ins Hochland.", sEn: "Before a trip into the highlands.", n: "suéter aus dem Englischen, überall verständlich.", nEn: "suéter from English, understood everywhere." },
    kj11: { e: "¿Necesito un abrigo en Patagonia?", d: "Brauche ich einen Mantel in Patagonien?", dEn: "Do I need a coat in Patagonia?", s: "Bei der Reiseplanung in kalte Regionen.", sEn: "When planning a trip to cold regions.", n: "abrigo = dicker Mantel.", nEn: "abrigo = a thick coat." },
    kj12: { e: "¿Dónde venden calcetines?", d: "Wo verkaufen sie Socken?", dEn: "Where do they sell socks?", s: "Beim Nachkaufen unterwegs.", sEn: "When restocking on the go.", n: "calcetines = Socken; in manchen Ländern medias.", nEn: "calcetines = socks; in some countries medias." },
    kj13: { e: "Necesito comprar ropa interior.", d: "Ich muss Unterwäsche kaufen.", dEn: "I need to buy underwear.", s: "Beim Nachkaufen.", sEn: "When restocking.", n: "ropa interior = Unterwäsche (Sammelbegriff).", nEn: "ropa interior = underwear (a general term)." },
    kj14: { e: "¿Tiene estos zapatos en el número 42?", d: "Haben Sie diese Schuhe in Größe 42?", dEn: "Do you have these shoes in size 42?", s: "Beim Schuhkauf.", sEn: "When buying shoes.", n: "Schuhgröße = número (nicht talla).", nEn: "Shoe size = número (not talla)." },
    kj15: { e: "Busco unas sandalias cómodas.", d: "Ich suche bequeme Sandalen.", dEn: "I'm looking for comfy sandals.", s: "Für warme Regionen.", sEn: "For warm regions.", n: "cómodas = bequem.", nEn: "cómodas = comfy." },
    kj16: { e: "Para la playa solo necesito chanclas.", d: "Für den Strand brauche ich nur Flip-Flops.", dEn: "For the beach I just need flip-flops.", s: "Am Strand oder im Hostel-Bad.", sEn: "At the beach or in the hostel bathroom.", n: "chanclas = Flip-Flops, praktisch auch für Gemeinschaftsduschen.", nEn: "chanclas = flip-flops, handy for shared showers too." },
    kj17: { e: "Necesito un sombrero para el sol.", d: "Ich brauche einen Hut gegen die Sonne.", dEn: "I need a hat for the sun.", s: "In sonnigen Regionen.", sEn: "In sunny regions.", n: "sombrero = (Sonnen-)Hut mit Krempe.", nEn: "sombrero = a (sun) hat with a brim." },
    kj18: { e: "En la montaña llevo un gorro.", d: "In den Bergen trage ich eine Mütze.", dEn: "In the mountains I wear a beanie.", s: "Im kalten Hochland.", sEn: "In the cold highlands.", n: "gorro = Mütze; sombrero eher mit Krempe.", nEn: "gorro = beanie; sombrero rather with a brim." },
    kj19: { e: "Se me rompieron los lentes de sol.", d: "Meine Sonnenbrille ist kaputtgegangen.", dEn: "My sunglasses have broken.", s: "Beim Nachkaufen.", sEn: "When restocking.", n: "In LatAm oft lentes de sol; in Spanien gafas de sol.", nEn: "In LatAm often lentes de sol; in Spain gafas de sol." },
    kj20: { e: "¿Tiene un cinturón de cuero?", d: "Haben Sie einen Ledergürtel?", dEn: "Do you have a leather belt?", s: "Auf dem Kunsthandwerksmarkt.", sEn: "At the craft market.", n: "cuero = Leder; cinturón = Gürtel.", nEn: "cuero = leather; cinturón = belt." },
    kj21: { e: "Compré una bufanda de alpaca.", d: "Ich habe einen Alpaka-Schal gekauft.", dEn: "I bought an alpaca scarf.", s: "Im Andenland als Souvenir.", sEn: "As a souvenir in the Andes.", n: "Alpaka-Textilien sind in Peru und Bolivien typisch.", nEn: "Alpaca textiles are typical in Peru and Bolivia." },
    kj22: { e: "Para el volcán necesito guantes.", d: "Für den Vulkan brauche ich Handschuhe.", dEn: "For the volcano I need gloves.", s: "Vor Touren in große Höhen.", sEn: "Before tours at high altitude.", n: "guantes = Handschuhe.", nEn: "guantes = gloves." },
    kj23: { e: "¿Dónde compro un traje de baño?", d: "Wo kaufe ich einen Badeanzug oder eine Badehose?", dEn: "Where do I buy a swimsuit or swimming trunks?", s: "Vor dem Strand- oder Pooltag.", sEn: "Before a beach or pool day.", n: "traje de baño gilt für beides; auch bañador.", nEn: "traje de baño covers both; also bañador." },
    kj24: { e: "Estas joyas son artesanales.", d: "Dieser Schmuck ist handgemacht.", dEn: "This jewellery is handmade.", s: "Auf dem Kunsthandwerksmarkt.", sEn: "At the craft market.", n: "joyas = echter Schmuck, bisutería = Modeschmuck.", nEn: "joyas = real jewellery, bisutería = costume jewellery." },
    kj25: { e: "Me gustan estos aretes de plata.", d: "Mir gefallen diese Silberohrringe.", dEn: "I like these silver earrings.", s: "Beim Schmuckkauf.", sEn: "When buying jewellery.", n: "In LatAm aretes; in Spanien pendientes.", nEn: "In LatAm aretes; in Spain pendientes." },
    kj26: { e: "¿Cuánto cuesta este collar?", d: "Wie viel kostet diese Halskette?", dEn: "How much is this necklace?", s: "Auf dem Markt.", sEn: "At the market.", n: "collar = Halskette.", nEn: "collar = necklace." },
    kj27: { e: "¿La cadena es de plata de verdad?", d: "Ist die Kette aus echtem Silber?", dEn: "Is the chain real silver?", s: "Beim Schmuckkauf – Qualität prüfen.", sEn: "When buying jewellery – checking the quality.", n: "de plata de verdad = aus echtem Silber.", nEn: "de plata de verdad = made of real silver." },
    kj28: { e: "Me llevo esta pulsera, es bonita.", d: "Ich nehme dieses Armband, es ist schön.", dEn: "I'll take this bracelet, it's lovely.", s: "Als Souvenir.", sEn: "As a souvenir.", n: "pulsera = Armband.", nEn: "pulsera = bracelet." },
    kj29: { e: "¿Tiene este anillo en otra medida?", d: "Haben Sie diesen Ring in einer anderen Größe?", dEn: "Do you have this ring in another size?", s: "Beim Ringkauf.", sEn: "When buying a ring.", n: "Ringgröße = medida/talla; anillo = Ring.", nEn: "Ring size = medida/talla; anillo = ring." },
    kj30: { e: "Compré una tobillera en la playa.", d: "Ich habe eine Fußkette am Strand gekauft.", dEn: "I bought an anklet at the beach.", s: "In Strandorten beliebt.", sEn: "Popular in beach towns.", n: "tobillera = Fußkettchen (von tobillo, Knöchel).", nEn: "tobillera = anklet (from tobillo, ankle)." },
    kj31: { e: "Se me paró el reloj.", d: "Meine Uhr ist stehengeblieben.", dEn: "My watch has stopped.", s: "Beim Uhrmacher oder auf dem Markt.", sEn: "At the watchmaker's or the market.", n: "reloj = Uhr (Armband- und Wanduhr).", nEn: "reloj = clock/watch (both kinds)." },
    kj32: { e: "Este broche es de artesanía local.", d: "Diese Brosche ist lokales Kunsthandwerk.", dEn: "This brooch is local craftwork.", s: "Auf dem Souvenirmarkt.", sEn: "At the souvenir market.", n: "broche = Brosche/Anstecker.", nEn: "broche = brooch/pin." },
    kj33: { e: "¿Es de plata o de oro?", d: "Ist das aus Silber oder aus Gold?", dEn: "Is this silver or gold?", s: "Beim Schmuckkauf.", sEn: "When buying jewellery.", n: "plata = Silber (und umgangssprachlich Geld!), oro = Gold.", nEn: "plata = silver (and slang for money!), oro = gold." },
    kj34: { e: "¿Qué talla es esta camisa?", d: "Welche Größe hat dieses Hemd?", dEn: "What size is this shirt?", s: "Beim Kleiderkauf.", sEn: "When buying clothes.", n: "talla = Kleidergröße; Schuhe: número.", nEn: "talla = clothing size; shoes: número." },
    kj35: { e: "Me gusta. ¿Puedo probármelo?", d: "Es gefällt mir. Kann ich es anprobieren?", dEn: "I like it. Can I try it on?", s: "Im Bekleidungsgeschäft.", sEn: "At the clothes shop.", n: "Umkleide: el probador; -melo = es mir.", nEn: "Changing room: el probador; -melo = it (to) me." },
    kj36: { e: "Me queda chico. ¿Lo tiene en otra talla?", d: "Es ist mir zu klein. Haben Sie es in einer anderen Größe?", dEn: "It's too small for me. Do you have it in another size?", s: "Nach dem Anprobieren.", sEn: "After trying it on.", n: "me queda chico/grande = es ist mir zu klein/groß.", nEn: "me queda chico/grande = it's too small/big for me." },
    kj37: { e: "No me queda, es demasiado grande.", d: "Es passt mir nicht, es ist zu groß.", dEn: "It doesn't fit me, it's too big.", s: "Nach dem Anprobieren.", sEn: "After trying it on.", n: "demasiado = zu (sehr); kleiner: ¿más pequeño?", nEn: "demasiado = too (much); smaller: ¿más pequeño?" },

    // ===================== WEGBESCHREIBUNG =====================
    dir01: { e: "Dobla a la derecha en la esquina.", d: "Biege an der Ecke nach rechts ab.", dEn: "Turn right at the corner.", s: "Wenn dir jemand den Weg beschreibt.", sEn: "When someone gives you directions.", n: "derecha = rechts; nicht mit derecho (geradeaus) verwechseln!", nEn: "derecha = right; don't confuse it with derecho (straight on)!" },
    dir02: { e: "La farmacia está a la izquierda.", d: "Die Apotheke ist auf der linken Seite.", dEn: "The pharmacy is on the left.", s: "Beim Suchen eines Ladens auf der Straße.", sEn: "When looking for a shop in the street.", n: "a la izquierda = links / auf der linken Seite.", nEn: "a la izquierda = left / on the left." },
    dir03: { e: "Sigue derecho hasta la plaza.", d: "Geh geradeaus bis zum Platz.", dEn: "Go straight on to the square.", s: "Wenn der Weg ohne Abbiegen weitergeht.", sEn: "When the way continues without turning.", n: "In LatAm hört man fast immer 'derecho', seltener 'recto'.", nEn: "In LatAm you almost always hear 'derecho', rarely 'recto'." },
    dir04: { e: "El cajero está en la esquina.", d: "Der Geldautomat ist an der Ecke.", dEn: "The cash machine is on the corner.", s: "Als Orientierungspunkt beim Suchen.", sEn: "As a landmark when searching.", n: "esquina = Straßenecke; 'a la vuelta de la esquina' = gleich um die Ecke.", nEn: "esquina = street corner; 'a la vuelta de la esquina' = just around the corner." },
    dir05: { e: "Queda a tres cuadras de aquí.", d: "Es ist drei Häuserblocks von hier entfernt.", dEn: "It's three blocks from here.", s: "Wenn dir die Entfernung in Blocks genannt wird.", sEn: "When you're given the distance in blocks.", n: "In ganz LatAm zählt man in cuadras, nicht in Metern.", nEn: "All over LatAm distance is counted in cuadras, not metres." },
    dir06: { e: "¿En qué calle está el hostal?", d: "In welcher Straße ist das Hostel?", dEn: "What street is the hostel on?", s: "Wenn du eine konkrete Adresse suchst.", sEn: "When you're looking for a specific address.", n: "calle = Straße; größer/breiter: avenida.", nEn: "calle = street; bigger/wider: avenida." },
    dir07: { e: "El museo está sobre la avenida principal.", d: "Das Museum liegt an der Hauptstraße.", dEn: "The museum is on the main road.", s: "Bei großen, breiten Straßen im Zentrum.", sEn: "With large, wide streets in the centre.", n: "Adressen kürzen die avenida oft als 'Av.' ab.", nEn: "Addresses often shorten avenida to 'Av.'." },
    dir08: { e: "Tranquilo, está muy cerca.", d: "Keine Sorge, es ist ganz nah.", dEn: "Don't worry, it's very close.", s: "Wenn das Ziel nur ein paar Schritte entfernt ist.", sEn: "When the destination is just a few steps away.", n: "cerca = nah; Gegenteil: lejos.", nEn: "cerca = near; opposite: lejos." },
    dir09: { e: "Uy, eso queda muy lejos, mejor toma un taxi.", d: "Oje, das ist sehr weit, nimm besser ein Taxi.", dEn: "Oh dear, that's very far, better take a taxi.", s: "Wenn das Ziel zu weit zum Laufen ist.", sEn: "When the destination is too far to walk.", n: "lejos = weit; bei langen Strecken lohnt das colectivo oder Taxi.", nEn: "lejos = far; for long stretches a colectivo or taxi is worth it." },
    dir10: { e: "Baja aquí, por favor.", d: "Steig bitte hier aus.", dEn: "Get off here, please.", s: "Im Taxi oder colectivo, wenn du aussteigen willst.", sEn: "In the taxi or colectivo, when you want to get off.", n: "aquí = hier; 'acá' ist in vielen Ländern noch gebräuchlicher.", nEn: "aquí = here; 'acá' is even more common in many countries." },
    dir11: { e: "El baño está allí, al fondo.", d: "Die Toilette ist dort, ganz hinten.", dEn: "The toilet is over there, right at the back.", s: "Wenn dir etwas in der Ferne gezeigt wird.", sEn: "When something is pointed out in the distance.", n: "allí/allá = dort; 'al fondo' = ganz hinten.", nEn: "allí/allá = there; 'al fondo' = right at the back." },
    dir12: { e: "El hostal está enfrente de la iglesia.", d: "Das Hostel ist gegenüber der Kirche.", dEn: "The hostel is opposite the church.", s: "Wenn ein Gebäude als Orientierung dient.", sEn: "When a building serves as a landmark.", n: "enfrente de = gegenüber; nicht mit 'al lado de' (daneben) verwechseln.", nEn: "enfrente de = opposite; don't confuse it with 'al lado de' (next to)." },
    dir13: { e: "La parada está al lado del mercado.", d: "Die Haltestelle ist neben dem Markt.", dEn: "The bus stop is next to the market.", s: "Beim Beschreiben benachbarter Orte.", sEn: "When describing neighbouring places.", n: "al lado de = direkt daneben.", nEn: "al lado de = right next to." },
    dir14: { e: "El cajero está detrás del banco.", d: "Der Geldautomat ist hinter der Bank.", dEn: "The cash machine is behind the bank.", s: "Wenn das Ziel nicht direkt sichtbar ist.", sEn: "When the destination isn't directly visible.", n: "detrás de = hinter; Gegenteil: delante de / enfrente de.", nEn: "detrás de = behind; opposite: delante de / enfrente de." },
    dir15: { e: "La tienda está entre el banco y la farmacia.", d: "Der Laden ist zwischen der Bank und der Apotheke.", dEn: "The shop is between the bank and the pharmacy.", s: "Zur genauen Lage zwischen zwei Punkten.", sEn: "For the exact spot between two points.", n: "entre A y B = zwischen A und B.", nEn: "entre A y B = between A and B." },
    dir16: { e: "¿Me puede escribir la dirección?", d: "Können Sie mir die Adresse aufschreiben?", dEn: "Can you write down the address for me?", s: "Damit du sie dem Taxifahrer zeigen kannst.", sEn: "So you can show it to the taxi driver.", n: "dirección = Adresse (und auch Richtung!); aufschreiben hilft enorm.", nEn: "dirección = address (and also direction!); writing it down helps a lot." },
    dir17: { e: "¿Me lo marca en el mapa?", d: "Markieren Sie es mir auf der Karte?", dEn: "Could you mark it on the map for me?", s: "Wenn Worte nicht reichen, zeig es auf der Karte.", sEn: "When words aren't enough, show it on the map.", n: "el mapa ist trotz -a maskulin: 'el mapa'.", nEn: "el mapa is masculine despite the -a: 'el mapa'." },
    dir18: { e: "Disculpe, ¿dónde está la escuela?", d: "Entschuldigung, wo ist die Schule?", dEn: "Excuse me, where's the school?", s: "Die Standardfrage nach einem festen Ort.", sEn: "The standard question for a fixed place.", n: "está (von estar) für Orte; bei Gebäuden auch 'queda'.", nEn: "está (from estar) for locations; for buildings also 'queda'." },
    dir19: { e: "Perdón, ¿dónde queda el hostal Sol?", d: "Verzeihung, wo liegt das Hostel Sol?", dEn: "Excuse me, where's the Hostel Sol?", s: "Beim Fragen nach deiner Unterkunft.", sEn: "When asking about your accommodation.", n: "'queda' für Lage ist in LatAm sehr verbreitet – wie 'wo liegt …'.", nEn: "'queda' for location is very common in LatAm – like 'where is …'." },
    dir20: { e: "Perdón, ¿cómo llego al centro?", d: "Verzeihung, wie komme ich ins Zentrum?", dEn: "Excuse me, how do I get to the centre?", s: "Wenn du den Weg zum Stadtzentrum brauchst.", sEn: "When you need the way to the city centre.", n: "llegar a = ankommen bei; 'al' = a + el.", nEn: "llegar a = to arrive at; 'al' = a + el." },
    dir21: { e: "¿Puede decirme cómo llegar a la terminal?", d: "Können Sie mir sagen, wie ich zum Busbahnhof komme?", dEn: "Can you tell me how to get to the bus station?", s: "Höfliche, vollständige Frage nach dem Weg.", sEn: "A polite, full way of asking for directions.", n: "'¿Puede decirme …?' klingt besonders höflich.", nEn: "'¿Puede decirme …?' sounds especially polite." },
    dir22: { e: "Oiga, ¿dónde hay un cajero por acá?", d: "Hallo, wo gibt es hier in der Nähe einen Geldautomaten?", dEn: "Hi, where's there a cash machine near here?", s: "Wenn du dringend Bargeld brauchst.", sEn: "When you urgently need cash.", n: "'¿Dónde hay …?' fragt allgemein 'wo gibt es …?'.", nEn: "'¿Dónde hay …?' asks generally 'where is there …?'." },
    dir23: { e: "¿Está lejos o cerca de aquí?", d: "Ist es weit weg oder nah von hier?", dEn: "Is it far or near from here?", s: "Um zu entscheiden, ob du läufst oder fährst.", sEn: "To decide whether to walk or ride.", n: "Gleich nachfragen spart dir lange Umwege zu Fuß.", nEn: "Asking right away saves you long detours on foot." },
    dir24: { e: "¿A cuántas cuadras está el mercado?", d: "Wie viele Blocks ist der Markt entfernt?", dEn: "How many blocks away is the market?", s: "Wenn die Antwort 'cerca' dir zu ungenau ist.", sEn: "When the answer 'cerca' is too vague for you.", n: "Antworten kommen meist als 'a dos cuadras' o.ä.", nEn: "Answers usually come as 'a dos cuadras' or similar." },
    dir25: { e: "¿Cuál es la dirección exacta?", d: "Wie lautet die genaue Adresse?", dEn: "What's the exact address?", s: "Vor einer Taxifahrt oder zum Eintippen ins Handy.", sEn: "Before a taxi ride or to type into your phone.", n: "'¿Cuál es …?' fragt nach einer konkreten Angabe.", nEn: "'¿Cuál es …?' asks for a specific detail." },
    dir26: { e: "No entiendo bien. ¿Me lo muestra en el mapa?", d: "Ich verstehe nicht ganz. Zeigen Sie es mir auf der Karte?", dEn: "I don't quite understand. Can you show me on the map?", s: "Wenn die Wegbeschreibung zu kompliziert wird.", sEn: "When the directions get too complicated.", n: "Karte zeigen lassen ist der sicherste Weg, sich nicht zu verlaufen.", nEn: "Having it shown on the map is the surest way not to get lost." },
    dir27: { e: "Disculpe, ¿hay un banco por aquí?", d: "Entschuldigung, gibt es hier in der Nähe eine Bank?", dEn: "Excuse me, is there a bank near here?", s: "Auf der Suche nach Bank, Apotheke oder Supermarkt.", sEn: "When looking for a bank, pharmacy or supermarket.", n: "'por aquí' = hier in der Gegend / in der Nähe.", nEn: "'por aquí' = around here / nearby." },
    dir28: { e: "Dobla a la derecha en el semáforo.", d: "Biege an der Ampel nach rechts ab.", dEn: "Turn right at the traffic light.", s: "Typische Anweisung beim Wegbeschreiben.", sEn: "A typical instruction when giving directions.", n: "doblar = abbiegen; semáforo = Ampel.", nEn: "doblar = to turn; semáforo = traffic light." },
    dir29: { e: "Dobla a la izquierda después del parque.", d: "Biege nach dem Park nach links ab.", dEn: "Turn left after the park.", s: "Wenn ein Orientierungspunkt den Abbiegepunkt markiert.", sEn: "When a landmark marks where to turn.", n: "después de = nach; antes de = vor.", nEn: "después de = after; antes de = before." },
    dir30: { e: "Sigue derecho dos cuadras más.", d: "Geh noch zwei Blocks geradeaus.", dEn: "Go straight on for two more blocks.", s: "Wenn der Weg eine Weile gerade weitergeht.", sEn: "When the way continues straight for a while.", n: "'… dos cuadras más' = noch zwei Blocks weiter.", nEn: "'… dos cuadras más' = two more blocks on." },
    dir31: { e: "Cruza la calle con cuidado.", d: "Überquere die Straße vorsichtig.", dEn: "Cross the street carefully.", s: "Wenn das Ziel auf der anderen Straßenseite liegt.", sEn: "When the destination is across the street.", n: "cruzar = überqueren; 'con cuidado' = vorsichtig.", nEn: "cruzar = to cross; 'con cuidado' = carefully." },
    dir32: { e: "Camina dos cuadras y ahí está.", d: "Geh zwei Blocks und dort ist es.", dEn: "Go two blocks and there it is.", s: "Kurze, klare Wegbeschreibung zu Fuß.", sEn: "Short, clear directions on foot.", n: "caminar = (zu Fuß) gehen; 'ahí' = dort.", nEn: "caminar = to walk; 'ahí' = there." },
    dir33: { e: "Toma la primera calle a la derecha.", d: "Nimm die erste Straße rechts.", dEn: "Take the first street on the right.", s: "Beim genauen Abzählen der Abzweigungen.", sEn: "When counting the turnings exactly.", n: "primera/segunda calle = erste/zweite Straße.", nEn: "primera/segunda calle = first/second street." },
    dir34: { e: "El restaurante está en la esquina, no tiene pierde.", d: "Das Restaurant ist an der Ecke, du kannst es nicht verfehlen.", dEn: "The restaurant is on the corner, you can't miss it.", s: "Beruhigende Wegauskunft.", sEn: "Reassuring directions.", n: "'no tiene pierde' = man kann es nicht verfehlen (sehr LatAm).", nEn: "'no tiene pierde' = you can't miss it (very LatAm)." },
    dir35: { e: "La panadería está al lado del mercado.", d: "Die Bäckerei ist neben dem Markt.", dEn: "The bakery is next to the market.", s: "Lage über einen bekannten Nachbarort erklären.", sEn: "Explaining a location via a known neighbouring place.", n: "al lado del = a + el lado de el (Verschmelzung del).", nEn: "al lado del = a + el lado de el (the del contraction)." },
    dir36: { e: "El hotel está enfrente de la iglesia.", d: "Das Hotel ist gegenüber der Kirche.", dEn: "The hotel is opposite the church.", s: "Kirchen sind oft der beste Orientierungspunkt.", sEn: "Churches are often the best landmark.", n: "Plaza und iglesia sind in jeder Stadt verlässliche Landmarken.", nEn: "The plaza and iglesia are reliable landmarks in any town." },
    dir37: { e: "El cajero está entre el banco y la farmacia.", d: "Der Geldautomat ist zwischen der Bank und der Apotheke.", dEn: "The cash machine is between the bank and the pharmacy.", s: "Genaue Lage zwischen zwei Geschäften.", sEn: "The exact spot between two shops.", n: "entre … y … grenzt den Ort eindeutig ein.", nEn: "entre … y … pins down the location clearly." },
    dir38: { e: "Queda a dos cuadras de aquí, nomás.", d: "Es ist nur zwei Blocks von hier entfernt.", dEn: "It's just two blocks from here.", s: "Wenn das Ziel zum Glück ganz nah ist.", sEn: "When the destination is luckily very close.", n: "'nomás' (= nur) ist ein typisches LatAm-Füllwort.", nEn: "'nomás' (= just) is a typical LatAm filler word." },
    dir39: { e: "Camina hacia la plaza, hacia el norte.", d: "Geh in Richtung Platz, nach Norden.", dEn: "Head towards the square, to the north.", s: "Wenn dir eine grobe Richtung statt eines Ziels genannt wird.", sEn: "When you're given a rough direction instead of a destination.", n: "hacia = in Richtung; gibt die Richtung an, nicht das genaue Ziel.", nEn: "hacia = towards; gives the direction, not the exact destination." },
    dir40: { e: "Sigue derecho hasta el semáforo.", d: "Geh geradeaus bis zur Ampel.", dEn: "Go straight on to the traffic light.", s: "Wenn ein Punkt das Ende der Strecke markiert.", sEn: "When a point marks the end of the route.", n: "hasta = bis (zu); markiert den Endpunkt des Wegstücks.", nEn: "hasta = up to/until; marks the end of the stretch." },
    dir41: { e: "El banco está diagonal al supermercado.", d: "Die Bank ist schräg gegenüber dem Supermarkt.", dEn: "The bank is diagonally opposite the supermarket.", s: "Für eine Lage über Eck an einer Kreuzung.", sEn: "For a spot diagonally across a junction.", n: "diagonal a = schräg/diagonal gegenüber.", nEn: "diagonal a = diagonally opposite." },
    dir42: { e: "El hostal está junto a la iglesia.", d: "Das Hostel ist direkt bei der Kirche.", dEn: "The hostel is right by the church.", s: "Für etwas unmittelbar daneben.", sEn: "For something right next to it.", n: "junto a / próximo a = direkt bei / nahe bei.", nEn: "junto a / próximo a = right by / close to." },
    dir43: { e: "Dobla a la derecha antes del puente.", d: "Bieg vor der Brücke rechts ab.", dEn: "Turn right before the bridge.", s: "Wenn der Abbiegepunkt vor einer Landmarke liegt.", sEn: "When the turning is before a landmark.", n: "antes de = vor; del = de + el.", nEn: "antes de = before; del = de + el." },
    dir44: { e: "La farmacia está después del cruce.", d: "Die Apotheke ist nach der Kreuzung.", dEn: "The pharmacy is after the junction.", s: "Wenn das Ziel hinter einem Punkt liegt.", sEn: "When the destination is beyond a point.", n: "después de = nach (örtlich wie zeitlich).", nEn: "después de = after (both place and time)." },
    dir45: { e: "El cajero está a la vuelta de la esquina.", d: "Der Geldautomat ist gleich um die Ecke.", dEn: "The cash machine is just around the corner.", s: "Wenn etwas ganz nah, nur um die Ecke ist.", sEn: "When something is very close, just around the corner.", n: "a la vuelta de la esquina = gleich um die Ecke.", nEn: "a la vuelta de la esquina = just around the corner." },
    dir46: { e: "Tranquilo, está a un paso de aquí.", d: "Keine Sorge, es ist nur einen Katzensprung entfernt.", dEn: "Don't worry, it's just a stone's throw away.", s: "Wenn das Ziel sehr nah ist.", sEn: "When the destination is very close.", n: "a un paso = ganz nah, wörtlich 'einen Schritt' entfernt.", nEn: "a un paso = very close, literally 'a step' away." },
    dir47: { e: "El mar queda hacia el norte.", d: "Das Meer liegt im Norden.", dEn: "The sea is to the north.", s: "Bei grober Orientierung nach Himmelsrichtung.", sEn: "For rough orientation by compass direction.", n: "Norte, Sur, Este, Oeste – die vier Himmelsrichtungen.", nEn: "Norte, Sur, Este, Oeste – the four compass directions." },
    dir48: { e: "El centro está más al sur.", d: "Das Zentrum ist weiter südlich.", dEn: "The centre is further south.", s: "Grobe Orientierung in der Stadt.", sEn: "Rough orientation around the city.", n: "'más al sur' = weiter südlich.", nEn: "'más al sur' = further south." },
    dir49: { e: "El sol sale por el este.", d: "Die Sonne geht im Osten auf.", dEn: "The sun rises in the east.", s: "Eselsbrücke zur Orientierung.", sEn: "A memory aid for orientation.", n: "este = Osten; nicht mit 'este' (= dieser) verwechseln.", nEn: "este = east; don't confuse it with 'este' (= this)." },
    dir50: { e: "La playa está al oeste.", d: "Der Strand liegt im Westen.", dEn: "The beach is to the west.", s: "Orientierung Richtung Küste.", sEn: "Orienting towards the coast.", n: "oeste = Westen; dort geht die Sonne unter.", nEn: "oeste = west; that's where the sun sets." },
    dir51: { e: "Dobla a la derecha en el semáforo.", d: "Bieg an der Ampel rechts ab.", dEn: "Turn right at the traffic light.", s: "Ampeln sind klare Orientierungspunkte.", sEn: "Traffic lights are clear landmarks.", n: "semáforo = Ampel; wird oft als Wegmarke genannt.", nEn: "semáforo = traffic light; often used as a landmark." },
    dir52: { e: "Da la vuelta en la rotonda y sigue derecho.", d: "Fahr im Kreisverkehr herum und dann geradeaus.", dEn: "Go round the roundabout and then straight on.", s: "Beim Beschreiben eines Kreisverkehrs.", sEn: "When describing a roundabout.", n: "rotonda; je nach Land auch glorieta (Mexiko) oder redondel.", nEn: "rotonda; depending on the country also glorieta (Mexico) or redondel." },
    dir53: { e: "Para en el próximo cruce, por favor.", d: "Halt bitte an der nächsten Kreuzung.", dEn: "Stop at the next junction, please.", s: "Im Taxi oder colectivo zum Aussteigen.", sEn: "In the taxi or colectivo, to get off.", n: "cruce = Kreuzung; auch intersección.", nEn: "cruce = junction; also intersección." },
    dir54: { e: "Cruza el puente y sigue derecho.", d: "Überquere die Brücke und geh geradeaus.", dEn: "Cross the bridge and go straight on.", s: "Wenn der Weg über eine Brücke führt.", sEn: "When the way goes over a bridge.", n: "puente = Brücke; eine gut sichtbare Landmarke.", nEn: "puente = bridge; a clearly visible landmark." },
    dir55: { e: "La parada está al lado del mercado.", d: "Die Haltestelle ist neben dem Markt.", dEn: "The bus stop is next to the market.", s: "Auf der Suche nach Bus oder colectivo.", sEn: "When looking for a bus or colectivo.", n: "parada = Haltestelle; Busbahnhof: terminal.", nEn: "parada = bus stop; bus station: terminal." },
    dir56: { e: "Gira a la derecha en la esquina.", d: "Bieg an der Ecke rechts ab.", dEn: "Turn right at the corner.", s: "Variante zu 'doblar' beim Wegbeschreiben.", sEn: "A variant of 'doblar' when giving directions.", n: "girar = abbiegen; in Mexiko auch 'voltear'.", nEn: "girar = to turn; in Mexico also 'voltear'." },
    dir57: { e: "Sube por esta calle hasta la plaza.", d: "Geh diese Straße hinauf bis zum Platz.", dEn: "Go up this street to the square.", s: "Bei ansteigenden Straßen (Hügel).", sEn: "On uphill streets (hills).", n: "subir = hinaufgehen; in hügeligen Städten ständig gebraucht.", nEn: "subir = to go up; constantly used in hilly towns." },
    dir58: { e: "Baja por esta calle dos cuadras.", d: "Geh diese Straße zwei Blocks hinunter.", dEn: "Go down this street for two blocks.", s: "Bei abfallenden Straßen.", sEn: "On downhill streets.", n: "bajar = hinuntergehen; Gegenteil von subir.", nEn: "bajar = to go down; the opposite of subir." },
    dir59: { e: "Te pasaste, devuélvete una cuadra.", d: "Du bist zu weit, geh einen Block zurück.", dEn: "You've gone too far, go back one block.", s: "Wenn du zu weit gelaufen bist.", sEn: "When you've walked too far.", n: "devuélvete / regrésate = geh zurück (sehr LatAm).", nEn: "devuélvete / regrésate = go back (very LatAm)." },
    dir60: { e: "Pasa el semáforo y está a la izquierda.", d: "Geh an der Ampel vorbei, dann ist es links.", dEn: "Go past the traffic light, then it's on the left.", s: "Wenn das Ziel kurz hinter einem Punkt liegt.", sEn: "When the destination is just past a point.", n: "pasar = vorbeigehen / passieren.", nEn: "pasar = to go past / to happen." },
    dir61: { e: "Disculpe, ¿por dónde se va al mercado?", d: "Entschuldigung, wo geht's zum Markt lang?", dEn: "Excuse me, which way to the market?", s: "Allgemeine Frage nach der Richtung.", sEn: "A general question about the direction.", n: "'¿Por dónde se va a…?' = wie kommt man zu…?", nEn: "'¿Por dónde se va a…?' = how do you get to…?" },
    dir62: { e: "Perdón, ¿voy bien para la plaza?", d: "Verzeihung, bin ich auf dem richtigen Weg zur Plaza?", dEn: "Excuse me, am I on the right way to the plaza?", s: "Unterwegs kurz rückversichern.", sEn: "A quick double-check on the way.", n: "'¿Voy bien para…?' = bin ich richtig Richtung…?", nEn: "'¿Voy bien para…?' = am I going the right way to…?" },
    dir63: { e: "¿Dónde hay una tienda de ropa por aquí?", d: "Wo gibt es hier in der Nähe ein Bekleidungsgeschäft?", dEn: "Where is there a clothes shop near here?", s: "Auf der Suche nach einem bestimmten Laden.", sEn: "When looking for a particular shop.", n: "'¿Dónde hay…?' fragt allgemein nach 'wo gibt es…?'.", nEn: "'¿Dónde hay…?' asks generally 'where is there…?'." },
    dir64: { e: "¿Se puede ir caminando o mejor tomo un taxi?", d: "Kann man zu Fuß gehen oder nehme ich besser ein Taxi?", dEn: "Can you walk there or is it better to take a taxi?", s: "Um den Aufwand abzuschätzen.", sEn: "To gauge the effort.", n: "ir caminando / a pie = zu Fuß gehen.", nEn: "ir caminando / a pie = to go on foot." },
    dir65: { e: "¿Cuánto se tarda a pie hasta el centro?", d: "Wie lange dauert es zu Fuß bis ins Zentrum?", dEn: "How long does it take on foot to the centre?", s: "Die Gehzeit erfragen.", sEn: "Asking how long it takes on foot.", n: "'a pie' = zu Fuß; 'tardar' = (Zeit) brauchen.", nEn: "'a pie' = on foot; 'tardar' = to take (time)." },

    // ===================== KONJUGIEREN (Verben im Präsens) =====================
    vb01: { e: "Voy a la terminal de buses.", d: "Ich fahre zum Busbahnhof.", dEn: "I'm going to the bus station.", s: "Wenn dich jemand fragt, wohin du unterwegs bist.", sEn: "When someone asks where you're headed.", n: "ir + a = hingehen/hinfahren. Vor el wird daraus al: Voy al centro.", nEn: "ir + a = to go to. Before el it becomes al: Voy al centro." },
    vb02: { e: "¿Vas a la fiesta del hostal esta noche?", d: "Gehst du heute Abend zur Hostel-Party?", dEn: "Are you going to the hostel party tonight?", s: "Smalltalk im Dorm oder in der Gemeinschaftsküche.", sEn: "Small talk in the dorm or shared kitchen.", n: "Mit ¿Vas a …? lädst du ganz nebenbei zum Mitkommen ein.", nEn: "With ¿Vas a …? you casually invite someone along." },
    vb03: { e: "Este bus va al aeropuerto, ¿verdad?", d: "Dieser Bus fährt zum Flughafen, oder?", dEn: "This bus goes to the airport, right?", s: "Vor dem Einsteigen kurz absichern.", sEn: "A quick check before boarding.", n: "va gilt auch für usted: ¿Va al centro? = Fahren Sie ins Zentrum?", nEn: "va also works for usted: ¿Va al centro? = Are you going to the centre?" },
    vb04: { e: "Vamos a la playa, ¿te unes?", d: "Wir gehen an den Strand, kommst du mit?", dEn: "We're going to the beach, are you coming?", s: "Pläne in der Hostel-Runde schmieden.", sEn: "Making plans with the hostel crowd.", n: "¡Vamos! allein heißt 'Los geht's!' – eines der nützlichsten Wörter überhaupt.", nEn: "¡Vamos! on its own means 'Let's go!' – one of the most useful words there is." },
    vb05: { e: "Mis amigos van a Medellín mañana.", d: "Meine Freunde fahren morgen nach Medellín.", dEn: "My friends are going to Medellín tomorrow.", s: "Wenn du Reisepläne anderer weitergibst.", sEn: "When you pass on other people's travel plans.", n: "van gilt für ellos UND ustedes: ¿Van al mismo hostal? = Geht ihr ins selbe Hostel?", nEn: "van works for ellos AND ustedes: ¿Van al mismo hostal? = Are you going to the same hostel?" },
    vb06: { e: "Doblo a la derecha en el semáforo, ¿no?", d: "Ich biege an der Ampel rechts ab, oder?", dEn: "I turn right at the traffic light, don't I?", s: "Eine erklärte Route noch einmal rückversichern.", sEn: "Double-checking a route you've been told.", n: "Die ich-Form endet bei fast allen Verben auf -o – daran erkennst du den Sprecher sofort.", nEn: "The I-form ends in -o for almost all verbs – that tells you the speaker instantly." },
    vb07: { e: "Doblas a la izquierda y ahí está la plaza.", d: "Du biegst links ab, und da ist der Platz.", dEn: "You turn left, and there's the square.", s: "So klingt die Antwort, wenn dir jemand den Weg erklärt.", sEn: "How the answer sounds when someone explains the way.", n: "Wegbeschreibungen kommen oft in der du-Form (-as) statt als Befehl – beides ist üblich.", nEn: "Directions often come in the you-form (-as) rather than as a command – both are common." },
    vb08: { e: "El bus dobla en la esquina y para enfrente del mercado.", d: "Der Bus biegt an der Ecke ab und hält gegenüber dem Markt.", dEn: "The bus turns at the corner and stops opposite the market.", s: "Wenn dir jemand die Busroute beschreibt.", sEn: "When someone describes the bus route to you.", n: "Dieselbe Form für er/sie/usted – der Zusammenhang verrät, wer gemeint ist.", nEn: "The same form for he/she/usted – context tells you who's meant." },
    vb09: { e: "¿Doblamos aquí o en la próxima calle?", d: "Biegen wir hier ab oder an der nächsten Straße?", dEn: "Do we turn here or at the next street?", s: "Gemeinsam unterwegs, kurz die Route klären.", sEn: "Travelling together, quickly sorting out the route.", n: "-amos ist immer die wir-Form bei -ar-Verben: caminamos, tomamos, cruzamos.", nEn: "-amos is always the we-form for -ar verbs: caminamos, tomamos, cruzamos." },
    vb10: { e: "Los taxis doblan aquí porque la calle está cerrada.", d: "Die Taxis biegen hier ab, weil die Straße gesperrt ist.", dEn: "The taxis turn here because the street is closed.", s: "Wenn jemand eine Umleitung erklärt.", sEn: "When someone explains a diversion.", n: "-an deckt sie UND ihr ab: ¿Doblan ustedes también? = Biegt ihr auch ab?", nEn: "-an covers they AND you all: ¿Doblan ustedes también? = Are you turning too?" },
    vb11: { e: "Camino al centro, no está lejos.", d: "Ich gehe zu Fuß ins Zentrum, es ist nicht weit.", dEn: "I'm walking to the centre, it's not far.", s: "Wenn du ein Taxi-Angebot freundlich ablehnst.", sEn: "When you politely decline a taxi offer.", n: "Gleiches Muster wie doblo: Stamm camin- + -o. So funktionieren alle -ar-Verben.", nEn: "Same pattern as doblo: stem camin- + -o. That's how all -ar verbs work." },
    vb12: { e: "Cruzas el puente y el hostal queda a la derecha.", d: "Du überquerst die Brücke, und das Hostel liegt rechts.", dEn: "You cross the bridge, and the hostel is on the right.", s: "Typischer Satz in einer Wegbeschreibung.", sEn: "A typical phrase in directions.", n: "cruzar, doblar, caminar, seguir – die vier Verben, mit denen fast jede Route erklärt wird.", nEn: "cruzar, doblar, caminar, seguir – the four verbs that explain almost any route." },
    vb13: { e: "Tomo el bus de las ocho a Salta.", d: "Ich nehme den Acht-Uhr-Bus nach Salta.", dEn: "I'm taking the eight o'clock bus to Salta.", s: "Deine Reisepläne erzählen oder ein Ticket kaufen.", sEn: "Telling people your travel plans or buying a ticket.", n: "tomar heißt auch trinken: Tomo un café = Ich trinke einen Kaffee.", nEn: "tomar also means to drink: Tomo un café = I'm having a coffee." },
    vb14: { e: "Hablo un poco de español.", d: "Ich spreche ein bisschen Spanisch.", dEn: "I speak a little Spanish.", s: "Der ehrliche Eisbrecher in jedem Gespräch.", sEn: "The honest ice-breaker in any conversation.", n: "Bescheiden bleiben lohnt sich – dein Gegenüber spricht dann automatisch langsamer.", nEn: "Staying modest pays off – the other person then automatically speaks more slowly." },
    vb15: { e: "¿Hablas inglés o solo español?", d: "Sprichst du Englisch oder nur Spanisch?", dEn: "Do you speak English or only Spanish?", s: "Beim Kennenlernen im Hostel.", sEn: "When getting to know people at the hostel.", n: "Höflich an Fremde gerichtet: ¿Habla inglés? (usted-Form, ohne -s).", nEn: "Politely to strangers: ¿Habla inglés? (usted form, without -s)." },
    vb16: { e: "Como en el mercado, es más barato.", d: "Ich esse auf dem Markt, das ist billiger.", dEn: "I eat at the market, it's cheaper.", s: "Backpacker-Spartipp beim Essen-Smalltalk.", sEn: "A backpacker money-saver in food small talk.", n: "-er-Verben: -o/-es/-e/-emos/-en – fast wie -ar, nur mit e.", nEn: "-er verbs: -o/-es/-e/-emos/-en – almost like -ar, just with e." },
    vb17: { e: "¿Comes carne o eres vegetariano?", d: "Isst du Fleisch oder bist du Vegetarier?", dEn: "Do you eat meat or are you vegetarian?", s: "Vor dem gemeinsamen Kochen oder Restaurantbesuch.", sEn: "Before cooking together or going to a restaurant.", n: "Für Frauen: vegetariana. Praktisch beim Bestellen: sin carne = ohne Fleisch.", nEn: "For women: vegetariana. Handy when ordering: sin carne = without meat." },
    vb18: { e: "Hoy comemos todos juntos en el hostal.", d: "Heute essen wir alle zusammen im Hostel.", dEn: "Today we're all eating together at the hostel.", s: "Gemeinsames Abendessen im Hostel organisieren.", sEn: "Organising a shared dinner at the hostel.", n: "comemos = wir essen; bei -ir-Verben wäre es -imos: vivimos.", nEn: "comemos = we eat; for -ir verbs it would be -imos: vivimos." },
    vb19: { e: "Vivo en Alemania, pero viajo seis meses.", d: "Ich wohne in Deutschland, aber ich reise sechs Monate.", dEn: "I live in Germany, but I'm travelling for six months.", s: "Die Standard-Vorstellung unter Backpackern.", sEn: "The standard introduction among backpackers.", n: "Der Klassiker nach ¿De dónde eres? – kurz, ehrlich, gesprächsöffnend.", nEn: "The classic after ¿De dónde eres? – short, honest, conversation-opening." },
    vb20: { e: "¿Vives aquí o también estás de viaje?", d: "Wohnst du hier oder bist du auch auf Reisen?", dEn: "Do you live here or are you travelling too?", s: "Smalltalk im Café oder auf einer Tour.", sEn: "Small talk at the café or on a tour.", n: "estar de viaje = auf Reisen sein – super Anschlussfrage zum Kennenlernen.", nEn: "estar de viaje = to be travelling – a great follow-up question for getting to know people." },
    vb21: { e: "Estoy en la esquina, ¿dónde estás tú?", d: "Ich bin an der Ecke – wo bist du?", dEn: "I'm at the corner – where are you?", s: "Wenn ihr euch in der Stadt sucht (z. B. per WhatsApp).", sEn: "When you're trying to find each other in town (e.g. via WhatsApp).", n: "estar für Ort & Zustand: Estoy perdido = Ich habe mich verlaufen.", nEn: "estar for location & state: Estoy perdido = I'm lost." },
    vb22: { e: "¿Estás cerca o tomamos un taxi?", d: "Bist du in der Nähe, oder nehmen wir ein Taxi?", dEn: "Are you nearby, or shall we take a taxi?", s: "Treffen koordinieren, wenn die Zeit knapp ist.", sEn: "Coordinating a meet-up when time is tight.", n: "estás trägt den Akzent auf dem a – hörbar betont: es-TAS.", nEn: "estás carries the accent on the a – audibly stressed: es-TAS." },
    vb23: { e: "Disculpe, ¿dónde está la terminal?", d: "Entschuldigung, wo ist der Busbahnhof?", dEn: "Excuse me, where's the bus station?", s: "DIE Frage, mit der jede Wegbeschreibung beginnt.", sEn: "THE question that every set of directions starts with.", n: "Nach Orten IMMER mit estar fragen, nie mit ser: ¿Dónde está …?", nEn: "ALWAYS ask about locations with estar, never with ser: ¿Dónde está …?" },
    vb24: { e: "Ya estamos en el centro, ¿ahora a dónde?", d: "Wir sind schon im Zentrum – wohin jetzt?", dEn: "We're already in the centre – where to now?", s: "Unterwegs mit anderen die nächste Etappe klären.", sEn: "On the road with others, sorting out the next leg.", n: "ya = schon/bereits; estamos = wir sind (am Ort).", nEn: "ya = already; estamos = we are (at a place)." },
    vb25: { e: "Soy de Alemania, ¿y tú?", d: "Ich bin aus Deutschland, und du?", dEn: "I'm from Germany, and you?", s: "Die häufigste Frage im Hostel beantworten.", sEn: "Answering the most common hostel question.", n: "Herkunft & Eigenschaften mit ser; Ort & Zustand mit estar – die wichtigste Unterscheidung.", nEn: "Origin & qualities with ser; location & state with estar – the most important distinction." },
    vb26: { e: "¿Eres de aquí? Busco una buena arepería.", d: "Bist du von hier? Ich suche ein gutes Arepa-Lokal.", dEn: "Are you from here? I'm looking for a good arepa place.", s: "Einheimische nach Geheimtipps fragen.", sEn: "Asking locals for insider tips.", n: "Lokale Tipps schlagen jede App – die Frage öffnet fast immer ein nettes Gespräch.", nEn: "Local tips beat any app – the question almost always opens a nice chat." },
    vb27: { e: "Ella es mi amiga del hostal.", d: "Sie ist meine Freundin aus dem Hostel.", dEn: "She's my friend from the hostel.", s: "Reisebekanntschaften einander vorstellen.", sEn: "Introducing travel acquaintances to each other.", n: "es = er/sie/usted-Form von ser. Nicht verwechseln mit está (Ort/Zustand).", nEn: "es = the he/she/usted form of ser. Don't confuse it with está (location/state)." },
    vb28: { e: "Tengo una reserva a nombre de Marcel.", d: "Ich habe eine Reservierung auf den Namen Marcel.", dEn: "I have a reservation under the name Marcel.", s: "Beim Check-in im Hostel oder Hotel.", sEn: "At check-in at the hostel or hotel.", n: "tengo brauchst du ständig: Tengo hambre/sed/frío = Ich habe Hunger/Durst/mir ist kalt.", nEn: "tengo comes up constantly: Tengo hambre/sed/frío = I'm hungry/thirsty/cold." },
    vb29: { e: "¿Tienes cambio para el bus?", d: "Hast du Kleingeld für den Bus?", dEn: "Do you have small change for the bus?", s: "Unter Reisenden, bevor der colectivo kommt.", sEn: "Among travellers, before the colectivo arrives.", n: "cambio = Kleingeld/Wechselgeld – im Bus oft Pflicht, große Scheine sind unbeliebt.", nEn: "cambio = small change – often required on the bus, large notes are unwelcome." },
    vb30: { e: "¿Tiene una cama libre para esta noche?", d: "Haben Sie ein Bett frei für heute Nacht?", dEn: "Do you have a bed free for tonight?", s: "Spontan ohne Buchung im Hostel ankommen.", sEn: "Arriving at the hostel on the spot, without a booking.", n: "tiene = usted-Form – die höfliche Standardform an jeder Rezeption.", nEn: "tiene = the usted form – the polite standard form at any reception." },
    vb31: { e: "¿Puedo dejar mi mochila aquí?", d: "Kann ich meinen Rucksack hier lassen?", dEn: "Can I leave my backpack here?", s: "Vor dem Check-in oder nach dem Check-out.", sEn: "Before check-in or after check-out.", n: "puedo + Infinitiv = ich kann/darf …: ¿Puedo pagar con tarjeta? = Kann ich mit Karte zahlen?", nEn: "puedo + infinitive = I can/may …: ¿Puedo pagar con tarjeta? = Can I pay by card?" },
    vb32: { e: "¿Puedes repetir más despacio, por favor?", d: "Kannst du das bitte langsamer wiederholen?", dEn: "Can you repeat that more slowly, please?", s: "Wenn die Antwort zu schnell kam.", sEn: "When the answer came too fast.", n: "Stammwechsel o→ue: puedo, puedes, puede – nur podemos bleibt beim o.", nEn: "Stem change o→ue: puedo, puedes, puede – only podemos keeps the o." },
    vb33: { e: "¿Puede mostrarme en el mapa?", d: "Können Sie es mir auf der Karte zeigen?", dEn: "Can you show me on the map?", s: "Wenn die Wegbeschreibung zu kompliziert wird.", sEn: "When the directions get too complicated.", n: "puede = höfliche Sie-Form. Der Karten-Trick rettet jede verlorene Wegbeschreibung.", nEn: "puede = the polite you-form. The map trick saves any failed set of directions." },
    vb34: { e: "Quiero un boleto a Cusco, por favor.", d: "Ich möchte ein Ticket nach Cusco, bitte.", dEn: "I'd like a ticket to Cusco, please.", s: "Am Busschalter oder bei der Agentur.", sEn: "At the bus desk or the agency.", n: "quiero + Nomen oder Infinitiv: Quiero ir a Cusco = Ich will nach Cusco fahren.", nEn: "quiero + noun or infinitive: Quiero ir a Cusco = I want to go to Cusco." },
    vb35: { e: "¿Quieres ir a comer algo?", d: "Willst du etwas essen gehen?", dEn: "Do you want to go for something to eat?", s: "Jemanden aus dem Hostel locker einladen.", sEn: "Casually inviting someone from the hostel.", n: "Stammwechsel e→ie: quiero, quieres, quiere – queremos bleibt beim e.", nEn: "Stem change e→ie: quiero, quieres, quiere – queremos keeps the e." },
    vb36: { e: "Sigo derecho hasta la plaza, ¿verdad?", d: "Ich gehe weiter geradeaus bis zum Platz, richtig?", dEn: "I carry straight on to the square, right?", s: "Die gehörte Route zur Sicherheit wiederholen.", sEn: "Repeating the route you heard, just to be sure.", n: "Wer die Beschreibung in der ich-Form nachspricht, merkt sie sich doppelt so gut.", nEn: "Repeating the directions in the I-form makes you remember them twice as well." },
    vb37: { e: "Sigues derecho dos cuadras más.", d: "Du gehst noch zwei Blocks geradeaus weiter.", dEn: "You carry straight on for two more blocks.", s: "Der häufigste Satz in jeder Wegbeschreibung.", sEn: "The most common phrase in any set of directions.", n: "seguir + derecho = geradeaus weitergehen; cuadra = Häuserblock (LatAm).", nEn: "seguir + derecho = to carry straight on; cuadra = block (LatAm)." },
    vb38: { e: "Usted sigue por esta calle hasta el final.", d: "Sie gehen diese Straße bis zum Ende weiter.", dEn: "You carry on down this street to the end.", s: "So erklären es dir ältere oder förmlichere Menschen.", sEn: "How older or more formal people explain it to you.", n: "Auch als Anweisung üblich: ¡Siga derecho! – die höfliche Befehlsform.", nEn: "Also common as an instruction: ¡Siga derecho! – the polite command form." },
    vb39: { e: "Voy al centro a buscar un cajero.", d: "Ich gehe ins Zentrum, um einen Geldautomaten zu suchen.", dEn: "I'm going to the centre to find a cash machine.", s: "Kurz sagen, wohin du verschwindest.", sEn: "Quickly saying where you're off to.", n: "a + el verschmilzt zu al – Voy a el centro gibt es nicht.", nEn: "a + el merges into al – Voy a el centro doesn't exist." },
    vb40: { e: "Doblas a la derecha y sigues derecho hasta el parque.", d: "Du biegst rechts ab und gehst geradeaus weiter bis zum Park.", dEn: "You turn right and carry straight on to the park.", s: "Eine komplette Mini-Wegbeschreibung verstehen.", sEn: "Understanding a complete mini set of directions.", n: "Zwei du-Endungen hintereinander (-as, -es) – hör auf die Endungen, nicht auf Pronomen.", nEn: "Two you-endings in a row (-as, -es) – listen to the endings, not to pronouns." },
    vb41: { e: "Mañana vamos a Cusco en bus nocturno.", d: "Morgen fahren wir mit dem Nachtbus nach Cusco.", dEn: "Tomorrow we're taking the night bus to Cusco.", s: "Reisepläne mit anderen teilen.", sEn: "Sharing travel plans with others.", n: "vamos a + Ort = wir fahren nach; vamos a + Verb = wir werden … (nahe Zukunft!).", nEn: "vamos a + place = we're going to; vamos a + verb = we're going to … (near future!)." },
    vb42: { e: "¿Puede hablar más despacio? Estoy aprendiendo español.", d: "Können Sie langsamer sprechen? Ich lerne gerade Spanisch.", dEn: "Can you speak more slowly? I'm learning Spanish.", s: "Wenn die Antwort auf deine Frage zu schnell kommt.", sEn: "When the answer to your question comes too fast.", n: "Der Zusatz Estoy aprendiendo zaubert fast immer ein Lächeln und viel Geduld hervor.", nEn: "Adding Estoy aprendiendo almost always brings out a smile and a lot of patience." },

    // ===================== ZEITEN (Tiempos) =====================
    tp01: { e: "Llegué ayer en la noche.", d: "Ich bin gestern Abend angekommen.", dEn: "I arrived last night.", s: "Im Hostel erzählen, seit wann du da bist.", sEn: "Telling people at the hostel how long you've been there.", n: "Indefinido: abgeschlossene Vergangenheit mit klarem Zeitpunkt (ayer). llegar → llegué (g→gu vor e).", nEn: "Indefinido: completed past with a clear time (ayer). llegar → llegué (g→gu before e)." },
    tp02: { e: "Tomé el bus equivocado.", d: "Ich habe den falschen Bus genommen.", dEn: "I took the wrong bus.", s: "Erklären, warum du zu spät oder am falschen Ort bist.", sEn: "Explaining why you're late or in the wrong place.", n: "tomar → tomé. Die -ar-Vergangenheit der ich-Form endet immer auf -é.", nEn: "tomar → tomé. The -ar past in the I-form always ends in -é." },
    tp03: { e: "Compramos los boletos en la terminal.", d: "Wir haben die Tickets am Busbahnhof gekauft.", dEn: "We bought the tickets at the bus station.", s: "Erzählen, wo ihr eure Fahrkarten besorgt habt.", sEn: "Telling people where you got your tickets.", n: "Bei -ar-Verben ist die wir-Form im Indefinido gleich wie in der Gegenwart (compramos) – der Satz verrät die Zeit.", nEn: "For -ar verbs the we-form in the Indefinido is the same as in the present (compramos) – the sentence tells you the tense." },
    tp04: { e: "Estuve en Cusco tres días.", d: "Ich war drei Tage in Cusco.", dEn: "I was in Cusco for three days.", s: "Von deiner Route und vergangenen Stationen erzählen.", sEn: "Telling people about your route and past stops.", n: "estar ist unregelmäßig: estuve/estuviste/estuvo. Nicht 'esté'.", nEn: "estar is irregular: estuve/estuviste/estuvo. Not 'esté'." },
    tp05: { e: "Ayer fuimos a la playa todo el día.", d: "Gestern waren wir den ganzen Tag am Strand.", dEn: "Yesterday we were at the beach all day.", s: "Vom gestrigen Ausflug erzählen.", sEn: "Telling people about yesterday's trip.", n: "ir und ser teilen dieselbe Vergangenheit: fui/fuiste/fue/fuimos/fueron. Der Kontext sagt, welches gemeint ist.", nEn: "ir and ser share the same past: fui/fuiste/fue/fuimos/fueron. Context tells you which is meant." },
    tp06: { e: "Me gustó mucho el ceviche.", d: "Das Ceviche hat mir sehr gefallen.", dEn: "I really liked the ceviche.", s: "Nach dem Essen ein Kompliment machen.", sEn: "Giving a compliment after the meal.", n: "gustar in der Vergangenheit: me gustó (Einzahl), me gustaron (Mehrzahl).", nEn: "gustar in the past: me gustó (singular), me gustaron (plural)." },
    tp07: { e: "¿Qué hiciste el fin de semana?", d: "Was hast du am Wochenende gemacht?", dEn: "What did you do at the weekend?", s: "Smalltalk im Hostel oder mit Reisebekanntschaften.", sEn: "Small talk at the hostel or with travel acquaintances.", n: "hacer ist unregelmäßig: hice/hiciste/hizo. Beliebte Gesprächs-Eröffnung.", nEn: "hacer is irregular: hice/hiciste/hizo. A popular conversation opener." },
    tp08: { e: "Perdí mi pasaporte en el bus.", d: "Ich habe meinen Pass im Bus verloren.", dEn: "I lost my passport on the bus.", s: "Der Ernstfall – bei Polizei, Botschaft oder Hostel-Rezeption.", sEn: "The serious case – at the police, embassy or hostel reception.", n: "perder → perdí. -er/-ir-Verben enden in der ich-Vergangenheit auf -í.", nEn: "perder → perdí. -er/-ir verbs end in -í in the past I-form." },
    tp09: { e: "Ayer llovió toda la tarde.", d: "Gestern hat es den ganzen Nachmittag geregnet.", dEn: "Yesterday it rained all afternoon.", s: "Übers Wetter und verschobene Pläne reden.", sEn: "Talking about the weather and postponed plans.", n: "llovió = es regnete (einmaliges Ereignis). 'llovía' wäre der andauernde Hintergrund.", nEn: "llovió = it rained (a one-off event). 'llovía' would be the ongoing background." },
    tp10: { e: "Ya he comido, gracias.", d: "Ich habe schon gegessen, danke.", dEn: "I've already eaten, thanks.", s: "Ein Angebot höflich ablehnen.", sEn: "Politely declining an offer.", n: "Perfecto: haber + Partizip (he comido). 'ya' (schon) ist das typische Signalwort.", nEn: "Present perfect: haber + participle (he comido). 'ya' (already) is the typical signal word." },
    tp11: { e: "¿Has visto Machu Picchu alguna vez?", d: "Hast du Machu Picchu schon mal gesehen?", dEn: "Have you ever seen Machu Picchu?", s: "Nach Reise-Erfahrungen fragen.", sEn: "Asking about travel experiences.", n: "ver hat ein unregelmäßiges Partizip: visto (nicht 'veído').", nEn: "ver has an irregular participle: visto (not 'veído')." },
    tp12: { e: "Nunca he estado aquí, soy nuevo.", d: "Ich war noch nie hier, ich bin neu.", dEn: "I've never been here before, I'm new.", s: "Um eine Empfehlung oder Hilfe bitten.", sEn: "Asking for a recommendation or help.", n: "Perfecto für Lebens-Erfahrung: 'nunca he estado' = noch nie gewesen.", nEn: "Present perfect for life experience: 'nunca he estado' = never been." },
    tp13: { e: "Hemos llegado hace cinco minutos.", d: "Wir sind vor fünf Minuten angekommen.", dEn: "We arrived five minutes ago.", s: "An der Rezeption beim Einchecken.", sEn: "At reception when checking in.", n: "wir-Form des Perfekts: hemos + Partizip. Für gerade eben Geschehenes.", nEn: "We-form of the perfect: hemos + participle. For things that just happened." },
    tp14: { e: "El hostal era muy bonito y tranquilo.", d: "Das Hostel war sehr schön und ruhig.", dEn: "The hostel was lovely and quiet.", s: "Eine Unterkunft weiterempfehlen oder beschreiben.", sEn: "Recommending or describing a place to stay.", n: "Imperfecto für Beschreibungen: era (ser). Kein klarer Endpunkt, sondern ein Zustand.", nEn: "Imperfecto for descriptions: era (ser). No clear endpoint, but a state." },
    tp15: { e: "De niño viajaba mucho con mi familia.", d: "Als Kind bin ich viel mit meiner Familie gereist.", dEn: "As a child I travelled a lot with my family.", s: "Beim Erzählen aus der Vergangenheit, von Gewohnheiten.", sEn: "When talking about the past, about habits.", n: "Imperfecto für Gewohnheiten: viajaba = reiste regelmäßig (-aba bei -ar-Verben).", nEn: "Imperfecto for habits: viajaba = used to travel (-aba for -ar verbs)." },
    tp16: { e: "Hola, solo quería preguntar una cosa.", d: "Hallo, ich wollte nur etwas fragen.", dEn: "Hi, I just wanted to ask something.", s: "Höflich ein Anliegen einleiten.", sEn: "Politely introducing a request.", n: "'quería' (Imperfekt) klingt sanfter und höflicher als das direkte 'quiero'.", nEn: "'quería' (imperfect) sounds softer and more polite than the direct 'quiero'." },
    tp17: { e: "¿A qué hora sale el próximo bus?", d: "Wann fährt der nächste Bus?", dEn: "When does the next bus leave?", s: "Am Schalter oder Busbahnhof nach dem Fahrplan fragen.", sEn: "Asking about the timetable at the desk or bus station.", n: "Gegenwart für Festes wie Fahrpläne: sale (salir) = fährt ab.", nEn: "Present for fixed things like timetables: sale (salir) = leaves." },
    tp18: { e: "Hoy me quedo en el hostal a descansar.", d: "Heute bleibe ich zum Ausruhen im Hostel.", dEn: "Today I'm staying at the hostel to rest.", s: "Pläne für den Tag mitteilen.", sEn: "Sharing your plans for the day.", n: "Gegenwart für das, was heute gilt. quedarse = bleiben (reflexiv: me quedo).", nEn: "Present for what holds true today. quedarse = to stay (reflexive: me quedo)." },
    tp19: { e: "Voy a tomar el bus de las ocho.", d: "Ich werde den Acht-Uhr-Bus nehmen.", dEn: "I'm going to take the eight o'clock bus.", s: "Deinen nächsten Schritt ankündigen.", sEn: "Announcing your next move.", n: "ir a + Infinitiv = nahe Zukunft. Der einfachste Weg, Pläne auszudrücken.", nEn: "ir a + infinitive = near future. The easiest way to express plans." },
    tp20: { e: "Vamos a salir mañana temprano.", d: "Wir werden morgen früh aufbrechen.", dEn: "We'll set off early tomorrow.", s: "Eine gemeinsame Abfahrt planen.", sEn: "Planning to set off together.", n: "vamos a + Infinitiv = wir werden … Achtung: 'vamos a' kann auch 'lass uns …' heißen.", nEn: "vamos a + infinitive = we're going to … Note: 'vamos a' can also mean 'let's …'." },
    tp21: { e: "¿Qué vas a hacer en La Paz?", d: "Was wirst du in La Paz machen?", dEn: "What will you do in La Paz?", s: "Nach den Plänen deiner Reisebekanntschaft fragen.", sEn: "Asking about your travel companion's plans.", n: "vas a + Infinitiv. Sehr häufige Frage unter Reisenden.", nEn: "vas a + infinitive. A very common question among travellers." },
    tp22: { e: "Lleva paraguas, va a llover.", d: "Nimm einen Schirm mit, es wird regnen.", dEn: "Take an umbrella, it's going to rain.", s: "Eine Wetter-Warnung oder einen Tipp geben.", sEn: "Giving a weather warning or a tip.", n: "va a llover = es wird regnen. Wetter-Verben gibt es nur in der er/es-Form.", nEn: "va a llover = it's going to rain. Weather verbs only exist in the he/it form." },
    tp23: { e: "Voy a hacer una reserva para dos noches.", d: "Ich werde eine Reservierung für zwei Nächte machen.", dEn: "I'm going to make a reservation for two nights.", s: "An der Rezeption oder am Telefon buchen.", sEn: "Booking at reception or over the phone.", n: "ir a + hacer. hacer una reserva = reservieren/buchen.", nEn: "ir a + hacer. hacer una reserva = to make a reservation/book." },
    tp24: { e: "Llegaré mañana por la mañana.", d: "Ich werde morgen früh ankommen.", dEn: "I'll arrive early tomorrow.", s: "Deine Ankunft beim Gastgeber ankündigen.", sEn: "Letting your host know you're arriving.", n: "Futuro simple: Infinitiv llegar + é. Endung -é/-ás/-á/-emos/-án für alle Verben.", nEn: "Simple future: infinitive llegar + é. Endings -é/-ás/-á/-emos/-án for all verbs." },
    tp25: { e: "Un taxi al aeropuerto será caro.", d: "Ein Taxi zum Flughafen wird teuer sein.", dEn: "A taxi to the airport will be expensive.", s: "Kosten abschätzen, bevor du dich entscheidest.", sEn: "Estimating costs before you decide.", n: "Futur auch für Vermutungen: 'será caro' = das ist wohl/wird teuer.", nEn: "Future also for guesses: 'será caro' = that's probably/will be expensive." },
    tp26: { e: "No sé todavía, ya veremos.", d: "Ich weiß noch nicht, wir werden sehen.", dEn: "I don't know yet, we'll see.", s: "Eine Entscheidung offen lassen.", sEn: "Leaving a decision open.", n: "'Ya veremos' ist eine feste Floskel – sehr gebräuchlich in ganz LatAm.", nEn: "'Ya veremos' is a set phrase – very common all over LatAm." },
    tp27: { e: "Querría una habitación privada, por favor.", d: "Ich hätte gern ein Privatzimmer, bitte.", dEn: "I'd like a private room, please.", s: "Höflich an der Rezeption nach einem Zimmer fragen.", sEn: "Politely asking for a room at reception.", n: "Condicional 'querría' (oder 'me gustaría') ist die höflichste Art zu bestellen.", nEn: "The conditional 'querría' (or 'me gustaría') is the most polite way to order." },
    tp28: { e: "¿Podría ayudarme con la dirección?", d: "Könnten Sie mir mit der Adresse helfen?", dEn: "Could you help me with the address?", s: "Jemanden höflich um Hilfe bitten.", sEn: "Politely asking someone for help.", n: "'¿Podría?' ist höflicher als '¿Puede?' – ideal bei Fremden und in Ämtern.", nEn: "'¿Podría?' is more polite than '¿Puede?' – ideal with strangers and at offices." },
    tp29: { e: "Ayer estaba cansado, pero hoy estoy bien.", d: "Gestern war ich müde, aber heute geht's mir gut.", dEn: "Yesterday I was tired, but today I'm fine.", s: "Übers eigene Befinden reden.", sEn: "Talking about how you're feeling.", n: "estaba (Imperfekt, Zustand gestern) vs. estoy (Gegenwart, jetzt). Signalwörter: ayer/hoy.", nEn: "estaba (imperfect, yesterday's state) vs. estoy (present, now). Signal words: ayer/hoy." },
    tp30: { e: "Mañana voy a Lima en avión.", d: "Morgen fliege ich nach Lima.", dEn: "Tomorrow I'm flying to Lima.", s: "Den nächsten Reise-Abschnitt ankündigen.", sEn: "Announcing the next leg of your trip.", n: "Fürs ganz Nahe reicht oft die Gegenwart: 'mañana voy' statt 'iré'. Das Wort mañana macht die Zukunft klar.", nEn: "For the very near future the present often does: 'mañana voy' instead of 'iré'. The word mañana makes the future clear." },
    tp31: { e: "Estoy comiendo, te llamo después.", d: "Ich esse gerade, ich rufe dich später an.", dEn: "I'm eating right now, I'll call you later.", s: "Kurz sagen, dass du gerade beschäftigt bist.", sEn: "Quickly saying you're busy right now.", n: "estar + Gerundio (-ando/-iendo) = genau jetzt im Gange. Nicht für die Zukunft verwenden.", nEn: "estar + gerund (-ando/-iendo) = happening right now. Don't use it for the future." },
    tp32: { e: "¿Qué estás haciendo aquí?", d: "Was machst du gerade hier?", dEn: "What are you doing here right now?", s: "Eine bekannte Person überrascht antreffen.", sEn: "Bumping into someone you know, surprised.", n: "haciendo ist das Gerundio von hacer. estás + Gerundio fragt nach dem Moment.", nEn: "haciendo is the gerund of hacer. estás + gerund asks about the moment." },
    tp33: { e: "Estamos esperando el bus desde hace una hora.", d: "Wir warten schon seit einer Stunde auf den Bus.", dEn: "We've been waiting for the bus for an hour.", s: "Sich über eine lange Wartezeit austauschen.", sEn: "Comparing notes on a long wait.", n: "esperando = wartend. 'desde hace' drückt aus, seit wann etwas läuft.", nEn: "esperando = waiting. 'desde hace' expresses how long something's been going on." },
    tp34: { e: "No salgas, está lloviendo fuerte.", d: "Geh nicht raus, es regnet stark.", dEn: "Don't go out, it's raining hard.", s: "Vor schlechtem Wetter warnen.", sEn: "Warning about bad weather.", n: "Wetter im Moment: está lloviendo. Das Gerundio von llover ist lloviendo.", nEn: "Weather right now: está lloviendo. The gerund of llover is lloviendo." },
    tp35: { e: "Estoy buscando un hostal barato cerca del centro.", d: "Ich suche gerade ein günstiges Hostel nahe dem Zentrum.", dEn: "I'm looking for a cheap hostel near the centre.", s: "Bei der Ankunft nach einer Unterkunft fragen.", sEn: "Asking about accommodation on arrival.", n: "buscando = suchend. Tipp: 'estoy buscando' klingt aktiver als nur 'busco'.", nEn: "buscando = searching. Tip: 'estoy buscando' sounds more active than just 'busco'." },
    tp36: { e: "Dígame, ¿en qué le puedo ayudar?", d: "Sagen Sie, womit kann ich Ihnen helfen?", dEn: "Tell me, how can I help you?", s: "So wirst du oft an der Rezeption begrüßt.", sEn: "How you're often greeted at reception.", n: "Dígame ist der höfliche Befehl (usted) von decir – am Telefon auch einfach 'Hallo?'.", nEn: "Dígame is the polite command (usted) of decir – on the phone also just 'Hello?'." },
    tp37: { e: "Siga derecho y doble en la esquina.", d: "Gehen Sie geradeaus und biegen Sie an der Ecke ab.", dEn: "Go straight on and turn at the corner.", s: "Eine Wegbeschreibung verstehen oder geben.", sEn: "Understanding or giving directions.", n: "Siga = höflicher Befehl von seguir. Befehle an 'usted' enden bei -ir/-er-Verben auf -a.", nEn: "Siga = polite command of seguir. usted commands end in -a for -ir/-er verbs." },
    tp38: { e: "Espere un momento, por favor.", d: "Warten Sie bitte einen Moment.", dEn: "Please wait a moment.", s: "Jemanden höflich um kurze Geduld bitten.", sEn: "Politely asking someone for a moment's patience.", n: "Espere = Befehl (usted) von esperar. -ar-Verben enden im usted-Befehl auf -e.", nEn: "Espere = command (usted) of esperar. -ar verbs end in -e in the usted command." },
    tp39: { e: "Ayúdeme, por favor, estoy perdido.", d: "Helfen Sie mir bitte, ich habe mich verlaufen.", dEn: "Please help me, I'm lost.", s: "Im Notfall oder bei Orientierungslosigkeit.", sEn: "In an emergency or when you're lost.", n: "ayudar → ayude (usted) + me = ayúdeme. Das angehängte me bekommt einen Akzent.", nEn: "ayudar → ayude (usted) + me = ayúdeme. The attached me takes an accent." },
    tp40: { e: "Tráigame la cuenta, por favor.", d: "Bringen Sie mir bitte die Rechnung.", dEn: "Please bring me the bill.", s: "Im Restaurant nach der Rechnung fragen.", sEn: "Asking for the bill at the restaurant.", n: "traer → traiga (usted) + me = tráigame. la cuenta = die Rechnung.", nEn: "traer → traiga (usted) + me = tráigame. la cuenta = the bill." },
    tp41: { e: "Dime, ¿cómo llego a la plaza?", d: "Sag mir, wie komme ich zum Platz?", dEn: "Tell me, how do I get to the square?", s: "Vertraut jemanden um eine Auskunft bitten.", sEn: "Casually asking someone for information.", n: "Dime ist die vertraute Form (tú) von decir. Locker unter Reisenden gleichen Alters.", nEn: "Dime is the informal form (tú) of decir. Casual among travellers of the same age." },
    tp42: { e: "Ven, el bus ya está aquí.", d: "Komm, der Bus ist schon da.", dEn: "Come on, the bus is here.", s: "Eine vertraute Person zur Eile antreiben.", sEn: "Hurrying along someone you know well.", n: "Ven ist ein unregelmäßiger tú-Befehl von venir – ganz kurz, nur ein Wort.", nEn: "Ven is an irregular tú command of venir – very short, just one word." },
    tp43: { e: "Mira, ese es nuestro hostal.", d: "Schau, das ist unser Hostel.", dEn: "Look, that's our hostel.", s: "Jemanden auf etwas aufmerksam machen.", sEn: "Pointing something out to someone.", n: "Mira (von mirar) heißt wörtlich 'schau' – wird oft nur als 'hey, pass auf' benutzt.", nEn: "Mira (from mirar) literally means 'look' – often used just as 'hey, listen'." },
    tp44: { e: "Acabo de llegar a la ciudad.", d: "Ich bin gerade in der Stadt angekommen.", dEn: "I've just arrived in the city.", s: "Sagen, dass du eben erst da bist.", sEn: "Saying you've only just arrived.", n: "acabar de + Infinitiv = gerade eben getan. Praktischer als das Perfekt für 'soeben'.", nEn: "acabar de + infinitive = just done. Handier than the perfect for 'just now'." },
    tp45: { e: "El bus acaba de salir, hay otro en una hora.", d: "Der Bus ist gerade abgefahren, in einer Stunde gibt es einen anderen.", dEn: "The bus has just left, there's another in an hour.", s: "Wenn du den Anschluss knapp verpasst hast.", sEn: "When you've just missed your connection.", n: "acaba de salir = ist gerade abgefahren. acabar passt sich der Person an (acabo/acaba).", nEn: "acaba de salir = has just left. acabar agrees with the person (acabo/acaba)." },
    tp46: { e: "¿Hay wifi aquí? ¿Cuál es la contraseña?", d: "Gibt es hier WLAN? Wie lautet das Passwort?", dEn: "Is there wifi here? What's the password?", s: "Im Café, Hostel oder am Busbahnhof.", sEn: "At the café, hostel or bus station.", n: "hay = es gibt (für eins oder viele gleich). Sehr häufige Reise-Frage.", nEn: "hay = there is/are (same for one or many). A very common travel question." },
    tp47: { e: "No había agua caliente en la ducha.", d: "Es gab kein warmes Wasser in der Dusche.", dEn: "There was no hot water in the shower.", s: "An der Rezeption ein Problem melden.", sEn: "Reporting a problem at reception.", n: "había = es gab (Imperfekt von hay), für andauernde Zustände in der Vergangenheit.", nEn: "había = there was/were (imperfect of hay), for ongoing states in the past." },
    tp48: { e: "¿Habrá un bus nocturno a Arequipa?", d: "Wird es einen Nachtbus nach Arequipa geben?", dEn: "Will there be a night bus to Arequipa?", s: "Nach künftigen Verbindungen fragen.", sEn: "Asking about future connections.", n: "habrá = es wird geben (Futur von hay). Eine Form für eins oder viele.", nEn: "habrá = there will be (future of hay). One form for one or many." },
    tp49: { e: "Tuve un problema con la reserva.", d: "Ich hatte ein Problem mit der Reservierung.", dEn: "I had a problem with the reservation.", s: "Eine Schwierigkeit beim Einchecken erklären.", sEn: "Explaining a hitch at check-in.", n: "tener wird in der Vergangenheit zu tuve/tuvo – Stammwechsel, kein Akzent.", nEn: "tener becomes tuve/tuvo in the past – stem change, no accent." },
    tp50: { e: "No pude dormir por el ruido.", d: "Ich konnte wegen des Lärms nicht schlafen.", dEn: "I couldn't sleep because of the noise.", s: "Über eine schlechte Nacht im Hostel klagen.", sEn: "Complaining about a bad night at the hostel.", n: "poder → pude (kein Akzent). 'No pude' = ich schaffte es nicht / konnte nicht.", nEn: "poder → pude (no accent). 'No pude' = I couldn't manage it / couldn't." },
    tp51: { e: "El taxista me dijo que es caro.", d: "Der Taxifahrer hat mir gesagt, dass es teuer ist.", dEn: "The taxi driver told me it's expensive.", s: "Etwas weitergeben, das dir jemand gesagt hat.", sEn: "Passing on something someone told you.", n: "decir → dijo (mit j). 'me dijo que …' = er/sie sagte mir, dass …", nEn: "decir → dijo (with j). 'me dijo que …' = he/she told me that …" },
    tp52: { e: "¿Cuándo viniste a Bolivia?", d: "Wann bist du nach Bolivien gekommen?", dEn: "When did you come to Bolivia?", s: "Smalltalk über die Reise des anderen.", sEn: "Small talk about the other person's trip.", n: "venir → viniste (du). Stammwechsel ven- → vin-, ohne Akzent.", nEn: "venir → viniste (you). Stem change ven- → vin-, no accent." },
    tp53: { e: "Le di el dinero al chofer y bajé.", d: "Ich gab dem Fahrer das Geld und stieg aus.", dEn: "I gave the driver the money and got off.", s: "Vom Bezahlen im Sammeltaxi oder Bus erzählen.", sEn: "Telling people about paying in the shared taxi or bus.", n: "dar → di (nur zwei Buchstaben!). chofer = Fahrer in LatAm.", nEn: "dar → di (just two letters!). chofer = driver in LatAm." },
    tp54: { e: "Perdón, ¿qué has dicho?", d: "Entschuldigung, was hast du gesagt?", dEn: "Sorry, what did you say?", s: "Höflich um Wiederholung bitten.", sEn: "Politely asking for a repeat.", n: "dicho ist das unregelmäßige Partizip von decir (nicht 'decido').", nEn: "dicho is the irregular participle of decir (not 'decido')." },
    tp55: { e: "Ya he abierto la puerta, pasa.", d: "Ich habe die Tür schon geöffnet, komm rein.", dEn: "I've already opened the door, come in.", s: "Jemandem signalisieren, dass offen ist.", sEn: "Letting someone know the door's open.", n: "abierto = Partizip von abrir. Auch als Schild: 'Abierto' = geöffnet.", nEn: "abierto = participle of abrir. Also as a sign: 'Abierto' = open." },
    tp56: { e: "Todavía no han hecho la habitación.", d: "Sie haben das Zimmer noch nicht gemacht.", dEn: "They haven't done the room yet.", s: "Wenn dein Zimmer beim Check-in noch nicht fertig ist.", sEn: "When your room isn't ready at check-in.", n: "hecho = Partizip von hacer. 'hacer la habitación' = das Zimmer herrichten.", nEn: "hecho = participle of hacer. 'hacer la habitación' = to make up the room." },
    tp57: { e: "He roto mis lentes, necesito una óptica.", d: "Ich habe meine Brille kaputt gemacht, ich brauche einen Optiker.", dEn: "I've broken my glasses, I need an optician.", s: "Ein kleines Reise-Missgeschick erklären.", sEn: "Explaining a small travel mishap.", n: "roto = Partizip von romper. lentes (auch gafas/anteojos) = Brille.", nEn: "roto = participle of romper. lentes (also gafas/anteojos) = glasses." },
    tp58: { e: "Cuando llegué, ya era tarde.", d: "Als ich ankam, war es schon spät.", dEn: "When I arrived, it was already late.", s: "Den Hintergrund einer Geschichte schildern.", sEn: "Setting the scene for a story.", n: "era (Imperfekt von ser) beschreibt den Rahmen; llegué (Indefinido) ist das Ereignis.", nEn: "era (imperfect of ser) sets the scene; llegué (Indefinido) is the event." },
    tp59: { e: "No conocía la ciudad, así que usé el mapa.", d: "Ich kannte die Stadt nicht, also benutzte ich die Karte.", dEn: "I didn't know the city, so I used the map.", s: "Erklären, warum du dich erst orientieren musstest.", sEn: "Explaining why you had to get your bearings first.", n: "conocer im Imperfekt (conocía) = kannte (Zustand). conocer = kennen/kennenlernen.", nEn: "conocer in the imperfect (conocía) = knew (a state). conocer = to know/to meet." },
    tp60: { e: "Teníamos hambre y buscamos un mercado.", d: "Wir hatten Hunger und suchten einen Markt.", dEn: "We were hungry and looked for a market.", s: "Von einer gemeinsamen Situation erzählen.", sEn: "Telling people about a shared situation.", n: "tener hambre = Hunger haben. Im Imperfekt: teníamos (andauernder Zustand).", nEn: "tener hambre = to be hungry. In the imperfect: teníamos (an ongoing state)." },
    tp61: { e: "Te voy a llamar más tarde, ¿está bien?", d: "Ich rufe dich später an, okay?", dEn: "I'll call you later, okay?", s: "Ein Treffen oder einen Anruf vereinbaren.", sEn: "Arranging a meet-up or a call.", n: "ir a + Infinitiv für die nahe Zukunft. te … llamar = dich anrufen.", nEn: "ir a + infinitive for the near future. te … llamar = to call you." },
    tp62: { e: "¿Cuánto tiempo te vas a quedar en Cusco?", d: "Wie lange wirst du in Cusco bleiben?", dEn: "How long will you stay in Cusco?", s: "Reisepläne der anderen Person erfragen.", sEn: "Asking about the other person's travel plans.", n: "quedarse = bleiben (reflexiv). vas a quedarte / te vas a quedar – beides geht.", nEn: "quedarse = to stay (reflexive). vas a quedarte / te vas a quedar – both work." },
    tp63: { e: "El tour es caro, pero valdrá la pena.", d: "Die Tour ist teuer, aber es wird sich lohnen.", dEn: "The tour is expensive, but it'll be worth it.", s: "Eine Ausgabe vor dir selbst rechtfertigen.", sEn: "Justifying an expense to yourself.", n: "valer → valdrá (unregelmäßiges Futur). valer la pena = sich lohnen.", nEn: "valer → valdrá (irregular future). valer la pena = to be worth it." },
    tp64: { e: "¿Qué me recomendaría para comer aquí?", d: "Was würden Sie mir hier zu essen empfehlen?", dEn: "What would you recommend I eat here?", s: "Im Restaurant höflich um einen Tipp bitten.", sEn: "Politely asking for a tip at the restaurant.", n: "Condicional (recomendaría) klingt höflicher als die direkte Frage 'qué recomienda'.", nEn: "The conditional (recomendaría) sounds more polite than the direct 'qué recomienda'." },
    tp65: { e: "Preferiría ir a pie, no está lejos.", d: "Ich würde lieber zu Fuß gehen, es ist nicht weit.", dEn: "I'd rather walk, it's not far.", s: "Höflich eine Vorliebe äußern.", sEn: "Politely expressing a preference.", n: "preferir → preferiría (Condicional). ir a pie = zu Fuß gehen.", nEn: "preferir → preferiría (conditional). ir a pie = to go on foot." },
    tp66: { e: "Debería tomar un taxi, ya es de noche.", d: "Sie sollten ein Taxi nehmen, es ist schon dunkel.", dEn: "You should take a taxi, it's already dark.", s: "Jemandem einen vorsichtigen Rat geben.", sEn: "Giving someone a gentle piece of advice.", n: "debería (von deber) = sollte – die höfliche Art, einen Rat zu geben.", nEn: "debería (from deber) = should – the polite way to give advice." },

    // ===================== FARBEN =====================
    col01: { e: "¿Tiene esta camiseta en rojo?", d: "Haben Sie dieses T-Shirt in Rot?", dEn: "Do you have this T-shirt in red?", s: "Beim Klamotten-Kauf am Markt oder im Laden.", sEn: "When buying clothes at the market or shop.", n: "Farbe steht meist nach dem Nomen: una mochila roja, una bici roja.", nEn: "The colour usually comes after the noun: una mochila roja, una bici roja." },
    col02: { e: "Me gusta más la azul.", d: "Die blaue gefällt mir besser.", dEn: "I prefer the blue one.", s: "Wenn du zwischen mehreren Varianten wählst.", sEn: "When choosing between several options.", n: "Die Farbe passt sich an: el azul / la azul je nach Gegenstand.", nEn: "The colour agrees: el azul / la azul depending on the object." },
    col03: { e: "¿El semáforo ya está en verde?", d: "Ist die Ampel schon grün?", dEn: "Is the light green yet?", s: "An der Straße, bevor du losgehst.", sEn: "By the road, before you set off.", n: "verde bleibt gleich für männlich/weiblich: un carro verde, una puerta verde.", nEn: "verde stays the same for masculine/feminine: un carro verde, una puerta verde." },
    col04: { e: "El taxi amarillo es el oficial.", d: "Das gelbe Taxi ist das offizielle.", dEn: "The yellow taxi is the official one.", s: "Beim Taxi-Suchen in vielen Städten.", sEn: "When looking for a taxi in many cities.", n: "amarillo/-a passt sich an: una flor amarilla.", nEn: "amarillo/-a agrees: una flor amarilla." },
    col05: { e: "Quiero el jugo de naranja, el de color naranja.", d: "Ich möchte den Orangensaft, den orangefarbenen.", dEn: "I'd like the orange juice, the orange one.", s: "Beim Bestellen, wenn die Farbe hilft zu zeigen.", sEn: "When ordering, if the colour helps you point.", n: "naranja als Farbe bleibt oft unverändert: dos camisetas naranja.", nEn: "naranja as a colour often stays unchanged: dos camisetas naranja." },
    col06: { e: "Mi mochila es la negra, la grande.", d: "Mein Rucksack ist der schwarze, der große.", dEn: "My backpack is the black one, the big one.", s: "Am Gepäckband oder im Sammeltaxi dein Gepäck beschreiben.", sEn: "Describing your luggage at the carousel or in the shared taxi.", n: "negro/-a passt sich an: una maleta negra.", nEn: "negro/-a agrees: una maleta negra." },
    col07: { e: "Busco una casa blanca con puerta azul.", d: "Ich suche ein weißes Haus mit blauer Tür.", dEn: "I'm looking for a white house with a blue door.", s: "Beim Suchen einer Unterkunft nach Beschreibung.", sEn: "When finding accommodation by description.", n: "blanco/-a passt sich an: una pared blanca.", nEn: "blanco/-a agrees: una pared blanca." },
    col08: { e: "El edificio gris, a la derecha.", d: "Das graue Gebäude, rechts.", dEn: "The grey building, on the right.", s: "Wegbeschreibung an Merkmalen festmachen.", sEn: "Pinning directions to landmarks.", n: "gris bleibt gleich für beide Geschlechter: una nube gris.", nEn: "gris stays the same for both genders: una nube gris." },
    col09: { e: "La casa rosada de la esquina es el hostal.", d: "Das rosa Haus an der Ecke ist das Hostel.", dEn: "The pink house on the corner is the hostel.", s: "Eine Adresse über die Hausfarbe finden.", sEn: "Finding an address by the colour of the house.", n: "In LatAm sehr oft rosado/-a; rosa bleibt meist unverändert.", nEn: "In LatAm very often rosado/-a; rosa usually stays unchanged." },
    col10: { e: "¿Lo tiene en café en vez de negro?", d: "Haben Sie es in Braun statt Schwarz?", dEn: "Do you have it in brown instead of black?", s: "Beim Schuh- oder Taschenkauf nach der Farbe fragen.", sEn: "Asking about the colour when buying shoes or a bag.", n: "In LatAm sagt man meist café für Braun, seltener marrón.", nEn: "In LatAm people usually say café for brown, rarely marrón." },
    col11: { e: "¿De qué color es tu mochila? Es café.", d: "Welche Farbe hat dein Rucksack? Er ist braun.", dEn: "What colour is your backpack? It's brown.", s: "Wenn du Gepäck oder einen Gegenstand beschreibst.", sEn: "When describing luggage or an item.", n: "el color = die Farbe; ¿De qué color? = welche Farbe?", nEn: "el color = the colour; ¿De qué color? = what colour?" },
    col12: { e: "¿Lo quiere claro u oscuro?", d: "Möchten Sie es hell oder dunkel?", dEn: "Would you like it light or dark?", s: "Bei Kaffee, Bier oder beim Aussuchen einer Farbnuance.", sEn: "With coffee, beer or when choosing a shade.", n: "claro = hell, oscuro = dunkel – auch für café claro / café oscuro.", nEn: "claro = light, oscuro = dark – also for café claro / café oscuro." },
    col13: { e: "La línea morada del metro va al centro.", d: "Die lila Metro-Linie fährt ins Zentrum.", dEn: "The purple metro line goes to the centre.", s: "Beim Orientieren im Nahverkehr nach Linienfarben.", sEn: "When orienting by line colour on local transport.", n: "In LatAm meist morado für Lila/Violett, in Spanien eher violeta.", nEn: "In LatAm usually morado for purple/violet, in Spain rather violeta." },
    col14: { e: "El agua aquí es de un celeste increíble.", d: "Das Wasser ist hier von einem unglaublichen Himmelblau.", dEn: "The water here is an incredible sky blue.", s: "Beim Schwärmen über Strände, Lagunen oder Flüsse.", sEn: "When raving about beaches, lagoons or rivers.", n: "celeste = himmelblau/hellblau; sehr verbreitet in ganz LatAm.", nEn: "celeste = sky blue/light blue; very common all over LatAm." },
    col15: { e: "El uniforme es violeta, no azul.", d: "Die Uniform ist violett, nicht blau.", dEn: "The uniform is violet, not blue.", s: "Wenn du etwas genauer von einer Farbe abgrenzt.", sEn: "When you distinguish something more precisely by colour.", n: "violeta bleibt meist unverändert: dos camisas violeta.", nEn: "violeta usually stays unchanged: dos camisas violeta." },
    col16: { e: "Las aguas termales tienen un color turquesa.", d: "Die heißen Quellen haben eine türkise Farbe.", dEn: "The hot springs are a turquoise colour.", s: "Beim Beschreiben von Natur, Pools oder Schmuck.", sEn: "When describing nature, pools or jewellery.", n: "turquesa bleibt unverändert: un mar turquesa, una piedra turquesa.", nEn: "turquesa stays unchanged: un mar turquesa, una piedra turquesa." },
    col17: { e: "Los pantalones beige van con todo.", d: "Die beigen Hosen passen zu allem.", dEn: "The beige trousers go with everything.", s: "Beim Klamotten-Kauf oder Outfit-Tipp.", sEn: "When buying clothes or giving an outfit tip.", n: "beige bleibt unverändert; sprich es etwa „BEISCH“.", nEn: "beige stays unchanged; pronounce it roughly „BAYSH“." },
    col18: { e: "¿Tiene aretes dorados?", d: "Haben Sie goldene Ohrringe?", dEn: "Do you have gold earrings?", s: "Beim Schmuck- oder Souvenir-Kauf am Markt.", sEn: "When buying jewellery or souvenirs at the market.", n: "dorado/-a = golden; plateado/-a = silbern.", nEn: "dorado/-a = gold; plateado/-a = silver." },
    col19: { e: "Prefiero el reloj plateado.", d: "Ich bevorzuge die silberne Uhr.", dEn: "I prefer the silver watch.", s: "Bei der Auswahl von Schmuck, Uhren oder Deko.", sEn: "When choosing jewellery, watches or decor.", n: "plateado/-a passt sich an: una cadena plateada.", nEn: "plateado/-a agrees: una cadena plateada." },
    col20: { e: "El atardecer se pone color vino.", d: "Der Sonnenuntergang wird weinrot.", dEn: "The sunset turns maroon.", s: "Beim Beschreiben einer dunkelroten Farbe.", sEn: "When describing a dark red colour.", n: "vino oder bordó für Weinrot; tinto meint speziell den Rotwein selbst.", nEn: "vino or bordó for maroon; tinto refers specifically to the red wine itself." },
    col21: { e: "Quiero unos jeans azul claro.", d: "Ich möchte eine hellblaue Jeans.", dEn: "I'd like light blue jeans.", s: "Beim Kleiderkauf, wenn du den Farbton genau angibst.", sEn: "When buying clothes and specifying the exact shade.", n: "Nuance über claro/oscuro: azul claro = hellblau, azul oscuro = dunkelblau.", nEn: "Shade via claro/oscuro: azul claro = light blue, azul oscuro = dark blue." },
    col22: { e: "La selva se ve verde oscuro desde el mirador.", d: "Der Dschungel sieht vom Aussichtspunkt dunkelgrün aus.", dEn: "The jungle looks dark green from the viewpoint.", s: "Beim Beschreiben von Landschaft oder Farbnuancen.", sEn: "When describing scenery or shades of colour.", n: "verde oscuro = dunkelgrün, verde claro = hellgrün.", nEn: "verde oscuro = dark green, verde claro = light green." },
    col23: { e: "¿De qué color es el bus para Salento?", d: "Welche Farbe hat der Bus nach Salento?", dEn: "What colour is the bus to Salento?", s: "Am Busterminal das richtige Fahrzeug finden.", sEn: "Finding the right vehicle at the bus terminal.", n: "Busse sind oft nach Farbe oder Linie unterscheidbar – praktische Rückfrage.", nEn: "Buses can often be told apart by colour or line – a handy thing to ask." },
    col24: { e: "Mi color favorito es el verde, como la selva.", d: "Meine Lieblingsfarbe ist Grün, wie der Dschungel.", dEn: "My favourite colour is green, like the jungle.", s: "Beim Smalltalk im Hostel oder mit Locals.", sEn: "During small talk at the hostel or with locals.", n: "Mi color favorito es ... – ein lockerer Einstieg für ein Gespräch.", nEn: "Mi color favorito es ... – a casual way into a conversation." },

    // ===================== GEGENTEILE (Contrarios) =====================
    op01: { e: "¿Tiene una habitación más grande? Esta es muy pequeña.", d: "Haben Sie ein größeres Zimmer? Dieses ist sehr klein.", dEn: "Do you have a bigger room? This one is very small.", s: "Beim Check-in, wenn dir das Zimmer zu klein ist.", sEn: "At check-in, when the room is too small for you.", n: "grande = groß, pequeño/-a = klein – passt sich an: una mochila pequeña.", nEn: "grande = big, pequeño/-a = small – agrees: una mochila pequeña." },
    op02: { e: "El primer hostel era bueno, pero el segundo era malo.", d: "Das erste Hostel war gut, aber das zweite war schlecht.", dEn: "The first hostel was good, but the second was bad.", s: "Beim Vergleichen von Unterkünften oder Restaurants.", sEn: "When comparing places to stay or restaurants.", n: "Vor einem männlichen Nomen wird bueno → buen: un buen hostal.", nEn: "Before a masculine noun bueno → buen: un buen hostal." },
    op03: { e: "Tengo mucho tiempo pero poco dinero.", d: "Ich habe viel Zeit, aber wenig Geld.", dEn: "I have lots of time but little money.", s: "Beim Planen als Backpacker mit kleinem Budget.", sEn: "When planning as a backpacker on a small budget.", n: "mucho/poco passen sich an: mucha agua, pocas horas.", nEn: "mucho/poco agree: mucha agua, pocas horas." },
    op04: { e: "El agua de la ducha está fría, no caliente.", d: "Das Duschwasser ist kalt, nicht warm.", dEn: "The shower water is cold, not hot.", s: "Im Hostel-Bad, wenn die Dusche kalt bleibt.", sEn: "In the hostel bathroom, when the shower stays cold.", n: "Achtung: tener frío = frieren, hacer frío = es ist kalt (Wetter).", nEn: "Note: tener frío = to be cold (a person), hacer frío = it's cold (weather)." },
    op05: { e: "Este bus es viejo, pero el otro es nuevo.", d: "Dieser Bus ist alt, aber der andere ist neu.", dEn: "This bus is old, but the other one is new.", s: "Beim Vergleichen von Bussen am Terminal.", sEn: "When comparing buses at the terminal.", n: "nuevo/-a = neu, viejo/-a = alt (für Dinge); für Personen lieber mayor.", nEn: "nuevo/-a = new, viejo/-a = old (for things); for people use mayor instead." },
    op06: { e: "Este mercado es caro, el otro es más barato.", d: "Dieser Markt ist teuer, der andere ist billiger.", dEn: "This market is expensive, the other one is cheaper.", s: "Beim Vergleichen von Preisen auf dem Markt.", sEn: "When comparing prices at the market.", n: "barato = billig; ¿Tiene algo más barato? hilft beim Handeln.", nEn: "barato = cheap; ¿Tiene algo más barato? helps with haggling." },
    op07: { e: "¿La farmacia está abierta o cerrada los domingos?", d: "Ist die Apotheke sonntags offen oder geschlossen?", dEn: "Is the pharmacy open or closed on Sundays?", s: "Vor dem Besuch von Geschäft, Apotheke oder Bank.", sEn: "Before visiting a shop, pharmacy or bank.", n: "Schild abierto = offen, cerrado = zu.", nEn: "Sign abierto = open, cerrado = closed." },
    op08: { e: "¿El terminal está cerca o lejos de aquí?", d: "Ist das Terminal nah oder weit von hier?", dEn: "Is the terminal near or far from here?", s: "Bei der Orientierung, bevor du losläufst oder ein Taxi nimmst.", sEn: "When getting your bearings, before walking or taking a taxi.", n: "cerca de = in der Nähe von, lejos de = weit weg von.", nEn: "cerca de = near, lejos de = far from." },
    op09: { e: "El wifi aquí es muy lento, no es rápido.", d: "Das WLAN hier ist sehr langsam, nicht schnell.", dEn: "The wifi here is very slow, not fast.", s: "Im Hostel, wenn das Internet kriecht.", sEn: "At the hostel, when the internet crawls.", n: "Más despacio = langsamer (beim Sprechen); lento = langsam (Sache).", nEn: "Más despacio = slower (when speaking); lento = slow (a thing)." },
    op10: { e: "El camino es fácil al inicio y difícil al final.", d: "Der Weg ist am Anfang leicht und am Ende schwierig.", dEn: "The path is easy at the start and difficult at the end.", s: "Vor einer Wanderung, wenn du nach der Schwierigkeit fragst.", sEn: "Before a hike, when you ask about the difficulty.", n: "¿Es difícil la caminata? – nützliche Frage vor einem Trek.", nEn: "¿Es difícil la caminata? – a useful question before a trek." },
    op11: { e: "El bus no sale de aquí, sale de allá.", d: "Der Bus fährt nicht von hier, er fährt von dort.", dEn: "The bus doesn't leave from here, it leaves from there.", s: "Am Busbahnhof, wenn man dir den richtigen Steig zeigt.", sEn: "At the bus station, when you're shown the right platform.", n: "aquí = hier, allá/allí = dort; acá ist in LatAm sehr verbreitet.", nEn: "aquí = here, allá/allí = there; acá is very common in LatAm." },
    op12: { e: "¿Está incluido el desayuno? – Sí. ¿Y la cena? – No.", d: "Ist das Frühstück inklusive? – Ja. Und das Abendessen? – Nein.", dEn: "Is breakfast included? – Yes. And dinner? – No.", s: "Beim Nachfragen an der Rezeption.", sEn: "When asking again at reception.", n: "sí (mit Akzent) = ja; si (ohne) = wenn/falls.", nEn: "sí (with accent) = yes; si (without) = if." },
    op13: { e: "El primer bus está lleno, el otro va vacío.", d: "Der erste Bus ist voll, der andere fährt leer.", dEn: "The first bus is full, the other one leaves empty.", s: "Am Terminal, wenn du einen freien Platz suchst.", sEn: "At the terminal, when looking for a free seat.", n: "lleno = voll, vacío = leer; el tanque lleno = voller Tank.", nEn: "lleno = full, vacío = empty; el tanque lleno = a full tank." },
    op14: { e: "El bus sale temprano y llega tarde.", d: "Der Bus fährt früh ab und kommt spät an.", dEn: "The bus leaves early and arrives late.", s: "Beim Planen einer langen Busfahrt.", sEn: "When planning a long bus ride.", n: "temprano = früh, tarde = spät; la tarde = der Nachmittag.", nEn: "temprano = early, tarde = late; la tarde = the afternoon." },
    op15: { e: "El baño compartido está limpio, no sucio.", d: "Das Gemeinschaftsbad ist sauber, nicht schmutzig.", dEn: "The shared bathroom is clean, not dirty.", s: "Bei der Zimmer- oder Hostelwahl.", sEn: "When choosing a room or hostel.", n: "limpio/-a = sauber, sucio/-a = schmutzig.", nEn: "limpio/-a = clean, sucio/-a = dirty." },
    op16: { e: "Quiero pagar menos, no más.", d: "Ich will weniger zahlen, nicht mehr.", dEn: "I want to pay less, not more.", s: "Beim Handeln auf dem Markt oder mit dem Taxi.", sEn: "When haggling at the market or with the taxi.", n: "más = mehr, menos = weniger; un poco menos, por favor.", nEn: "más = more, menos = less; un poco menos, por favor." },
    op17: { e: "Doble a la izquierda, no a la derecha.", d: "Biegen Sie links ab, nicht rechts.", dEn: "Turn left, not right.", s: "Bei einer Wegbeschreibung zu Fuß oder im Taxi.", sEn: "When given directions on foot or in the taxi.", n: "a la izquierda = nach links, a la derecha = nach rechts.", nEn: "a la izquierda = to the left, a la derecha = to the right." },
    op18: { e: "Tomo el primer bus, no el último.", d: "Ich nehme den ersten Bus, nicht den letzten.", dEn: "I'm taking the first bus, not the last one.", s: "Beim Planen der Abfahrtszeit.", sEn: "When planning the departure time.", n: "Vor männl. Nomen apokopiert: el primer bus, el último día.", nEn: "Shortened before a masc. noun: el primer bus, el último día." },
    op19: { e: "Estoy feliz de viajar, un poco triste de irme.", d: "Ich bin glücklich zu reisen, ein bisschen traurig zu gehen.", dEn: "I'm happy to be travelling, a bit sad to leave.", s: "Beim Smalltalk über die Reise im Hostel.", sEn: "During small talk about the trip at the hostel.", n: "feliz = glücklich, triste = traurig; mit estar für die Stimmung.", nEn: "feliz = happy, triste = sad; with estar for a mood." },
    op20: { e: "¿A qué hora abren y cierran?", d: "Um wie viel Uhr öffnen und schließen sie?", dEn: "What time do they open and close?", s: "Vor dem Besuch von Geschäft, Museum oder Markt.", sEn: "Before visiting a shop, museum or market.", n: "abrir = öffnen, cerrar = schließen; cierra (Wechsel e→ie).", nEn: "abrir = to open, cerrar = to close; cierra (e→ie change)." },
    op21: { e: "Prefiero un cuarto claro, no tan oscuro.", d: "Ich bevorzuge ein helles Zimmer, nicht so dunkel.", dEn: "I prefer a light room, not so dark.", s: "Bei der Zimmerwahl im Hostel.", sEn: "When choosing a room at the hostel.", n: "claro = hell, oscuro = dunkel; auch für Farbtöne: azul claro/oscuro.", nEn: "claro = light, oscuro = dark; also for shades: azul claro/oscuro." },
    op22: { e: "La señal del wifi es débil aquí, más fuerte afuera.", d: "Das WLAN-Signal ist hier schwach, draußen stärker.", dEn: "The wifi signal is weak here, stronger outside.", s: "Wenn du im Hostel besseren Empfang suchst.", sEn: "When you want better signal at the hostel.", n: "fuerte = stark, débil = schwach; la señal = das Signal.", nEn: "fuerte = strong, débil = weak; la señal = the signal." },
    op23: { e: "¿El trayecto es largo o corto?", d: "Ist die Strecke lang oder kurz?", dEn: "Is the route long or short?", s: "Vor einer Busfahrt, um die Dauer einzuschätzen.", sEn: "Before a bus ride, to gauge how long it takes.", n: "largo = lang, corto = kurz; el viaje es largo = die Fahrt ist lang.", nEn: "largo = long, corto = short; el viaje es largo = the journey is long." },
    op24: { e: "Lleva ropa seca, el camino está mojado.", d: "Nimm trockene Kleidung mit, der Weg ist nass.", dEn: "Take dry clothes, the path is wet.", s: "Vor einer Wanderung in der Regenzeit.", sEn: "Before a hike in the rainy season.", n: "seco/-a = trocken, mojado/-a = nass; temporada seca = Trockenzeit.", nEn: "seco/-a = dry, mojado/-a = wet; temporada seca = dry season." },
    op25: { e: "El dormitorio es ruidoso, busco algo más silencioso.", d: "Der Schlafsaal ist laut, ich suche etwas Ruhigeres.", dEn: "The dorm is noisy, I'm looking for somewhere quieter.", s: "Wenn du im Hostel ein ruhigeres Bett willst.", sEn: "When you want a quieter bed at the hostel.", n: "ruidoso = laut, silencioso = leise/ruhig; auch tranquilo = ruhig.", nEn: "ruidoso = loud, silencioso = quiet; also tranquilo = calm." },
    op26: { e: "El guía es joven, el conductor es más viejo.", d: "Der Guide ist jung, der Fahrer ist älter.", dEn: "The guide is young, the driver is older.", s: "Beim Beschreiben von Personen auf einer Tour.", sEn: "When describing people on a tour.", n: "joven = jung, viejo = alt; für Personen höflicher: mayor.", nEn: "joven = young, viejo = old; for people more politely: mayor." },

    // ===================== KOLUMBIEN-PAKET =====================
    co01: { e: "¿Dónde puedo tomar un taxi al centro?", d: "Wo kann ich ein Taxi ins Zentrum nehmen?", dEn: "Where can I get a taxi to the centre?", s: "Direkt nach der Landung am Flughafen oder am Busterminal.", sEn: "Right after landing at the airport or at the bus terminal.", n: "In Kolumbien sagt man tomar un taxi, nicht coger (das ist anderswo unhöflich).", nEn: "In Colombia you say tomar un taxi, not coger (which is rude elsewhere)." },
    co02: { e: "Lléveme al centro, por favor. ¿Cuánto sería?", d: "Bringen Sie mich bitte ins Zentrum. Wie viel wäre das?", dEn: "Take me to the centre, please. How much would it be?", s: "Beim Einsteigen ins Taxi, um Ziel und Preis zu klären.", sEn: "When getting into the taxi, to settle destination and price.", n: "Gleich nach dem Preis fragen schützt vor Überraschungen.", nEn: "Asking the price right away saves surprises." },
    co03: { e: "¿Cuánto cuesta la carrera hasta el hostal en Getsemaní?", d: "Wie viel kostet die Fahrt zum Hostel in Getsemaní?", dEn: "How much is the ride to the hostel in Getsemaní?", s: "Vor Fahrtbeginn, wenn das Taxi kein Taxameter nutzt.", sEn: "Before setting off, when the taxi doesn't use a meter.", n: "carrera = die Taxifahrt; viele Taxis fahren mit Festpreis statt Taxameter.", nEn: "carrera = the taxi ride; many taxis use a fixed price, not a meter." },
    co04: { e: "¿Podemos acordar la tarifa antes de salir?", d: "Können wir den Preis vereinbaren, bevor wir losfahren?", dEn: "Can we agree the fare before we leave?", s: "Bei Taxis ohne Taxameter, um Streit am Ziel zu vermeiden.", sEn: "With meterless taxis, to avoid arguments at the destination.", n: "tarifa = Tarif/Festpreis; ruhig einmal kurz verhandeln (regatear).", nEn: "tarifa = fare/fixed price; it's fine to haggle a little (regatear)." },
    co05: { e: "¿Me deja en la esquina, por favor?", d: "Können Sie mich an der Ecke absetzen, bitte?", dEn: "Can you drop me at the corner, please?", s: "Wenn die genaue Adresse schwer zu finden ist.", sEn: "When the exact address is hard to find.", n: "esquina = Straßenecke; aquí está bien = hier ist gut.", nEn: "esquina = street corner; aquí está bien = here is fine." },
    co06: { e: "¿Es por aplicación o en efectivo?", d: "Geht es über eine App oder bar?", dEn: "Is it via an app or cash?", s: "Beim Bezahlen von Taxi oder Tour.", sEn: "When paying for a taxi or tour.", n: "Apps sind in Großstädten verbreitet; auf der Küste lieber efectivo (bar) bereithalten.", nEn: "Apps are common in big cities; on the coast keep efectivo (cash) ready." },
    co07: { e: "Hola, tengo una reserva a nombre de Marcel.", d: "Hallo, ich habe eine Reservierung auf den Namen Marcel.", dEn: "Hi, I have a reservation under the name Marcel.", s: "Beim Check-in im Hostel oder Hotel.", sEn: "At check-in at the hostel or hotel.", n: "a nombre de = auf den Namen von; danach oft nach dem Pass gefragt.", nEn: "a nombre de = under the name of; they'll often ask for your passport next." },
    co08: { e: "Con este calor, ¿hay ventilador o aire acondicionado?", d: "Bei dieser Hitze – gibt es einen Ventilator oder eine Klimaanlage?", dEn: "In this heat, is there a fan or air conditioning?", s: "Beim Check-in an der heißen Karibikküste.", sEn: "At check-in on the hot Caribbean coast.", n: "ventilador = Ventilator, aire acondicionado = Klimaanlage; an der Küste Gold wert.", nEn: "ventilador = fan, aire acondicionado = AC; worth gold on the coast." },
    co09: { e: "¿Hay una familia anfitriona cerca de la escuela?", d: "Gibt es eine Gastfamilie in der Nähe der Schule?", dEn: "Is there a host family near the school?", s: "Bei Sprachschule oder Sprachaufenthalt mit Unterkunft.", sEn: "With a language school or stay that includes accommodation.", n: "familia anfitriona = Gastfamilie; alltäglicher: familia que recibe estudiantes.", nEn: "familia anfitriona = host family; more casually: familia que recibe estudiantes." },
    co10: { e: "¿Hay agua caliente en la ducha?", d: "Gibt es heißes Wasser in der Dusche?", dEn: "Is there hot water in the shower?", s: "Beim Check-in, besonders im kühlen Bogotá oder in den Bergen.", sEn: "At check-in, especially in chilly Bogotá or the mountains.", n: "An der heißen Küste ist kaltes Wasser oft normal und sogar angenehm.", nEn: "On the hot coast cold water is often normal and even welcome." },
    co11: { e: "¿Cómo llego a Getsemaní desde aquí?", d: "Wie komme ich von hier nach Getsemaní?", dEn: "How do I get to Getsemaní from here?", s: "Wenn du das lebhafte Ausgehviertel von Cartagena suchst.", sEn: "When you're looking for Cartagena's lively nightlife district.", n: "Getsemaní = Szeneviertel mit Streetart, Bars und Plaza de la Trinidad.", nEn: "Getsemaní = hip district with street art, bars and Plaza de la Trinidad." },
    co12: { e: "Quiero ir al centro histórico, a la ciudad amurallada.", d: "Ich möchte in die Altstadt, in die ummauerte Stadt.", dEn: "I want to go to the old town, the walled city.", s: "Wenn du Cartagenas koloniale Altstadt besuchen willst.", sEn: "When you want to visit Cartagena's colonial old town.", n: "ciudad amurallada = die berühmte ummauerte Stadt von Cartagena.", nEn: "ciudad amurallada = Cartagena's famous walled city." },
    co13: { e: "¿A qué hora sale la lancha a las Islas del Rosario?", d: "Wann fährt das Boot zu den Islas del Rosario?", dEn: "When does the boat to the Islas del Rosario leave?", s: "Am Hafen Muelle de la Bodeguita beim Buchen einer Inseltour.", sEn: "At the Muelle de la Bodeguita pier when booking an island tour.", n: "lancha = Motorboot; nach der Rückfahrt fragen: ¿A qué hora regresa?", nEn: "lancha = motorboat; ask about the return: ¿A qué hora regresa?" },
    co14: { e: "¿Cuánto vale una limonada de coco?", d: "Was kostet eine Kokoslimonade?", dEn: "How much is a coconut lemonade?", s: "An einem Strandstand oder in einem Café der Altstadt.", sEn: "At a beach stand or a café in the old town.", n: "limonada de coco = cremiger Küsten-Klassiker; vale = kostet (wie cuesta).", nEn: "limonada de coco = creamy coastal classic; vale = costs (like cuesta)." },
    co15: { e: "Hace mucho calor, necesito agua, por favor.", d: "Es ist sehr heiß, ich brauche Wasser, bitte.", dEn: "It's very hot, I need water, please.", s: "Mittags in Cartagena oder an der Karibikküste.", sEn: "At midday in Cartagena or on the Caribbean coast.", n: "Immer Wasser dabei haben; una botella de agua bien fría wirkt Wunder.", nEn: "Always carry water; una botella de agua bien fría works wonders." },
    co16: { e: "¿Venden bloqueador solar aquí?", d: "Verkaufen Sie hier Sonnencreme?", dEn: "Do you sell sunscreen here?", s: "Im Laden oder an der Apotheke vor einem Strandtag.", sEn: "At a shop or pharmacy before a beach day.", n: "bloqueador (solar) = Sonnencreme; auch protector solar verständlich.", nEn: "bloqueador (solar) = sunscreen; protector solar is also understood." },
    co17: { e: "¿Podemos visitar el Castillo San Felipe por la mañana?", d: "Können wir die Festung San Felipe vormittags besuchen?", dEn: "Can we visit the San Felipe fortress in the morning?", s: "Bei der Tagesplanung mit Guide oder Reisegruppe.", sEn: "When planning the day with a guide or travel group.", n: "Castillo San Felipe = Cartagenas große Festung; morgens ist es kühler.", nEn: "Castillo San Felipe = Cartagena's big fortress; mornings are cooler." },
    co18: { e: "Una palenquera vende fruta en la plaza.", d: "Eine Palenquera verkauft Obst auf dem Platz.", dEn: "A palenquera is selling fruit in the square.", s: "In der Altstadt, wo die Frauen in bunten Kleidern Obst anbieten.", sEn: "In the old town, where women in colourful dresses sell fruit.", n: "Vor einem Foto fragen: ¿Le puedo tomar una foto? – meist gegen ein Trinkgeld.", nEn: "Ask before a photo: ¿Le puedo tomar una foto? – usually for a small tip." },
    co19: { e: "¿Cómo llego al metro desde aquí?", d: "Wie komme ich von hier zur Metro?", dEn: "How do I get to the metro from here?", s: "In Medellín, der einzigen Stadt Kolumbiens mit Metro.", sEn: "In Medellín, the only city in Colombia with a metro.", n: "Die Medellín-Metro ist sauber und günstig; mit ihr fährst du fast überall hin.", nEn: "The Medellín metro is clean and cheap; it gets you almost everywhere." },
    co20: { e: "¿Este metrocable va a la Comuna 13?", d: "Fährt diese Seilbahn zur Comuna 13?", dEn: "Does this cable car go to Comuna 13?", s: "An einer Metro-Station, wenn du die berühmte Comuna 13 sehen willst.", sEn: "At a metro station, when you want to see the famous Comuna 13.", n: "metrocable = Seilbahn als Teil des Nahverkehrs; spektakulärer Blick über die Stadt.", nEn: "metrocable = cable car that's part of public transit; great views over the city." },
    co21: { e: "¿Me recomiendas Guatapé para un día?", d: "Empfiehlst du mir Guatapé für einen Tag?", dEn: "Do you recommend Guatapé for a day?", s: "Wenn du einen Tagesausflug aus Medellín planst.", sEn: "When planning a day trip out of Medellín.", n: "Guatapé = bunter Ort mit dem Felsen El Peñol; gut als Tagestour.", nEn: "Guatapé = colourful town with the El Peñol rock; great as a day tour." },
    co22: { e: "¿Bien o qué, parce?", d: "Alles klar, Kumpel?", dEn: "All good, mate?", s: "Lockere Begrüßung unter jungen Leuten in Medellín.", sEn: "A casual greeting among young people in Medellín.", n: "parce/parcero = Kumpel (paisa-Slang); ¿bien o qué? = na, wie läuft's?", nEn: "parce/parcero = mate (paisa slang); ¿bien o qué? = hey, how's it going?" },
    co23: { e: "¡Qué nota ese mirador!", d: "Was für ein toller Aussichtspunkt!", dEn: "What a great viewpoint!", s: "Wenn dir etwas richtig gut gefällt.", sEn: "When you really like something.", n: "¡qué nota! / ¡qué bacano! = wie cool!; sehr kolumbianisch.", nEn: "¡qué nota! / ¡qué bacano! = how cool!; very Colombian." },
    co24: { e: "Medellín es la ciudad de la eterna primavera.", d: "Medellín ist die Stadt des ewigen Frühlings.", dEn: "Medellín is the city of eternal spring.", s: "Smalltalk über das milde Klima von Medellín.", sEn: "Small talk about Medellín's mild climate.", n: "eterna primavera = ewiger Frühling; angenehm das ganze Jahr, daher der Beiname.", nEn: "eterna primavera = eternal spring; pleasant all year, hence the nickname." },
    co25: { e: "Aquí hace frío, necesito una chaqueta.", d: "Hier ist es kalt, ich brauche eine Jacke.", dEn: "It's cold here, I need a jacket.", s: "Im hochgelegenen, kühlen Bogotá (rund 2.600 m).", sEn: "In high, chilly Bogotá (around 2,600 m).", n: "Bogotá ist deutlich kühler als die Küste; abends wird es richtig frisch.", nEn: "Bogotá is much cooler than the coast; evenings get really fresh." },
    co26: { e: "Me siento un poco mareado por la altura.", d: "Mir ist von der Höhe etwas schwindelig.", dEn: "I feel a bit dizzy from the altitude.", s: "In Bogotá oder den Anden, wenn dir die Höhe zusetzt.", sEn: "In Bogotá or the Andes, when the altitude affects you.", n: "mareado = schwindelig; viel Wasser trinken und langsam machen hilft.", nEn: "mareado = dizzy; drink plenty of water and take it slow." },
    co27: { e: "¿Cómo subo a Monserrate, en funicular o teleférico?", d: "Wie komme ich nach Monserrate hinauf, mit Standseilbahn oder Seilbahn?", dEn: "How do I get up to Monserrate, by funicular or cable car?", s: "Am Fuß des Hausbergs von Bogotá.", sEn: "At the foot of Bogotá's landmark hill.", n: "Monserrate = Aussichtsberg über Bogotá; funicular und teleférico fahren hinauf.", nEn: "Monserrate = lookout hill above Bogotá; a funicular and cable car go up." },
    co28: { e: "Quiero probar un ajiaco bien caliente.", d: "Ich möchte einen schön heißen Ajiaco probieren.", dEn: "I'd like to try a nice hot ajiaco.", s: "In einem Restaurant in Bogotá.", sEn: "At a restaurant in Bogotá.", n: "ajiaco = typische Hühner-Kartoffel-Suppe aus Bogotá, mit Mais und Kapern.", nEn: "ajiaco = classic Bogotá chicken-and-potato soup with corn and capers." },
    co29: { e: "¿Por dónde queda La Candelaria?", d: "Wo geht es zum Viertel La Candelaria?", dEn: "Which way to the La Candelaria district?", s: "Im Zentrum von Bogotá auf dem Weg zur Altstadt.", sEn: "In central Bogotá on the way to the old town.", n: "La Candelaria = historisches Altstadtviertel; queda = liegt/befindet sich.", nEn: "La Candelaria = historic old-town district; queda = is located." },
    co30: { e: "¿Este TransMilenio va al centro?", d: "Fährt dieser TransMilenio zum Zentrum?", dEn: "Does this TransMilenio go to the centre?", s: "An einer Bus-Station des Schnellbussystems von Bogotá.", sEn: "At a station of Bogotá's rapid bus system.", n: "TransMilenio = Schnellbus in eigenen Spuren; zur Rushhour sehr voll.", nEn: "TransMilenio = rapid bus in dedicated lanes; very crowded at rush hour." },
    co31: { e: "¿A qué hora sale el bus a Santa Marta?", d: "Wann fährt der Bus nach Santa Marta?", dEn: "When does the bus to Santa Marta leave?", s: "Am Busterminal von Cartagena Richtung Karibikküste.", sEn: "At Cartagena's bus terminal heading along the Caribbean coast.", n: "Santa Marta = Tor zum Tayrona-Park; die Fahrt dauert mehrere Stunden.", nEn: "Santa Marta = gateway to Tayrona park; the ride takes several hours." },
    co32: { e: "¿Cuánto cuesta la entrada al parque Tayrona?", d: "Wie viel kostet der Eintritt zum Tayrona-Park?", dEn: "How much is entry to Tayrona park?", s: "Am Eingang des Nationalparks Tayrona.", sEn: "At the entrance to Tayrona National Park.", n: "entrada = Eintritt; Ausländer zahlen mehr, Ausweis bereithalten.", nEn: "entrada = entry; foreigners pay more, keep your ID ready." },
    co33: { e: "¿Puedo alquilar una hamaca para dormir?", d: "Kann ich eine Hängematte zum Schlafen mieten?", dEn: "Can I rent a hammock to sleep in?", s: "Im Tayrona-Park, wo man in Hängematten übernachtet.", sEn: "In Tayrona park, where you sleep in hammocks.", n: "hamaca = Hängematte; alquilar = mieten; frühzeitig sichern, sie sind begehrt.", nEn: "hamaca = hammock; alquilar = to rent; grab one early, they're popular." },
    co34: { e: "¿Vale la pena ir a Minca por dos días?", d: "Lohnt es sich, für zwei Tage nach Minca zu fahren?", dEn: "Is it worth going to Minca for two days?", s: "Beim Planen mit anderen Reisenden im Hostel.", sEn: "When planning with other travellers at the hostel.", n: "vale la pena = es lohnt sich; Minca = grünes Bergdorf mit Wasserfällen und Kaffee.", nEn: "vale la pena = it's worth it; Minca = green mountain village with waterfalls and coffee." },
    co35: { e: "En Palomino se puede flotar en el río en una llanta.", d: "In Palomino kann man auf einem Reifen den Fluss hinunter treiben.", dEn: "In Palomino you can float down the river on a tube.", s: "Beim Tipps-Austausch über das Strand- und Flussdorf Palomino.", sEn: "When swapping tips about the beach-and-river village of Palomino.", n: "flotar = treiben; llanta = (Auto-)Reifen als Schwimmreifen; tubing-Klassiker.", nEn: "flotar = to float; llanta = a tyre used as a tube; a tubing classic." },
    co36: { e: "¿Qué plato típico me recomienda?", d: "Welches typische Gericht empfehlen Sie mir?", dEn: "Which typical dish do you recommend?", s: "Im Restaurant, wenn du regionale Spezialitäten probieren willst.", sEn: "At a restaurant, when you want to try regional specialities.", n: "plato típico = typisches Gericht; in Kolumbien je nach Region ganz unterschiedlich.", nEn: "plato típico = typical dish; varies a lot by region in Colombia." },
    co37: { e: "Una arepa con queso, por favor.", d: "Eine Arepa mit Käse, bitte.", dEn: "An arepa with cheese, please.", s: "Am Frühstücksstand oder beim Streetfood.", sEn: "At a breakfast stand or with street food.", n: "arepa = gegrillter Maisfladen; an der Küste oft arepa de huevo (mit Ei).", nEn: "arepa = grilled corn flatbread; on the coast often arepa de huevo (with egg)." },
    co38: { e: "Quiero el menú del día, ¿qué incluye?", d: "Ich nehme das Tagesmenü, was ist dabei?", dEn: "I'll have the menu of the day, what's included?", s: "Mittags in einem einfachen Lokal.", sEn: "At lunchtime in a simple eatery.", n: "menú del día / corrientazo = günstiges Mittagsmenü mit Suppe, Hauptgang und Saft.", nEn: "menú del día / corrientazo = cheap set lunch with soup, main and juice." },
    co39: { e: "¿Qué lleva una bandeja paisa?", d: "Was ist in einer Bandeja Paisa?", dEn: "What's in a bandeja paisa?", s: "In Medellín oder der Kaffeezone, vor dem Bestellen.", sEn: "In Medellín or the coffee region, before ordering.", n: "bandeja paisa = riesiger Teller mit Bohnen, Reis, Fleisch, Ei, Kochbanane und mehr.", nEn: "bandeja paisa = huge platter with beans, rice, meat, egg, plantain and more." },
    co40: { e: "Un tinto, por favor.", d: "Einen schwarzen Kaffee, bitte.", dEn: "A black coffee, please.", s: "Im Café oder beim Straßenverkäufer mit Thermoskanne.", sEn: "At a café or from a street vendor with a thermos.", n: "tinto = kleiner schwarzer Kaffee (in Kolumbien, nicht Rotwein!).", nEn: "tinto = small black coffee (in Colombia, not red wine!)." },
    co41: { e: "¿El jugo lo quiere en agua o en leche?", d: "Möchten Sie den Saft mit Wasser oder mit Milch?", dEn: "Do you want the juice with water or with milk?", s: "Beim Bestellen eines frischen Safts – die typische Rückfrage.", sEn: "When ordering a fresh juice – the typical follow-up question.", n: "In Kolumbien wird Saft oft mit Milch gemixt; en agua = mit Wasser, en leche = mit Milch.", nEn: "In Colombia juice is often blended with milk; en agua = with water, en leche = with milk." },
    co42: { e: "Un jugo natural de mango, por favor.", d: "Einen frischen Mangosaft, bitte.", dEn: "A fresh mango juice, please.", s: "Im Café, am Saftstand oder beim Frühstück.", sEn: "At a café, juice stand or breakfast.", n: "jugo natural = frisch gepresster Saft; probier lulo, maracuyá oder guanábana.", nEn: "jugo natural = freshly made juice; try lulo, maracuyá or guanábana." },
    co43: { e: "¿Me regala una cerveza bien fría?", d: "Könnte ich ein schön kaltes Bier haben?", dEn: "Could I have a nice cold beer?", s: "In Bar, Restaurant oder am Kiosk (tienda).", sEn: "At a bar, restaurant or corner shop (tienda).", n: "regalar = höfliches 'geben/reichen' in Kolumbien; ¿Me regala…? klingt freundlich.", nEn: "regalar = a polite 'to give/hand' in Colombia; ¿Me regala…? sounds friendly." },
    co44: { e: "¿El aguardiente es muy fuerte?", d: "Ist der Aguardiente sehr stark?", dEn: "Is the aguardiente very strong?", s: "Abends beim Ausgehen, wenn die Flasche kreist.", sEn: "On a night out, when the bottle goes round.", n: "aguardiente (Spitzname guaro) = Anis-Schnaps, Kolumbiens Party-Klassiker.", nEn: "aguardiente (nicknamed guaro) = anise liquor, Colombia's party classic." },
    co45: { e: "Quiero un patacón con guacamole.", d: "Ich hätte gern einen Patacón mit Guacamole.", dEn: "I'd like a patacón with guacamole.", s: "Als Beilage oder Snack zum Essen.", sEn: "As a side or snack with your meal.", n: "patacón = platt gedrückte, frittierte grüne Kochbanane; herzhaft, nicht süß.", nEn: "patacón = flattened, fried green plantain; savoury, not sweet." },
    co46: { e: "¿Hay algo vegetariano en la carta?", d: "Gibt es etwas Vegetarisches auf der Karte?", dEn: "Is there anything vegetarian on the menu?", s: "Im Restaurant, wenn du kein Fleisch isst.", sEn: "At a restaurant, when you don't eat meat.", n: "Ergänze sin carne (ohne Fleisch); vegan ist seltener, frag nach sin queso/huevo.", nEn: "Add sin carne (no meat); vegan is rarer, ask for sin queso/huevo." },
    co47: { e: "¿A cómo está la libra de mango?", d: "Was kostet das Pfund Mango?", dEn: "How much is a pound of mango?", s: "Am Obst- oder Marktstand, wo nach Gewicht verkauft wird.", sEn: "At a fruit or market stall that sells by weight.", n: "a cómo está = umgangssprachlich 'was kostet'; la libra = das Pfund (≈ 500 g).", nEn: "a cómo está = casual 'how much is'; la libra = the pound (≈ 500 g)." },
    co48: { e: "¿Aceptan tarjeta o solo efectivo?", d: "Akzeptieren Sie Karte oder nur bar?", dEn: "Do you accept card or only cash?", s: "Vor dem Bezahlen in kleineren Lokalen oder Läden.", sEn: "Before paying at smaller eateries or shops.", n: "Auf Märkten und in kleinen tiendas oft nur efectivo (Bargeld).", nEn: "At markets and small tiendas it's often efectivo (cash) only." },
    co49: { e: "¿Hay un cajero cerca de aquí?", d: "Gibt es einen Geldautomaten in der Nähe?", dEn: "Is there an ATM near here?", s: "Wenn dir das Bargeld ausgeht.", sEn: "When you're running out of cash.", n: "cajero (automático) = Geldautomat; tagsüber und an belebten Orten abheben.", nEn: "cajero (automático) = ATM; withdraw by day and in busy places." },
    co50: { e: "¿Me da el vuelto, por favor?", d: "Bekomme ich bitte mein Wechselgeld?", dEn: "Can you give me the change, please?", s: "Nach dem Bezahlen mit einem großen Schein.", sEn: "After paying with a big note.", n: "vuelto = Wechselgeld (in Kolumbien); kleine Scheine helfen, Streit zu vermeiden.", nEn: "vuelto = change (in Colombia); small notes help avoid hassle." },
    co51: { e: "¿El servicio ya está incluido en la cuenta?", d: "Ist die Bedienung schon in der Rechnung enthalten?", dEn: "Is the service charge already included in the bill?", s: "Beim Bezahlen im Restaurant.", sEn: "When paying at a restaurant.", n: "Oft kommen 10% propina voluntaria dazu; du darfst Nein sagen, wenn du willst.", nEn: "Often a 10% propina voluntaria is added; you may decline if you wish." },
    co52: { e: "¿Esta buseta va al centro?", d: "Fährt diese Buseta zum Zentrum?", dEn: "Does this little bus go to the centre?", s: "An der Straße, bevor du in den Kleinbus einsteigst.", sEn: "At the roadside, before getting on the minibus.", n: "buseta = Kleinbus; Ziel steht oft auf einem Schild in der Frontscheibe.", nEn: "buseta = minibus; the destination is often on a sign in the windscreen." },
    co53: { e: "¿El bus para cerca del centro histórico?", d: "Hält der Bus in der Nähe der Altstadt?", dEn: "Does the bus stop near the old town?", s: "Beim Einsteigen, um die richtige Ausstiegsstelle zu klären.", sEn: "When boarding, to work out the right stop.", n: "parar = (an)halten; sag Bescheid: ¡En la próxima, por favor! (an der nächsten).", nEn: "parar = to stop; speak up: ¡En la próxima, por favor! (at the next one)." },
    co54: { e: "¿Me deja más adelante, por favor?", d: "Können Sie mich etwas weiter vorne rauslassen?", dEn: "Can you let me off a bit further on, please?", s: "Im Bus oder colectivo kurz vor deinem Ziel.", sEn: "On the bus or colectivo just before your stop.", n: "más adelante = weiter vorn; im Bus oft auch: ¡Pare, por favor! (Halt, bitte!).", nEn: "más adelante = further ahead; on the bus also: ¡Pare, por favor! (Stop, please!)." },
    co55: { e: "¿Hay mototaxi para acá?", d: "Gibt es ein Moto-Taxi hierher?", dEn: "Is there a moto-taxi to here?", s: "In kleineren Orten und Dörfern, wo Mototaxis üblich sind.", sEn: "In smaller towns and villages where moto-taxis are common.", n: "mototaxi = Motorrad-Taxi; günstig und schnell, aber frag nach einem Helm (casco).", nEn: "mototaxi = motorbike taxi; cheap and fast, but ask for a helmet (casco)." },
    co56: { e: "Vamos en chiva a la fiesta esta noche.", d: "Lass uns heute Abend mit einer Chiva zur Party fahren.", dEn: "Let's take a chiva to the party tonight.", s: "Bei einer Gruppen-Partytour mit Musik.", sEn: "On a group party tour with music.", n: "chiva = bunt bemalter Holzbus mit Live-Musik; rollende Party (chiva rumbera).", nEn: "chiva = brightly painted wooden bus with live music; a rolling party (chiva rumbera)." },
    co57: { e: "¿Quiubo? ¿Qué más?", d: "Hallo, wie läuft's?", dEn: "Hi, how's it going?", s: "Lockere Begrüßung unter Freunden und Bekannten.", sEn: "A casual greeting among friends and acquaintances.", n: "¿Quiubo? (von ¿qué hubo?) und ¿qué más? sind sehr kolumbianische 'Na?'-Floskeln.", nEn: "¿Quiubo? (from ¿qué hubo?) and ¿qué más? are very Colombian ways to say 'hey'." },
    co58: { e: "Todo bien, gracias, ¿y tú?", d: "Alles gut, danke, und dir?", dEn: "All good, thanks, and you?", s: "Antwort auf eine Begrüßung.", sEn: "A reply to a greeting.", n: "Einfache, immer passende Antwort; die Rückfrage ¿y tú? hält das Gespräch in Gang.", nEn: "A simple, always-fitting reply; the follow-up ¿y tú? keeps the chat going." },
    co59: { e: "¡Qué bacano este lugar!", d: "Dieser Ort ist echt super!", dEn: "This place is awesome!", s: "Wenn dir ein Ort, eine Sache oder ein Plan gefällt.", sEn: "When you like a place, thing or plan.", n: "bacano = cool/super (Kolumbien); Synonyme: chévere, nota, una nota.", nEn: "bacano = cool/great (Colombia); synonyms: chévere, nota, una nota." },
    co60: { e: "¡Qué pena con usted!", d: "Wie peinlich! / Entschuldigung!", dEn: "How embarrassing! / Excuse me!", s: "Wenn dir etwas unangenehm ist oder du dich entschuldigst.", sEn: "When you feel awkward or want to apologise.", n: "In Kolumbien heißt ¡qué pena! oft 'wie peinlich' / 'Entschuldigung', nicht nur 'wie schade'.", nEn: "In Colombia ¡qué pena! often means 'how embarrassing' / 'sorry', not just 'what a shame'." },
    co61: { e: "—Gracias. —A la orden.", d: "—Danke. —Gern geschehen.", dEn: "—Thanks. —You're welcome.", s: "Im Laden, Taxi oder Restaurant als höfliche Floskel.", sEn: "At a shop, taxi or restaurant as a polite phrase.", n: "a la orden = gern geschehen / zu Diensten; auch als 'Was darf's sein?' beim Anbieten.", nEn: "a la orden = you're welcome / at your service; also 'how can I help?' when offering." },
    co62: { e: "Listo, nos vemos a las ocho.", d: "Alles klar, wir sehen uns um acht.", dEn: "Okay, see you at eight.", s: "Um eine Verabredung oder Abmachung zu bestätigen.", sEn: "To confirm a plan or arrangement.", n: "listo = okay/abgemacht; eines der häufigsten Wörter im kolumbianischen Alltag.", nEn: "listo = okay/done; one of the most common words in everyday Colombian speech." },
    co63: { e: "¿Vamos a la playa? ¡De una!", d: "Gehen wir an den Strand? Auf jeden Fall!", dEn: "Shall we go to the beach? Definitely!", s: "Spontane, begeisterte Zusage zu einem Plan.", sEn: "A spontaneous, enthusiastic yes to a plan.", n: "de una = sofort/auf jeden Fall; zeigt Lust und Tempo.", nEn: "de una = right away/for sure; shows you're keen." },
    co64: { e: "¿Hacemos un parche esta noche?", d: "Treffen wir uns heute Abend?", dEn: "Shall we hang out tonight?", s: "Um andere Reisende oder Locals zu einem Plan einzuladen.", sEn: "To invite other travellers or locals to a plan.", n: "parche = Treffen/Clique/Plan; hacer un parche = was zusammen unternehmen.", nEn: "parche = hangout/crew/plan; hacer un parche = to do something together." },
    co65: { e: "¡Vamos a bailar salsa!", d: "Lass uns Salsa tanzen gehen!", dEn: "Let's go dancing salsa!", s: "Abends, wenn die Gruppe ausgehen will.", sEn: "In the evening, when the group wants to go out.", n: "bailar = tanzen; in Cali ist Salsa Pflicht, an der Küste eher champeta.", nEn: "bailar = to dance; in Cali salsa is a must, on the coast it's more champeta." },
    co66: { e: "¿Me enseñas a bailar salsa?", d: "Bringst du mir Salsa bei?", dEn: "Will you teach me to dance salsa?", s: "Auf der Tanzfläche oder bei einem Tanzkurs.", sEn: "On the dance floor or at a dance class.", n: "enseñar = beibringen; ein super Eisbrecher: No sé bailar, ¿me enseñas?", nEn: "enseñar = to teach; a great icebreaker: No sé bailar, ¿me enseñas?" },
    co67: { e: "Una fría, por favor.", d: "Ein kaltes Bier, bitte.", dEn: "A cold one, please.", s: "In der Bar, am Strand oder im Club.", sEn: "At the bar, on the beach or in the club.", n: "una fría = ein kaltes Bier; gängige Marken sind Águila, Poker und Club Colombia.", nEn: "una fría = a cold beer; common brands are Águila, Poker and Club Colombia." },
    co68: { e: "Esta noche hay champeta y salsa en la plaza.", d: "Heute Abend gibt es Champeta und Salsa auf dem Platz.", dEn: "Tonight there's champeta and salsa in the square.", s: "Beim Planen des Abends an der Karibikküste.", sEn: "When planning the evening on the Caribbean coast.", n: "champeta = energiegeladene Musik und Tanz aus Cartagena.", nEn: "champeta = high-energy music and dance from Cartagena." },
    co69: { e: "¿Dónde se puede rumbear bien por aquí?", d: "Wo kann man hier gut feiern?", dEn: "Where's a good place to party around here?", s: "Wenn du nach dem besten Ausgehviertel fragst.", sEn: "When asking for the best nightlife area.", n: "rumbear = feiern gehen; la rumba = die Partynacht.", nEn: "rumbear = to go out partying; la rumba = the night out." },
    co70: { e: "¡Tomémonos una foto todos juntos!", d: "Lass uns alle zusammen ein Foto machen!", dEn: "Let's all take a photo together!", s: "Mit der Reisegruppe an einem schönen Ort.", sEn: "With the travel group at a nice spot.", n: "tomarse una foto = ein Foto von sich machen; foto grupal = Gruppenfoto.", nEn: "tomarse una foto = to take a photo of yourselves; foto grupal = group photo." },
    co71: { e: "¿Es seguro caminar aquí de noche?", d: "Ist es sicher, hier nachts zu laufen?", dEn: "Is it safe to walk here at night?", s: "Bevor du abends allein durch ein Viertel gehst.", sEn: "Before walking through a neighbourhood alone at night.", n: "seguro = sicher; im Zweifel ein Taxi/App nehmen – 'no dar papaya' (kein Risiko bieten).", nEn: "seguro = safe; if unsure take a taxi/app – 'no dar papaya' (don't invite trouble)." },
    co72: { e: "¿Me recomienda un buen barrio para quedarme?", d: "Können Sie mir ein gutes Viertel zum Übernachten empfehlen?", dEn: "Can you recommend a good neighbourhood to stay in?", s: "An der Rezeption oder bei Locals zur Orientierung.", sEn: "At reception or with locals to get your bearings.", n: "barrio = Stadtviertel; in Medellín ist El Poblado/Laureles bei Reisenden beliebt.", nEn: "barrio = neighbourhood; in Medellín, El Poblado/Laureles is popular with travellers." },
    co73: { e: "¿Hay algún festival en la ciudad esta semana?", d: "Gibt es diese Woche ein Fest in der Stadt?", dEn: "Is there a festival in town this week?", s: "Wenn du wissen willst, was gerade los ist.", sEn: "When you want to know what's on.", n: "festival/feria = Fest; Kolumbien feiert viel – frag ruhig nach Terminen.", nEn: "festival/feria = festival; Colombia loves to celebrate – just ask what's coming up." },
    co74: { e: "¿Cuánto dura el viaje a Cali en bus?", d: "Wie lange dauert die Busfahrt nach Cali?", dEn: "How long is the bus trip to Cali?", s: "Bei der Routenplanung zur Salsa-Hauptstadt.", sEn: "When planning your route to the salsa capital.", n: "durar = dauern; Cali gilt als Welthauptstadt der Salsa.", nEn: "durar = to last; Cali is known as the world capital of salsa." },
    co75: { e: "¡Me encanta Colombia, la gente es muy amable!", d: "Ich liebe Kolumbien, die Menschen sind sehr freundlich!", dEn: "I love Colombia, the people are so friendly!", s: "Ein herzliches Kompliment im Gespräch mit Locals.", sEn: "A warm compliment when chatting with locals.", n: "me encanta = ich liebe/mag sehr; kommt überall gut an.", nEn: "me encanta = I love it; always goes down well." },

    // ----- Kaffeeregion: Salento · Valle del Cocora · Kaffee-Finca -----
    co76: { e: "¿Cómo llego a Salento desde la terminal?", d: "Wie komme ich von der Busstation nach Salento?", dEn: "How do I get to Salento from the bus terminal?", s: "Bei der Ankunft in der Kaffeezone (Quindío).", sEn: "When arriving in the coffee zone (Quindío).", n: "Salento ist der bunte Ausgangsort fürs Valle del Cocora.", nEn: "Salento is the colourful base town for the Cocora Valley." },
    co77: { e: "¿De dónde sale el Willys al Valle del Cocora?", d: "Von wo fährt der Jeep zum Valle del Cocora ab?", dEn: "Where does the jeep to the Cocora Valley leave from?", s: "Morgens am Hauptplatz von Salento.", sEn: "In the morning on Salento's main square.", n: "Willys = die alten Jeeps; man fährt oft hinten stehend mit.", nEn: "Willys = the old jeeps; you often ride standing on the back." },
    co78: { e: "Quiero ver las palmas de cera más altas del mundo.", d: "Ich möchte die höchsten Wachspalmen der Welt sehen.", dEn: "I want to see the tallest wax palms in the world.", s: "Auf der Wanderung durchs Valle del Cocora.", sEn: "On the hike through the Cocora Valley.", n: "Die palma de cera ist Kolumbiens Nationalbaum – bis 60 m hoch.", nEn: "The palma de cera is Colombia's national tree – up to 60 m tall." },
    co79: { e: "¿Cuánto dura la caminata hasta el mirador?", d: "Wie lange dauert die Wanderung bis zum Aussichtspunkt?", dEn: "How long is the hike up to the viewpoint?", s: "Vor dem Start am Eingang des Tals.", sEn: "Before setting off at the valley entrance.", n: "Die volle Runde dauert oft 5–6 Stunden – früh starten.", nEn: "The full loop often takes 5–6 hours – start early." },
    co80: { e: "¿Hacen un tour de café en la finca?", d: "Macht ihr eine Kaffeetour auf der Finca?", dEn: "Do you run a coffee tour on the farm?", s: "Auf einer Kaffeefinca rund um Salento.", sEn: "At a coffee farm around Salento.", n: "Viele fincas zeigen den Weg von der Bohne zur Tasse.", nEn: "Many fincas show the journey from bean to cup." },
    co81: { e: "¿Podemos recoger el café nosotros mismos?", d: "Können wir den Kaffee selbst pflücken?", dEn: "Can we pick the coffee ourselves?", s: "Während der Führung über die Plantage.", sEn: "During the tour across the plantation.", n: "Nur die reifen roten Kirschen werden gepflückt – las cerezas rojas.", nEn: "Only the ripe red cherries are picked – las cerezas rojas." },
    co82: { e: "¿Cómo se tuesta el café aquí?", d: "Wie wird der Kaffee hier geröstet?", dEn: "How is the coffee roasted here?", s: "Beim Rösten-/Verkostungsteil der Tour.", sEn: "During the roasting/tasting part of the tour.", n: "tostar = rösten; suave/medio/fuerte beschreibt die Röstung.", nEn: "tostar = to roast; suave/medio/fuerte describe the roast." },
    co83: { e: "Quiero un café suave, por favor.", d: "Ich hätte gern einen milden Kaffee, bitte.", dEn: "I'd like a mild coffee, please.", s: "Bei der Verkostung oder im Café der Finca.", sEn: "At the tasting or in the farm's café.", n: "suave = mild, fuerte = stark; Einheimische trinken ihn oft süß.", nEn: "suave = mild, fuerte = strong; locals often drink it sweet." },
    co84: { e: "¿Cuánto cuesta la cata de café?", d: "Was kostet die Kaffeeverkostung?", dEn: "How much is the coffee tasting?", s: "Beim Buchen der Tour an der Finca.", sEn: "When booking the tour at the farm.", n: "cata = Verkostung; oft im Tourpreis schon enthalten.", nEn: "cata = tasting; often already included in the tour price." },
    co85: { e: "¿Dónde hay un buen mirador por aquí?", d: "Wo gibt es hier einen guten Aussichtspunkt?", dEn: "Where's a good viewpoint around here?", s: "In Salento oder oben im Cocora-Tal.", sEn: "In Salento or up in the Cocora valley.", n: "Der Mirador de Salento über der Calle Real ist ein Klassiker.", nEn: "The Mirador de Salento above Calle Real is a classic." },
    co86: { e: "¿Se pueden ver colibríes por aquí?", d: "Kann man hier Kolibris sehen?", dEn: "Can you see hummingbirds around here?", s: "An Aussichtspunkten oder Reservaten bei Salento.", sEn: "At viewpoints or reserves near Salento.", n: "colibrí = Kolibri; in den Bergen häufig an Futterstellen.", nEn: "colibrí = hummingbird; common at feeders in the hills." },
    co87: { e: "Una trucha con patacón, por favor.", d: "Eine Forelle mit Kochbanane, bitte.", dEn: "A trout with fried plantain, please.", s: "Beim Mittagessen in Salento.", sEn: "At lunch in Salento.", n: "trucha = Forelle, die Spezialität der Region.", nEn: "trucha = trout, the regional specialty." },
    co88: { e: "¿Vamos a jugar tejo esta noche?", d: "Sollen wir heute Abend Tejo spielen?", dEn: "Shall we play tejo tonight?", s: "Abends in einer Tejo-Bar mit der Gruppe.", sEn: "In the evening at a tejo bar with the group.", n: "tejo = Wurfspiel mit kleinen Schwarzpulver-Zielen, die knallen; Bier inklusive.", nEn: "tejo = a throwing game with little gunpowder targets that bang; beer included." },
    co89: { e: "Este café está delicioso, ¿es de la finca?", d: "Dieser Kaffee ist köstlich, ist er von der Finca?", dEn: "This coffee is delicious, is it from the farm?", s: "Nach dem ersten Schluck bei der Verkostung.", sEn: "After the first sip at the tasting.", n: "Ein einfaches Kompliment, das überall gut ankommt.", nEn: "A simple compliment that always goes down well." },

    // ===================== CARTAGENA (Stadt-Pack) =====================
    cg01: { e: "Buenos días, necesito ir a Getsemaní, por favor.", d: "Guten Tag, ich muss nach Getsemaní, bitte.", dEn: "Good day, I need to get to Getsemaní, please.", s: "Beim Taxi am Flughafen oder Busterminal von Cartagena.", sEn: "In a taxi at Cartagena's airport or bus terminal.", n: "Getsemaní liegt zu Fuß nah am historischen Zentrum – lebendig und voller Streetart.", nEn: "Getsemaní is a short walk from the historic centre – lively and full of street art." },
    cg02: { e: "¿Cuánto cuesta la carrera del aeropuerto al centro?", d: "Wie viel kostet die Fahrt vom Flughafen ins Zentrum?", dEn: "How much is the ride from the airport to the centre?", s: "Bevor du am Flughafen Rafael Núñez ins Taxi steigst.", sEn: "Before you get into a taxi at Rafael Núñez airport.", n: "carrera ist hier die Taxifahrt; frag immer vor dem Einsteigen nach dem Preis.", nEn: "carrera here means the taxi ride; always ask the price before getting in." },
    cg03: { e: "¿Podemos acordar la tarifa antes de salir?", d: "Können wir den Preis vereinbaren, bevor wir losfahren?", dEn: "Can we agree the price before we set off?", s: "Im Taxi ohne Taxameter, gerade bei Touristenstrecken.", sEn: "In a taxi without a meter, especially on tourist routes.", n: "tarifa = Tarif/Preis; ein fester Preis vorab erspart Diskussionen am Ziel.", nEn: "tarifa = fare/price; a fixed price up front avoids arguments at the destination." },
    cg04: { e: "Lléveme a la ciudad amurallada, por favor.", d: "Bringen Sie mich bitte in die Altstadt.", dEn: "Take me to the old town, please.", s: "Wenn du ins historische Zentrum innerhalb der Stadtmauern willst.", sEn: "When you want the historic centre inside the city walls.", n: "ciudad amurallada = die ummauerte Altstadt; jeder Fahrer weiß sofort, was gemeint ist.", nEn: "ciudad amurallada = the walled old town; every driver knows it instantly." },
    cg05: { e: "¿Bocagrande queda lejos de aquí?", d: "Ist Bocagrande weit von hier?", dEn: "Is Bocagrande far from here?", s: "Wenn du Entfernungen einschätzen willst, etwa zum Strandviertel.", sEn: "When sizing up distances, e.g. to the beach district.", n: "quedar wird in Kolumbien oft für „liegen/sich befinden“ benutzt: ¿Dónde queda…?", nEn: "In Colombia quedar is often used for \"to be located\": ¿Dónde queda…?" },
    cg06: { e: "Hola, soy el nuevo estudiante de la escuela.", d: "Hallo, ich bin der neue Schüler an der Sprachschule.", dEn: "Hi, I'm the new student from the language school.", s: "Bei der ersten Begrüßung in der Gastfamilie.", sEn: "When first greeting your host family.", n: "Eine herzliche Vorstellung öffnet Türen; ergänze gern deinen Namen: Me llamo…", nEn: "A warm introduction opens doors; add your name: Me llamo…" },
    cg07: { e: "¿A qué hora es la cena en la casa?", d: "Um wie viel Uhr gibt es zu Hause Abendessen?", dEn: "What time is dinner at the house?", s: "In der Gastfamilie, um den Tagesablauf zu verstehen.", sEn: "In the host family, to understand the daily routine.", n: "An der Küste isst man oft später; nachfragen zeigt Respekt für die Hausregeln.", nEn: "On the coast people often eat late; asking shows respect for house rules." },
    cg08: { e: "¿Puedo usar la lavadora esta semana?", d: "Darf ich diese Woche die Waschmaschine benutzen?", dEn: "May I use the washing machine this week?", s: "Wenn du in der Gastfamilie Wäsche waschen möchtest.", sEn: "When you'd like to do laundry at the host family.", n: "lavadora = Waschmaschine; bei feuchtem Karibikklima trocknet Wäsche draußen schnell.", nEn: "lavadora = washing machine; in the humid Caribbean clothes dry fast outside." },
    cg09: { e: "Perdón, ¿dónde está mi habitación?", d: "Entschuldigung, wo ist mein Zimmer?", dEn: "Excuse me, where's my room?", s: "Am ersten Tag im Homestay oder in der Unterkunft.", sEn: "On the first day at the homestay or accommodation.", n: "habitación = Zimmer; im Hostel sagt man für das Bett eher cama.", nEn: "habitación = room; in a hostel you'd say cama for the bed." },
    cg10: { e: "¿Hay wifi en la casa? ¿Cuál es la clave?", d: "Gibt es WLAN im Haus? Wie lautet das Passwort?", dEn: "Is there wifi in the house? What's the password?", s: "Beim Ankommen in Gastfamilie oder Unterkunft.", sEn: "When arriving at the host family or accommodation.", n: "clave (oder contraseña) = Passwort; wifi spricht man „güi-fi“.", nEn: "clave (or contraseña) = password; wifi is said \"WEE-fee\"." },
    cg11: { e: "Disculpe, ¿dónde está la Plaza de la Trinidad?", d: "Entschuldigung, wo ist die Plaza de la Trinidad?", dEn: "Excuse me, where's the Plaza de la Trinidad?", s: "Wenn du abends den Treffpunkt in Getsemaní suchst.", sEn: "When looking for Getsemaní's evening meeting spot.", n: "An der Plaza de la Trinidad treffen sich abends Einheimische und Reisende.", nEn: "Locals and travellers gather at Plaza de la Trinidad in the evenings." },
    cg12: { e: "¿Este barrio es seguro de noche?", d: "Ist dieses Viertel nachts sicher?", dEn: "Is this neighbourhood safe at night?", s: "Bevor du abends allein losziehst, an der Rezeption oder bei Einheimischen.", sEn: "Before heading out alone at night, at reception or with locals.", n: "barrio = Viertel; ruhig fragen wirkt souverän, nicht ängstlich.", nEn: "barrio = neighbourhood; asking calmly comes across as confident, not anxious." },
    cg13: { e: "¿Dónde está la Torre del Reloj?", d: "Wo ist der Uhrenturm?", dEn: "Where is the clock tower?", s: "Zur Orientierung am Haupteingang der Altstadt.", sEn: "For orientation at the main entrance to the old town.", n: "Die Torre del Reloj ist das gelbe Wahrzeichen und ein guter Treffpunkt.", nEn: "The Torre del Reloj is the yellow landmark and a good meeting point." },
    cg14: { e: "¿Qué barrio me recomienda para salir de noche?", d: "Welches Viertel empfehlen Sie zum abendlichen Ausgehen?", dEn: "Which neighbourhood do you recommend for a night out?", s: "Bei Einheimischen oder im Hostel nach Tipps fragen.", sEn: "Asking locals or hostel staff for tips.", n: "Die häufigste Antwort ist Getsemaní – Bars, Musik und Streetfood.", nEn: "The most common answer is Getsemaní – bars, music and street food." },
    cg15: { e: "Una arepa de huevo, por favor.", d: "Eine Arepa de huevo, bitte.", dEn: "One arepa de huevo, please.", s: "Am Streetfood-Stand oder beim Frühstück.", sEn: "At a street-food stall or for breakfast.", n: "arepa de huevo = frittierte Maistasche mit Ei, ein Klassiker der Karibikküste.", nEn: "arepa de huevo = fried corn pocket with egg, a Caribbean-coast classic." },
    cg16: { e: "¿Cuál es el menú del día?", d: "Was ist das Tagesmenü?", dEn: "What's the menu of the day?", s: "Mittags in einem einfachen Restaurant.", sEn: "At lunchtime in a simple restaurant.", n: "menú del día = günstiges Mittagsmenü, meist Suppe, Hauptgang und Saft.", nEn: "menú del día = cheap set lunch, usually soup, a main and a juice." },
    cg17: { e: "Un jugo de corozo, por favor.", d: "Einen Corozo-Saft, bitte.", dEn: "A corozo juice, please.", s: "An der Saftbude oder im Restaurant bei Hitze.", sEn: "At a juice stand or restaurant in the heat.", n: "corozo ist eine rote Karibikfrucht; probiere auch lulo, maracuyá oder zapote.", nEn: "corozo is a red Caribbean fruit; also try lulo, maracuyá or zapote." },
    cg18: { e: "¿Esto es muy picante?", d: "Ist das sehr scharf?", dEn: "Is this very spicy?", s: "Bevor du beim Essen den ají (Chili) dazugibst.", sEn: "Before adding the ají (chilli) to your food.", n: "An der Küste kommt die Schärfe meist separat als ají – du dosierst selbst.", nEn: "On the coast the heat usually comes separately as ají – you control the dose." },
    cg19: { e: "¿El pescado es fresco hoy?", d: "Ist der Fisch heute frisch?", dEn: "Is the fish fresh today?", s: "Im Strandrestaurant oder an einem Fischstand.", sEn: "At a beach restaurant or fish stall.", n: "pescado frito (frittierter ganzer Fisch mit Kochbanane) ist das typische Küstengericht.", nEn: "pescado frito (whole fried fish with plantain) is the typical coastal dish." },
    cg20: { e: "¡Muy rico, gracias!", d: "Sehr lecker, danke!", dEn: "Very tasty, thanks!", s: "Nach dem Essen als kleines Kompliment.", sEn: "After the meal as a small compliment.", n: "rico heißt an der Küste „lecker“; ein ¡Qué rico! kommt immer gut an.", nEn: "rico means \"tasty\" on the coast; a ¡Qué rico! always goes down well." },
    cg21: { e: "No, gracias, no quiero nada.", d: "Nein danke, ich möchte nichts.", dEn: "No thanks, I don't want anything.", s: "Wenn Strandverkäufer dir etwas anbieten.", sEn: "When beach vendors offer you something.", n: "Freundlich, aber klar; ein ruhiges No, gracias und Blick nach vorn genügt meist.", nEn: "Friendly but clear; a calm No, gracias and looking ahead usually does it." },
    cg22: { e: "¿Cuánto cuesta un tour a las Islas del Rosario?", d: "Wie viel kostet eine Tour zu den Islas del Rosario?", dEn: "How much is a tour to the Islas del Rosario?", s: "Bei einer Agentur in der Altstadt oder am Hafen.", sEn: "At an agency in the old town or at the port.", n: "Die Islas del Rosario sind eine Inselgruppe zum Schnorcheln vor Cartagena.", nEn: "The Islas del Rosario are a group of snorkelling islands off Cartagena." },
    cg23: { e: "¿El almuerzo está incluido en el precio?", d: "Ist das Mittagessen im Preis inbegriffen?", dEn: "Is lunch included in the price?", s: "Bevor du eine Bootstour buchst.", sEn: "Before booking a boat tour.", n: "Frag auch nach dem impuesto portuario (Hafensteuer) – der kommt oft extra dazu.", nEn: "Also ask about the impuesto portuario (port tax) – it's often added on top." },
    cg24: { e: "¿Hay sombra en la playa?", d: "Gibt es Schatten am Strand?", dEn: "Is there shade on the beach?", s: "Wenn du am Strand einen Platz suchst.", sEn: "When looking for a spot on the beach.", n: "sombra = Schatten; bei der Karibikhitze sind Sonnenschirm und Wasser Pflicht.", nEn: "sombra = shade; in the Caribbean heat an umbrella and water are a must." },
    cg25: { e: "¿Me puede recomendar un protector solar?", d: "Können Sie mir ein Sonnenschutzmittel empfehlen?", dEn: "Can you recommend a sunscreen?", s: "In der Apotheke oder im Supermarkt vor dem Strandtag.", sEn: "At the pharmacy or supermarket before a beach day.", n: "protector solar = Sonnencreme; nahe am Äquator schützt ein hoher Faktor.", nEn: "protector solar = sunscreen; near the equator go for a high factor." },
    cg26: { e: "¿A qué hora regresa la lancha?", d: "Um wie viel Uhr fährt das Boot zurück?", dEn: "What time does the boat go back?", s: "Auf der Insel, damit du die Rückfahrt nicht verpasst.", sEn: "On the island, so you don't miss the return.", n: "lancha = Schnellboot; präg dir die Uhrzeit gut ein, es gibt oft nur wenige Fahrten.", nEn: "lancha = speedboat; note the time well, there are often only a few runs." },
    cg27: { e: "¿Me recomienda un sitio para bailar salsa?", d: "Können Sie mir einen Ort zum Salsa-Tanzen empfehlen?", dEn: "Can you recommend a place to dance salsa?", s: "Abends im Hostel oder bei Einheimischen.", sEn: "In the evening at the hostel or with locals.", n: "Das Café Havana in Getsemaní ist der berühmteste Salsa-Klassiker.", nEn: "Café Havana in Getsemaní is the most famous salsa classic." },
    cg28: { e: "No bailo muy bien, ¡pero lo intento!", d: "Ich tanze nicht so gut, aber ich versuche es!", dEn: "I don't dance very well, but I'll try!", s: "Wenn dich jemand zum Tanzen auffordert.", sEn: "When someone invites you to dance.", n: "Mitmachen zählt mehr als Können – Lockerheit kommt überall gut an.", nEn: "Joining in counts more than skill – being easy-going always lands well." },
    cg29: { e: "¿Hay música en vivo esta noche?", d: "Gibt es heute Abend Live-Musik?", dEn: "Is there live music tonight?", s: "An der Bar oder beim Eingang eines Lokals.", sEn: "At the bar or a venue's entrance.", n: "música en vivo = Live-Musik; in Getsemaní spielt fast jeden Abend irgendwo eine Band.", nEn: "música en vivo = live music; in Getsemaní a band plays somewhere most nights." },
    cg30: { e: "¿De dónde sale el bus a Santa Marta?", d: "Von wo fährt der Bus nach Santa Marta?", dEn: "Where does the bus to Santa Marta leave from?", s: "Am Busterminal von Cartagena.", sEn: "At Cartagena's bus terminal.", n: "Santa Marta ist das Tor zum Tayrona-Nationalpark, rund vier Stunden entfernt.", nEn: "Santa Marta is the gateway to Tayrona National Park, about four hours away." },
    cg31: { e: "¿Cuánto dura el viaje al Tayrona?", d: "Wie lange dauert die Fahrt zum Tayrona?", dEn: "How long is the trip to Tayrona?", s: "Bei der Planung eines Tages- oder Übernachtungsausflugs.", sEn: "When planning a day or overnight trip.", n: "Tayrona = Nationalpark mit Dschungel und Karibikstränden; früh starten lohnt sich.", nEn: "Tayrona = national park with jungle and Caribbean beaches; an early start pays off." },
    cg32: { e: "¿Necesito comprar el boleto con anticipación?", d: "Muss ich das Ticket im Voraus kaufen?", dEn: "Do I need to buy the ticket in advance?", s: "Vor beliebten Touren oder Busfahrten in der Hochsaison.", sEn: "Before popular tours or bus rides in high season.", n: "con anticipación = im Voraus; boleto = Ticket (auch pasaje für die Fahrkarte).", nEn: "con anticipación = in advance; boleto = ticket (also pasaje for the fare)." },
    cg33: { e: "¿Cuánto cuesta la entrada al Castillo San Felipe?", d: "Wie viel kostet der Eintritt zum Castillo San Felipe?", dEn: "How much is the entrance to the Castillo San Felipe?", s: "Am Eingang der Festung Castillo San Felipe de Barajas.", sEn: "At the entrance to the Castillo San Felipe de Barajas fortress.", n: "Die Festung ist Cartagenas bekanntestes Wahrzeichen; früh oder spät am Tag ist es kühler.", nEn: "The fortress is Cartagena's most famous landmark; early or late in the day it's cooler." },
    cg34: { e: "¿Aceptan tarjeta o solo efectivo?", d: "Nehmen Sie Karte oder nur Bargeld?", dEn: "Do you take card or only cash?", s: "Vor dem Bezahlen an Ständen, in kleinen Läden oder im Taxi.", sEn: "Before paying at stalls, small shops or in a taxi.", n: "efectivo = Bargeld; an der Küste haben viele Stände kein Kartengerät – Bargeld dabeihaben.", nEn: "efectivo = cash; on the coast many stalls have no card reader – keep cash on you." },

    // ===================== MEDELLÍN (Stadt-Pack) =====================
    md01: { e: "¿Cómo llego del aeropuerto a El Poblado?", d: "Wie komme ich vom Flughafen nach El Poblado?", dEn: "How do I get from the airport to El Poblado?", s: "Direkt nach der Landung am Flughafen José María Córdova.", sEn: "Right after landing at José María Córdova airport.", n: "Der Flughafen liegt ~45 Min außerhalb in Rionegro; Taxi, Colectivo oder Flughafenbus.", nEn: "The airport is ~45 min out of town in Rionegro; taxi, colectivo or airport bus." },
    md02: { e: "¿Cuánto cuesta el taxi del aeropuerto a la ciudad?", d: "Was kostet das Taxi vom Flughafen in die Stadt?", dEn: "How much is the taxi from the airport to the city?", s: "Am Taxistand vor dem Flughafen, vor der Fahrt.", sEn: "At the taxi rank outside the airport, before the ride.", n: "Es gibt einen Festpreis je Zone; der Flughafenbus ist deutlich günstiger.", nEn: "There's a fixed price per zone; the airport bus is much cheaper." },
    md03: { e: "¿Dónde está la estación de metro más cercana?", d: "Wo ist die nächste Metrostation?", dEn: "Where is the nearest metro station?", s: "Wenn du dich in der Stadt fortbewegen willst.", sEn: "When you want to get around the city.", n: "Medellíns Metro ist sauber, sicher und günstig – der Stolz der Paisas.", nEn: "Medellín's metro is clean, safe and cheap – the Paisas' pride." },
    md04: { e: "¿Dónde puedo comprar una tarjeta Cívica?", d: "Wo kann ich eine Cívica-Karte kaufen?", dEn: "Where can I buy a Cívica card?", s: "An einer Metrostation, bevor du häufiger fährst.", sEn: "At a metro station, before you travel often.", n: "Die Cívica gilt für Metro, Metrocable und integrierte Busse – einmal aufladen, überall fahren.", nEn: "The Cívica works on metro, cable car and integrated buses – top up once, ride everywhere." },
    md05: { e: "¿Puedo ir al Parque Arví en metrocable?", d: "Kann ich mit der Metrocable zum Parque Arví fahren?", dEn: "Can I take the cable car to Parque Arví?", s: "Wenn du den Ausflug zum Naturpark planst.", sEn: "When planning the trip to the nature park.", n: "Línea L fährt hoch nach Arví; die Fahrt über die Stadt ist schon das Highlight.", nEn: "Line L climbs to Arví; the ride over the city is a highlight in itself." },
    md06: { e: "¿Hasta qué hora funciona el metro?", d: "Bis wann fährt die Metro?", dEn: "Until what time does the metro run?", s: "Wenn du abends unterwegs bist und zurück willst.", sEn: "When you're out in the evening and need to get back.", n: "Meist bis etwa 23 Uhr (sonntags kürzer) – danach Taxi oder App nehmen.", nEn: "Usually until about 11 pm (shorter on Sundays) – after that take a taxi or app." },
    md07: { e: "Disculpe, ¿dónde está el Parque Lleras?", d: "Entschuldigung, wo ist der Parque Lleras?", dEn: "Excuse me, where is Parque Lleras?", s: "In El Poblado, wenn du das Ausgehviertel suchst.", sEn: "In El Poblado, when looking for the nightlife area.", n: "Parque Lleras = touristisches Bar-/Restaurant-Zentrum; lebhaft, aber auch teurer.", nEn: "Parque Lleras = touristy bar/restaurant hub; lively but also pricier." },
    md08: { e: "¿Laureles es un buen barrio para quedarse?", d: "Ist Laureles ein gutes Viertel zum Bleiben?", dEn: "Is Laureles a good neighbourhood to stay in?", s: "Bei der Suche nach Unterkunft oder einem Wohnviertel.", sEn: "When looking for accommodation or a place to stay.", n: "Laureles ist ruhiger, lokaler und flacher zum Laufen als das hügelige El Poblado.", nEn: "Laureles is quieter, more local and flatter to walk than hilly El Poblado." },
    md09: { e: "¿Cómo llego a la Comuna 13?", d: "Wie komme ich zur Comuna 13?", dEn: "How do I get to Comuna 13?", s: "Beim Planen des Comuna-13-Besuchs.", sEn: "When planning a visit to Comuna 13.", n: "Metro Linie B bis San Javier, dann zu Fuß oder mit den berühmten Rolltreppen.", nEn: "Metro line B to San Javier, then on foot or via the famous escalators." },
    md10: { e: "¿A dónde sale la gente local por la noche?", d: "Wo gehen die Einheimischen abends hin?", dEn: "Where do locals go out at night?", s: "Wenn du Lust auf weniger touristische Orte hast.", sEn: "When you fancy less touristy spots.", n: "Frag nach Laureles oder „La 70“ statt nur Lleras – oft lockerer und günstiger.", nEn: "Ask about Laureles or \"La 70\" instead of just Lleras – often more relaxed and cheaper." },
    md11: { e: "¿Queda lejos a pie?", d: "Ist es weit zu Fuß?", dEn: "Is it far on foot?", s: "Wenn du entscheidest, ob laufen oder fahren.", sEn: "When deciding whether to walk or ride.", n: "quedar wird in Kolumbien für „liegen/sich befinden“ benutzt: ¿Dónde queda…?", nEn: "In Colombia quedar is used for \"to be located\": ¿Dónde queda…?" },
    md12: { e: "¿Aquí de verdad dicen parce a los amigos?", d: "Sagt man hier wirklich „parce“ zu Freunden?", dEn: "Do people here really say \"parce\" to friends?", s: "Im lockeren Gespräch mit Einheimischen.", sEn: "In casual conversation with locals.", n: "parce/parcero = Kumpel; das vielleicht typischste Paisa-Wort überhaupt.", nEn: "parce/parcero = buddy; maybe the most typical Paisa word of all." },
    md13: { e: "¿Bien o qué?", d: "Na, alles gut?", dEn: "Hey, all good?", s: "Als lockere Begrüßung unter jungen Leuten.", sEn: "As a casual greeting among young people.", n: "Sehr paisa; locker und freundlich gemeint, Antwort z. B. „¡Bien, parce!“.", nEn: "Very Paisa; casual and friendly, answer e.g. \"¡Bien, parce!\"." },
    md14: { e: "¿Puede hablar un poco más despacio, por favor?", d: "Können Sie bitte etwas langsamer sprechen?", dEn: "Could you speak a bit more slowly, please?", s: "Wenn der schnelle Paisa-Akzent dich überfordert.", sEn: "When the fast Paisa accent is too much.", n: "Der Paisa-Akzent ist schnell und melodisch; keine Scheu, nachzufragen.", nEn: "The Paisa accent is fast and melodic; don't be shy to ask." },
    md15: { e: "¿Qué significa pues?", d: "Was bedeutet „pues“?", dEn: "What does \"pues\" mean?", s: "Wenn dir das ständige „pues“ auffällt.", sEn: "When you notice the constant \"pues\".", n: "pues ist ein Füllwort; „¡listo, pues!“ heißt etwa „alles klar dann!“.", nEn: "pues is a filler word; \"¡listo, pues!\" means roughly \"all right then!\"." },
    md16: { e: "Una bandeja paisa, por favor.", d: "Eine Bandeja paisa, bitte.", dEn: "One bandeja paisa, please.", s: "Mittags in einem typischen Paisa-Restaurant.", sEn: "At lunch in a typical Paisa restaurant.", n: "Riesiger Teller: Bohnen, Reis, Hackfleisch, chicharrón, Ei, Kochbanane, Avocado, Arepa.", nEn: "Huge platter: beans, rice, mince, chicharrón, egg, plantain, avocado, arepa." },
    md17: { e: "¿Podemos compartir el plato?", d: "Können wir das Gericht teilen?", dEn: "Can we share the dish?", s: "Wenn die Portion sehr groß ist.", sEn: "When the portion is very large.", n: "Eine bandeja paisa reicht oft locker für zwei – fragen lohnt sich.", nEn: "One bandeja paisa often easily feeds two – worth asking." },
    md18: { e: "¿Me regala un tinto, por favor?", d: "Bringen Sie mir bitte einen Tinto?", dEn: "Could you bring me a tinto, please?", s: "Am Café oder beim Straßenverkäufer für den Koffein-Kick.", sEn: "At a café or from a street vendor for a caffeine kick.", n: "regalar heißt hier höflich „bringen/geben“; und Achtung: tinto ist ein kleiner schwarzer Kaffee, NICHT Rotwein.", nEn: "regalar here is a polite \"to bring/give\"; and note: tinto is a small black coffee, NOT red wine." },
    md19: { e: "¿Podemos visitar una finca de café?", d: "Können wir eine Kaffeefinca besuchen?", dEn: "Can we visit a coffee farm?", s: "Beim Planen eines Tagesausflugs aufs Land.", sEn: "When planning a day trip to the countryside.", n: "Das Kaffeedreieck (Eje Cafetero) liegt nicht weit; viele Fincas bieten Touren.", nEn: "The coffee triangle (Eje Cafetero) isn't far; many farms offer tours." },
    md20: { e: "Un jugo natural, por favor.", d: "Einen frischen Saft, bitte.", dEn: "A fresh juice, please.", s: "Im Restaurant oder an der Saftbude.", sEn: "At a restaurant or juice stand.", n: "Probier lokale Früchte: lulo, mango, maracuyá, guanábana – en agua oder en leche.", nEn: "Try local fruits: lulo, mango, maracuyá, guanábana – with water or milk." },
    md21: { e: "¿El agua de la llave aquí es potable?", d: "Ist das Leitungswasser hier trinkbar?", dEn: "Is the tap water here drinkable?", s: "In Unterkunft oder Restaurant, bevor du Leitungswasser trinkst.", sEn: "At your accommodation or restaurant, before drinking tap water.", n: "In Medellín gilt das Leitungswasser allgemein als sicher – ungewöhnlich gut in der Region.", nEn: "In Medellín the tap water is generally considered safe – unusually good for the region." },
    md22: { e: "¿Qué me recomienda típico de aquí?", d: "Was empfehlen Sie typisch von hier?", dEn: "What typical local dish do you recommend?", s: "Wenn du Lokales statt Standard probieren willst.", sEn: "When you want to try local rather than standard food.", n: "Frag nach mondongo (Kuttelsuppe), arepa paisa oder buñuelo zum Frühstück.", nEn: "Ask about mondongo (tripe soup), arepa paisa or buñuelo for breakfast." },
    md23: { e: "¿Cuánto cuesta el tour de grafitis en la Comuna 13?", d: "Was kostet die Graffiti-Tour in der Comuna 13?", dEn: "How much is the graffiti tour in Comuna 13?", s: "Beim Anbieter oder Guide vor Ort.", sEn: "With the operator or guide on site.", n: "Die Comuna 13 erzählt mit Graffiti ihre Wandlung von Gewalt zu Hoffnung – nimm einen lokalen Guide.", nEn: "Comuna 13 tells its shift from violence to hope through street art – take a local guide." },
    md24: { e: "¿Dónde están las escaleras eléctricas?", d: "Wo sind die Rolltreppen?", dEn: "Where are the escalators?", s: "In der Comuna 13 zur Orientierung.", sEn: "In Comuna 13 for orientation.", n: "Die Freiluft-Rolltreppen (escaleras eléctricas) sind das Wahrzeichen des Viertels.", nEn: "The outdoor escalators (escaleras eléctricas) are the district's landmark." },
    md25: { e: "¿De dónde sale el bus a Guatapé?", d: "Von wo fährt der Bus nach Guatapé?", dEn: "Where does the bus to Guatapé leave from?", s: "Am Busterminal beim Planen des Tagesausflugs.", sEn: "At the bus terminal when planning the day trip.", n: "Busse fahren vom Terminal Norte (~2 Std.); Guatapé ist das bunte Seendorf.", nEn: "Buses leave from Terminal Norte (~2 hrs); Guatapé is the colourful lakeside town." },
    md26: { e: "¿Vale la pena subir la piedra del Peñol?", d: "Lohnt es sich, den Felsen El Peñol zu besteigen?", dEn: "Is it worth climbing El Peñol rock?", s: "In Guatapé vor dem Aufstieg.", sEn: "In Guatapé before the climb.", n: "740 Stufen, aber der Rundblick über die Stauseen ist spektakulär – Wasser mitnehmen.", nEn: "740 steps, but the panorama over the reservoirs is spectacular – bring water." },
    md27: { e: "¿Aquí se puede bailar salsa o reguetón?", d: "Kann man hier Salsa oder Reggaetón tanzen?", dEn: "Can you dance salsa or reggaeton here?", s: "An der Bar oder im Club beim Ausgehen.", sEn: "At the bar or club when going out.", n: "Medellín ist heute ein Zentrum des Reggaetón; viele Lokale mischen beides.", nEn: "Medellín is now a hub of reggaeton; many venues mix both." },
    md28: { e: "¿A qué hora suele parar la lluvia?", d: "Wann hört der Regen meist auf?", dEn: "When does the rain usually stop?", s: "Wenn du deinen Nachmittag planst.", sEn: "When planning your afternoon.", n: "„Ewiger Frühling“: mild das ganze Jahr, aber oft kräftiger Nachmittagsregen.", nEn: "\"Eternal spring\": mild all year, but often heavy afternoon rain." },
    md29: { e: "¿Hay buen wifi aquí?", d: "Gibt es hier gutes WLAN?", dEn: "Is there good wifi here?", s: "Im Café, Hostel oder Coworking beim Arbeiten.", sEn: "At a café, hostel or coworking when working.", n: "Medellín ist ein Top-Hub für Digitalnomaden; Café-WLAN ist meist solide.", nEn: "Medellín is a top hub for digital nomads; café wifi is usually solid." },
    md30: { e: "¿Tiene una habitación por un mes?", d: "Haben Sie ein Zimmer für einen Monat?", dEn: "Do you have a room for a month?", s: "Bei längerem Aufenthalt in Hostel oder Apartment.", sEn: "For a longer stay in a hostel or apartment.", n: "Für Langzeit nach einem descuento por mes (Monatsrabatt) fragen.", nEn: "For long stays ask for a descuento por mes (monthly discount)." },
    md31: { e: "¿Hay un coworking cerca de aquí?", d: "Gibt es in der Nähe einen Coworking-Space?", dEn: "Is there a coworking space nearby?", s: "Wenn du zum Arbeiten einen ruhigen Platz suchst.", sEn: "When you need a quiet place to work.", n: "El Poblado und Laureles sind voll von Coworkings und Café-Arbeitsplätzen.", nEn: "El Poblado and Laureles are full of coworkings and café work spots." },
    md32: { e: "¿Qué zonas debo evitar de noche?", d: "Welche Gegenden sollte ich nachts meiden?", dEn: "Which areas should I avoid at night?", s: "Beim Einholen von Sicherheitstipps an der Rezeption.", sEn: "When getting safety tips at reception.", n: "Ruhig und respektvoll fragen; Einheimische geben gern ehrliche Hinweise.", nEn: "Ask calmly and respectfully; locals are happy to give honest advice." },
    md33: { e: "¿Puedo pagar con Nequi?", d: "Kann ich mit Nequi bezahlen?", dEn: "Can I pay with Nequi?", s: "An kleinen Ständen, in Cafés oder beim Verkäufer.", sEn: "At small stalls, in cafés or with a vendor.", n: "Nequi (und Daviplata) sind sehr verbreitete Handy-Bezahl-Apps in Kolumbien.", nEn: "Nequi (and Daviplata) are very common mobile payment apps in Colombia." },
    md34: { e: "¿Qué significa no dar papaya?", d: "Was bedeutet „no dar papaya“?", dEn: "What does \"no dar papaya\" mean?", s: "Wenn dir der Ausdruck im Sicherheitsgespräch begegnet.", sEn: "When the phrase comes up in a safety chat.", n: "„Keine Papaya geben“ = keine Gelegenheit bieten; Wertsachen nicht offen zeigen.", nEn: "\"Don't give papaya\" = don't give an opening; keep valuables out of sight." },

    // ===================== CUSCO (Stadt-Pack) =====================
    cu01: { e: "Acabo de llegar a Cusco.", d: "Ich bin gerade in Cusco angekommen.", dEn: "I've just arrived in Cusco.", s: "Beim ersten Kontakt im Hostel oder mit Einheimischen.", sEn: "On first contact at the hostel or with locals.", n: "acabar de + Infinitiv heißt „gerade eben etwas getan haben“.", nEn: "acabar de + infinitive means \"to have just done something\"." },
    cu02: { e: "¿Cómo llego del aeropuerto a la Plaza de Armas?", d: "Wie komme ich vom Flughafen zur Plaza de Armas?", dEn: "How do I get from the airport to the Plaza de Armas?", s: "Direkt nach der Landung am Flughafen Velasco Astete.", sEn: "Right after landing at Velasco Astete airport.", n: "Der Flughafen liegt mitten in der Stadt – Taxi oder Colectivo sind kurz.", nEn: "The airport is right in the city – taxi or colectivo is a short ride." },
    cu03: { e: "Me siento mal por la altura.", d: "Mir geht es wegen der Höhe nicht gut.", dEn: "I feel unwell because of the altitude.", s: "In den ersten Stunden, wenn dich die Höhe trifft.", sEn: "In the first hours, when the altitude hits you.", n: "soroche = Höhenkrankheit; Cusco liegt auf ~3.400 m, langsam machen.", nEn: "soroche = altitude sickness; Cusco is at ~3,400 m, take it slow." },
    cu04: { e: "Un mate de coca, por favor.", d: "Einen Coca-Tee, bitte.", dEn: "A coca tea, please.", s: "Im Hostel, Café oder Restaurant gegen die Höhe.", sEn: "At the hostel, café or restaurant to ease the altitude.", n: "mate de coca ist überall üblich und hilft vielen gegen soroche.", nEn: "mate de coca is common everywhere and helps many with soroche." },
    cu05: { e: "¿Debería tomarme el primer día con calma?", d: "Sollte ich den ersten Tag ruhig angehen?", dEn: "Should I take the first day easy?", s: "Bei der Planung der ersten Tage in der Höhe.", sEn: "When planning your first days at altitude.", n: "Akklimatisieren: erst langsam, viel Wasser, wenig Alkohol, schwere Touren später.", nEn: "Acclimatise: go slow, drink water, little alcohol, save hard hikes for later." },
    cu06: { e: "¿Dónde puedo comprar pastillas para la altura?", d: "Wo kann ich Tabletten gegen die Höhe kaufen?", dEn: "Where can I buy pills for the altitude?", s: "In der Apotheke, wenn der Coca-Tee nicht reicht.", sEn: "At the pharmacy, if coca tea isn't enough.", n: "In jeder farmacia erhältlich; oft als „sorojchi pills“ verkauft.", nEn: "Available at any farmacia; often sold as \"sorojchi pills\"." },
    cu07: { e: "Disculpe, ¿dónde está la Plaza de Armas?", d: "Entschuldigung, wo ist die Plaza de Armas?", dEn: "Excuse me, where is the Plaza de Armas?", s: "Zur Orientierung im historischen Zentrum.", sEn: "For orientation in the historic centre.", n: "Der zentrale Hauptplatz mit Kathedrale – von hier findest du alles.", nEn: "The central main square with the cathedral – everything radiates from here." },
    cu08: { e: "¿Cómo llego al barrio de San Blas?", d: "Wie komme ich zum Viertel San Blas?", dEn: "How do I get to the San Blas neighbourhood?", s: "Wenn du das Künstlerviertel besuchen willst.", sEn: "When you want to visit the artisan quarter.", n: "San Blas = steile, enge Gassen, Werkstätten und Aussicht.", nEn: "San Blas = steep narrow lanes, workshops and views." },
    cu09: { e: "¿Queda lejos subir a Sacsayhuamán?", d: "Ist es weit, zu Sacsayhuamán hochzulaufen?", dEn: "Is it far to walk up to Sacsayhuamán?", s: "Beim Planen des Aufstiegs zur Inka-Festung.", sEn: "When planning the walk up to the Inca fortress.", n: "Liegt direkt über der Stadt; der Name klingt wie „sexy woman“ – gute Eselsbrücke.", nEn: "Just above the city; the name sounds like \"sexy woman\" – a handy mnemonic." },
    cu10: { e: "¿Aquí venden el Boleto Turístico?", d: "Verkaufen Sie hier das Boleto Turístico?", dEn: "Do you sell the Boleto Turístico here?", s: "Bevor du mehrere Stätten in Cusco und im Tal besuchst.", sEn: "Before visiting several sites in Cusco and the valley.", n: "Kombiticket für viele Ruinen/Museen; lohnt sich ab ein paar Besuchen.", nEn: "Combined ticket for many ruins/museums; worth it from a few visits on." },
    cu11: { e: "¿Es seguro caminar aquí de noche?", d: "Ist es hier nachts sicher zu Fuß?", dEn: "Is it safe to walk here at night?", s: "Vor dem abendlichen Rückweg, an der Rezeption gefragt.", sEn: "Before walking back at night, asked at reception.", n: "Das Zentrum ist meist belebt; ruhig nachfragen wirkt souverän.", nEn: "The centre is usually busy; asking calmly comes across as confident." },
    cu12: { e: "¿Cuánto cuesta el tour al Valle Sagrado?", d: "Was kostet die Tour ins Heilige Tal?", dEn: "How much is the tour to the Sacred Valley?", s: "Bei einer Agentur rund um die Plaza de Armas.", sEn: "At an agency around the Plaza de Armas.", n: "Valle Sagrado = Pisac, Ollantaytambo, Maras/Moray – meist als Tagestour.", nEn: "Valle Sagrado = Pisac, Ollantaytambo, Maras/Moray – usually a day tour." },
    cu13: { e: "¿De dónde sale el tren a Machu Picchu?", d: "Von wo fährt der Zug nach Machu Picchu?", dEn: "Where does the train to Machu Picchu leave from?", s: "Bei der Planung des Machu-Picchu-Tages.", sEn: "When planning the Machu Picchu day.", n: "Die meisten Züge starten in Ollantaytambo, nicht direkt in Cusco.", nEn: "Most trains start in Ollantaytambo, not directly in Cusco." },
    cu14: { e: "¿Tengo que comprar la entrada a Machu Picchu con anticipación?", d: "Muss ich das Ticket für Machu Picchu im Voraus kaufen?", dEn: "Do I need to buy the Machu Picchu ticket in advance?", s: "Tage bis Wochen vor dem Besuch.", sEn: "Days to weeks before the visit.", n: "Ja – die Eintritte sind kontingentiert und oft ausgebucht; früh sichern.", nEn: "Yes – entries are capped and often sold out; secure them early." },
    cu15: { e: "¿A qué hora sale el primer tren a Aguas Calientes?", d: "Wann fährt der erste Zug nach Aguas Calientes?", dEn: "What time does the first train to Aguas Calientes leave?", s: "Bei der Zugbuchung für den frühen Aufstieg.", sEn: "When booking the train for an early ascent.", n: "Aguas Calientes (Machupicchu Pueblo) ist der Ort direkt unterhalb der Ruinen.", nEn: "Aguas Calientes (Machupicchu Pueblo) is the town right below the ruins." },
    cu16: { e: "¿Dónde tomo el bus para subir a Machu Picchu?", d: "Wo nehme ich den Bus nach Machu Picchu hinauf?", dEn: "Where do I take the bus up to Machu Picchu?", s: "Morgens in Aguas Calientes vor dem Aufstieg.", sEn: "In the morning in Aguas Calientes before going up.", n: "Die Busse fahren in Serpentinen hoch; alternativ ~1,5 Std. steil zu Fuß.", nEn: "Buses zigzag up; or ~1.5 hrs steeply on foot." },
    cu17: { e: "¿La subida al Huayna Picchu está incluida en la entrada?", d: "Ist der Aufstieg zum Huayna Picchu im Ticket enthalten?", dEn: "Is the climb up Huayna Picchu included in the ticket?", s: "Beim Kauf des Machu-Picchu-Tickets.", sEn: "When buying the Machu Picchu ticket.", n: "Nur mit speziellem Kombiticket und Zeitfenster; separat und früh buchen.", nEn: "Only with a special combined ticket and time slot; book separately and early." },
    cu18: { e: "¿Cómo llego a Ollantaytambo?", d: "Wie komme ich nach Ollantaytambo?", dEn: "How do I get to Ollantaytambo?", s: "Beim Planen der Anreise ins Tal oder zum Zug.", sEn: "When planning the trip into the valley or to the train.", n: "Colectivos (Sammeltaxis) fahren günstig ab der Calle Pavitos in Cusco.", nEn: "Colectivos (shared taxis) run cheaply from Calle Pavitos in Cusco." },
    cu19: { e: "¿Vale la pena Pisac con su mercado?", d: "Lohnt sich Pisac mit seinem Markt?", dEn: "Is Pisac with its market worth it?", s: "Bei der Auswahl der Stopps im Heiligen Tal.", sEn: "When choosing stops in the Sacred Valley.", n: "Pisac = Inka-Terrassen oben plus bekannter Kunsthandwerksmarkt im Ort.", nEn: "Pisac = Inca terraces above plus a famous craft market in town." },
    cu20: { e: "¿Qué me recomienda típico de los Andes?", d: "Was empfehlen Sie typisch aus den Anden?", dEn: "What typical Andean dish do you recommend?", s: "Im Restaurant, wenn du Lokales probieren willst.", sEn: "At a restaurant, when you want to try local food.", n: "Frag nach lomo saltado, ají de gallina oder einer Anden-Suppe (chairo).", nEn: "Ask about lomo saltado, ají de gallina or an Andean soup (chairo)." },
    cu21: { e: "Quiero probar el cuy.", d: "Ich möchte gern Cuy probieren.", dEn: "I'd like to try cuy.", s: "Wenn du dich an die regionale Spezialität wagst.", sEn: "When you dare to try the regional speciality.", n: "cuy = Meerschweinchen; eine traditionelle Anden-Spezialität, oft im Ganzen serviert.", nEn: "cuy = guinea pig; a traditional Andean speciality, often served whole." },
    cu22: { e: "Una chicha morada, por favor.", d: "Eine Chicha morada, bitte.", dEn: "A chicha morada, please.", s: "Zum Essen oder an der Saftbude.", sEn: "With a meal or at a juice stand.", n: "Süßes, alkoholfreies Getränk aus lila Mais – nicht mit der Maisbier-chicha verwechseln.", nEn: "Sweet, non-alcoholic purple-corn drink – not to be confused with the corn-beer chicha." },
    cu23: { e: "¿Este plato es de alpaca?", d: "Ist das ein Gericht mit Alpaka?", dEn: "Is this a dish with alpaca?", s: "Beim Bestellen, wenn du neugierig auf Alpaka bist.", sEn: "When ordering, if you're curious about alpaca.", n: "Alpaka-Fleisch ist mager und proteinreich; typisch in der Andenküche.", nEn: "Alpaca meat is lean and high in protein; typical in Andean cuisine." },
    cu24: { e: "¿Dónde está el mercado de San Pedro?", d: "Wo ist der Markt San Pedro?", dEn: "Where is the San Pedro market?", s: "Wenn du Säfte, Käse oder Souvenirs suchst.", sEn: "When looking for juices, cheese or souvenirs.", n: "Großer überdachter Markt nahe dem Zentrum; gut für frische Säfte.", nEn: "Big covered market near the centre; great for fresh juices." },
    cu25: { e: "¿Esto es de lana de alpaca de verdad?", d: "Ist das aus echter Alpakawolle?", dEn: "Is this real alpaca wool?", s: "Beim Kauf von Textilien auf dem Markt.", sEn: "When buying textiles at the market.", n: "Viel „Alpaka“ ist in Wahrheit Acryl; bei sehr niedrigem Preis misstrauisch sein.", nEn: "Much \"alpaca\" is actually acrylic; be wary if the price is very low." },
    cu26: { e: "Allillanchu.", d: "Hallo. (auf Quechua)", dEn: "Hello. (in Quechua)", s: "Zur Begrüßung, besonders auf dem Land.", sEn: "As a greeting, especially in the countryside.", n: "Allillanchu = „Hallo, wie geht's?“ auf Quechua; Antwort: „Allillanmi“.", nEn: "Allillanchu = \"hello, how are you?\" in Quechua; reply: \"Allillanmi\"." },
    cu27: { e: "Sulpayki.", d: "Danke. (auf Quechua)", dEn: "Thank you. (in Quechua)", s: "Als Dank gegenüber Einheimischen.", sEn: "To thank locals.", n: "Sulpayki = „danke“ auf Quechua; ein paar Worte kommen herzlich an.", nEn: "Sulpayki = \"thank you\" in Quechua; a few words are warmly received." },
    cu28: { e: "¿Qué significa Apu?", d: "Was bedeutet „Apu“?", dEn: "What does \"Apu\" mean?", s: "Wenn dir der Begriff bei Touren oder Ritualen begegnet.", sEn: "When the term comes up on tours or in rituals.", n: "Apu = heiliger Berggeist; die Anden-Gipfel gelten als beschützende Wesen.", nEn: "Apu = sacred mountain spirit; Andean peaks are seen as protective beings." },
    cu29: { e: "¿Puedo tomar una foto?", d: "Darf ich ein Foto machen?", dEn: "May I take a photo?", s: "Vor dem Fotografieren von Menschen, Märkten oder Lamas.", sEn: "Before photographing people, markets or llamas.", n: "Höflich fragen; für Fotos mit Lamas oder in Tracht wird oft ein kleiner Betrag erwartet.", nEn: "Ask politely; photos with llamas or in costume often expect a small tip." },
    cu30: { e: "¿A qué altura está la montaña de colores?", d: "Auf welcher Höhe liegt der Regenbogenberg?", dEn: "How high is the Rainbow Mountain?", s: "Bei der Entscheidung für die Vinicunca-Tour.", sEn: "When deciding on the Vinicunca tour.", n: "Vinicunca liegt auf ~5.000 m – erst ein paar Tage akklimatisieren, sonst hart.", nEn: "Vinicunca is at ~5,000 m – acclimatise for a few days first, or it's tough." },
    cu31: { e: "El tour sale muy temprano, ¿verdad?", d: "Die Tour startet sehr früh, oder?", dEn: "The tour starts very early, right?", s: "Beim Buchen eines Tagesausflugs.", sEn: "When booking a day trip.", n: "Höhen-Tagestrips holen oft um 3–4 Uhr morgens ab; früh schlafen.", nEn: "High-altitude day trips often pick up at 3–4 am; get to bed early." },
    cu32: { e: "¿Necesito efectivo en soles?", d: "Brauche ich Bargeld in Soles?", dEn: "Do I need cash in soles?", s: "Vor Markt, Trinkgeld oder kleinen Läden.", sEn: "Before the market, tips or small shops.", n: "Auf dem Markt, in Colectivos und für Trinkgelder: ja, soles dabeihaben.", nEn: "At the market, in colectivos and for tips: yes, carry soles." },
    cu33: { e: "El sol aquí es muy fuerte.", d: "Die Sonne ist hier sehr stark.", dEn: "The sun is very strong here.", s: "Tagsüber im Freien, besonders auf Touren.", sEn: "Outdoors during the day, especially on tours.", n: "In der Höhe ist die UV-Strahlung intensiv – Sonnencreme, Hut, Wasser.", nEn: "At altitude the UV is intense – sunscreen, hat, water." },
    cu34: { e: "¿Podemos descansar un momento? Estoy sin aliento.", d: "Können wir kurz Pause machen? Ich bin außer Atem.", dEn: "Can we take a short break? I'm out of breath.", s: "Beim Wandern oder Treppensteigen in der Höhe.", sEn: "When hiking or climbing stairs at altitude.", n: "Auf 3.400 m+ ist Kurzatmigkeit normal – ruhig öfter kurze Pausen machen.", nEn: "At 3,400 m+ being short of breath is normal – take frequent short breaks." },

    // ===================== PERU (Destination-Pack) =====================
    pe01: { e: "¿Dónde tomo un taxi del aeropuerto al centro?", d: "Wo nehme ich ein Taxi vom Flughafen ins Zentrum?", dEn: "Where do I get a taxi from the airport to the centre?", s: "Direkt nach der Landung in Lima.", sEn: "Right after landing in Lima.", n: "Offizielle Taxis am Schalter sind sicherer; Preis vorher klären.", nEn: "Official desk taxis are safer; settle the price first." },
    pe02: { e: "Lléveme a Miraflores, por favor.", d: "Bringen Sie mich bitte nach Miraflores.", dEn: "Take me to Miraflores, please.", s: "Im Taxi auf dem Weg in die Unterkunft.", sEn: "In the taxi on the way to your accommodation.", n: "Miraflores und Barranco gelten als sichere, lebendige Viertel.", nEn: "Miraflores and Barranco are seen as safe, lively districts." },
    pe03: { e: "¿Cuánto cobra hasta el centro?", d: "Wie viel verlangen Sie bis ins Zentrum?", dEn: "How much do you charge to the centre?", s: "Vor Fahrtantritt, da Limas Taxis kein Taxameter haben.", sEn: "Before the ride, since Lima taxis have no meter.", n: "Ruhig verhandeln; vergleiche kurz mit einer App wie Uber/Cabify.", nEn: "Negotiate calmly; quickly compare with an app like Uber/Cabify." },
    pe04: { e: "Quiero caminar por el malecón de Miraflores.", d: "Ich möchte am Malecón von Miraflores entlanggehen.", dEn: "I'd like to walk along the Miraflores malecón.", s: "Beim Spaziergang an der Steilküste über dem Pazifik.", sEn: "Strolling along the cliff-top above the Pacific.", n: "Schöner bei Sonnenuntergang; Paragleiter starten hier.", nEn: "Best at sunset; paragliders launch from here." },
    pe05: { e: "¿Es seguro caminar por esta zona de noche?", d: "Ist es sicher, nachts durch diese Gegend zu laufen?", dEn: "Is it safe to walk in this area at night?", s: "Bevor du abends losziehst, frag im Hostel nach.", sEn: "Before heading out at night, ask at your hostel.", n: "Locals fragen ist immer der beste Sicherheits-Check.", nEn: "Asking locals is always the best safety check." },
    pe06: { e: "Me siento mal por la altura.", d: "Mir ist von der Höhe schlecht.", dEn: "I feel sick from the altitude.", s: "In Cusco oder Puno (über 3.300 m) am ersten Tag.", sEn: "In Cusco or Puno (over 3,300 m) on the first day.", n: "soroche = Höhenkrankheit; langsam machen, viel trinken.", nEn: "soroche = altitude sickness; take it slow, drink a lot." },
    pe07: { e: "¿Tiene mate de coca para el soroche?", d: "Haben Sie Kokatee gegen die Höhenkrankheit?", dEn: "Do you have coca tea for altitude sickness?", s: "An der Hotelrezeption oder im Café in den Anden.", sEn: "At hotel reception or a café in the Andes.", n: "mate de coca ist legal und üblich gegen Höhenbeschwerden.", nEn: "mate de coca is legal and common against altitude symptoms." },
    pe08: { e: "¿Hay una farmacia por aquí?", d: "Gibt es hier in der Nähe eine Apotheke?", dEn: "Is there a pharmacy near here?", s: "Wenn du Tabletten gegen die Höhe oder den Magen brauchst.", sEn: "When you need pills for altitude or your stomach.", n: "In Peru gibt es viele „boticas“ – dasselbe wie farmacia.", nEn: "In Peru there are many „boticas“ – the same as a farmacia." },
    pe09: { e: "Necesito agua, por favor. Sin gas.", d: "Ich brauche Wasser, bitte. Ohne Kohlensäure.", dEn: "I need water, please. Still.", s: "Im Restaurant oder Kiosk, besonders in der Höhe.", sEn: "At a restaurant or kiosk, especially at altitude.", n: "sin gas = still, con gas = mit Kohlensäure.", nEn: "sin gas = still, con gas = sparkling." },
    pe10: { e: "Hoy necesito aclimatarme a la altura.", d: "Heute muss ich mich an die Höhe gewöhnen.", dEn: "Today I need to acclimatise to the altitude.", s: "Am Ankunftstag in Cusco, vor anstrengenden Touren.", sEn: "On arrival day in Cusco, before strenuous tours.", n: "Erst akklimatisieren, dann Machu Picchu/Regenbogenberg.", nEn: "Acclimatise first, then Machu Picchu/Rainbow Mountain." },
    pe11: { e: "¿A qué hora sale el bus cama a Arequipa?", d: "Wann fährt der Nachtbus nach Arequipa?", dEn: "When does the night bus to Arequipa leave?", s: "Am Busterminal bei der Routenplanung.", sEn: "At the bus terminal when planning your route.", n: "bus cama = Liegesitze; „cama“ liegt flacher als „semicama“.", nEn: "bus cama = reclining seats; „cama“ lies flatter than „semicama“." },
    pe12: { e: "Tengo un boleto de tren a Aguas Calientes.", d: "Ich habe ein Zugticket nach Aguas Calientes.", dEn: "I have a train ticket to Aguas Calientes.", s: "Am Bahnhof in Ollantaytambo oder Cusco.", sEn: "At the station in Ollantaytambo or Cusco.", n: "Aguas Calientes (Machu Picchu Pueblo) ist der Ort unter MP.", nEn: "Aguas Calientes (Machu Picchu Pueblo) is the town below MP." },
    pe13: { e: "¿Hay colectivo al Valle Sagrado?", d: "Fährt ein Sammeltaxi ins Heilige Tal?", dEn: "Is there a shared taxi to the Sacred Valley?", s: "Für günstige Fahrten zwischen Cusco, Pisac und Ollantaytambo.", sEn: "For cheap rides between Cusco, Pisac and Ollantaytambo.", n: "colectivo = teilt man sich; fährt ab, wenn voll.", nEn: "colectivo = shared; leaves once it's full." },
    pe14: { e: "¿Cuánto dura el viaje hasta Puno?", d: "Wie lange dauert die Fahrt nach Puno?", dEn: "How long is the journey to Puno?", s: "Bei langen Anden-Etappen mit Bus oder Bahn.", sEn: "On long Andean legs by bus or train.", n: "durar = dauern; Strecken in den Anden sind oft lang.", nEn: "durar = to last; Andean routes are often long." },
    pe15: { e: "¿El bus para en Chivay, en el Colca?", d: "Hält der Bus in Chivay am Colca?", dEn: "Does the bus stop in Chivay at the Colca?", s: "Auf dem Weg von Arequipa zum Colca-Canyon.", sEn: "On the way from Arequipa to the Colca Canyon.", n: "Chivay ist der Hauptort und das Tor zum Cañón del Colca.", nEn: "Chivay is the main town and gateway to the Colca Canyon." },
    pe16: { e: "¡Qué bonito el volcán Misti!", d: "Wie schön der Vulkan Misti ist!", dEn: "How beautiful the Misti volcano is!", s: "Beim Blick über Arequipa.", sEn: "Looking out over Arequipa.", n: "Der Misti (5.822 m) prägt Arequipas Postkartenblick.", nEn: "El Misti (5,822 m) defines Arequipa's postcard view." },
    pe17: { e: "¿A qué hora se ven los cóndores en la Cruz del Cóndor?", d: "Wann sieht man die Kondore am Cruz del Cóndor?", dEn: "When can you see the condors at Cruz del Cóndor?", s: "Am berühmten Aussichtspunkt im Colca-Canyon.", sEn: "At the famous viewpoint in the Colca Canyon.", n: "Am frühen Vormittag steigen die Andenkondore in der Thermik auf.", nEn: "In the late morning the Andean condors ride the thermals." },
    pe18: { e: "¿Podemos ir al mirador?", d: "Können wir zum Aussichtspunkt gehen?", dEn: "Can we go to the viewpoint?", s: "An jedem Anden-Stopp mit Panoramablick.", sEn: "At any Andean stop with a panoramic view.", n: "mirador = Aussichtspunkt; gibt es fast überall in Peru.", nEn: "mirador = viewpoint; found almost everywhere in Peru." },
    pe19: { e: "El centro de Arequipa es de sillar blanco.", d: "Arequipas Zentrum ist aus weißem Sillar-Stein.", dEn: "Arequipa's centre is built of white sillar stone.", s: "Beim Bummel durch die „weiße Stadt“.", sEn: "Wandering through the 'white city'.", n: "sillar = heller Vulkanstein; daher „la Ciudad Blanca“.", nEn: "sillar = pale volcanic stone; hence 'la Ciudad Blanca'." },
    pe20: { e: "¿Qué tan profundo es el cañón del Colca?", d: "Wie tief ist der Colca-Canyon?", dEn: "How deep is the Colca Canyon?", s: "Im Gespräch mit dem Guide am Canyon.", sEn: "Chatting with the guide at the canyon.", n: "Mit über 3.000 m doppelt so tief wie der Grand Canyon.", nEn: "At over 3,000 m it's about twice as deep as the Grand Canyon." },
    pe21: { e: "¿A qué hora sale la lancha a las islas flotantes?", d: "Wann fährt das Boot zu den schwimmenden Inseln?", dEn: "When does the boat to the floating islands leave?", s: "Am Hafen von Puno am Titicacasee.", sEn: "At the port of Puno on Lake Titicaca.", n: "islas flotantes de los Uros = aus Totora-Schilf gebaut.", nEn: "islas flotantes de los Uros = built from totora reed." },
    pe22: { e: "Los uros viven en islas de totora.", d: "Die Uros leben auf Schilfinseln.", dEn: "The Uros live on reed islands.", s: "Beim Besuch der Uros-Gemeinschaft.", sEn: "When visiting the Uros community.", n: "totora = Schilf; Inseln, Boote und Häuser bestehen daraus.", nEn: "totora = reed; the islands, boats and houses are made of it." },
    pe23: { e: "¿Dormimos con una familia en Taquile?", d: "Übernachten wir bei einer Familie auf Taquile?", dEn: "Are we staying with a family on Taquile?", s: "Bei einem Homestay auf der Insel Taquile.", sEn: "On a homestay on Taquile island.", n: "Taquile ist für seine UNESCO-gelistete Webkunst bekannt.", nEn: "Taquile is known for its UNESCO-listed weaving." },
    pe24: { e: "El lago Titicaca es enorme, parece un mar.", d: "Der Titicacasee ist riesig, wie ein Meer.", dEn: "Lake Titicaca is huge, it looks like a sea.", s: "Beim ersten Blick über das Wasser.", sEn: "At the first sight across the water.", n: "Der höchste schiffbare See der Welt (3.812 m).", nEn: "The highest navigable lake in the world (3,812 m)." },
    pe25: { e: "¿Dónde está la Plaza de Armas?", d: "Wo ist die Plaza de Armas?", dEn: "Where is the Plaza de Armas?", s: "Zur Orientierung in jeder peruanischen Stadt.", sEn: "To get your bearings in any Peruvian town.", n: "Die Plaza de Armas ist immer der zentrale Hauptplatz.", nEn: "The Plaza de Armas is always the central main square." },
    pe26: { e: "Quiero visitar Sacsayhuamán.", d: "Ich möchte Sacsayhuamán besuchen.", dEn: "I'd like to visit Sacsayhuamán.", s: "Beim Planen der Touren rund um Cusco.", sEn: "When planning the tours around Cusco.", n: "Inka-Festung mit riesigen, fugenlosen Steinen.", nEn: "Inca fortress with huge, seamless stones." },
    pe27: { e: "¿Cuánto cuesta la entrada a la ruina?", d: "Was kostet der Eintritt zur Ruine?", dEn: "How much is entry to the ruins?", s: "Am Eingang archäologischer Stätten.", sEn: "At the entrance to archaeological sites.", n: "Oft lohnt das „boleto turístico“ für mehrere Stätten.", nEn: "The „boleto turístico“ often pays off for several sites." },
    pe28: { e: "¿Hoy hay mercado en Pisac?", d: "Gibt es heute Markt in Pisac?", dEn: "Is there a market in Pisac today?", s: "Bei der Tagesplanung im Heiligen Tal.", sEn: "When planning a day in the Sacred Valley.", n: "Pisac ist für seinen Kunsthandwerksmarkt berühmt.", nEn: "Pisac is famous for its handicraft market." },
    pe29: { e: "¿Cómo llego a las terrazas de Ollantaytambo?", d: "Wie komme ich zu den Terrassen von Ollantaytambo?", dEn: "How do I get to the terraces of Ollantaytambo?", s: "Im Inka-Ort vor der Zugfahrt nach Machu Picchu.", sEn: "In the Inca town before the train to Machu Picchu.", n: "Ollantaytambo = lebende Inka-Stadt und MP-Zugbahnhof.", nEn: "Ollantaytambo = living Inca town and MP train station." },
    pe30: { e: "Estas paredes todavía son de los incas.", d: "Diese Mauern sind noch von den Inka.", dEn: "These walls are still from the Incas.", s: "Beim Bummel durch Cuscos Altstadtgassen.", sEn: "Wandering Cusco's old-town lanes.", n: "Berühmt: der zwölfeckige Stein in der Calle Hatun Rumiyoc.", nEn: "Famous: the twelve-angled stone on Calle Hatun Rumiyoc." },
    pe31: { e: "Tengo mi boleto a Machu Picchu para mañana.", d: "Ich habe mein Machu-Picchu-Ticket für morgen.", dEn: "I have my Machu Picchu ticket for tomorrow.", s: "Bei der Kontrolle oder im Hostel-Gespräch.", sEn: "At the check or chatting at the hostel.", n: "Tickets sind zeit- und kontingentgebunden – früh buchen.", nEn: "Tickets are time- and quota-limited – book early." },
    pe32: { e: "¿A qué hora debemos estar en la entrada?", d: "Um wie viel Uhr müssen wir am Eingang sein?", dEn: "What time do we need to be at the entrance?", s: "Beim Abstimmen der Gruppe für den frühen Start.", sEn: "Coordinating the group for the early start.", n: "Frühe Slots = weniger Andrang und besseres Licht.", nEn: "Early slots = fewer crowds and better light." },
    pe33: { e: "¿Necesito un guía para las ruinas?", d: "Brauche ich einen Führer für die Ruinen?", dEn: "Do I need a guide for the ruins?", s: "Am Eingang von Machu Picchu oder anderen Stätten.", sEn: "At the entrance to Machu Picchu or other sites.", n: "In Machu Picchu ist ein Guide oft vorgeschrieben.", nEn: "At Machu Picchu a guide is often required." },
    pe34: { e: "La caminata a la Montaña de Colores es agotadora.", d: "Die Wanderung zum Regenbogenberg ist anstrengend.", dEn: "The hike to Rainbow Mountain is exhausting.", s: "Vor oder nach der Tour zum Vinicunca.", sEn: "Before or after the Vinicunca tour.", n: "Auf über 5.000 m – langsam gehen, Höhe ernst nehmen.", nEn: "At over 5,000 m – go slowly, respect the altitude." },
    pe35: { e: "¿Puedo alquilar un caballo aquí?", d: "Kann ich hier ein Pferd mieten?", dEn: "Can I rent a horse here?", s: "Am Fuß des Regenbogenbergs, wenn die Höhe zu viel wird.", sEn: "At the foot of Rainbow Mountain when the altitude is too much.", n: "Einheimische bieten Pferde fast bis zum Gipfel an.", nEn: "Locals offer horses almost to the summit." },
    pe36: { e: "Un ceviche, por favor.", d: "Einen Ceviche, bitte.", dEn: "A ceviche, please.", s: "Mittags an der Küste – ceviche isst man frisch.", sEn: "At lunchtime on the coast – ceviche is eaten fresh.", n: "Perus Nationalgericht: roher Fisch in Limette, scharf.", nEn: "Peru's national dish: raw fish in lime, with chilli." },
    pe37: { e: "Quiero probar un lomo saltado.", d: "Ich möchte ein Lomo Saltado probieren.", dEn: "I'd like to try a lomo saltado.", s: "Im Restaurant, wenn du es deftig magst.", sEn: "At a restaurant when you want something hearty.", n: "Rind, Zwiebeln, Tomate, Pommes – chinesisch beeinflusst.", nEn: "Beef, onion, tomato, fries – Chinese-influenced." },
    pe38: { e: "Un pisco sour, por favor.", d: "Einen Pisco Sour, bitte.", dEn: "A pisco sour, please.", s: "Abends in einer Bar, zum Anstoßen.", sEn: "In a bar in the evening, for a toast.", n: "Nationalcocktail aus Pisco, Limette und Eiweiß.", nEn: "National cocktail of pisco, lime and egg white." },
    pe39: { e: "¿Qué es el cuy? ¿Lo recomienda?", d: "Was ist Cuy? Empfehlen Sie es?", dEn: "What is cuy? Do you recommend it?", s: "Beim Lesen einer Anden-Speisekarte.", sEn: "Reading a menu in the Andes.", n: "cuy = gegrilltes Meerschweinchen, traditionelle Delikatesse.", nEn: "cuy = grilled guinea pig, a traditional delicacy." },
    pe40: { e: "Una chicha morada, por favor.", d: "Eine Chicha Morada, bitte.", dEn: "A chicha morada, please.", s: "Zum Essen, eine alkoholfreie Erfrischung.", sEn: "With your meal, a non-alcoholic refresher.", n: "Süßes Getränk aus violettem Mais – nicht alkoholisch.", nEn: "A sweet drink from purple corn – non-alcoholic." },
    pe41: { e: "¿Cuánto cuesta esta chompa de alpaca?", d: "Wie viel kostet diese Alpaka-Jacke?", dEn: "How much is this alpaca jumper?", s: "Auf dem Handwerksmarkt in Pisac oder Cusco.", sEn: "At the craft market in Pisac or Cusco.", n: "chompa = Pullover/Jacke; „baby alpaca“ ist weicher (und teurer).", nEn: "chompa = jumper/jacket; „baby alpaca“ is softer (and pricier)." },
    pe42: { e: "¿Me puede hacer una rebaja?", d: "Können Sie mir einen kleinen Rabatt geben?", dEn: "Can you give me a little discount?", s: "Beim Handeln auf dem Markt.", sEn: "When haggling at the market.", n: "rebaja = Nachlass; freundlich bleiben, das gehört dazu.", nEn: "rebaja = discount; stay friendly, it's part of the game." },
    pe43: { e: "¿Aceptan soles o solo tarjeta?", d: "Akzeptieren Sie Soles oder nur Karte?", dEn: "Do you take soles or only card?", s: "Beim Bezahlen in Läden und Restaurants.", sEn: "When paying in shops and restaurants.", n: "sol (S/) = Landeswährung; auf kleinen Märkten zählt Bargeld.", nEn: "sol (S/) = the currency; at small markets cash is king." },
    pe44: { e: "¡Allillanchu!", d: "Hallo! (auf Quechua)", dEn: "Hello! (in Quechua)", s: "Als Gruß gegenüber Quechua-sprechenden Einheimischen.", sEn: "As a greeting to Quechua-speaking locals.", n: "Allillanchu = Hallo / „geht's gut?“; Antwort: „allillanmi“ (mir geht's gut).", nEn: "Allillanchu = hello / „are you well?“; reply: „allillanmi“ (I'm well)." },
    pe45: { e: "¡Me encanta Perú, sulpayki!", d: "Ich liebe Peru, danke! (sulpayki = Quechua-Danke)", dEn: "I love Peru, thank you! (sulpayki = Quechua thanks)", s: "Ein herzlicher Abschluss im Gespräch mit Locals.", sEn: "A warm sign-off when chatting with locals.", n: "Quechua-Danke ist „sulpayki“; in der Cusco-Region hört man auch „añay“.", nEn: "Quechua for thanks is „sulpayki“; around Cusco you'll also hear „añay“." },

    // ===================== MEXIKO (Destination-Pack) =====================
    mx01: { e: "¿Dónde tomo un taxi autorizado del aeropuerto al centro?", d: "Wo nehme ich ein autorisiertes Taxi vom Flughafen ins Zentrum?", dEn: "Where do I get an authorised taxi from the airport to the centre?", s: "Direkt nach der Landung am AICM (Mexico-City-Flughafen).", sEn: "Right after landing at AICM (Mexico City airport).", n: "Ticket im Voraus am „Taxi Autorizado“-Schalter kaufen, nicht bei Schleppern.", nEn: "Buy a fixed-price ticket at the „Taxi Autorizado“ desk, not from touts." },
    mx02: { e: "Lléveme a La Condesa, por favor.", d: "Bringen Sie mich bitte nach La Condesa.", dEn: "Take me to La Condesa, please.", s: "Im Taxi auf dem Weg in die Unterkunft.", sEn: "In the taxi on the way to your accommodation.", n: "Condesa und Roma gelten als sichere, lebendige Viertel mit Cafés und Parks.", nEn: "Condesa and Roma are seen as safe, lively districts with cafés and parks." },
    mx03: { e: "¿Cuánto cuesta el viaje con taxímetro?", d: "Wie viel kostet die Fahrt mit Taxameter?", dEn: "How much is the ride with the meter?", s: "Bevor du in ein Straßentaxi steigst.", sEn: "Before getting into a street taxi.", n: "In CDMX ist Uber/DiDi meist günstiger, transparenter und sicherer.", nEn: "In CDMX, Uber/DiDi is usually cheaper, clearer and safer." },
    mx03b: { e: "¿Mande?", d: "Wie bitte?", dEn: "Pardon?", s: "Wenn du jemanden nicht verstanden hast und höflich nachfragst.", sEn: "When you didn’t catch what someone said and ask politely.", n: "¿Mande? klingt höflicher als „¿qué?“ und ist typisch mexikanisch.", nEn: "¿Mande? sounds more polite than „¿qué?“ and is typically Mexican." },
    mx04: { e: "¡Qué chido está esto!", d: "Wie cool ist das denn!", dEn: "How cool is this!", s: "Wenn dir etwas richtig gut gefällt.", sEn: "When you really like something.", n: "chido und padre sind die mexikanischen Alltagswörter für „cool/toll“.", nEn: "chido and padre are the everyday Mexican words for „cool/great“." },
    mx05: { e: "¡Órale, qué increíble!", d: "Wow, wie unglaublich!", dEn: "Wow, that’s incredible!", s: "Beim Staunen, z. B. vor den Pyramiden von Teotihuacán.", sEn: "When marvelling, e.g. before the Teotihuacán pyramids.", n: "¡Órale! ist extrem vielseitig: Staunen, Zustimmung oder „los geht’s!“.", nEn: "¡Órale! is super versatile: surprise, agreement or „let’s go!“." },
    mx06: { e: "¡Aguas con el escalón!", d: "Achtung, die Stufe!", dEn: "Careful, the step!", s: "Wenn du jemanden vor einer Gefahr warnst.", sEn: "When warning someone of a hazard.", n: "¡Aguas! kommt vom Ruf, wenn früher Wasser auf die Straße gekippt wurde.", nEn: "¡Aguas! comes from the old shout when water was tossed onto the street." },
    mx07: { e: "Sale, nos vemos al rato.", d: "Alles klar, bis später.", dEn: "Alright, see you later.", s: "Wenn du eine Verabredung oder einen Vorschlag bestätigst.", sEn: "When confirming a plan or suggestion.", n: "sale = mexikanisches „okay, abgemacht“; oft als „sale y vale“.", nEn: "sale = Mexican „okay, deal“; often said as „sale y vale“." },
    mx08: { e: "¡Provecho!", d: "Guten Appetit!", dEn: "Enjoy your meal!", s: "Beim Essen, auch wenn du an fremden Tischen vorbeigehst.", sEn: "While eating, even passing other people’s tables.", n: "In Mexiko wünscht man auch Fremden „provecho“ – ein netter Brauch.", nEn: "In Mexico you wish even strangers „provecho“ – a nice custom." },
    mx09: { e: "¿Qué me recomienda de comer aquí?", d: "Was empfehlen Sie mir hier zu essen?", dEn: "What do you recommend I eat here?", s: "An einem Marktstand oder in einer kleinen Fonda.", sEn: "At a market stall or a small fonda.", n: "Fondas und Märkte (z. B. Oaxaca) bieten das authentischste Essen.", nEn: "Fondas and markets (e.g. Oaxaca) serve the most authentic food." },
    mx10: { e: "Tres tacos al pastor, por favor.", d: "Drei Tacos al pastor, bitte.", dEn: "Three tacos al pastor, please.", s: "An einer Taquería am Abend.", sEn: "At a taquería in the evening.", n: "Al pastor wird vom Spieß geschnitten, klassisch mit Ananas, Zwiebel & Koriander.", nEn: "Al pastor is sliced off the spit, classically with pineapple, onion & coriander." },
    mx11: { e: "¿Qué son los antojitos?", d: "Was sind Antojitos?", dEn: "What are antojitos?", s: "Wenn du die Speisekarte eines Streetfood-Stands liest.", sEn: "When reading a street-food stall’s menu.", n: "Antojitos = kleine Maisgerichte wie Tacos, Sopes, Tlacoyos, Quesadillas.", nEn: "Antojitos = small corn-based dishes like tacos, sopes, tlacoyos, quesadillas." },
    mx12: { e: "Que no pique mucho, por favor.", d: "Nicht zu scharf, bitte.", dEn: "Not too spicy, please.", s: "Beim Bestellen, wenn du Schärfe nicht gewohnt bist.", sEn: "When ordering if you’re not used to heat.", n: "Bitte die Salsa lieber „aparte“ (separat); manche Salsas sind extrem scharf.", nEn: "Ask for the salsa „aparte“ (on the side); some salsas are extremely hot." },
    mx13: { e: "Con gusto pruebo unos chapulines.", d: "Ich probiere gern ein paar geröstete Heuschrecken.", dEn: "I’ll happily try some roasted grasshoppers.", s: "Auf dem Mercado in Oaxaca.", sEn: "At the market in Oaxaca.", n: "Chapulines mit Limette und Chili sind eine echte Oaxaca-Spezialität.", nEn: "Chapulines with lime and chilli are a true Oaxaca speciality." },
    mx14: { e: "La cuenta, por favor.", d: "Die Rechnung, bitte.", dEn: "The bill, please.", s: "Am Ende des Essens im Restaurant.", sEn: "At the end of a meal in a restaurant.", n: "Propina von 10–15 % ist üblich und für viele Kellner existenziell.", nEn: "A tip (propina) of 10–15 % is customary and vital for many waiters." },
    mx15: { e: "¿La propina ya está incluida?", d: "Ist das Trinkgeld schon dabei?", dEn: "Is the tip already included?", s: "Wenn du die Rechnung prüfst.", sEn: "When checking the bill.", n: "Meist nicht enthalten; manche Touri-Lokale schlagen sie aber auf.", nEn: "Usually not included, though some tourist spots add it." },
    mx16: { e: "¿Puedo pagar con tarjeta?", d: "Kann ich mit Karte zahlen?", dEn: "Can I pay by card?", s: "Bevor du bestellst oder einkaufst.", sEn: "Before ordering or buying.", n: "Märkte, Stände und Colectivos sind reine Bargeld-Welt – immer Pesos dabei.", nEn: "Markets, stalls and colectivos are cash-only – always carry pesos." },
    mx17: { e: "¿Dónde hay un cajero automático?", d: "Wo ist ein Geldautomat?", dEn: "Where is an ATM?", s: "Wenn du Bargeld brauchst.", sEn: "When you need cash.", n: "Cajeros in Banken sind sicherer; freistehende Automaten oft mit hohen Gebühren.", nEn: "ATMs inside banks are safer; standalone ones often charge high fees." },
    mx18: { e: "¿Me cambia esto en billetes chicos?", d: "Können Sie mir das in kleine Scheine wechseln?", dEn: "Can you change this into small bills for me?", s: "Nach dem Abheben am Automaten.", sEn: "After withdrawing from the ATM.", n: "An Ständen wird ein 500er ungern gewechselt – kleine Scheine sind Gold wert.", nEn: "Stalls dislike breaking a 500-peso note – small bills are gold." },
    mx19: { e: "¿Me da un mejor precio si llevo dos?", d: "Geben Sie mir einen besseren Preis, wenn ich zwei nehme?", dEn: "Will you give me a better price if I take two?", s: "Auf einem Kunsthandwerksmarkt in Oaxaca oder San Cristóbal.", sEn: "At a craft market in Oaxaca or San Cristóbal.", n: "Freundlich und mit Humor feilschen; im Supermarkt gibt es feste Preise.", nEn: "Haggle kindly and with humour; supermarkets have fixed prices." },
    mx20: { e: "¿Cuánto cuesta esto?", d: "Wie viel kostet das?", dEn: "How much does this cost?", s: "Beim Stöbern am Marktstand.", sEn: "When browsing a market stall.", n: "Auf Märkten hört man oft „¿a cómo?“ statt „¿cuánto?“.", nEn: "At markets you often hear „¿a cómo?“ instead of „¿cuánto?“." },
    mx21: { e: "¿De dónde sale el camión a Oaxaca?", d: "Wo fährt der Bus nach Oaxaca ab?", dEn: "Where does the bus to Oaxaca leave from?", s: "Am Busbahnhof, wenn du den Bussteig suchst.", sEn: "At the bus terminal, looking for the platform.", n: "In Mexiko heißt der Bus oft „camión“; der Fernbus aber meist „autobús“.", nEn: "In Mexico the bus is often „camión“; long-distance ones are mostly „autobús“." },
    mx22: { e: "Quiero comprar un boleto de autobús a Mérida en ADO.", d: "Ich möchte ein Busticket nach Mérida bei ADO kaufen.", dEn: "I’d like to buy a bus ticket to Mérida with ADO.", s: "Am ADO-Schalter oder in der App.", sEn: "At the ADO counter or in the app.", n: "ADO ist komfortabel und pünktlich; früh buchen für gute Plätze (GL/Platino).", nEn: "ADO is comfortable and punctual; book early for good seats (GL/Platino)." },
    mx23: { e: "¿Este colectivo para en Valladolid?", d: "Hält dieses Sammeltaxi in Valladolid?", dEn: "Does this shared taxi stop in Valladolid?", s: "An einer Straßenecke, wo Colectivos abfahren.", sEn: "At a street corner where colectivos depart.", n: "Colectivos sind billig und flexibel; man zahlt meist beim Aussteigen.", nEn: "Colectivos are cheap and flexible; you usually pay when getting off." },
    mx24: { e: "¿A qué hora sale el autobús nocturno?", d: "Um wie viel Uhr fährt der Nachtbus ab?", dEn: "What time does the night bus leave?", s: "Bei der Planung einer langen Etappe, z. B. CDMX–Chiapas.", sEn: "Planning a long leg, e.g. CDMX–Chiapas.", n: "Bei der 360°-Route gibt es eine Nachtfahrt; Jacke & Ohrstöpsel einpacken.", nEn: "The 360° route has one overnight ride; pack a jacket & earplugs." },
    mx25: { e: "¿Qué tan lejos está Teotihuacán de aquí?", d: "Wie weit ist Teotihuacán von hier?", dEn: "How far is Teotihuacán from here?", s: "Bei der Tagesplanung von CDMX aus.", sEn: "Planning a day trip from CDMX.", n: "Etwa 50 km nordöstlich; morgens hin, um Hitze und Massen zu vermeiden.", nEn: "About 50 km north-east; go early to dodge heat and crowds." },
    mx26: { e: "¿Cuánto cuesta la entrada a la zona arqueológica?", d: "Was kostet der Eintritt zur Ausgrabungsstätte?", dEn: "How much is admission to the archaeological site?", s: "Am Ticketschalter von Chichén Itzá oder Palenque.", sEn: "At the ticket booth of Chichén Itzá or Palenque.", n: "Oft zwei Tickets (Bund + Bundesstaat); Studentenausweis kann sparen.", nEn: "Often two tickets (federal + state); a student card can save money." },
    mx27: { e: "¿Se puede nadar en este cenote?", d: "Kann man in dieser Cenote schwimmen?", dEn: "Can you swim in this cenote?", s: "Am Eingang einer Cenote wie Ik Kil.", sEn: "At the entrance of a cenote like Ik Kil.", n: "Cenoten sind heilige Maya-Orte; vor dem Bad duschen, kein Sonnenöl.", nEn: "Cenotes are sacred Maya sites; shower before swimming, no sunscreen oils." },
    mx28: { e: "¿Tengo que usar chaleco salvavidas?", d: "Muss ich eine Schwimmweste tragen?", dEn: "Do I have to wear a life vest?", s: "Vor dem Sprung ins kühle Cenoten-Wasser.", sEn: "Before jumping into the cool cenote water.", n: "In tiefen Cenoten oft Pflicht; nur biologisch abbaubaren Sonnenschutz nutzen.", nEn: "Often compulsory in deep cenotes; use only biodegradable sunscreen." },
    mx29: { e: "¿A qué hora empieza el paseo en lancha por el Cañón del Sumidero?", d: "Wann beginnt die Bootstour durch den Sumidero-Canyon?", dEn: "When does the boat tour through Sumidero Canyon start?", s: "Am Bootsanleger in Chiapa de Corzo.", sEn: "At the boat dock in Chiapa de Corzo.", n: "Die bis zu 1000 m hohen Wände, Brüllaffen & Krokodile sind der Höhepunkt.", nEn: "The walls up to 1000 m, howler monkeys & crocodiles are the highlight." },
    mx30: { e: "¿Hay un tour guiado en alemán o inglés?", d: "Gibt es eine geführte Tour auf Deutsch oder Englisch?", dEn: "Is there a guided tour in German or English?", s: "Am Eingang einer Maya-Stätte oder Altstadt.", sEn: "At the entrance to a Maya site or old town.", n: "Ein guter Guide erklärt die Maya-Geschichte; vorher Preis vereinbaren.", nEn: "A good guide explains the Maya history; agree the price first." },
    mx31: { e: "¿Es seguro caminar aquí a esta hora?", d: "Ist es sicher, hier um diese Uhrzeit zu laufen?", dEn: "Is it safe to walk here at this hour?", s: "Wenn du abends die Gegend einschätzt.", sEn: "When sizing up the area in the evening.", n: "Tagsüber meist entspannt; nachts in CDMX lieber Uber/DiDi nehmen.", nEn: "Usually relaxed by day; at night in CDMX better take Uber/DiDi." },
    mx32: { e: "¿De dónde eres? Yo soy de Alemania.", d: "Woher kommst du? Ich komme aus Deutschland.", dEn: "Where are you from? I’m from Germany.", s: "Beim lockeren Plausch mit Locals oder in der Reisegruppe.", sEn: "Chatting casually with locals or your travel group.", n: "Mexikaner sind herzlich und neugierig; Smalltalk öffnet schnell Türen.", nEn: "Mexicans are warm and curious; small talk opens doors fast." },
    mx33: { e: "Me encanta tu país, está muy padre.", d: "Ich liebe dein Land, es ist wirklich toll.", dEn: "I love your country, it’s really great.", s: "Wenn du dich für Gastfreundschaft bedankst.", sEn: "When showing appreciation for hospitality.", n: "„Está muy padre“ ist ein echtes Kompliment im mexikanischen Mund.", nEn: "„Está muy padre“ is a genuine compliment the Mexican way." },
    mx34: { e: "¿Vamos por unas chelas al rato, güey?", d: "Gehen wir später ein paar Bier trinken, Kumpel?", dEn: "Shall we grab a few beers later, buddy?", s: "Wenn du mit neuen Bekannten abends ausgehen willst.", sEn: "When inviting new acquaintances out in the evening.", n: "güey nur unter Freunden/jungen Leuten benutzen, nie förmlich.", nEn: "Use güey only among friends/young people, never formally." },
    mx35: { e: "¿Qué celebran en el Día de Muertos?", d: "Was feiert ihr am Día de Muertos?", dEn: "What do you celebrate on Día de Muertos?", s: "Ende Oktober/Anfang November, wenn die Altäre erscheinen.", sEn: "Late October/early November when the altars appear.", n: "Kein „mexikanisches Halloween“: es ist liebevolles Gedenken, kein Gruseln.", nEn: "Not „Mexican Halloween“: it’s loving remembrance, not horror." },
    mx36: { e: "¿Qué significa esta ofrenda con flores de cempasúchil?", d: "Was bedeutet dieser Altar mit den Ringelblumen?", dEn: "What does this altar with the marigolds mean?", s: "Vor einer ofrenda in einem Haus, Café oder Friedhof.", sEn: "In front of an ofrenda in a home, café or cemetery.", n: "Cempasúchil-Blüten und Kerzen sollen die Seelen nach Hause leiten.", nEn: "Cempasúchil flowers and candles guide the souls back home." },
    mx37: { e: "Un mezcal, por favor.", d: "Einen Mezcal, bitte.", dEn: "A mezcal, please.", s: "In einer Mezcalería in Oaxaca.", sEn: "In a mezcalería in Oaxaca.", n: "Spruch: „Para todo mal, mezcal; para todo bien, también.“", nEn: "Saying: „For all that’s bad, mezcal; for all that’s good, too.“" },
    mx38: { e: "¿Cuál mezcal es el menos ahumado?", d: "Welcher Mezcal ist am wenigsten rauchig?", dEn: "Which mezcal is the least smoky?", s: "Bei einer Mezcal-Verkostung.", sEn: "During a mezcal tasting.", n: "Mezcal nicht „schießen“, sondern pur nippen, mit Orange & Sal de gusano.", nEn: "Don’t shoot mezcal; sip it neat with orange & worm salt." },
    mx39: { e: "¿Dónde está el mejor bar de playa en Tulum?", d: "Wo ist die schönste Strandbar in Tulum?", dEn: "Where’s the nicest beach bar in Tulum?", s: "Beim Ausklang an der Karibikküste.", sEn: "Winding down on the Caribbean coast.", n: "Die Hotelzone ist teuer; im Tulum Pueblo isst und trinkt man günstiger.", nEn: "The hotel zone is pricey; Tulum Pueblo is cheaper to eat and drink." },
    mx40: { e: "¿Es cierto que la laguna de Bacalar tiene siete colores?", d: "Stimmt es, dass die Lagune von Bacalar sieben Farben hat?", dEn: "Is it true that Bacalar’s lagoon has seven colours?", s: "Am Ufer der Laguna de Bacalar.", sEn: "On the shore of Bacalar lagoon.", n: "Die „Laguna de los Siete Colores“ schimmert je nach Tiefe türkis bis tiefblau.", nEn: "The „Lagoon of Seven Colours“ shimmers turquoise to deep blue by depth." },

    // ===================== COSTA RICA (Destination-Pack) =====================
    cr01: { e: "Disculpe, ¿dónde tomo un taxi para ir al centro?", d: "Entschuldigung, wo bekomme ich ein Taxi ins Zentrum?", dEn: "Excuse me, where do I get a taxi to the centre?", s: "Direkt nach der Landung am Flughafen SJO (San José).", sEn: "Right after landing at SJO airport (San José).", n: "Offizielle Taxis sind orange; rote Taxis sollten das „María“-Taxameter nutzen.", nEn: "Official taxis are orange; red taxis should use the „María“ meter." },
    cr02: { e: "Lléveme al centro de San José, por favor.", d: "Bringen Sie mich bitte ins Zentrum von San José.", dEn: "Take me to downtown San José, please.", s: "Beim Einsteigen ins Taxi vom Flughafen oder Busbahnhof.", sEn: "Getting into the taxi from the airport or bus station.", n: "Apps wie Uber funktionieren in San José; oft günstiger als das Straßentaxi.", nEn: "Apps like Uber work in San José; often cheaper than a street taxi." },
    cr03: { e: "¡Hola! ¿Cómo está? — ¡Pura vida!", d: "Hallo! Wie geht's? – Voll gut!", dEn: "Hi! How's it going? – Great!", s: "Bei jeder Begrüßung, von der Rezeption bis zum Busfahrer.", sEn: "At any greeting, from reception to the bus driver.", n: "„Pura vida“ ist Gruß, Abschied, Dank und Lebensgefühl in einem; Antwort auf Dank: „con mucho gusto“.", nEn: "„Pura vida“ is greeting, goodbye, thanks and a whole attitude in one; reply to thanks: „con mucho gusto“." },
    cr04: { e: "¿Cuánto le debo?", d: "Wie viel schulde ich Ihnen?", dEn: "How much do I owe you?", s: "Beim Bezahlen in der Soda, im Taxi oder am Marktstand.", sEn: "When paying at a soda, in a taxi or at a market stall.", n: "Sehr tico und höflich; die Antwort kommt oft mit „con mucho gusto“.", nEn: "Very Tico and polite; the reply often comes with „con mucho gusto“." },
    cr05: { e: "¿Aceptan dólares o solo colones?", d: "Akzeptieren Sie Dollar oder nur Colones?", dEn: "Do you take dollars or only colones?", s: "Beim Bezahlen, wenn du noch keine Landeswährung hast.", sEn: "When paying before you've got local currency.", n: "Dollar werden oft genommen, aber Wechselgeld kommt in colones zu schlechtem Kurs.", nEn: "Dollars are often accepted, but change comes in colones at a poor rate." },
    cr06: { e: "Disculpe, ¿hay una soda buena aquí cerca?", d: "Entschuldigung, gibt es hier in der Nähe eine gute Soda?", dEn: "Excuse me, is there a good soda nearby?", s: "Wenn du günstig und lokal essen willst statt im Touri-Restaurant.", sEn: "When you want a cheap, local bite instead of a tourist restaurant.", n: "Sodas sind das Herz der tico-Küche: frisch, billig, hausgemacht.", nEn: "Sodas are the heart of Tico cooking: fresh, cheap, home-made." },
    cr07: { e: "Para mí un casado con pollo, por favor.", d: "Für mich einen Casado mit Hähnchen, bitte.", dEn: "A casado with chicken for me, please.", s: "Beim Mittagessen in einer Soda.", sEn: "At lunch in a soda.", n: "Casado = „verheiratet“; ein voller Teller wie zu Hause: Reis, Bohnen, Fleisch, Kochbanane, Salat.", nEn: "Casado means „married“; a full home-style plate: rice, beans, meat, plantain, salad." },
    cr08: { e: "¿Qué lleva el gallo pinto?", d: "Was ist im Gallo Pinto drin?", dEn: "What's in the gallo pinto?", s: "Beim Frühstück, das oft im Hostel-Preis enthalten ist.", sEn: "At breakfast, often included in the hostel price.", n: "Gallo pinto = Reis mit schwarzen Bohnen; Geheimzutat ist die salsa Lizano.", nEn: "Gallo pinto = rice with black beans; the secret is salsa Lizano." },
    cr09: { e: "¿Es picante? No me gusta muy picante.", d: "Ist es scharf? Ich mag es nicht sehr scharf.", dEn: "Is it spicy? I don't like it very spicy.", s: "Beim Bestellen, wenn du Schärfe vermeiden willst.", sEn: "When ordering, if you want to avoid heat.", n: "Tico-Küche ist generell mild; „chilero“ (eingelegtes Gemüse) gibt extra Würze.", nEn: "Tico food is generally mild; „chilero“ (pickled veg) adds extra kick." },
    cr10: { e: "La cuenta, por favor.", d: "Die Rechnung, bitte.", dEn: "The bill, please.", s: "Am Ende des Essens in Restaurant oder Soda.", sEn: "At the end of the meal in a restaurant or soda.", n: "Oft sind „10 % servicio“ schon dabei; ein Blick auf die Rechnung lohnt.", nEn: "Often „10% servicio“ is already included; worth a glance at the bill." },
    cr11: { e: "¿La propina ya está incluida en la cuenta?", d: "Ist das Trinkgeld schon in der Rechnung enthalten?", dEn: "Is the tip already included in the bill?", s: "Vor dem Bezahlen, wenn du nicht doppelt Trinkgeld geben willst.", sEn: "Before paying, so you don't tip twice.", n: "Standard sind 10 % servicio plus 13 % Steuer; extra Trinkgeld ist freiwillig.", nEn: "Standard is 10% servicio plus 13% tax; extra tipping is optional." },
    cr12: { e: "Un café, por favor. ¿Lo tienen chorreado?", d: "Einen Kaffee, bitte. Haben Sie ihn als Chorreado?", dEn: "A coffee, please. Do you have it chorreado?", s: "Im Café oder auf einer Kaffee-Finca in Monteverde.", sEn: "At a café or coffee finca in Monteverde.", n: "„Café chorreado“ wird durch einen Stofffilter („chorreador“) gegossen.", nEn: "„Café chorreado“ is poured through a cloth filter (a „chorreador“)." },
    cr13: { e: "Un fresco de mora en agua, por favor.", d: "Einen Brombeer-Saft mit Wasser, bitte.", dEn: "A blackberry fresco with water, please.", s: "Beim Essen in der Soda, statt Softdrink.", sEn: "With your meal at the soda, instead of a soft drink.", n: "„Fresco natural“ gibt es „en agua“ oder „en leche“; mora, cas und tamarindo sind Klassiker.", nEn: "„Fresco natural“ comes „en agua“ or „en leche“; mora, cas and tamarindo are classics." },
    cr14: { e: "¿A qué hora sale el bus para La Fortuna?", d: "Um wie viel Uhr fährt der Bus nach La Fortuna?", dEn: "What time does the bus to La Fortuna leave?", s: "Am Busterminal in San José beim Planen der Etappe zum Arenal.", sEn: "At the San José terminal when planning the leg to Arenal.", n: "La Fortuna ist der Ausgangsort für Vulkan, Wasserfall und heiße Quellen.", nEn: "La Fortuna is the base for the volcano, waterfall and hot springs." },
    cr15: { e: "Disculpe, ¿este bus para en Monteverde?", d: "Entschuldigung, hält dieser Bus in Monteverde?", dEn: "Excuse me, does this bus stop in Monteverde?", s: "Beim Einsteigen, wenn du nicht sicher bist, ob es der richtige Bus ist.", sEn: "When boarding, if you're unsure it's the right bus.", n: "Manche Routen nutzen „jeep-boat-jeep“ über den Arenalsee – schneller als die Straße.", nEn: "Some routes use „jeep-boat-jeep“ across Lake Arenal – faster than the road." },
    cr16: { e: "¿Hay un shuttle para Manuel Antonio mañana?", d: "Gibt es morgen ein Shuttle nach Manuel Antonio?", dEn: "Is there a shuttle to Manuel Antonio tomorrow?", s: "An der Hostel-Rezeption oder im Tourbüro beim Weiterplanen.", sEn: "At hostel reception or a tour office when planning ahead.", n: "Shared shuttles holen am Hostel ab und sparen Umsteigen – ideal mit Gepäck.", nEn: "Shared shuttles pick up at the hostel and save transfers – ideal with luggage." },
    cr17: { e: "¿Cuánto cuesta el boleto?", d: "Wie viel kostet das Ticket?", dEn: "How much is the ticket?", s: "Am Schalter oder direkt beim Busfahrer.", sEn: "At the counter or directly with the driver.", n: "Öffentliche Busse sind sehr günstig; Kleingeld in colones bereithalten.", nEn: "Public buses are very cheap; keep small change in colones ready." },
    cr18: { e: "¿Dónde está la entrada del parque nacional?", d: "Wo ist der Eingang zum Nationalpark?", dEn: "Where's the national park entrance?", s: "An den Parks von Manuel Antonio, Cahuita oder Tortuguero.", sEn: "At Manuel Antonio, Cahuita or Tortuguero parks.", n: "Manuel Antonio braucht Online-Tickets vorab und ist montags geschlossen.", nEn: "Manuel Antonio needs tickets booked online and is closed on Mondays." },
    cr19: { e: "¡Mira, un perezoso en el árbol!", d: "Schau, ein Faultier im Baum!", dEn: "Look, a sloth in the tree!", s: "Auf einem Naturpfad mit Guide oder in Cahuita.", sEn: "On a nature trail with a guide or in Cahuita.", n: "Es gibt zwei Arten: das zwei- und das dreizehige Faultier („perezoso“).", nEn: "There are two kinds: the two-toed and three-toed sloth („perezoso“)." },
    cr20: { e: "Hay un tucán en ese árbol, ¿lo ves?", d: "Da ist ein Tukan in dem Baum, siehst du ihn?", dEn: "There's a toucan in that tree, can you see it?", s: "Bei einer Vogelbeobachtung im Karibik-Tiefland.", sEn: "While birdwatching in the Caribbean lowlands.", n: "Ein Guide mit Spektiv findet Tiere, die du allein nie sehen würdest.", nEn: "A guide with a scope finds wildlife you'd never spot alone." },
    cr21: { e: "¿Son peligrosos los monos aquí?", d: "Sind die Affen hier gefährlich?", dEn: "Are the monkeys here dangerous?", s: "Am Strand von Manuel Antonio, wo viele Affen leben.", sEn: "On Manuel Antonio beach, where lots of monkeys live.", n: "Kapuzineraffen klauen Essen und Taschen; Rucksack zu lassen.", nEn: "Capuchin monkeys steal food and bags; keep your backpack closed." },
    cr22: { e: "¿Podemos ver tortugas en Tortuguero?", d: "Können wir in Tortuguero Schildkröten sehen?", dEn: "Can we see turtles in Tortuguero?", s: "Beim Buchen der Tour im Karibik-Dorf Tortuguero.", sEn: "When booking the tour in the Caribbean village of Tortuguero.", n: "Tortuguero erreicht man nur per Boot oder Flugzeug; Nistsaison Juli–Oktober.", nEn: "Tortuguero is reachable only by boat or plane; nesting season July–October." },
    cr23: { e: "¿A qué hora empieza el tour en bote?", d: "Um wie viel Uhr beginnt die Bootstour?", dEn: "What time does the boat tour start?", s: "An der Lodge in Tortuguero beim Planen des nächsten Morgens.", sEn: "At the Tortuguero lodge when planning the next morning.", n: "Die frühen Touren in den Kanälen sehen Kaimane, Affen und Vögel am aktivsten.", nEn: "Early canal tours catch caimans, monkeys and birds at their most active." },
    cr24: { e: "Quiero hacer los puentes colgantes mañana.", d: "Ich möchte morgen die Hängebrücken machen.", dEn: "I'd like to do the hanging bridges tomorrow.", s: "Beim Buchen der Arenal-Aktivitäten im Hostel.", sEn: "When booking Arenal activities at the hostel.", n: "Die Hängebrücken führen durch das Kronendach mit Blick auf den Vulkan.", nEn: "The hanging bridges run through the canopy with views of the volcano." },
    cr25: { e: "¿Cuánto cuesta el canopy?", d: "Wie viel kostet das Ziplining?", dEn: "How much is the zip-lining?", s: "In Monteverde, dem besten Ort für Canopy-Touren.", sEn: "In Monteverde, the top spot for canopy tours.", n: "Ziplining heißt in Costa Rica „canopy“ oder „tirolina“ – nicht „zipline“.", nEn: "Zip-lining in Costa Rica is „canopy“ or „tirolina“ – not „zipline“." },
    cr26: { e: "¿Las aguas termales están incluidas en el tour?", d: "Sind die heißen Quellen in der Tour inbegriffen?", dEn: "Are the hot springs included in the tour?", s: "Beim Buchen am Arenal nach einem langen Wandertag.", sEn: "When booking at Arenal after a long day of hiking.", n: "Die Quellen werden vom Vulkan erhitzt; abends mit Vulkanblick am schönsten.", nEn: "The springs are heated by the volcano; loveliest in the evening with a volcano view." },
    cr27: { e: "Me gustaría hacer rafting en el Río Pacuare.", d: "Ich würde gern auf dem Río Pacuare Rafting machen.", dEn: "I'd like to go rafting on the Río Pacuare.", s: "Beim Buchen der Abenteuer-Etappe (WeRoad-Klassiker).", sEn: "When booking the adventure leg (a WeRoad classic).", n: "Der Pacuare zählt zu den weltweit schönsten Wildwasserflüssen, oft mit Jungle-Lodge-Übernachtung.", nEn: "The Pacuare is among the world's most scenic whitewater rivers, often with a jungle-lodge stay." },
    cr28: { e: "¿Podemos ver el Río Celeste en el Tenorio?", d: "Können wir den Río Celeste im Tenorio sehen?", dEn: "Can we see the Río Celeste in Tenorio?", s: "Beim Planen des Ausflugs in den Tenorio-Nationalpark.", sEn: "When planning the trip to Tenorio National Park.", n: "Das Türkisblau entsteht durch vulkanische Mineralien, wo zwei Flüsse zusammentreffen.", nEn: "The turquoise comes from volcanic minerals where two rivers meet." },
    cr29: { e: "¿Se ve el volcán hoy o está nublado?", d: "Sieht man den Vulkan heute oder ist es bewölkt?", dEn: "Can you see the volcano today or is it cloudy?", s: "Morgens in La Fortuna, mit Blick zum Arenal.", sEn: "In the morning in La Fortuna, looking towards Arenal.", n: "Der Gipfel ist oft in Wolken; früh aufstehen lohnt sich für freie Sicht.", nEn: "The summit is often clouded; getting up early pays off for a clear view." },
    cr30: { e: "Disculpe, ¿por dónde se va a la playa?", d: "Entschuldigung, wo geht es zum Strand?", dEn: "Excuse me, which way to the beach?", s: "In Manuel Antonio oder Puerto Viejo auf dem Weg zum Wasser.", sEn: "In Manuel Antonio or Puerto Viejo on the way to the water.", n: "Pazifik (Manuel Antonio) und Karibik (Puerto Viejo) fühlen sich völlig verschieden an.", nEn: "The Pacific (Manuel Antonio) and Caribbean (Puerto Viejo) feel completely different." },
    cr31: { e: "¿Se puede surfear aquí? Soy principiante.", d: "Kann man hier surfen? Ich bin Anfänger.", dEn: "Can you surf here? I'm a beginner.", s: "Am Strand von Puerto Viejo oder Cahuita.", sEn: "On the beach at Puerto Viejo or Cahuita.", n: "Puerto Viejo hat die berühmte Welle „Salsa Brava“ – nur für Profis.", nEn: "Puerto Viejo has the famous „Salsa Brava“ wave – pros only." },
    cr32: { e: "¿Puedo alquilar una bici por el día?", d: "Kann ich ein Fahrrad für den Tag mieten?", dEn: "Can I rent a bike for the day?", s: "In Puerto Viejo, um die Strände entlangzufahren.", sEn: "In Puerto Viejo, to ride along the beaches.", n: "Zwischen Puerto Viejo und Manzanillo ist das Rad das beste Verkehrsmittel.", nEn: "Between Puerto Viejo and Manzanillo the bike is the best way to get around." },
    cr33: { e: "¿Hay un tour de cacao en el territorio Bribri?", d: "Gibt es eine Kakao-Tour im Bribri-Gebiet?", dEn: "Is there a cacao tour in the Bribri territory?", s: "An der Südkaribik, beim Besuch des indigenen Reservats.", sEn: "On the southern Caribbean, visiting the indigenous reserve.", n: "Die Bribri zeigen den Weg von der Kakaobohne zur Schokolade – sehr authentisch.", nEn: "The Bribri show the journey from cacao bean to chocolate – very authentic." },
    cr34: { e: "¿Dónde hacen un tour de café por aquí?", d: "Wo gibt es hier eine Kaffeetour?", dEn: "Where can I do a coffee tour around here?", s: "In Monteverde oder im zentralen Hochland.", sEn: "In Monteverde or the central highlands.", n: "Auf den Touren siehst du Ernte, Röstung und probierst frisch gebrühten Kaffee.", nEn: "On the tours you see harvest, roasting and taste freshly brewed coffee." },
    cr35: { e: "¡Qué chiva, mae! Eso estuvo tuanis.", d: "Wie krass, Alter! Das war voll cool.", dEn: "How awesome, dude! That was so cool.", s: "Nach einem Abenteuer wie Rafting, Canopy oder Vulkanwanderung.", sEn: "After an adventure like rafting, canopy or a volcano hike.", n: "„¡Qué chiva!“ und „tuanis“ sind tico-Slang für „genial/super“.", nEn: "„¡Qué chiva!“ and „tuanis“ are Tico slang for „awesome/great“." },
    cr36: { e: "Todo bien, mae, ¡pura vida!", d: "Alles gut, Kumpel, pura vida!", dEn: "All good, mate, pura vida!", s: "Im lockeren Gespräch mit Locals oder der Reisegruppe.", sEn: "In a casual chat with locals or your travel group.", n: "„Mae“ ist allgegenwärtig – etwa wie „Alter“ oder „dude“.", nEn: "„Mae“ is everywhere – a bit like „dude“ or „mate“." },
    cr37: { e: "¿Es seguro caminar por aquí de noche?", d: "Ist es sicher, hier nachts spazieren zu gehen?", dEn: "Is it safe to walk around here at night?", s: "Abends in San José oder einem unbekannten Ort.", sEn: "In the evening in San José or an unfamiliar place.", n: "Costa Rica ist sicher; in San José nachts trotzdem auf Wertsachen achten und Taxi/Uber nehmen.", nEn: "Costa Rica is safe; in San José still watch valuables at night and take a taxi/Uber." },
    cr38: { e: "¿Puedo tomar el agua de la llave aquí?", d: "Kann ich hier das Leitungswasser trinken?", dEn: "Can I drink the tap water here?", s: "Im Hostel oder Restaurant, bevor du Flaschenwasser kaufst.", sEn: "At the hostel or restaurant, before buying bottled water.", n: "In den meisten Regionen ist Leitungswasser sicher; an entlegenen Karibik-Orten lieber fragen.", nEn: "Tap water is safe in most regions; in remote Caribbean spots better ask first." },
    cr39: { e: "¿De dónde sos? Yo viajo con un grupo.", d: "Woher kommst du? Ich reise mit einer Gruppe.", dEn: "Where are you from? I'm travelling with a group.", s: "Beim Kennenlernen im Hostel oder auf einer Tour.", sEn: "Getting to know people at the hostel or on a tour.", n: "Ticos benutzen „vos“ statt „tú“: „¿de dónde sos?“ klingt ganz natürlich.", nEn: "Ticos use „vos“ instead of „tú“: „¿de dónde sos?“ sounds totally natural." },
    cr40: { e: "Estuvo hermoso todo. ¡Muchas gracias por todo, pura vida!", d: "Alles war wunderschön. Vielen Dank für alles, pura vida!", dEn: "Everything was beautiful. Thanks for everything, pura vida!", s: "Beim Abschied von Guide, Gruppe oder Gastgebern.", sEn: "Saying goodbye to your guide, group or hosts.", n: "Ein warmes „pura vida“ zum Abschied bleibt im Gedächtnis und ist echt tico.", nEn: "A warm „pura vida“ goodbye sticks in the memory and is truly Tico." },

    // ===================== ECUADOR (Destination-Pack) =====================
    ec01: { e: "¿Disculpe, dónde tomo un taxi oficial del aeropuerto al centro?", d: "Entschuldigung, wo nehme ich ein offizielles Taxi vom Flughafen ins Zentrum?", dEn: "Excuse me, where do I get an official taxi from the airport to the centre?", s: "Direkt nach der Landung am Flughafen Mariscal Sucre (UIO) bei Quito.", sEn: "Right after landing at Quito's Mariscal Sucre airport (UIO).", n: "Der Flughafen liegt rund 45 Minuten außerhalb; offizielle Taxis am Schalter buchen, Preis vorher klären.", nEn: "The airport is about 45 minutes out; book an official taxi at the desk and settle the price first." },
    ec02: { e: "Por favor, lléveme al centro histórico de Quito.", d: "Bitte bringen Sie mich in die Altstadt von Quito.", dEn: "Please take me to Quito's old town.", s: "Im Taxi auf dem Weg in die Stadt.", sEn: "In the taxi on the way into the city.", n: "Die Altstadt von Quito war 1978 eine der ersten UNESCO-Welterbestätten überhaupt.", nEn: "Quito's old town was one of the very first UNESCO World Heritage sites, in 1978." },
    ec03: { e: "¿Cuánto me cobra hasta el centro, por favor?", d: "Wie viel berechnen Sie mir bis ins Zentrum, bitte?", dEn: "How much do you charge me to the centre, please?", s: "Bevor du ins Taxi steigst oder losfährst.", sEn: "Before getting in or setting off.", n: "Gezahlt wird in US-Dollar; bei Taxis ohne Taxameter den Preis immer vorher vereinbaren.", nEn: "You pay in US dollars; with meterless taxis always agree the price up front." },
    ec04: { e: "Buenos días, ¿cómo está usted?", d: "Guten Morgen, wie geht es Ihnen?", dEn: "Good morning, how are you?", s: "Beim Betreten eines Ladens, einer Pension oder beim Gruß an Einheimische.", sEn: "When entering a shop, a guesthouse or greeting locals.", n: "In den Anden ist ein förmlicher, freundlicher Gruß Pflicht, bevor man irgendetwas fragt.", nEn: "In the Andes a formal, friendly greeting comes before you ask anything." },
    ec05: { e: "¡Alli puncha! Así se dice buenos días en kichwa.", d: "Alli puncha! So sagt man Guten Morgen auf Kichwa.", dEn: "Alli puncha! That's how you say good morning in Kichwa.", s: "Auf dem Otavalo-Markt oder in einer Amazonas-Gemeinde.", sEn: "At the Otavalo market or in an Amazon community.", n: "Kichwa ist die meistgesprochene indigene Sprache Ecuadors; ein Gruß löst oft ein breites Lächeln aus.", nEn: "Kichwa is Ecuador's most-spoken indigenous language; the greeting often earns a big smile." },
    ec06: { e: "¿Qué fue, mano? ¿Todo bien?", d: "Was geht, Kumpel? Alles gut?", dEn: "What's up, man? All good?", s: "Lockerer Gruß unter jüngeren Leuten oder in deiner WeRoad-Gruppe.", sEn: "A casual greeting among younger people or in your WeRoad group.", n: "„¿qué fue?“ ist typisch ecuadorianisch; „mano“ (von hermano) heißt Kumpel.", nEn: "„¿qué fue?“ is typically Ecuadorian; „mano“ (from hermano) means buddy." },
    ec07: { e: "¡Qué chévere, está bacán este lugar!", d: "Wie cool, dieser Ort ist echt super!", dEn: "How cool, this place is really great!", s: "Wenn dir ein Aussichtspunkt, ein Essen oder die Stimmung gefällt.", sEn: "When you love a viewpoint, a dish or the vibe.", n: "chévere und bacán sind die ecuadorianischen Wörter für „cool/super“ und immer passend.", nEn: "chévere and bacán are the Ecuadorian words for „cool/great“ and always fit." },
    ec08: { e: "¿Aquí se paga en dólares, verdad?", d: "Hier zahlt man mit Dollar, oder?", dEn: "You pay in dollars here, right?", s: "An der Kasse oder beim ersten Einkauf im Land.", sEn: "At the till or on your first purchase in the country.", n: "Ecuador hat 2000 den Sucre abgeschafft und nutzt seither offiziell den US-Dollar; keine Wechselstube nötig.", nEn: "Ecuador dropped the Sucre in 2000 and officially uses the US dollar; no exchange office needed." },
    ec09: { e: "¿Tiene sencillo? Solo tengo un billete de veinte.", d: "Haben Sie Wechselgeld? Ich habe nur einen Zwanziger.", dEn: "Do you have change? I only have a twenty.", s: "Beim Bezahlen von etwas Günstigem im Bus, Laden oder Taxi.", sEn: "When paying for something cheap on a bus, in a shop or a taxi.", n: "Kleine Scheine und Münzen sind im Alltag Gold wert; große Scheine kann kaum jemand wechseln.", nEn: "Small bills and coins are gold in daily life; few people can break large bills." },
    ec10: { e: "Voy a comprar algo rapidito en la tienda.", d: "Ich kaufe schnell etwas im Eckladen.", dEn: "I'll quickly buy something at the corner shop.", s: "Für Wasser, Snacks oder eine SIM-Karte unterwegs.", sEn: "For water, snacks or a SIM card on the go.", n: "la tienda ist der kleine Nachbarschaftsladen; oft günstiger und persönlicher als Supermärkte.", nEn: "la tienda is the little neighbourhood shop; often cheaper and friendlier than supermarkets." },
    ec11: { e: "Disculpe, ¿esta buseta va a Otavalo?", d: "Entschuldigung, fährt dieser Kleinbus nach Otavalo?", dEn: "Excuse me, does this minibus go to Otavalo?", s: "Am Busterminal Carcelén in Quito vor der Fahrt nach Norden.", sEn: "At Quito's Carcelén terminal before heading north.", n: "buseta = Kleinbus; nach Otavalo dauert es rund zwei Stunden und kostet nur wenige Dollar.", nEn: "buseta = minibus; Otavalo is about two hours away and costs just a few dollars." },
    ec12: { e: "¿A qué hora sale el próximo bus, por favor?", d: "Um wie viel Uhr fährt der nächste Bus, bitte?", dEn: "What time does the next bus leave, please?", s: "Am Busbahnhof zwischen zwei Etappen der Route.", sEn: "At the bus station between two stages of the route.", n: "An Terminals rufen Helfer die Ziele laut aus; einfach nach dem Ortsnamen Ausschau halten.", nEn: "At terminals helpers shout out destinations; just listen for the place name." },
    ec13: { e: "¿Dónde queda el mercado de Otavalo?", d: "Wo liegt der Markt von Otavalo?", dEn: "Where is the Otavalo market?", s: "In Otavalo auf der Suche nach der Plaza de los Ponchos.", sEn: "In Otavalo, looking for the Plaza de los Ponchos.", n: "Der Markt (Plaza de los Ponchos) ist der größte Indigenen-Markt der Anden; samstags ist er am lebhaftesten.", nEn: "The market (Plaza de los Ponchos) is the largest Andean indigenous market; Saturday is busiest." },
    ec14: { e: "¿Este chal es hecho a mano?", d: "Ist dieses Tuch handgemacht?", dEn: "Is this scarf handmade?", s: "An einem Stand mit Webwaren in Otavalo.", sEn: "At a weaving stall in Otavalo.", n: "hecho a mano = handgemacht; echte Alpaka- oder Schafwolle fühlt sich wärmer an als Acryl.", nEn: "hecho a mano = handmade; real alpaca or sheep wool feels warmer than acrylic." },
    ec15: { e: "¿Me puede dar un mejorcito en el precio?", d: "Können Sie mir beim Preis ein bisschen entgegenkommen?", dEn: "Could you give me a slightly better price?", s: "Beim freundlichen Handeln auf dem Otavalo-Markt.", sEn: "When haggling kindly at the Otavalo market.", n: "„un mejorcito“ ist die höfliche Art, nach Rabatt zu fragen; lächeln statt feilschen.", nEn: "„un mejorcito“ is the polite way to ask for a discount; smile rather than haggle hard." },
    ec16: { e: "¿Qué tan lejos queda la mitad del mundo?", d: "Wie weit ist es bis zur Mitte der Welt?", dEn: "How far is it to the middle of the world?", s: "In Quito bei der Planung des Äquator-Ausflugs.", sEn: "In Quito, planning the Equator excursion.", n: "la mitad del mundo = das Äquatordenkmal in San Antonio de Pichincha, etwa eine Stunde nördlich.", nEn: "la mitad del mundo = the Equator monument in San Antonio de Pichincha, about an hour north." },
    ec17: { e: "¿Me toma una foto sobre la línea ecuatorial?", d: "Machen Sie ein Foto von mir auf der Äquatorlinie?", dEn: "Will you take a photo of me on the Equator line?", s: "Am Äquatordenkmal mit einem Bein in jeder Hemisphäre.", sEn: "At the Equator monument with one foot in each hemisphere.", n: "Im nahen Museo Intiñan zeigen sie Äquator-Experimente; Breite 0°.", nEn: "The nearby Museo Intiñan shows Equator experiments; latitude 0°." },
    ec18: { e: "Me siento un poco mal por la altura.", d: "Mir ist von der Höhe etwas schlecht.", dEn: "I feel a bit sick from the altitude.", s: "An den ersten Tagen in Quito oder am Quilotoa.", sEn: "In the first days in Quito or at Quilotoa.", n: "Quito liegt auf 2.850 m, Quilotoa noch höher; soroche = Höhenkrankheit, langsam machen hilft.", nEn: "Quito sits at 2,850 m, Quilotoa higher; soroche = altitude sickness, taking it slow helps." },
    ec19: { e: "¿Tiene un agüita para el soroche?", d: "Haben Sie einen Kräutertee gegen die Höhenkrankheit?", dEn: "Do you have a herbal tea for altitude sickness?", s: "In einem Café oder einer Pension in den Hochanden.", sEn: "In a café or guesthouse in the high Andes.", n: "agüita ist ein Aufguss (oft Kräuter wie Kamille oder hierba luisa); dazu viel Wasser und wenig Alkohol.", nEn: "agüita is an infusion (often herbs like chamomile or hierba luisa); drink lots of water and little alcohol." },
    ec20: { e: "¡Achachay, qué frío hace aquí arriba!", d: "Brrr, ist das kalt hier oben!", dEn: "Brrr, it's so cold up here!", s: "Am frühen Morgen am Cotopaxi oder am Quilotoa-Krater.", sEn: "Early morning at Cotopaxi or the Quilotoa crater.", n: "achachay ist ein Kichwa-Wort, das alle Ecuadorianer für „brrr, kalt!“ benutzen.", nEn: "achachay is a Kichwa word all Ecuadorians use for „brrr, cold!“" },
    ec21: { e: "¡Arrarray, esta sopa está caliente!", d: "Autsch, diese Suppe ist heiß!", dEn: "Ouch, this soup is hot!", s: "Beim ersten Löffel einer dampfenden Locro-Suppe.", sEn: "At the first spoon of a steaming locro soup.", n: "arrarray ist das Gegenstück zu achachay und bedeutet „heiß!“ — beide aus dem Kichwa.", nEn: "arrarray is the counterpart to achachay and means „hot!“ — both from Kichwa." },
    ec22: { e: "¿Se ve el volcán Cotopaxi hoy?", d: "Sieht man den Vulkan Cotopaxi heute?", dEn: "Can you see the Cotopaxi volcano today?", s: "Bei der Ankunft im Cotopaxi-Nationalpark.", sEn: "On arrival at Cotopaxi National Park.", n: "Cotopaxi ist mit 5.897 m einer der höchsten aktiven Vulkane; sein Gipfel zeigt sich am klarsten frühmorgens.", nEn: "At 5,897 m Cotopaxi is one of the highest active volcanoes; its peak shows clearest at dawn." },
    ec23: { e: "¿Cuánto se demora la caminata hasta el refugio?", d: "Wie lange dauert die Wanderung bis zur Schutzhütte?", dEn: "How long is the hike up to the refuge?", s: "Vor dem Aufstieg zur Cotopaxi-Hütte mit der Gruppe.", sEn: "Before the climb to the Cotopaxi refuge with the group.", n: "Der refugio liegt auf rund 4.800 m; der Weg ist kurz, aber die Höhe macht ihn anstrengend.", nEn: "The refugio sits around 4,800 m; the path is short but the altitude makes it hard." },
    ec24: { e: "La laguna de Quilotoa es realmente impresionante.", d: "Die Quilotoa-Lagune ist wirklich atemberaubend.", dEn: "The Quilotoa lagoon is truly breathtaking.", s: "Am Kraterrand beim ersten Blick auf das Wasser.", sEn: "At the crater rim, first sight of the water.", n: "Der türkisgrüne See füllt eine bei einer Eruption um 1280 entstandene Caldera; der Abstieg dauert 30 Min., der Aufstieg fühlt sich endlos an.", nEn: "The turquoise lake fills a caldera formed by an eruption around 1280; 30 min down, the climb back feels endless." },
    ec25: { e: "¿Se puede caminar por el filo del cráter?", d: "Kann man am Kraterrand entlangwandern?", dEn: "Can you hike along the crater rim?", s: "Oben am Quilotoa bei der Planung der Wanderung.", sEn: "Up at Quilotoa, planning the hike.", n: "Die Rundwanderung um den Krater dauert mehrere Stunden und ist windig; warm anziehen.", nEn: "The full rim loop takes several hours and is windy; dress warm." },
    ec26: { e: "Vamos a las aguas termales de Baños esta noche.", d: "Gehen wir heute Abend in die Thermalquellen von Baños.", dEn: "Let's go to the hot springs of Baños tonight.", s: "Nach der Ankunft in Baños de Agua Santa.", sEn: "After arriving in Baños de Agua Santa.", n: "Die Becken am Fuß des Tungurahua sind abends am stimmungsvollsten; Badesachen nicht vergessen.", nEn: "The pools below Tungurahua are most atmospheric at night; don't forget swimwear." },
    ec27: { e: "Me gustaría probar el columpio del fin del mundo.", d: "Ich würde gern die Schaukel am Ende der Welt ausprobieren.", dEn: "I'd love to try the swing at the end of the world.", s: "Beim Ausflug zur Casa del Árbol oberhalb von Baños.", sEn: "On the trip to the Casa del Árbol above Baños.", n: "Die Schaukel hängt über einem Tal mit Blick auf den Vulkan; angeschnallt völlig sicher.", nEn: "The swing hangs over a valley facing the volcano; harnessed, it's perfectly safe." },
    ec28: { e: "¿Qué tours de aventura hay por aquí?", d: "Welche Abenteuertouren gibt es hier?", dEn: "What adventure tours are there here?", s: "In einer Tour-Agentur in Baños.", sEn: "At a tour agency in Baños.", n: "Baños ist Ecuadors Abenteuer-Hauptstadt: Rafting, Canyoning, Zipline und die Ruta de las Cascadas.", nEn: "Baños is Ecuador's adventure capital: rafting, canyoning, zipline and the waterfall route." },
    ec29: { e: "¿Mañana bajamos a la Amazonía, a Tena?", d: "Fahren wir morgen in den Amazonas nach Tena?", dEn: "Are we heading down to the Amazon to Tena tomorrow?", s: "Beim Planen der nächsten Etappe mit der Gruppe.", sEn: "Planning the next stage with the group.", n: "Tena liegt im Oberen Amazonasbecken und ist Ecuadors Basis für Rafting und Dschungeltouren.", nEn: "Tena lies in the upper Amazon basin and is Ecuador's base for rafting and jungle trips." },
    ec30: { e: "¿El guía nos puede explicar la selva mientras caminamos?", d: "Kann der Guide uns beim Gehen den Regenwald erklären?", dEn: "Can the guide explain the rainforest as we walk?", s: "Bei der Dschungelwanderung im Amazonasgebiet.", sEn: "On the jungle walk in the Amazon region.", n: "Lokale Kichwa-Guides kennen Heilpflanzen, Spuren und Geräusche; immer dicht hinter ihnen bleiben.", nEn: "Local Kichwa guides know healing plants, tracks and sounds; stay close behind them." },
    ec31: { e: "¿Veremos monos o tucanes en la selva?", d: "Werden wir im Regenwald Affen oder Tukane sehen?", dEn: "Will we see monkeys or toucans in the rainforest?", s: "Vor einer frühen Bootsfahrt oder Wanderung im Amazonas.", sEn: "Before an early boat trip or walk in the Amazon.", n: "Tiere zeigen sich am ehesten in der Morgendämmerung; leise sein und Fernglas mitnehmen.", nEn: "Wildlife shows up best at dawn; stay quiet and bring binoculars." },
    ec32: { e: "Un encebollado bien caliente, por favor.", d: "Einen schön heißen Encebollado, bitte.", dEn: "One nice hot encebollado, please.", s: "Morgens an einem Marktstand oder in einer Fonda.", sEn: "In the morning at a market stall or a fonda.", n: "encebollado ist Ecuadors herzhaftes Frühstück: Thunfischsuppe mit Yuca und Zwiebeln, auch beliebt gegen Kater.", nEn: "encebollado is Ecuador's hearty breakfast: tuna soup with yuca and onions, also loved as a hangover cure." },
    ec33: { e: "¿Hay ceviche de camarón aquí?", d: "Gibt es hier Garnelen-Ceviche?", dEn: "Is there shrimp ceviche here?", s: "An der Küste oder in einem Cevichería-Lokal.", sEn: "On the coast or at a cevichería.", n: "Ecuadors ceviche ist saftiger als das peruanische, oft mit Tomatensud, und wird mit Chifles (Kochbananenchips) gegessen.", nEn: "Ecuadorian ceviche is juicier than the Peruvian, often tomato-based, and eaten with chifles (plantain chips)." },
    ec34: { e: "¿Qué trae el hornado que se ve tan rico?", d: "Was ist im Hornado, der so lecker aussieht?", dEn: "What's in the hornado that looks so good?", s: "An einem Markt-Imbiss in der Sierra.", sEn: "At a market food stall in the Sierra.", n: "hornado ist langsam gegartes Schwein, serviert mit Mais, llapingachos (Kartoffelpuffer) und Avocado.", nEn: "hornado is slow-roasted pork, served with corn, llapingachos (potato cakes) and avocado." },
    ec35: { e: "¿El locro de papa es muy picante?", d: "Ist der Kartoffel-Locro sehr scharf?", dEn: "Is the potato locro very spicy?", s: "Beim Bestellen einer warmen Suppe in den Anden.", sEn: "When ordering a warm soup in the Andes.", n: "locro de papa ist mild und cremig, mit Käse, Avocado und manchmal ají am Tisch zum Selbstwürzen.", nEn: "locro de papa is mild and creamy, with cheese, avocado and ají on the table to spice it yourself." },
    ec36: { e: "Mejor pruebo algo distinto a la guatita, gracias.", d: "Ich probiere lieber etwas anderes als die Guatita, danke.", dEn: "I'd rather try something other than the guatita, thanks.", s: "Wenn auf der Karte ein sehr lokales Gericht steht.", sEn: "When a very local dish is on the menu.", n: "guatita ist Kutteleintopf in Erdnusssauce — eine Delikatesse, aber nicht für jeden Magen.", nEn: "guatita is tripe stew in peanut sauce — a delicacy, but not for every stomach." },
    ec37: { e: "¿Es seguro caminar por aquí de noche?", d: "Ist es sicher, hier nachts zu Fuß zu gehen?", dEn: "Is it safe to walk here at night?", s: "Abends beim Verlassen eines Restaurants in einer Stadt.", sEn: "In the evening, leaving a restaurant in a city.", n: "Wie überall in Lateinamerika: Wertsachen verstecken, nachts App-Taxis nehmen und Locals nach No-Go-Vierteln fragen.", nEn: "As across Latin America: hide valuables, take app taxis at night and ask locals about no-go areas." },
    ec38: { e: "¿Dónde puedo retirar dólares en un cajero que sí funcione?", d: "Wo kann ich an einem funktionierenden Automaten Dollar abheben?", dEn: "Where can I withdraw dollars at an ATM that actually works?", s: "Wenn das Bargeld vor einer Busfahrt knapp wird.", sEn: "When cash runs low before a bus ride.", n: "Automaten (cajeros) haben oft Tageslimits und Gebühren; tagsüber an belebten, sicheren Orten abheben.", nEn: "ATMs (cajeros) often have daily limits and fees; withdraw by day in busy, safe spots." },
    ec39: { e: "¡Muchas gracias, todo estuvo hermoso!", d: "Vielen Dank, alles war wunderschön!", dEn: "Thank you so much, everything was beautiful!", s: "Beim Abschied von Guides, Gastgebern oder am Reiseende.", sEn: "Saying goodbye to guides, hosts or at the end of the trip.", n: "Ehrliches Lob für Land und Leute wird in Ecuador sehr geschätzt und oft warm erwidert.", nEn: "Honest praise for the country and its people is much appreciated in Ecuador and warmly returned." },
    ec40: { e: "Vamos a las islas Galápagos como extensión del viaje.", d: "Wir fliegen als Verlängerung auf die Galápagos-Inseln.", dEn: "We're flying to the Galápagos Islands as a trip extension.", s: "Beim Planen der optionalen Galápagos-Verlängerung in Quito.", sEn: "Planning the optional Galápagos extension in Quito.", n: "Galápagos erreicht man per Flug ab Quito; die Nationalpark-Gebühr zahlt man in bar (USD) bei Ankunft.", nEn: "Galápagos is reached by flight from Quito; you pay the national park fee in cash (USD) on arrival." },

    // ===================== GUATEMALA (Destination-Pack) =====================
    gt01: { e: "¿Dónde encuentro un taxi para Antigua?", d: "Direkt am Flughafen La Aurora in Guatemala-Stadt.", dEn: "Right at La Aurora airport in Guatemala City.", s: "Beim Verlassen der Ankunftshalle, wo die Fahrer warten.", sEn: "As you leave the arrivals hall where drivers wait.", n: "Nimm offizielle Flughafentaxis oder eine App – sicherer als spontane Straßentaxis.", nEn: "Take official airport taxis or an app – safer than flagging one on the street." },
    gt02: { e: "Lléveme a Antigua, por favor.", d: "Antigua liegt rund 45 Minuten vom Flughafen entfernt.", dEn: "Antigua is about 45 minutes from the airport.", s: "Im Taxi oder Shuttle, wenn du das Ziel nennst.", sEn: "In the taxi or shuttle when you state your destination.", n: "Shuttle-Sammelbusse nach Antigua sind günstig und unter Backpackern üblich.", nEn: "Shared shuttles to Antigua are cheap and popular with backpackers." },
    gt03: { e: "¿Cuánto cuesta el viaje desde el aeropuerto?", d: "Frag den Preis, bevor du einsteigst.", dEn: "Ask the price before you get in.", s: "Am Taxistand oder beim Shuttle-Schalter.", sEn: "At the taxi rank or the shuttle desk.", n: "Taxis haben oft kein Taxameter – Festpreis vorher aushandeln.", nEn: "Taxis often have no meter – agree a fixed price first." },
    gt04: { e: "¡Saqʼarik! Buenos días.", d: "„Saqʼarik“ ist der Morgengruß auf Kʼicheʼ-Maya.", dEn: "„Saqʼarik“ is the morning greeting in Kʼicheʼ Maya.", s: "Im Hochland um Atitlán oder Chichicastenango.", sEn: "In the highlands around Atitlán or Chichicastenango.", n: "Ein Maya-Gruß öffnet Herzen – viele im Hochland sprechen Kʼicheʼ als Erstsprache.", nEn: "A Maya greeting wins hearts – many highlanders speak Kʼicheʼ as their first language." },
    gt05: { e: "¿Qué onda, vos?", d: "In Guatemala duzt man mit „vos“ statt „tú“.", dEn: "In Guatemala people use „vos“ instead of „tú“.", s: "Im lockeren Gespräch mit Gleichaltrigen.", sEn: "In casual chat with people your age.", n: "„¿Qué onda, vos?“ ist sehr chapín; bei Älteren bleibt „usted“ höflich.", nEn: "„¿Qué onda, vos?“ is very chapín; with elders „usted“ stays polite." },
    gt06: { e: "¡Qué chilero!", d: "„Chilero“ heißt cool, klasse, super.", dEn: "„Chilero“ means cool, great, awesome.", s: "Als spontane Begeisterung über Essen, Aussicht oder Plan.", sEn: "As spontaneous delight about food, a view or a plan.", n: "Typisch guatemaltekisch – in keinem anderen Land so gebräuchlich.", nEn: "Typically Guatemalan – not as common in any other country." },
    gt07: { e: "¿Cuánto cuesta en quetzales?", d: "Die Währung heißt Quetzal (GTQ), nach dem Nationalvogel.", dEn: "The currency is the quetzal (GTQ), named after the national bird.", s: "Beim Bezahlen auf dem Markt oder im Laden.", sEn: "When paying at the market or in a shop.", n: "Etwa 1 Euro entspricht grob 8 Quetzales – immer aktuell prüfen.", nEn: "Roughly 1 euro is about 8 quetzales – always check the current rate." },
    gt08: { e: "¿Me lo deja un poco más barato?", d: "Auf Märkten ist freundliches Handeln üblich.", dEn: "Friendly haggling is normal at markets.", s: "Am Stand in Chichicastenango oder Panajachel.", sEn: "At a stall in Chichicastenango or Panajachel.", n: "In Läden mit Festpreis nicht handeln – nur auf offenen Märkten.", nEn: "Don't haggle in fixed-price shops – only at open markets." },
    gt09: { e: "¿Dónde puedo sacar pisto?", d: "„Pisto“ ist guatemaltekischer Slang für Geld.", dEn: "„Pisto“ is Guatemalan slang for money.", s: "Auf der Suche nach einem Geldautomaten.", sEn: "When looking for an ATM.", n: "Heb in der Stadt ab; auf dem Land sind Automaten selten und Bargeld König.", nEn: "Withdraw in town; ATMs are scarce rurally and cash is king." },
    gt10: { e: "¿De dónde sale la camioneta para Panajachel?", d: "„Camioneta“ ist der bunte alte US-Schulbus, der Chicken Bus.", dEn: "„Camioneta“ is the colourful old US school bus, the chicken bus.", s: "Am chaotischen Busbahnhof im Hochland.", sEn: "At the chaotic highland bus terminal.", n: "Camionetas sind spottbillig und ein Erlebnis – aber voll und ohne Fahrplan.", nEn: "Camionetas are dirt cheap and an experience – but crowded and timetable-free." },
    gt11: { e: "¿Esta camioneta para en Chichicastenango?", d: "Frag den Ayudante (Beifahrer), der das Geld kassiert.", dEn: "Ask the ayudante (conductor) who collects the fare.", s: "Beim Einsteigen oder unterwegs im Chicken Bus.", sEn: "When boarding or en route on the chicken bus.", n: "Der Ayudante hängt oft an der Tür und ruft die Ziele aus.", nEn: "The ayudante often hangs from the door shouting destinations." },
    gt12: { e: "¿Podemos tomar un tuc-tuc?", d: "Tuk-Tucs sind kleine dreirädrige Taxis für kurze Strecken.", dEn: "Tuk-tuks are small three-wheeled taxis for short trips.", s: "In Dörfern und Kleinstädten, wo keine Taxis fahren.", sEn: "In villages and small towns without regular taxis.", n: "Preise sind niedrig, aber vorher den Fahrpreis abklären.", nEn: "Fares are low, but agree the price beforehand." },
    gt13: { e: "¿A qué hora sale la lancha por el lago?", d: "Über den Lago de Atitlán reist man per Boot (lancha).", dEn: "You cross Lake Atitlán by boat (lancha).", s: "Am Bootssteg in Panajachel oder einem der Dörfer.", sEn: "At the jetty in Panajachel or one of the villages.", n: "Lanchas fahren oft erst los, wenn sie voll sind – plan etwas Zeit ein.", nEn: "Lanchas often leave only when full – allow some extra time." },
    gt14: { e: "Quiero ir a San Pedro la Laguna.", d: "San Pedro ist ein lebhaftes Backpacker-Dorf am See.", dEn: "San Pedro is a lively backpacker village on the lake.", s: "Beim Lösen des Bootstickets am Steg.", sEn: "When buying the boat ticket at the dock.", n: "Jedes Atitlán-Dorf hat eigenen Charakter – San Pedro ist das Party- und Sprachschuldorf.", nEn: "Each Atitlán village has its own character – San Pedro is the party and language-school hub." },
    gt15: { e: "¿Dónde atraca la lancha para San Juan?", d: "San Juan la Laguna ist berühmt für Webereien und Wandbilder.", dEn: "San Juan la Laguna is famous for weaving co-ops and murals.", s: "Beim Bootswechsel zwischen den Seedörfern.", sEn: "When changing boats between lake villages.", n: "In San Juan zeigen Frauenkooperativen das Färben mit Naturpflanzen.", nEn: "In San Juan women's co-ops demonstrate dyeing with natural plants." },
    gt16: { e: "Quisiera un pepián, por favor.", d: "Pepián ist ein würziger Eintopf und gilt als Nationalgericht.", dEn: "Pepián is a spicy stew, considered the national dish.", s: "In einem Comedor oder einer típica-Küche.", sEn: "In a comedor or a típica eatery.", n: "Pepián hat Maya-Wurzeln: Fleisch in Soße aus geröstetem Kürbiskern und Chili.", nEn: "Pepián has Maya roots: meat in a sauce of toasted pumpkin seed and chilli." },
    gt17: { e: "¿Hay tamales hoy?", d: "Tamales aus Maismasa werden in Blättern gedämpft.", dEn: "Tamales of corn masa are steamed in leaves.", s: "Vor allem abends und am Wochenende an Ständen.", sEn: "Mainly in the evenings and weekends at stalls.", n: "Guatemaltekische Tamales sind oft in Bananenblatt – ein Sonntags-Klassiker.", nEn: "Guatemalan tamales often come in banana leaf – a Sunday classic." },
    gt18: { e: "Dos tostadas con frijoles, por favor.", d: "Tostadas sind knusprige Tortillas mit Belag wie Bohnen.", dEn: "Tostadas are crispy tortillas topped with beans and more.", s: "Als Snack am Marktstand oder Comedor.", sEn: "As a snack at a market stall or comedor.", n: "Frijoles (schwarze Bohnen) gehören zu fast jeder Mahlzeit.", nEn: "Frijoles (black beans) come with almost every meal." },
    gt19: { e: "¿Qué es el güisquil?", d: "Güisquil ist der Chayote, ein milder Kürbis.", dEn: "Güisquil is the chayote, a mild squash.", s: "Wenn du eine unbekannte Zutat auf der Karte siehst.", sEn: "When you spot an unfamiliar ingredient on the menu.", n: "Güisquil landet in Suppen und Eintöpfen – das Wort stammt aus dem Nahuatl.", nEn: "Güisquil goes into soups and stews – the word comes from Nahuatl." },
    gt20: { e: "Un café de la región, por favor.", d: "Guatemala produziert weltberühmten Hochlandkaffee.", dEn: "Guatemala produces world-famous highland coffee.", s: "Im Café in Antigua oder auf einer Finca.", sEn: "In a café in Antigua or on a coffee finca.", n: "Antigua, Atitlán und Huehuetenango sind angesehene Anbauregionen.", nEn: "Antigua, Atitlán and Huehuetenango are respected growing regions." },
    gt21: { e: "¡Qué rico! ¿Me trae más tortillas?", d: "Frische Maistortillas begleiten fast jedes Gericht.", dEn: "Fresh corn tortillas accompany almost every dish.", s: "Beim Essen, wenn der Korb leer ist.", sEn: "While eating, when the basket is empty.", n: "Tortillas werden oft handgeklatscht und warm serviert – ruhig nachbestellen.", nEn: "Tortillas are often hand-patted and served warm – feel free to ask for more." },
    gt22: { e: "¿Qué día es el mercado en Chichicastenango?", d: "Der große Markt ist donnerstags und sonntags.", dEn: "The big market runs on Thursdays and Sundays.", s: "Bei der Tagesplanung im Hochland.", sEn: "When planning your highland days.", n: "„Chichi“ ist einer der größten indigenen Märkte Mittelamerikas.", nEn: "„Chichi“ is one of Central America's largest Indigenous markets." },
    gt23: { e: "¿Estos tejidos son hechos a mano?", d: "Viele Textilien werden noch am Rückengurt-Webstuhl gewebt.", dEn: "Many textiles are still woven on a backstrap loom.", s: "Am Textilstand auf dem Markt.", sEn: "At a textile stall in the market.", n: "Handgewebtes kostet mehr, aber unterstützt Maya-Weberinnen direkt.", nEn: "Handwoven costs more but supports Maya weavers directly." },
    gt24: { e: "¿Qué significa el diseño de este huipil?", d: "Der Huipil ist die bestickte Bluse der Maya-Frauen.", dEn: "The huipil is the embroidered blouse of Maya women.", s: "Im Gespräch mit einer Verkäuferin über ihr Kunsthandwerk.", sEn: "Chatting with a vendor about her craft.", n: "Muster und Farben verraten oft das Heimatdorf der Trägerin.", nEn: "Patterns and colours often reveal the wearer's home village." },
    gt25: { e: "¿Puedo tomar una foto del puesto?", d: "Frag immer um Erlaubnis, bevor du Menschen fotografierst.", dEn: "Always ask permission before photographing people.", s: "Auf dem Markt vor einem schönen Motiv.", sEn: "At the market in front of a great shot.", n: "Maya-Gemeinschaften reagieren sensibel auf Fotos – Respekt zahlt sich aus.", nEn: "Maya communities can be sensitive about photos – respect pays off." },
    gt26: { e: "¿Qué tan lejos están las ruinas de Tikal?", d: "Tikal ist die berühmteste Maya-Stadt im Petén-Dschungel.", dEn: "Tikal is the most famous Maya city in the Petén jungle.", s: "Bei der Tourplanung in Flores.", sEn: "When planning the tour from Flores.", n: "Von Flores sind es rund 1,5 Stunden – früh los lohnt sich.", nEn: "It's about 1.5 hours from Flores – leaving early is worth it." },
    gt27: { e: "¿Se puede subir a la gran pirámide?", d: "Einige Tempel-Pyramiden in Tikal darf man besteigen.", dEn: "Some temple pyramids at Tikal can be climbed.", s: "Vor Ort beim Erkunden der Ruinen.", sEn: "On site while exploring the ruins.", n: "Vom Tempel IV blickst du über das Dschungeldach – Star-Wars-Drehort.", nEn: "From Temple IV you look out over the jungle canopy – a Star Wars filming spot." },
    gt28: { e: "¿Hay un tour guiado al amanecer?", d: "Sonnenaufgangstouren zeigen Tikal im Morgennebel.", dEn: "Sunrise tours show Tikal in the morning mist.", s: "Beim Buchen der Tour am Vorabend.", sEn: "When booking the tour the evening before.", n: "Im Morgendunst über dem Dschungel brüllen die Affen am lautesten.", nEn: "In the dawn haze over the jungle the monkeys roar loudest." },
    gt29: { e: "¡Escucho monos aulladores en la selva!", d: "Brüllaffen sind im Petén-Dschungel oft zu hören.", dEn: "Howler monkeys are often heard in the Petén jungle.", s: "Beim Wandern zwischen den Ruinen.", sEn: "While hiking among the ruins.", n: "Ihr tiefes Brüllen klingt fast wie ein Sturm – völlig harmlos.", nEn: "Their deep roar sounds almost like a storm – completely harmless." },
    gt30: { e: "¿Hay una lancha de regreso a Flores?", d: "Flores ist eine charmante Inselstadt im Petén-See.", dEn: "Flores is a charming island town on Lake Petén Itzá.", s: "Am Abend zurück von Tikal oder beim Bootsausflug.", sEn: "Heading back from Tikal in the evening or on a lake trip.", n: "Flores ist über einen Damm verbunden; lanchas drehen Runden über den See.", nEn: "Flores is linked by a causeway; lanchas loop around the lake." },
    gt31: { e: "¿Cuánto dura la caminata al Acatenango?", d: "Der Acatenango ist ein 3976 m hoher Vulkan bei Antigua.", dEn: "Acatenango is a 3,976 m volcano near Antigua.", s: "Beim Buchen der zweitägigen Vulkanwanderung.", sEn: "When booking the two-day volcano hike.", n: "Meist Übernachtung im Camp – anstrengend, aber spektakulär.", nEn: "Usually an overnight camp – tough but spectacular." },
    gt32: { e: "¿Se ve el Fuego haciendo erupción desde ahí?", d: "Vom Acatenango blickt man auf den aktiven Fuego.", dEn: "From Acatenango you look across at the active Fuego.", s: "Nachts vom Basislager aus.", sEn: "At night from the base camp.", n: "Der Fuego speit fast täglich Lava – ein unvergessliches Schauspiel.", nEn: "Fuego spews lava almost daily – an unforgettable sight." },
    gt33: { e: "¿Necesito un guía y ropa abrigada?", d: "Für den Acatenango brauchst du Guide und warme Kleidung.", dEn: "For Acatenango you need a guide and warm clothing.", s: "Bei der Vorbereitung der Vulkantour.", sEn: "When preparing for the volcano tour.", n: "Nachts fällt die Temperatur am Gipfel oft unter null Grad.", nEn: "At night the summit temperature often drops below freezing." },
    gt34: { e: "¿Cómo se llega a las pozas de Semuc Champey?", d: "Semuc Champey sind türkise Kalkbecken über einem Fluss.", dEn: "Semuc Champey are turquoise limestone pools over a river.", s: "Beim Planen des Ausflugs von Lanquín aus.", sEn: "When planning the trip from Lanquín.", n: "Die holprige Anfahrt nach Lanquín ist lang, das Naturwunder aber unvergesslich.", nEn: "The bumpy ride to Lanquín is long, but the natural wonder is unforgettable." },
    gt35: { e: "¿Se puede entrar a las cuevas de Kʼanba?", d: "Die Kʼanba-Höhlen erkundet man mit Kerze im Wasser.", dEn: "The Kʼanba caves are explored by candlelight in the water.", s: "Als Zusatztour bei Semuc Champey.", sEn: "As an add-on tour at Semuc Champey.", n: "Man watet und schwimmt mit Kerze durch unterirdische Flüsse – Abenteuer pur.", nEn: "You wade and swim with a candle through underground rivers – pure adventure." },
    gt36: { e: "¡Aguas, el suelo está resbaloso!", d: "„¡Aguas!“ ist ein Warnruf wie „Vorsicht!“.", dEn: "„¡Aguas!“ is a warning shout like „watch out!“.", s: "Auf nassen Felsen bei Semuc Champey oder am See.", sEn: "On wet rocks at Semuc Champey or by the lake.", n: "Der Ausdruck stammt aus Mexiko/Mittelamerika und ist hier alltäglich.", nEn: "The phrase comes from Mexico/Central America and is everyday here." },
    gt37: { e: "¿Esta zona es segura de noche?", d: "Frag Locals oder das Hostel nach sicheren Wegen.", dEn: "Ask locals or your hostel about safe routes.", s: "Bevor du abends allein losziehst.", sEn: "Before heading out alone in the evening.", n: "In Guatemala-Stadt nachts lieber Taxi nehmen; Antigua und die Seedörfer sind ruhiger.", nEn: "In Guatemala City take a taxi at night; Antigua and the lake villages are calmer." },
    gt38: { e: "¿Me puede llamar un taxi de confianza?", d: "Bitte das Hostel um ein vertrauenswürdiges Taxi.", dEn: "Ask your hostel for a trustworthy taxi.", s: "An der Rezeption, wenn du abends wegmusst.", sEn: "At reception when you need to head out at night.", n: "Bestellte Taxis „de confianza“ sind sicherer als auf der Straße gewinkte.", nEn: "Pre-arranged „de confianza“ taxis are safer than ones flagged on the street." },
    gt39: { e: "¿Vos también sos chapín?", d: "„Chapín“ ist der liebevolle Spitzname für Guatemalteken.", dEn: "„Chapín“ is the affectionate nickname for Guatemalans.", s: "Beim Kennenlernen anderer Reisender oder Locals.", sEn: "When getting to know fellow travellers or locals.", n: "Mit „vos“ und „chapín“ klingst du sofort vertraut – das öffnet Gespräche.", nEn: "Using „vos“ and „chapín“ sounds instantly familiar – it opens up conversations." },
    gt40: { e: "¡Gracias, qué chilero estuvo el viaje!", d: "Ein warmer, sehr guatemaltekischer Abschiedssatz.", dEn: "A warm, very Guatemalan farewell line.", s: "Beim Abschied von der Gruppe oder den Gastgebern.", sEn: "When saying goodbye to your group or hosts.", n: "Verbindet Dank mit dem typischen „chilero“ – kommt unter chapines super an.", nEn: "Pairs thanks with the classic „chilero“ – goes down great with chapines." },

    // ===================== ARGENTINIEN (Destination-Pack) =====================
    ar01: { e: "Hola, ¿dónde tomo un taxi en el aeropuerto?", d: "Hallo, wo bekomme ich ein Taxi vom Flughafen?", dEn: "Hi, where do I get a taxi from the airport?", s: "Direkt nach der Landung in Ezeiza oder Aeroparque (Buenos Aires).", sEn: "Right after landing at Ezeiza or Aeroparque (Buenos Aires).", n: "Nimm offizielle Taxis am Schalter oder eine App wie Cabify/Uber – das spart Diskussionen.", nEn: "Take official taxis from the counter or an app like Cabify/Uber – it avoids haggling." },
    ar02: { e: "Lléveme a Palermo, por favor.", d: "Bringen Sie mich bitte nach Palermo.", dEn: "Take me to Palermo, please.", s: "Im Taxi, wenn du dein Viertel ansteuerst.", sEn: "In the taxi when heading to your district.", n: "Palermo (Soho/Hollywood) ist das Hostel- und Ausgehviertel schlechthin in Buenos Aires.", nEn: "Palermo (Soho/Hollywood) is the go-to hostel and nightlife district in Buenos Aires." },
    ar03: { e: "Che, ¿todo bien? ¿De dónde sos?", d: "Hey, alles gut? Woher kommst du?", dEn: "Hey, all good? Where are you from?", s: "Beim ersten Smalltalk im Hostel oder in der Tourgruppe.", sEn: "For first small talk at the hostel or in the tour group.", n: "„Che“ und „sos“ machen dich sofort sympathisch – das ist Rioplatense pur.", nEn: "„Che“ and „sos“ instantly make you sound friendly – that's pure Rioplatense." },
    ar04: { e: "¿Querés venir esta noche?", d: "Magst du heute Abend mitkommen?", dEn: "Do you want to come along tonight?", s: "Wenn du jemanden zum Ausgehen einlädst.", sEn: "When inviting someone out.", n: "„Querés“ ist der voseo zu „quieres“ – in Argentinien Standard, nicht salopp.", nEn: "„Querés“ is the voseo of „quieres“ – standard in Argentina, not slangy." },
    ar05: { e: "¡Bárbaro, dale, hagámoslo!", d: "Super, alles klar, machen wir!", dEn: "Great, all good, let's do it!", s: "Wenn du einem Plan begeistert zustimmst.", sEn: "When you enthusiastically agree to a plan.", n: "„Dale“ ist das Allzweck-Ja Argentiniens; „bárbaro“ heißt klasse, nicht barbarisch.", nEn: "„Dale“ is Argentina's all-purpose yes; „bárbaro“ means great, not barbaric." },
    ar06: { e: "¿Dónde puedo cargar la tarjeta SUBE?", d: "Wo kann ich die SUBE-Karte aufladen?", dEn: "Where can I top up the SUBE card?", s: "Vor der ersten Fahrt mit colectivo oder subte.", sEn: "Before your first ride on the bus or metro.", n: "Die SUBE bekommst du an Kiosken; ohne sie wird's im Nahverkehr umständlich.", nEn: "Get the SUBE at kiosks; without it local transport gets awkward." },
    ar07: { e: "¿Qué colectivo va al centro?", d: "Welcher Bus fährt ins Zentrum?", dEn: "Which bus goes to the centre?", s: "An der Haltestelle, wenn du die Linie suchst.", sEn: "At the stop when looking for the line.", n: "Bus heißt „colectivo“, lässig auch „bondi“; die App „Cómo llego“ hilft enorm.", nEn: "Bus is „colectivo“, casually „bondi“; the „Cómo llego“ app helps a lot." },
    ar08: { e: "Disculpá, ¿el subte va a Recoleta?", d: "Entschuldigung, fährt die U-Bahn nach Recoleta?", dEn: "Excuse me, does the metro go to Recoleta?", s: "In der U-Bahn-Station, wenn du die Linie prüfst.", sEn: "At the metro station when checking the line.", n: "„Subte“ ist die U-Bahn von BA; in Recoleta liegt der berühmte Friedhof mit Evitas Grab.", nEn: "„Subte“ is the BA metro; Recoleta has the famous cemetery with Evita's grave." },
    ar09: { e: "Una mesa para dos, por favor.", d: "Einen Tisch für zwei, bitte.", dEn: "A table for two, please.", s: "Beim Betreten einer parrilla oder eines Restaurants.", sEn: "When entering a parrilla or restaurant.", n: "Argentinier essen spät (ab 21 Uhr); in der parrilla lohnt eine Reservierung.", nEn: "Argentines eat late (from 9pm); at the parrilla a booking pays off." },
    ar10: { e: "Quiero un bife de chorizo, a punto.", d: "Ich möchte ein Bife de chorizo, medium.", dEn: "I'd like a bife de chorizo, medium.", s: "Beim Bestellen im Grillrestaurant.", sEn: "When ordering at the grill restaurant.", n: "Garstufen: jugoso (blutig), a punto (medium), bien cocido (durch).", nEn: "Doneness: jugoso (rare), a punto (medium), bien cocido (well done)." },
    ar11: { e: "¿Qué me recomendás del asado?", d: "Was empfiehlst du mir vom Asado?", dEn: "What do you recommend from the asado?", s: "Beim Asado mit Einheimischen oder im Lokal.", sEn: "At an asado with locals or at a restaurant.", n: "Frag ruhig nach Klassikern wie vacío, entraña oder chorizo – und probier chimichurri dazu.", nEn: "Ask for classics like vacío, entraña or chorizo – and try chimichurri with it." },
    ar12: { e: "Tres empanadas para llevar, por favor.", d: "Drei Empanadas zum Mitnehmen, bitte.", dEn: "Three empanadas to go, please.", s: "Am Schnellimbiss oder in der Bäckerei.", sEn: "At the takeaway or bakery.", n: "Jede Provinz hat ihre Variante; in Salta sind sie kleiner und schärfer gewürzt.", nEn: "Every province has its own version; in Salta they're smaller and spicier." },
    ar13: { e: "Voy a pedir una milanesa con papas fritas.", d: "Ich nehme eine Milanesa mit Pommes.", dEn: "I'll have a milanesa with fries.", s: "Beim Bestellen eines günstigen Hauptgerichts.", sEn: "When ordering a cheap main dish.", n: "Die „milanesa napolitana“ mit Schinken, Tomate und Käse ist besonders deftig.", nEn: "The „milanesa napolitana“ with ham, tomato and cheese is extra hearty." },
    ar14: { e: "Dame un choripán, por favor.", d: "Gib mir bitte einen Choripán.", dEn: "Give me a choripán, please.", s: "Am Straßenstand oder beim Fußball.", sEn: "At a street stall or at the football.", n: "Choripán = chorizo + pan; mit chimichurri ein günstiger Snack-Klassiker.", nEn: "Choripán = chorizo + bread; with chimichurri it's a cheap classic snack." },
    ar15: { e: "¿Tenés alfajores de dulce de leche?", d: "Hast du Alfajores mit Dulce de leche?", dEn: "Do you have alfajores with dulce de leche?", s: "Im Kiosk oder Supermarkt auf der Suche nach Süßem.", sEn: "At the kiosk or supermarket looking for something sweet.", n: "„Tenés“ ist voseo; Marken wie Havanna gelten als Souvenir-Klassiker.", nEn: "„Tenés“ is voseo; brands like Havanna are classic souvenirs." },
    ar16: { e: "¿Querés cebar un mate?", d: "Magst du einen Mate teilen?", dEn: "Want to share a mate?", s: "Im Park, im Bus oder beim Kennenlernen.", sEn: "In the park, on the bus or when getting to know people.", n: "„Cebar“ heißt aufgießen; Mate teilen ist in Argentinien ein soziales Ritual.", nEn: "„Cebar“ means to brew/pour; sharing mate is a social ritual in Argentina." },
    ar17: { e: "Gracias, digo „gracias“ cuando ya no quiero más mate.", d: "Danke, ich sage „danke“, wenn ich genug Mate hatte.", dEn: "Thanks, I'll say thank you when I've had enough mate.", s: "In der Mate-Runde, damit du den Code verstehst.", sEn: "In a mate round, so you know the code.", n: "Sag erst „gracias“, wenn du wirklich keinen mehr willst – sonst wirst du übersprungen.", nEn: "Only say „gracias“ when you truly want no more – otherwise you get skipped." },
    ar18: { e: "Un café con medialunas, por favor.", d: "Einen Kaffee mit Medialunas, bitte.", dEn: "A coffee with medialunas, please.", s: "Morgens im Café (la confitería).", sEn: "In the morning at the café (la confitería).", n: "Medialunas gibt's de manteca (süß-butterig) oder de grasa (herzhafter).", nEn: "Medialunas come de manteca (sweet, buttery) or de grasa (more savoury)." },
    ar19: { e: "¿Dónde hay una milonga esta noche?", d: "Wo finde ich heute Abend eine Milonga?", dEn: "Where can I find a milonga tonight?", s: "Wenn du echten Tango erleben willst.", sEn: "When you want to experience real tango.", n: "Milongas in San Telmo sind oft authentischer als die Touristen-Shows.", nEn: "Milongas in San Telmo are often more authentic than tourist shows." },
    ar20: { e: "¿Me podés enseñar un paso de tango?", d: "Kannst du mir einen Tango-Schritt beibringen?", dEn: "Can you teach me a tango step?", s: "Vor oder bei der Milonga, wenn du mitmachen willst.", sEn: "Before or during the milonga, if you want to join in.", n: "Viele Milongas starten mit einer „clase“ für Anfänger – trau dich.", nEn: "Many milongas start with a beginner „clase“ – give it a go." },
    ar21: { e: "Quiero conocer San Telmo y La Boca.", d: "Ich möchte San Telmo und La Boca sehen.", dEn: "I want to see San Telmo and La Boca.", s: "Bei der Tagesplanung in Buenos Aires.", sEn: "When planning your day in Buenos Aires.", n: "La Boca tagsüber besuchen und am bunten Caminito bleiben; sonntags Markt in San Telmo.", nEn: "Visit La Boca by day and stick to the colourful Caminito; Sunday market in San Telmo." },
    ar22: { e: "Ojo, acá hay un poco de quilombo, ¿no?", d: "Vorsicht, hier ist es etwas chaotisch, oder?", dEn: "Careful, it's a bit chaotic here, right?", s: "Im Gedränge, am Terminal oder bei einer Demo.", sEn: "In a crowd, at the terminal or during a protest.", n: "„Quilombo“ = Chaos/Durcheinander, sehr gebräuchlich; „acá“ statt „aquí“.", nEn: "„Quilombo“ = chaos/mess, very common; „acá“ instead of „aquí“." },
    ar23: { e: "¿Cuánto sale? ¿Puedo pagar con tarjeta?", d: "Wie viel kostet das? Kann ich mit Karte zahlen?", dEn: "How much is it? Can I pay by card?", s: "Beim Einkaufen oder im Restaurant.", sEn: "When shopping or at a restaurant.", n: "„¿Cuánto sale?“ klingt einheimischer als „¿cuánto cuesta?“.", nEn: "„¿Cuánto sale?“ sounds more local than „¿cuánto cuesta?“." },
    ar24: { e: "¿Aceptan efectivo o prefieren tarjeta?", d: "Akzeptieren Sie Bargeld oder lieber Karte?", dEn: "Do you take cash or do you prefer card?", s: "An kleinen Ständen, in Hostels oder bei Touren.", sEn: "At small stalls, hostels or when booking tours.", n: "Bargeld („la plata“) ist oft praktisch; informier dich vor Ort über die aktuellen Konditionen.", nEn: "Cash („la plata“) is often handy; check current conditions on the ground." },
    ar25: { e: "¿Dónde conviene cambiar plata a un buen tipo de cambio?", d: "Wo wechsle ich am besten Geld zu einem fairen Kurs?", dEn: "Where's the best place to change money at a fair rate?", s: "Wenn du Pesos brauchst und den Kurs verstehen willst.", sEn: "When you need pesos and want to understand the rate.", n: "Argentinien hat Inflation und mehrere Wechselkurse – informier dich tagesaktuell und nutze seriöse Wege statt unsicherer Straßenwechsler.", nEn: "Argentina has inflation and several rates – check daily and use reputable channels, not risky street changers." },
    ar26: { e: "¿Eso es en pesos o en dólares?", d: "Ist das in Pesos oder in Dollar?", dEn: "Is that in pesos or in dollars?", s: "Wenn ein Preis genannt wird und die Währung unklar ist.", sEn: "When a price is quoted and the currency is unclear.", n: "Touren und Hotels werden manchmal in US-Dollar angegeben; immer kurz nachfragen.", nEn: "Tours and hotels are sometimes quoted in US dollars; always double-check." },
    ar27: { e: "¿Me alcanza la guita para el pasaje de micro?", d: "Reicht meine Kohle für das Busticket?", dEn: "Is my cash enough for the bus ticket?", s: "Am Schalter des Busbahnhofs.", sEn: "At the bus station counter.", n: "„La guita“ = lockeres Wort für Geld; „micro“ ist der Fernbus.", nEn: "„La guita“ = casual word for money; „micro“ is the long-distance bus." },
    ar28: { e: "Quiero un pasaje de micro en cama, por favor.", d: "Ich möchte ein Fernbus-Ticket mit „cama“, bitte.", dEn: "I'd like a long-distance bus ticket with cama seats, please.", s: "Beim Kauf eines Tickets für lange Strecken.", sEn: "When buying a ticket for a long route.", n: "„Cama“ = fast flache Liegesitze; bei Nachtfahrten Gold wert, denn Argentinien ist riesig.", nEn: "„Cama“ = nearly flat sleeper seats; gold on overnight rides, as Argentina is huge." },
    ar29: { e: "¿A qué hora sale el micro a Mendoza?", d: "Um wie viel Uhr fährt der Bus nach Mendoza ab?", dEn: "What time does the bus to Mendoza leave?", s: "Bei der Reiseplanung am Terminal de Ómnibus.", sEn: "When planning your trip at the Terminal de Ómnibus.", n: "Buenos Aires–Mendoza dauert per Bus rund 13–15 Stunden; viele fahren nachts.", nEn: "Buenos Aires–Mendoza takes about 13–15 hours by bus; many go overnight." },
    ar30: { e: "Me encantaría hacer una cata de vinos en una bodega.", d: "Ich würde gern eine Weinprobe in einem Weingut machen.", dEn: "I'd love to do a wine tasting at a winery.", s: "Bei der Buchung einer Tour in Mendoza.", sEn: "When booking a tour in Mendoza.", n: "In Maipú und Luján de Cuyo kannst du mehrere bodegas mit dem Rad abfahren.", nEn: "In Maipú and Luján de Cuyo you can cycle between several bodegas." },
    ar31: { e: "Un Malbec, por favor. ¡Salud!", d: "Einen Malbec, bitte. Auf dein Wohl!", dEn: "A Malbec, please. Cheers!", s: "Beim Anstoßen im Weingut oder in der Bar.", sEn: "When toasting at the winery or bar.", n: "Malbec ist Argentiniens Aushängeschild; „¡Salud!“ ist das Standard-Prost.", nEn: "Malbec is Argentina's flagship grape; „¡Salud!“ is the standard toast." },
    ar32: { e: "¿Cuánto dura la caminata al Fitz Roy?", d: "Wie lange dauert die Wanderung zum Fitz Roy?", dEn: "How long is the hike to Fitz Roy?", s: "Bei der Tourplanung in El Chaltén.", sEn: "When planning a hike in El Chaltén.", n: "Die Laguna de los Tres (Fitz-Roy-Aussicht) ist anspruchsvoll – früh starten und Wasser mitnehmen.", nEn: "The Laguna de los Tres (Fitz Roy viewpoint) is demanding – start early and bring water." },
    ar33: { e: "¿Necesito botas de trekking para el glaciar?", d: "Brauche ich für den Gletscher feste Wanderschuhe?", dEn: "Do I need solid hiking boots for the glacier?", s: "Bei der Ausrüstungsfrage in El Calafate.", sEn: "When sorting gear in El Calafate.", n: "Für das Minitrekking auf dem Perito Moreno stellt der Anbieter Steigeisen; feste Schuhe trotzdem ratsam.", nEn: "For mini-trekking on Perito Moreno the operator provides crampons; solid boots are still advisable." },
    ar34: { e: "¿Qué tan frío va a hacer hoy en El Calafate?", d: "Wie kalt wird es heute in El Calafate?", dEn: "How cold will it get in El Calafate today?", s: "Beim Packen am Morgen in Patagonien.", sEn: "When packing in the morning in Patagonia.", n: "Der patagonische Wind macht es gefühlt kälter – Zwiebellook und Windjacke einpacken.", nEn: "The Patagonian wind makes it feel colder – pack layers and a windbreaker." },
    ar35: { e: "¿Estamos de verdad en el fin del mundo acá?", d: "Sind wir hier wirklich am Ende der Welt?", dEn: "Are we really at the end of the world here?", s: "In Ushuaia, am südlichsten Punkt der Reise.", sEn: "In Ushuaia, the southernmost point of the trip.", n: "Ushuaia nennt sich „fin del mundo“; von hier starten viele Antarktis-Schiffe.", nEn: "Ushuaia calls itself the „end of the world“; many Antarctic ships leave from here." },
    ar36: { e: "¿Dónde compro la entrada para las Cataratas del Iguazú?", d: "Wo kaufe ich das Ticket für die Iguazú-Wasserfälle?", dEn: "Where do I buy the ticket for the Iguazú Falls?", s: "Am Eingang des Nationalparks in Puerto Iguazú.", sEn: "At the national park entrance in Puerto Iguazú.", n: "Argentinische Seite = nah dran und viele Stege; brasilianische Seite = das große Panorama.", nEn: "Argentine side = up close with many walkways; Brazilian side = the big panorama." },
    ar37: { e: "¿Vale la pena recorrer el norte hasta Salta?", d: "Lohnt es sich, den Norden bis Salta zu bereisen?", dEn: "Is it worth travelling the north up to Salta?", s: "Bei der Routenplanung über Patagonien hinaus.", sEn: "When planning a route beyond Patagonia.", n: "Salta und Jujuy bieten bunte Berge, die Ruta 40 und die Weine von Cafayate – ganz anders als der Süden.", nEn: "Salta and Jujuy offer colourful mountains, Ruta 40 and Cafayate wines – very different from the south." },
    ar38: { e: "¿Es seguro caminar solo por acá de noche?", d: "Ist es sicher, nachts hier allein zu laufen?", dEn: "Is it safe to walk here alone at night?", s: "Wenn du abends das Viertel einschätzen willst.", sEn: "When sizing up the area in the evening.", n: "In Großstädten auf belebten Straßen bleiben, Handy nicht offen zeigen und im Zweifel ein Taxi/Cabify nehmen.", nEn: "In big cities stay on busy streets, don't flash your phone and grab a taxi/Cabify if in doubt." },
    ar39: { e: "Ojo, boludo, que no te cobren de más.", d: "Pass auf, Kumpel, lass dich nicht abzocken.", dEn: "Watch out, mate, don't let them rip you off.", s: "Unter Freunden, als lockere Warnung.", sEn: "Among friends, as a casual warning.", n: "„Boludo“ ist unter Vertrauten freundlicher Slang („Alter“) – nie im förmlichen Kontext und nicht gegenüber Fremden nutzen.", nEn: "„Boludo“ is friendly slang among close friends („dude“) – never use it formally or with strangers." },
    ar40: { e: "Fue genial conocerte. ¡Nos vemos, che!", d: "Es war genial, dich kennenzulernen. Bis bald!", dEn: "It was great to meet you. See you soon!", s: "Beim Abschied von neuen Reisebekanntschaften.", sEn: "When saying goodbye to new travel friends.", n: "„Genial“ und „che“ klingen herzlich argentinisch; zum Tschüss passt auch „chau“.", nEn: "„Genial“ and „che“ sound warmly Argentine; „chau“ also works for goodbye." },

    // ===================== CHILE (Destination-Pack) =====================
    cl01: { e: "¿Dónde encuentro un taxi al centro de Santiago?", d: "Direkt am Flughafen Arturo Merino Benítez (SCL).", dEn: "Right at Arturo Merino Benítez airport (SCL).", s: "Beim Verlassen der Ankunftshalle, wo die Fahrer stehen.", sEn: "As you leave the arrivals hall where drivers wait.", n: "Nimm offizielle Flughafentaxis oder eine App statt spontaner Straßenfahrer.", nEn: "Take official airport taxis or an app rather than flagging one on the street." },
    cl02: { e: "Lléveme a mi hostal, por favor.", d: "Zum Fahrer, wenn du die Adresse schon hast.", dEn: "To the driver once you have the address.", s: "Beim Einsteigen ins Taxi oder den colectivo.", sEn: "As you get into the taxi or colectivo.", n: "Adresse auf dem Handy zeigen – Stadtteile wie Bellavista kennt jeder.", nEn: "Show the address on your phone – districts like Bellavista are well known." },
    cl03: { e: "¿Cuánto cuesta el viaje desde el aeropuerto?", d: "Vor Fahrtantritt, am Taxistand.", dEn: "Before the ride, at the taxi rank.", s: "Wenn du den Preis abklären willst.", sEn: "When you want to settle the price.", n: "Festpreis oder Taxameter klären; Apps zeigen den Preis vorab.", nEn: "Agree a fixed price or the meter; apps show the fare upfront." },
    cl04: { e: "¡Hola! ¿Cómo estái?", d: "Beim lockeren Begrüßen von Gleichaltrigen.", dEn: "When casually greeting people your age.", s: "Im Hostel, im Café, unter jungen Leuten.", sEn: "In the hostel, a café, among young people.", n: "Das „-ái“ statt „-as“ ist DAS Erkennungszeichen chilenischen Sprechens.", nEn: "The „-ái“ instead of „-as“ is THE hallmark of Chilean speech." },
    cl05: { e: "¿Todo bien? ¿Cachái?", d: "Wenn du dich vergewisserst, ob alles klar ist.", dEn: "When checking that everything's understood.", s: "Im Gespräch als freundliche Rückfrage.", sEn: "Mid-conversation as a friendly check.", n: "„¿cachái?“ ist allgegenwärtig – wie ein gesprochenes „weißt du?“.", nEn: "„¿cachái?“ is everywhere – like a spoken „you know?“." },
    cl06: { e: "¡Qué bacán!", d: "Wenn dir etwas richtig gut gefällt.", dEn: "When you really like something.", s: "Bei einem coolen Ort, Plan oder Essen.", sEn: "About a cool place, plan or dish.", n: "„bacán“, „la raja“ und „filete“ heißen alle „super“ – sehr chilenisch.", nEn: "„bacán“, „la raja“ and „filete“ all mean „awesome“ – very Chilean." },
    cl07: { e: "Hagámoslo al tiro, ¿ya?", d: "Wenn etwas sofort passieren soll.", dEn: "When something should happen right now.", s: "Beim Planen mit der Gruppe oder dem Guide.", sEn: "When planning with the group or guide.", n: "„al tiro“ = sofort; „¿ya?“ am Ende ist ein freundliches „ok?“.", nEn: "„al tiro“ = right away; „¿ya?“ at the end is a friendly „ok?“." },
    cl08: { e: "¡Sí po, weón!", d: "Unter Freunden zur Zustimmung.", dEn: "Among friends to agree.", s: "In lockerer Runde mit Leuten, die du gut kennst.", sEn: "In a relaxed group with people you know well.", n: "„weón“ nur unter Freunden – fremden Leuten gegenüber wirkt es beleidigend.", nEn: "„weón“ only among friends – to strangers it sounds insulting." },
    cl09: { e: "Disculpe, ¿dónde está la estación de metro?", d: "Wenn du dich in Santiago orientierst.", dEn: "When finding your way in Santiago.", s: "Auf der Straße, höflich zu Passanten.", sEn: "On the street, politely to passers-by.", n: "Hol dir früh eine „tarjeta bip!“ für Metro und micros.", nEn: "Get a „tarjeta bip!“ card early for metro and buses." },
    cl10: { e: "¿Qué línea va a la Plaza de Armas?", d: "An der Metrostation, vor dem Einsteigen.", dEn: "At the metro station before boarding.", s: "Wenn du den richtigen Anschluss suchst.", sEn: "When looking for the right connection.", n: "Plaza de Armas, La Moneda und Cerro Santa Lucía liegen zentral.", nEn: "Plaza de Armas, La Moneda and Cerro Santa Lucía are all central." },
    cl11: { e: "¿Esta micro va al Cerro San Cristóbal?", d: "An der Bushaltestelle beim Einsteigen.", dEn: "At the bus stop as you board.", s: "Wenn du zum Aussichtshügel willst.", sEn: "When heading to the lookout hill.", n: "„la micro“ = Stadtbus; vom Cerro San Cristóbal hast du ganz Santiago im Blick.", nEn: "„la micro“ = city bus; from Cerro San Cristóbal you see all of Santiago." },
    cl12: { e: "¿Cuánto cuesta un colectivo hasta allá?", d: "Beim Einsteigen in ein Sammeltaxi.", dEn: "As you get into a shared taxi.", s: "Wenn die micro nicht direkt fährt.", sEn: "When the bus doesn't go direct.", n: "„colectivo“ folgt fester Route, teilt sich Fahrgäste, ist günstig.", nEn: "„colectivo“ follows a fixed route, shares passengers, and is cheap." },
    cl13: { e: "Voy a tomar un bus a Valparaíso.", d: "Beim Planen des Tagesausflugs an die Küste.", dEn: "When planning the coastal day trip.", s: "Am Busterminal Alameda in Santiago.", sEn: "At Terminal Alameda in Santiago.", n: "Fernbusse sind komfortabel; Valparaíso ist gut 1,5 Std. entfernt.", nEn: "Long-distance buses are comfy; Valparaíso is about 1.5 hours away." },
    cl14: { e: "¿Qué ascensor me sube al cerro?", d: "Unten in Valparaíso vor einer Steigung.", dEn: "Down in Valparaíso before a climb.", s: "Wenn du auf einen der bunten Hügel willst.", sEn: "When heading up one of the colourful hills.", n: "Die historischen „ascensores“ sparen dir den steilen Aufstieg.", nEn: "The historic „ascensores“ save you the steep climb." },
    cl15: { e: "Estos murales son preciosos.", d: "Beim Bummel durch Cerro Alegre.", dEn: "While strolling through Cerro Alegre.", s: "Vor einer der vielen Street-Art-Wände.", sEn: "In front of one of the many street-art walls.", n: "Valparaíso ist UNESCO-Welterbe und ein Open-Air-Kunstmuseum.", nEn: "Valparaíso is a UNESCO site and an open-air art museum." },
    cl16: { e: "¿Puedo sacar una foto de la casa de colores?", d: "Wenn Leute auf einem Foto sein könnten.", dEn: "When people might be in the photo.", s: "Höflich, bevor du fotografierst.", sEn: "Politely before you take the shot.", n: "„sacar una foto“ ist hier üblicher als „tomar una foto“.", nEn: "„sacar una foto“ is more common here than „tomar una foto“." },
    cl17: { e: "Quiero un completo, por favor.", d: "An einem Imbiss oder einer Fuente de Soda.", dEn: "At a snack stand or fuente de soda.", s: "Wenn du den Klassiker probieren willst.", sEn: "When you want to try the classic.", n: "„completo italiano“ = mit Avocado, Tomate, Mayo – die Chile-Farben.", nEn: "„completo italiano“ = avocado, tomato, mayo – the Chilean colours." },
    cl18: { e: "Una empanada de pino, por favor.", d: "An der Bäckerei oder im Lokal.", dEn: "At the bakery or in a restaurant.", s: "Wenn du den Klassiker bestellst.", sEn: "When ordering the classic.", n: "„pino“ = Hack mit Zwiebel, Ei und Olive; Vorsicht, kann heiß sein.", nEn: "„pino“ = beef with onion, egg and an olive; careful, can be hot." },
    cl19: { e: "¿Qué lleva un pastel de choclo?", d: "Wenn du die Speisekarte erkundest.", dEn: "When exploring the menu.", s: "Bevor du das traditionelle Gericht bestellst.", sEn: "Before ordering the traditional dish.", n: "Maisbrei über Fleisch, im Tontopf gebacken – Sommergericht.", nEn: "Corn purée over meat, baked in a clay pot – a summer dish." },
    cl20: { e: "Quiero una cazuela para entrar en calor.", d: "An einem kühlen Tag im Süden.", dEn: "On a chilly day in the south.", s: "Wenn du etwas Warmes und Herzhaftes willst.", sEn: "When you want something warm and hearty.", n: "Cazuela = klare Brühe mit Fleisch, Mais, Kürbis und Kartoffel.", nEn: "Cazuela = clear broth with meat, corn, pumpkin and potato." },
    cl21: { e: "¿Hay mariscos frescos hoy?", d: "In einem Lokal an der Küste.", dEn: "At a restaurant by the coast.", s: "Auf einem Fischmarkt oder am Hafen.", sEn: "At a fish market or harbour.", n: "Chiles kalter Humboldtstrom bringt erstklassige Meeresfrüchte.", nEn: "Chile's cold Humboldt current brings top-class seafood." },
    cl22: { e: "En Chiloé quiero probar curanto sí o sí.", d: "Wenn dein Plan die Insel Chiloé einschließt.", dEn: "When your plan includes Chiloé island.", s: "Bei einer Verlängerung ins Seengebiet/Chiloé.", sEn: "On an extension to the lake district/Chiloé.", n: "„sí o sí“ = auf jeden Fall; Curanto wird traditionell im Erdofen gegart.", nEn: "„sí o sí“ = definitely; curanto is traditionally cooked in an earth oven." },
    cl23: { e: "Un pisco sour, por favor.", d: "Beim Apéro mit der Gruppe.", dEn: "At drinks with the group.", s: "In einer Bar am ersten Abend.", sEn: "In a bar on the first evening.", n: "Chiles Pisco kommt u. a. aus dem Valle del Elqui im Norden.", nEn: "Chile's pisco comes partly from the Elqui Valley up north." },
    cl24: { e: "¿Qué es un terremoto? ¿Es fuerte?", d: "Wenn du das berühmte Mischgetränk siehst.", dEn: "When you spot the famous mixed drink.", s: "In einer traditionellen Picada oder Bar.", sEn: "In a traditional picada or bar.", n: "Süßer Wein mit Ananaseis – nach zweien kommt logischerweise die „réplica“.", nEn: "Sweet wine with pineapple ice cream – two of them and you'll feel the „aftershock“." },
    cl25: { e: "¿Vienes a la once en la tarde?", d: "Wenn dich Locals einladen.", dEn: "When locals invite you.", s: "Am späten Nachmittag, statt Abendessen.", sEn: "In the late afternoon, instead of dinner.", n: "„once“ = Tee mit Brot, Käse, Avocado; ein geselliges Ritual.", nEn: "„once“ = tea with bread, cheese, avocado; a sociable ritual." },
    cl26: { e: "¿Puedo pagar en pesos en efectivo?", d: "An der Kasse oder beim Fahrer.", dEn: "At the till or with the driver.", s: "Wenn Karten nicht akzeptiert werden.", sEn: "When cards aren't accepted.", n: "Kleine Lokale und micros wollen oft Bargeld; CLP-Scheine bereithalten.", nEn: "Small eateries and buses often want cash; keep CLP notes ready." },
    cl27: { e: "Eso cuesta cinco lucas, ¿cierto?", d: "Beim Bestätigen eines Preises.", dEn: "When confirming a price.", s: "Auf dem Markt oder im Laden.", sEn: "At the market or shop.", n: "„luca“ = 1.000 Pesos; Locals rechnen ständig in lucas.", nEn: "„luca“ = 1,000 pesos; locals count in lucas all the time." },
    cl28: { e: "¿Hay un cajero automático por acá?", d: "Wenn dir das Bargeld ausgeht.", dEn: "When you run low on cash.", s: "In einer Stadt vor einer Tour.", sEn: "In a town before a tour.", n: "In San Pedro und Puerto Natales vorher abheben – Automaten sind rar.", nEn: "Withdraw in San Pedro and Puerto Natales beforehand – ATMs are scarce." },
    cl29: { e: "Mañana volamos a San Pedro de Atacama.", d: "Beim Planen des Wüstenabschnitts.", dEn: "When planning the desert leg.", s: "Mit der Gruppe am Vorabend.", sEn: "With the group the evening before.", n: "Inlandsflug nach Calama, dann gut 1 Std. Transfer nach San Pedro.", nEn: "Domestic flight to Calama, then about an hour's transfer to San Pedro." },
    cl30: { e: "Por la altura tomo harta agua.", d: "In den ersten Stunden in der Höhe.", dEn: "In the first hours at altitude.", s: "Bevor du zu höher gelegenen Touren aufbrichst.", sEn: "Before heading to higher tours.", n: "„harta agua“ = viel Wasser; langsam akklimatisieren, Alkohol meiden.", nEn: "„harta agua“ = lots of water; acclimatise slowly, avoid alcohol." },
    cl31: { e: "¿A qué hora salimos al Valle de la Luna?", d: "Beim Abstimmen der Abfahrtszeit.", dEn: "When confirming the departure time.", s: "Mit Guide oder Tourveranstalter.", sEn: "With the guide or tour operator.", n: "Das Mond-Tal glüht zum Sonnenuntergang – Stirnlampe einpacken.", nEn: "Moon Valley glows at sunset – pack a headlamp." },
    cl32: { e: "Los géiseres del Tatio hay que verlos al amanecer.", d: "Wenn die Gruppe die frühe Tour plant.", dEn: "When the group plans the early tour.", s: "Am Vorabend, bei der Tourbesprechung.", sEn: "The evening before, at the tour briefing.", n: "Abfahrt oft um 4–5 Uhr; auf 4.300 m bitterkalt – Mütze und Handschuhe.", nEn: "Departure often at 4–5 a.m.; bitterly cold at 4,300 m – hat and gloves." },
    cl33: { e: "Los colores de las lagunas altiplánicas son increíbles.", d: "Während der Lagunen-Tour.", dEn: "During the lagoon tour.", s: "An den Lagunas Altiplánicas oder am Salar.", sEn: "At the altiplano lagoons or the salt flat.", n: "Flamingos und tiefblaues Wasser vor den Vulkanen – Sonnenschutz nicht vergessen.", nEn: "Flamingos and deep-blue water below volcanoes – don't forget sun protection." },
    cl34: { e: "Esta noche vamos a mirar las estrellas.", d: "Bei einer Astro-Tour in der Wüste.", dEn: "On an astronomy tour in the desert.", s: "Nach Einbruch der Dunkelheit, abseits der Lichter.", sEn: "After dark, away from the lights.", n: "Atacama hat kaum Lichtverschmutzung – die Milchstraße ist gestochen scharf.", nEn: "Atacama has almost no light pollution – the Milky Way is razor-sharp." },
    cl35: { e: "Seguimos a la Patagonia, al sur.", d: "Beim Wechsel von der Wüste in den Süden.", dEn: "When switching from the desert to the south.", s: "Vor dem langen Flug Richtung Süden.", sEn: "Before the long flight south.", n: "Meist Flug nach Punta Arenas, dann Bus nach Puerto Natales als Basis.", nEn: "Usually a flight to Punta Arenas, then a bus to Puerto Natales as your base." },
    cl36: { e: "¿Cuánto dura el W-Trek en Torres del Paine?", d: "Beim Vorbereiten des Treks.", dEn: "When preparing for the trek.", s: "Mit dem Guide oder im Refugio.", sEn: "With the guide or at the refugio.", n: "Der W-Trek führt in 4–5 Tagen zu Base Torres, Valle del Francés und Glaciar Grey.", nEn: "The W-Trek covers Base Torres, Valle del Francés and Glaciar Grey in 4–5 days." },
    cl37: { e: "En la Patagonia hay un viento helado.", d: "Beim Packen für den Trek.", dEn: "When packing for the trek.", s: "Draußen, wenn dich der Wind überrascht.", sEn: "Outdoors when the wind catches you out.", n: "„cuático“ = heftig/krass; im Schichtsystem und mit Windjacke planen.", nEn: "„cuático“ = intense; plan with layers and a windproof jacket." },
    cl38: { e: "¿Me puede recomendar un buen vino chileno?", d: "Im Restaurant oder bei einer Weinprobe.", dEn: "At a restaurant or a wine tasting.", s: "Bei einem Besuch im Weintal nahe Santiago.", sEn: "On a visit to a wine valley near Santiago.", n: "Carmenère ist die chilenische Signatur-Rebe; Colchagua und Maipo sind bekannt.", nEn: "Carmenère is Chile's signature grape; Colchagua and Maipo are famous." },
    cl39: { e: "¿Es seguro este barrio de noche?", d: "Wenn du abends unterwegs bist.", dEn: "When you're out in the evening.", s: "An der Rezeption oder bei Locals.", sEn: "At reception or with locals.", n: "In Santiago auf Taschendiebe an Bahnhöfen achten; Wertsachen unauffällig tragen.", nEn: "In Santiago watch for pickpockets at stations; keep valuables hidden." },
    cl40: { e: "¡Muchas gracias, lo pasé la raja!", d: "Beim Verabschieden nach einem tollen Tag.", dEn: "When saying goodbye after a great day.", s: "Zu Guides, Gastgebern oder neuen Freunden.", sEn: "To guides, hosts or new friends.", n: "„pasarlo la raja“ = sich super amüsieren; locker, unter Locals herzlich.", nEn: "„pasarlo la raja“ = to have a brilliant time; casual and warm among locals." },

    // ===================== BOLIVIEN (Destination-Pack) =====================
    bo01: { e: "Hola, ¿dónde tomo un taxi del aeropuerto de El Alto?", d: "Hallo, wo finde ich ein Taxi vom Flughafen El Alto?", dEn: "Hi, where do I find a taxi from El Alto airport?", s: "Direkt nach der Landung in La Paz, am Ausgang des Terminals.", sEn: "Right after landing in La Paz, at the terminal exit.", n: "El Alto liegt auf ~4.060 m – beweg dich langsam, der Körper braucht Zeit.", nEn: "El Alto sits at ~4,060 m – move slowly, your body needs time." },
    bo02: { e: "Lléveme al centro de La Paz, por favor.", d: "Bringen Sie mich bitte ins Zentrum von La Paz.", dEn: "Take me to the centre of La Paz, please.", s: "Im Taxi vom Flughafen hinunter ins Tal.", sEn: "In the taxi from the airport down into the valley.", n: "Von El Alto geht es steil bergab – die Aussicht auf La Paz ist spektakulär.", nEn: "From El Alto it's a steep descent – the view of La Paz is spectacular." },
    bo03: { e: "¿Cuánto me cobra hasta el hostal?", d: "Wie viel verlangen Sie bis zum Hostel?", dEn: "How much do you charge to the hostel?", s: "Vor dem Einsteigen, um den Preis festzulegen.", sEn: "Before getting in, to set the price.", n: "„cobrar“ heißt berechnen. In Bolivien zahlt man in bolivianos (Bs).", nEn: "„cobrar“ means to charge. In Bolivia you pay in bolivianos (Bs)." },
    bo04: { e: "Me afecta la altura. ¿Tiene mate de coca?", d: "Ich spüre die Höhe. Haben Sie Kokatee?", dEn: "I feel the altitude. Do you have coca tea?", s: "Im Hostel oder Café an den ersten Tagen in der Höhe.", sEn: "At the hostel or café during your first days at altitude.", n: "soroche = Höhenkrankheit. mate de coca gibt es fast überall und hilft.", nEn: "soroche = altitude sickness. mate de coca is everywhere and helps." },
    bo05: { e: "Tengo mareo por la altura.", d: "Mir ist schwindelig wegen der Höhe.", dEn: "I feel dizzy because of the altitude.", s: "Wenn dir Kopf oder Magen in der Höhe zu schaffen machen.", sEn: "When your head or stomach struggles at altitude.", n: "La Paz ~3.600 m, El Alto ~4.100 m. Viel trinken, wenig Alkohol, ruhig angehen.", nEn: "La Paz ~3,600 m, El Alto ~4,100 m. Drink lots, little alcohol, take it easy." },
    bo06: { e: "Buenas tardes, ¿cómo está?", d: "Guten Tag, wie geht es Ihnen?", dEn: "Good afternoon, how are you?", s: "Beim Betreten von Laden, Hostel oder Restaurant am Nachmittag.", sEn: "When entering a shop, hostel or restaurant in the afternoon.", n: "Bolivien ist höflich und förmlich – mit Fremden lieber „usted“ statt „tú“.", nEn: "Bolivia is polite and formal – with strangers prefer „usted“ over „tú“." },
    bo07: { e: "¡Kamisaraki!", d: "Hallo! (Gruß auf Aymara)", dEn: "Hello! (greeting in Aymara)", s: "Wenn du eine Aymara-Person im Hochland herzlich begrüßen willst.", sEn: "When you want to warmly greet an Aymara person in the highlands.", n: "„Kamisaraki“ ist der allgemeine Aymara-Gruß (nicht nur morgens). Die Antwort lautet „Waliki“.", nEn: "„Kamisaraki“ is the general Aymara greeting (not only in the morning). The reply is „Waliki“." },
    bo08: { e: "Waliki, gracias.", d: "Mir geht es gut, danke. (Antwort auf Aymara)", dEn: "I'm fine, thanks. (reply in Aymara)", s: "Als Antwort, wenn dich jemand mit „Kamisaraki“ grüßt.", sEn: "As a reply when someone greets you with „Kamisaraki“.", n: "„Waliki“ heißt „gut/alles in Ordnung“ auf Aymara – ein kurzes Lächeln wirkt Wunder.", nEn: "„Waliki“ means „good/all well“ in Aymara – a quick smile works wonders." },
    bo09: { e: "¿Dónde puedo sacar bolivianos?", d: "Wo kann ich Bolivianos abheben?", dEn: "Where can I withdraw bolivianos?", s: "Am Geldautomaten oder beim Suchen nach einer Bank.", sEn: "At the ATM or when looking for a bank.", n: "Die Währung ist der boliviano (Bs / BOB). Kleine Scheine sind sehr nützlich.", nEn: "The currency is the boliviano (Bs / BOB). Small notes are very useful." },
    bo10: { e: "¿Me puede cambiar dinero?", d: "Können Sie mir Geld wechseln?", dEn: "Can you change money for me?", s: "In einer Wechselstube oder einem kleinen Laden.", sEn: "At an exchange office or a small shop.", n: "Wechselstuben heißen „casa de cambio“. Den Kurs vorher erfragen.", nEn: "Exchange offices are „casa de cambio“. Ask the rate first." },
    bo11: { e: "¿Cómo llego a El Alto en el teleférico?", d: "Wie komme ich mit der Seilbahn nach El Alto?", dEn: "How do I get to El Alto by cable car?", s: "An einer Seilbahnstation in La Paz.", sEn: "At a cable-car station in La Paz.", n: "Der Teleférico ist das längste urbane Seilbahnnetz der Welt – günstig und mit Traumblick.", nEn: "The Teleférico is the world's longest urban cable-car network – cheap and with stunning views." },
    bo12: { e: "¿Qué línea del teleférico va al centro?", d: "Welche Linie der Seilbahn fährt ins Zentrum?", dEn: "Which cable-car line goes to the centre?", s: "Wenn du die richtige Seilbahnlinie suchst.", sEn: "When you're looking for the right cable-car line.", n: "Die Linien heißen nach Farben: Roja, Amarilla, Verde, Azul …", nEn: "Lines are named by colour: Roja, Amarilla, Verde, Azul …" },
    bo13: { e: "¿Este minibús va al Mercado de las Brujas?", d: "Fährt dieser Minibus zum Hexenmarkt?", dEn: "Does this minibus go to the Witches' Market?", s: "An einer Haltestelle, bevor du in den Minibus steigst.", sEn: "At a stop, before getting on the minibus.", n: "Mercado de las Brujas = Hexenmarkt in La Paz mit Kräutern und Ritualartikeln.", nEn: "Mercado de las Brujas = Witches' Market in La Paz with herbs and ritual items." },
    bo14: { e: "¿Dónde para el trufi a San Pedro?", d: "Wo hält der Trufi nach San Pedro?", dEn: "Where does the trufi to San Pedro stop?", s: "Wenn du den Sammeltaxi-Halt für ein Stadtviertel suchst.", sEn: "When looking for the shared-taxi stop for a neighbourhood.", n: "„trufi“ = Sammeltaxi mit fester Route, „micro“ = Kleinbus. Beide sind günstig.", nEn: "„trufi“ = shared taxi on a fixed route, „micro“ = small bus. Both are cheap." },
    bo15: { e: "Disculpe, casera, ¿cuánto cuesta esta manta?", d: "Entschuldigung, was kostet diese Decke?", dEn: "Excuse me, how much is this blanket?", s: "Am Markt, beim Stöbern nach Textilien aus Alpakawolle.", sEn: "At the market, browsing alpaca-wool textiles.", n: "„casera/casero“ ist die höfliche Anrede für Verkäufer:innen – wirkt sofort herzlich.", nEn: "„casera/casero“ is the polite way to address vendors – instantly warm." },
    bo16: { e: "¿Me hace un descuento, casera?", d: "Geht es etwas günstiger, Verkäuferin?", dEn: "Can you make it a bit cheaper?", s: "Beim freundlichen Handeln auf dem Markt.", sEn: "When haggling kindly at the market.", n: "Mit einem Lächeln und „casera“ verhandelt es sich respektvoll, nicht aggressiv.", nEn: "With a smile and „casera“ you bargain respectfully, not aggressively." },
    bo17: { e: "Quisiera una salteña, por favor.", d: "Ich hätte gern eine Salteña.", dEn: "I'd like a salteña, please.", s: "Vormittags am Stand oder in einer Salteñería.", sEn: "Mid-morning at a stall or in a salteñería.", n: "salteña = saftige gefüllte Teigtasche, traditionell der Vormittagssnack. Vorsicht, sie tropft!", nEn: "salteña = juicy stuffed pasty, traditionally the mid-morning snack. Careful, it drips!" },
    bo18: { e: "De desayuno, un api con pastel, por favor.", d: "Zum Frühstück ein Api mit Pastel, bitte.", dEn: "For breakfast, an api with pastel, please.", s: "Früh am Markt, wenn es noch kalt ist.", sEn: "Early at the market, when it's still cold.", n: "api = warmes Maisgetränk (lila oder gelb), pastel = frittiertes Käsegebäck mit Puderzucker.", nEn: "api = warm corn drink (purple or yellow), pastel = fried cheese pastry with icing sugar." },
    bo19: { e: "¿Qué lleva un silpancho?", d: "Was ist in einem Silpancho?", dEn: "What's in a silpancho?", s: "Beim Bestellen, wenn du das Gericht noch nicht kennst.", sEn: "When ordering, if you don't know the dish yet.", n: "silpancho = dünn geklopftes paniertes Fleisch auf Reis und Kartoffeln, mit Spiegelei. Aus Cochabamba.", nEn: "silpancho = thin breaded meat on rice and potatoes, topped with a fried egg. From Cochabamba." },
    bo20: { e: "¿El pique a lo macho es muy picante?", d: "Ist das Pique a lo Macho sehr scharf?", dEn: "Is the pique a lo macho very spicy?", s: "Beim Bestellen, wenn du Schärfe einschätzen willst.", sEn: "When ordering, if you want to gauge the spice.", n: "pique a lo macho = Fleisch, Würstchen und Pommes mit Zwiebeln und Chili – ideal zum Teilen.", nEn: "pique a lo macho = meat, sausage and fries with onion and chilli – ideal to share." },
    bo21: { e: "Un plato de fricasé, por favor.", d: "Eine Schüssel Fricasé, bitte.", dEn: "A bowl of fricasé, please.", s: "An einem kalten Tag im Hochland oder am Morgen danach.", sEn: "On a cold highland day, or the morning after.", n: "fricasé = scharfe Schweinesuppe mit Mais und Kartoffeln – wärmt herrlich gegen die Kälte.", nEn: "fricasé = spicy pork soup with corn and potatoes – wonderfully warming against the cold." },
    bo22: { e: "¿A qué hora sale el bus nocturno a Uyuni?", d: "Um wie viel Uhr fährt der Nachtbus nach Uyuni?", dEn: "What time does the night bus to Uyuni leave?", s: "Am Busterminal, wenn du nach Uyuni weiterreist.", sEn: "At the bus terminal, when heading on to Uyuni.", n: "Nachtbusse sind in Bolivien Standard. Zieh dich warm an – nachts wird es eisig.", nEn: "Night buses are standard in Bolivia. Dress warmly – it gets freezing at night." },
    bo23: { e: "Quiero hacer un tour de tres días en jeep por el salar.", d: "Ich möchte eine dreitägige Jeeptour durch den Salar machen.", dEn: "I'd like to do a three-day jeep tour across the Salar.", s: "In einer Agentur in Uyuni, beim Buchen der Tour.", sEn: "At an agency in Uyuni, when booking the tour.", n: "Salar de Uyuni ~3.660 m. Die klassische 3-Tage-Tour im 4x4 führt bis zu den Lagunen.", nEn: "Salar de Uyuni ~3,660 m. The classic 3-day 4x4 tour reaches the lagoons." },
    bo24: { e: "¿Nos levantamos temprano para el amanecer en el salar?", d: "Stehen wir früh für den Sonnenaufgang auf dem Salzsee auf?", dEn: "Are we getting up early for sunrise on the salt flat?", s: "Abends mit dem Guide, um den nächsten Tag zu planen.", sEn: "In the evening with the guide, planning the next day.", n: "Der Sonnenaufgang über dem weißen Salz ist eines der Highlights der ganzen Tour.", nEn: "Sunrise over the white salt is one of the highlights of the whole tour." },
    bo25: { e: "¿Cuándo hay efecto espejo en el salar?", d: "Wann gibt es den Spiegeleffekt im Salar?", dEn: "When does the mirror effect happen in the Salar?", s: "Wenn du wissen willst, ob der Salzsee gerade wie ein Spiegel wirkt.", sEn: "When you want to know if the salt flat is mirror-like right now.", n: "Der Spiegeleffekt entsteht durch eine dünne Wasserschicht, vor allem in der Regenzeit (Dez–März).", nEn: "The mirror effect comes from a thin layer of water, mainly in the rainy season (Dec–Mar)." },
    bo26: { e: "¿Paramos en la Isla Incahuasi con los cactus?", d: "Halten wir auf der Isla Incahuasi mit den Kakteen?", dEn: "Do we stop at Isla Incahuasi with the cacti?", s: "Während der Salar-Tour, beim Abstimmen der Stopps.", sEn: "During the Salar tour, when agreeing the stops.", n: "Isla Incahuasi = felsige Kakteen-Insel mitten im Salzsee, mit riesigen, jahrhundertealten Kakteen.", nEn: "Isla Incahuasi = rocky cactus island in the middle of the salt flat, with huge centuries-old cacti." },
    bo27: { e: "¿Cómo se llama esta laguna roja con flamencos?", d: "Wie heißt diese rote Lagune mit den Flamingos?", dEn: "What's this red lagoon with the flamingos called?", s: "Im Eduardo-Avaroa-Park, vor einer roten Lagune voller Flamingos.", sEn: "In Eduardo Avaroa park, before a red lagoon full of flamingos.", n: "Laguna Colorada = rote Lagune (durch Algen und Mineralien) mit drei Flamingo-Arten.", nEn: "Laguna Colorada = red lagoon (from algae and minerals) with three flamingo species." },
    bo28: { e: "¿Nos detenemos en los géiseres Sol de Mañana?", d: "Halten wir an den Geysiren Sol de Mañana?", dEn: "Do we stop at the Sol de Mañana geysers?", s: "Früh am dritten Tag der Salar-Tour, auf dem Weg zu den Geysiren.", sEn: "Early on day three of the Salar tour, heading to the geysers.", n: "Sol de Mañana liegt auf ~4.800–5.000 m: brodelnder Schlamm, Dampf, eisiger Wind. Warm anziehen!", nEn: "Sol de Mañana sits at ~4,800–5,000 m: bubbling mud, steam, icy wind. Dress warmly!" },
    bo29: { e: "¿Podemos bañarnos en las aguas termales?", d: "Können wir in den heißen Quellen baden?", dEn: "Can we bathe in the hot springs?", s: "Bei den Thermalbecken auf der Salar-Tour, am frühen Morgen.", sEn: "At the thermal pools on the Salar tour, in the early morning.", n: "Termas de Polques = warmes Becken mitten in der eiskalten Hochwüste – Badesachen bereithalten.", nEn: "Termas de Polques = warm pool in the freezing high desert – have your swimwear ready." },
    bo30: { e: "¿El hotel está hecho de sal de verdad?", d: "Ist das Hotel wirklich aus Salz gebaut?", dEn: "Is the hotel really built from salt?", s: "Am ersten Abend der Salar-Tour, bei der Ankunft in der Unterkunft.", sEn: "On the first evening of the Salar tour, arriving at the lodging.", n: "Wände, Tische und Betten bestehen teils aus Salzblöcken. Nachts wird es sehr kalt.", nEn: "Walls, tables and beds are partly made of salt blocks. It gets very cold at night." },
    bo31: { e: "Quiero hacer un tour a las minas del Cerro Rico.", d: "Ich möchte eine Tour in die Minen vom Cerro Rico machen.", dEn: "I'd like to do a tour into the Cerro Rico mines.", s: "In Potosí, beim Buchen einer Minentour.", sEn: "In Potosí, booking a mine tour.", n: "Potosí (~4.000 m) ist UNESCO-Welterbe. Der Cerro Rico war einer der reichsten Silberberge der Welt.", nEn: "Potosí (~4,000 m) is a UNESCO site. Cerro Rico was one of the world's richest silver mountains." },
    bo32: { e: "¿El tour a la mina es exigente físicamente?", d: "Ist die Minentour körperlich anstrengend?", dEn: "Is the mine tour physically demanding?", s: "Vor dem Buchen, wenn du die Anstrengung einschätzen willst.", sEn: "Before booking, if you want to gauge the effort.", n: "In der Mine ist es eng, heiß, staubig und hoch gelegen – nichts für Klaustrophobie.", nEn: "The mine is narrow, hot, dusty and high up – not for the claustrophobic." },
    bo33: { e: "Sucre es una ciudad blanca muy bonita, ¿verdad?", d: "Sucre ist eine wunderschöne weiße Stadt, oder?", dEn: "Sucre is a beautiful white city, isn't it?", s: "Beim Schlendern durch die koloniale Altstadt von Sucre.", sEn: "Strolling through Sucre's colonial old town.", n: "Sucre = UNESCO-Welterbe und konstitutionelle Hauptstadt, bekannt als „la ciudad blanca“.", nEn: "Sucre = UNESCO World Heritage and constitutional capital, known as „the white city“." },
    bo34: { e: "¿Cómo llego a Copacabana en el lago Titicaca?", d: "Wie komme ich nach Copacabana am Titicacasee?", dEn: "How do I get to Copacabana on Lake Titicaca?", s: "Beim Planen des Ausflugs von La Paz an den See.", sEn: "When planning the trip from La Paz to the lake.", n: "Titicaca liegt auf ~3.810 m und ist der höchste schiffbare See der Welt. Copacabana ist das Tor dorthin.", nEn: "Titicaca sits at ~3,810 m and is the world's highest navigable lake. Copacabana is the gateway." },
    bo35: { e: "¿La lancha va hoy a la Isla del Sol?", d: "Fährt das Boot heute zur Isla del Sol?", dEn: "Does the boat go to Isla del Sol today?", s: "Am Hafen von Copacabana, beim Kauf der Bootsfahrt.", sEn: "At Copacabana harbour, buying the boat trip.", n: "Isla del Sol gilt in der Inka-Mythologie als Geburtsstätte der Sonne. „lancha“ = kleines Boot.", nEn: "Isla del Sol is the mythical birthplace of the sun in Inca lore. „lancha“ = small boat." },
    bo36: { e: "¿Qué antigüedad tienen las ruinas de Tiwanaku?", d: "Wie alt sind die Ruinen von Tiwanaku?", dEn: "How old are the ruins of Tiwanaku?", s: "Bei einem Tagesausflug von La Paz zur Ausgrabungsstätte.", sEn: "On a day trip from La Paz to the archaeological site.", n: "Tiwanaku ist eine präinkaische Hochkultur, viele Jahrhunderte vor den Inka – das Sonnentor ist berühmt.", nEn: "Tiwanaku is a pre-Inca civilisation, many centuries before the Incas – the Sun Gate is famous." },
    bo37: { e: "¿Es seguro bajar por el Camino de la Muerte a Coroico?", d: "Ist die Fahrt auf der Todesstraße nach Coroico sicher?", dEn: "Is the ride down the Death Road to Coroico safe?", s: "Beim Buchen der Mountainbike-Tour ab La Paz.", sEn: "When booking the mountain-bike tour from La Paz.", n: "Der „Camino de la Muerte“ führt von der Höhe hinab in die grünen Yungas bei Coroico – nur mit seriöser Agentur fahren.", nEn: "The „Camino de la Muerte“ drops from the heights into the green Yungas near Coroico – only ride with a reputable agency." },
    bo38: { e: "¿Cómo se llama ella, con su traje de cholita?", d: "Wie heißt sie in ihrer Cholita-Tracht?", dEn: "What's her name, in her cholita dress?", s: "Beim respektvollen Smalltalk, z. B. nach einer Cholita-Wrestling-Show in El Alto.", sEn: "In respectful small talk, e.g. after a cholita wrestling show in El Alto.", n: "„cholita“ = Aymara-Frau in traditionellem Faltenrock (pollera) und Melone. Fotos immer vorher freundlich erfragen.", nEn: "„cholita“ = Aymara woman in the traditional pleated skirt (pollera) and bowler hat. Always ask kindly before photos." },
    bo39: { e: "¿Esta zona es segura de noche?", d: "Ist diese Gegend nachts sicher?", dEn: "Is this area safe at night?", s: "Im Hostel oder bei Einheimischen, bevor du abends losgehst.", sEn: "At the hostel or with locals, before heading out in the evening.", n: "Nachts lieber ein Funktaxi („radio taxi“) bestellen statt eines auf der Straße angehaltenen Taxis.", nEn: "At night, book a radio taxi rather than flagging one on the street." },
    bo40: { e: "Fue hermoso. ¡Jallalla Bolivia!", d: "Es war wunderschön. Es lebe Bolivien!", dEn: "It was beautiful. Long live Bolivia!", s: "Zum Abschied oder bei einem freudigen Moment mit Einheimischen.", sEn: "When saying goodbye or in a joyful moment with locals.", n: "„¡Jallalla!“ ist ein Aymara/Quechua-Hochruf der Freude und des Segens – ein Herzöffner zum Abschied.", nEn: "„¡Jallalla!“ is an Aymara/Quechua cheer of joy and blessing – a heart-opener when parting." },
  };

  window.SC = window.SC || {};
  window.SC.contextData = C;
})();
